INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('asmnt-q37','assessment','standardized-tests','fill_in','K-WISC-V에서 K-WISC-IV의 지각추론지표(PRI)가 두 개의 지표로 분리되었다. 분리된 두 지표는 ( ① )지표와 ( ② )지표이다. ①과 ②를 순서대로 쓰시오.',NULL,NULL,'① 시공간(VSI) / ② 유동추론(FRI)','K-WISC-IV에서는 지각추론지표(PRI) 하나로 측정하던 비언어적 인지 능력을, K-WISC-V에서는 시공간(Visual Spatial Index)과 유동추론(Fluid Reasoning Index)으로 분리하였다. 시공간지표는 시각적 자극의 분석·통합과 공간 관계 파악을, 유동추론지표는 새로운 상황에서의 추론과 규칙 발견 능력을 측정한다.',NULL,1,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('asmnt-q38','assessment','standardized-tests','fill_in','K-WISC-V의 작업기억지표(WMI)를 구성하는 2개의 기본 소검사는 ( ① )과/와 ( ② )이다. ①과 ②를 쓰시오.',NULL,NULL,'① 숫자 / ② 그림기억','K-WISC-V의 작업기억지표(Working Memory Index)는 정보를 일시적으로 저장하고 조작하는 능력을 측정하며, 기본 소검사는 숫자(Digit Span)와 그림기억(Picture Span)으로 구성된다. 숫자 소검사는 바로따라하기, 거꾸로따라하기, 순서대로따라하기의 3가지 과제를 포함한다.',NULL,2,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('asmnt-q39','assessment','standardized-tests','ox','검사-재검사 신뢰도는 동일한 검사를 동일한 대상에게 일정 시간 간격을 두고 두 번 실시한 후, 두 검사 점수 간의 상관계수로 산출한다.',NULL,NULL,'O','검사-재검사 신뢰도(test-retest reliability)는 안정성 계수(coefficient of stability)라고도 하며, 동일한 검사를 동일한 대상에게 시간 간격을 두고 두 번 실시하여 두 점수 간 상관계수를 산출하는 방법이다. 시간 간격이 너무 짧으면 연습효과가, 너무 길면 성숙효과가 신뢰도 추정에 영향을 줄 수 있다.',NULL,1,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('asmnt-q40','assessment','standardized-tests','multiple','다음 중 준거 타당도(criterion-related validity)의 하위 유형과 그 설명이 올바르게 짝지어진 것은?',NULL,ARRAY['공인 타당도 - 검사 결과가 미래의 수행을 예측하는 정도','예언 타당도 - 검사와 준거를 동시에 측정했을 때의 상관','공인 타당도 - 검사와 준거를 동시에 측정했을 때의 상관','구인 타당도 - 검사 결과와 외부 준거의 관련성'],'2','준거 타당도의 하위 유형은 공인 타당도(concurrent validity)와 예언 타당도(predictive validity)이다. 공인 타당도는 검사와 준거를 동시에 측정했을 때의 상관을 의미하고, 예언 타당도는 검사 결과가 미래의 수행을 예측하는 정도를 의미한다. 구인 타당도는 준거 타당도의 하위 유형이 아니라 별도의 타당도 유형이다.','{"0": "공인 타당도는 동시 측정이며, 미래 수행 예측은 예언 타당도에 해당한다.", "1": "동시 측정은 공인 타당도이며, 예언 타당도는 시차를 두고 상관을 분석한다.", "3": "구인 타당도는 이론적 구인을 정확히 측정하는 정도로, 준거 타당도와는 별개의 유형이다."}',2,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('asmnt-q41','assessment','standardized-tests','descriptive','KISE-KAT(한국판 적응행동검사)가 측정하는 적응행동의 3개 하위영역을 쓰고, 각 영역에 포함되는 하위 기술을 2가지씩 제시하시오.',NULL,NULL,'(1) 개념적 적응행동: 언어(수용·표현), 읽기·쓰기, 수 개념, 자기지시 등. (2) 사회적 적응행동: 대인관계, 사회적 책임, 규칙 준수, 자존감 등. (3) 실제적 적응행동: 일상생활활동(ADL), 건강·안전, 직업기술, 이동 등.','KISE-KAT(국립특수교육원 적응행동검사)는 AAIDD(2021)의 적응행동 개념 모델에 기반하여 개념적·사회적·실제적 적응행동의 3영역으로 구성된다. 지적장애 진단에서 지능검사(IQ 70 이하)와 함께 적응행동의 유의미한 제한이 동시에 확인되어야 하며, KISE-KAT는 이를 평가하는 대표적인 한국형 도구이다.',NULL,2,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('asmnt-q42','assessment','standardized-tests','descriptive','규준참조평가와 준거참조평가의 차이를 (1) 평가 목적, (2) 결과 해석 방식, (3) 특수교육에서의 활용 장면 측면에서 각각 비교하여 서술하시오.',NULL,NULL,'(1) 목적: 규준참조평가는 개인의 수행을 동일 연령/학년 집단과 비교하여 상대적 위치를 파악하는 것이 목적이고, 준거참조평가는 사전에 설정된 교육 목표나 기준에 비추어 학생이 무엇을 할 수 있는지 파악하는 것이 목적이다. (2) 해석: 규준참조평가는 백분위, 표준점수, 학력지수 등 상대적 위치로 해석하고, 준거참조평가는 도달/미도달, 숙달/미숙달 등 절대적 기준으로 해석한다. (3) 활용: 규준참조평가는 K-WISC-V, KISE-KAT 등 선정·배치·진단 단계에서, 준거참조평가는 CBM, IEP 목표 달성도 평가 등 교수·학습 계획 및 진전도 모니터링에서 활용된다.','규준참조평가는 ''누가 더 잘하는가''(상대적 비교)에, 준거참조평가는 ''무엇을 할 수 있는가''(절대적 기준)에 초점을 둔다. 특수교육 현장에서는 두 유형의 평가를 목적에 맞게 상호보완적으로 활용하는 것이 중요하다.',NULL,3,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('asmnt-q43','assessment','standardized-tests','fill_in','검사가 측정하고자 하는 이론적 구인(construct)을 정확하게 측정하는 정도를 ( ① ) 타당도라 하며, 이를 확인하기 위해 주로 ( ② ) 기법을 사용한다. ①과 ②를 쓰시오.',NULL,NULL,'① 구인 / ② 요인분석','구인 타당도(construct validity)는 검사가 이론적 구인을 얼마나 정확하게 측정하는지를 나타낸다. 확인 방법으로는 요인분석(factor analysis), 수렴 타당도(convergent validity), 변별 타당도(discriminant validity) 등이 있다. K-WISC-V의 5요인 구조는 확인적 요인분석(CFA)을 통해 검증되었다.',NULL,2,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('asmnt-q44','assessment','cbm','fill_in','교육과정중심측정(CBM)에서 기초선 점과 장기 목표 점을 직선으로 연결하여 학생의 기대 성장 경로를 나타내는 선을 ( ① )이라 하고, 실제 측정 데이터의 경향을 나타내는 선을 ( ② )이라 한다. ①과 ②를 쓰시오.',NULL,NULL,'① 목표선(aimline) / ② 추세선(trendline)','CBM에서 목표선(aimline 또는 goal line)은 현행 수준(기초선)과 장기 목표를 직선으로 연결하여 기대되는 성장 경로를 시각적으로 나타낸다. 추세선(trendline)은 실제 측정 데이터의 경향을 나타내며, 최소 6~8개의 데이터 포인트가 축적된 후 산출한다. 추세선과 목표선의 비교를 통해 교수 의사결정을 내린다.',NULL,1,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('asmnt-q45','assessment','cbm','ox','CBM에서 추세선이 목표선보다 아래에 위치할 경우, 학생의 성장이 목표에 미치지 못하므로 장기 목표를 하향 조정해야 한다.',NULL,NULL,'X','추세선이 목표선보다 아래에 위치할 경우, 학생의 성장이 목표에 미치지 못하는 것은 맞지만, 이때 장기 목표를 하향 조정하는 것이 아니라 교수 프로그램을 수정해야 한다. 교수 방법, 강도, 시간, 자료 등을 변경하여 학생의 성장률을 높이는 것이 올바른 의사결정이다. 목표 하향 조정은 CBM 의사결정 규칙에 해당하지 않는다.',NULL,2,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('asmnt-q46','assessment','cbm','multiple','읽기 CBM에서 구강읽기유창성(ORF)을 측정할 때의 실시 방법으로 옳은 것은?',NULL,ARRAY['학생에게 학년 수준의 지문을 제시하고 3분간 소리 내어 읽게 한 후 정확하게 읽은 어절 수를 기록한다.','학생에게 학년 수준의 지문을 제시하고 1분간 소리 내어 읽게 한 후 정확하게 읽은 음절 수(또는 어절 수)를 기록한다.','학생에게 학년 수준의 단어 목록을 제시하고 1분간 읽게 한 후 정확하게 읽은 단어 수를 기록한다.','학생에게 빈칸이 있는 지문을 제시하고 3분간 빈칸에 알맞은 단어를 선택하게 한 후 정답 수를 기록한다.'],'1','ORF(Oral Reading Fluency)는 학생에게 학년 수준의 지문을 제시하고 1분간 소리 내어 읽게 한 후, 정확하게 읽은 음절 수(또는 어절 수)를 기록하는 방법이다. 한국에서는 주로 음절 수를 단위로 사용하며, BASA: 읽기가 대표적인 도구이다. 선택지 4번의 빈칸 채우기 방식은 MAZE(미로) 검사에 해당한다.','{"0": "ORF의 측정 시간은 3분이 아니라 1분이다. 3분은 쓰기 CBM의 측정 시간이다.", "2": "단어 목록 읽기는 개별 단어 읽기 유창성 측정이며, ORF는 연결된 지문을 소리 내어 읽는 것이다.", "3": "빈칸에 알맞은 단어를 선택하는 방식은 MAZE 검사로, ORF와는 다른 읽기 CBM 유형이다."}',2,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('asmnt-q47','assessment','cbm','fill_in','쓰기 CBM에서 사용되는 3가지 채점 지표는 총 쓴 어절 수( ① ), 정확하게 쓴 어절 수( ② ), 정확한 어절 연결 수( ③ )이다. ①~③의 영문 약어를 쓰시오.',NULL,NULL,'① TWW / ② WSC / ③ CWS','쓰기 CBM의 3가지 주요 채점 지표: TWW(Total Words Written, 총 쓴 어절 수)는 작문의 양을 측정하고, WSC(Words Spelled Correctly, 정확하게 쓴 어절 수)는 철자 정확도를 반영하며, CWS(Correct Word Sequences, 정확한 어절 연결 수)는 인접한 두 어절이 문법적·의미적·철자적으로 모두 정확한 연결의 수를 측정하여 작문의 질적 측면을 반영한다.',NULL,2,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('asmnt-q48','assessment','cbm','descriptive','수학 CBM(연산 유창성)의 실시 절차를 (1) 검사 자료 준비, (2) 실시 방법, (3) 채점 방법의 순서로 서술하시오.',NULL,NULL,'(1) 검사 자료 준비: 학생의 학년 수준에 해당하는 연산 문제(덧셈, 뺄셈, 곱셈, 나눗셈 등)를 학년 교육과정에서 추출하여 한 페이지에 배치한다. 동일 난이도의 대안형(alternate form)을 여러 개 준비한다. (2) 실시 방법: 표준화된 지시문을 읽어주고, 2분간 가능한 한 많은 문제를 순서대로 풀게 한다. 모르는 문제는 건너뛸 수 있음을 안내한다. (3) 채점 방법: 2분 동안 정확하게 쓴 자릿수(correct digits, CD)를 세어 점수로 기록한다. 자릿수 단위 채점은 부분 점수를 인정하여 학생의 연산 능력 변화에 더 민감하게 반응한다.','수학 CBM에서 자릿수(correct digits) 채점 방식은 Shinn(1989)이 제안한 것으로, 정답의 각 자릿수가 맞으면 1점을 부여한다. 예를 들어, 23+45의 정답이 68인데 학생이 67이라고 쓴 경우, 문제 단위로는 0점이지만 자릿수 단위로는 6이 맞으므로 1점을 받는다. 이는 교수 민감성을 높이는 효과가 있다.',NULL,3,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('asmnt-q49','assessment','cbm','descriptive','RTI 모델에서 학습장애를 판별하기 위한 이중불일치(dual discrepancy) 모델의 두 가지 기준을 각각 설명하고, 전통적 능력-성취 불일치 모델과 비교하여 이중불일치 모델의 장점 2가지를 서술하시오.',NULL,NULL,'이중불일치의 두 기준: (1) 수준 불일치 - 학생의 현재 학업 수행 수준이 또래 평균보다 현저히 낮다. (2) 성장률 불일치 - 적절한 중재를 제공했음에도 학생의 학습 성장률(추세선 기울기)이 또래보다 현저히 낮다. 능력-성취 불일치 모델 대비 장점: (1) 실패를 기다릴 필요가 없다(wait-to-fail 문제 해결) - 중재를 제공하면서 동시에 판별할 수 있어 조기 개입이 가능하다. (2) 중재 반응성을 직접 확인한다 - 적절한 교수를 제공했는지 여부를 확인하므로, 교수 부족으로 인한 학업 부진과 학습장애를 구분할 수 있다.','Fuchs & Fuchs(1998)가 제안한 이중불일치 모델은 두 기준이 동시에 충족되어야 학습장애로 판별한다. 전통적 능력-성취 불일치 모델은 IQ와 학업 성취 간 유의미한 차이로 판별하는데, 충분한 차이가 나타날 때까지 기다려야 하는 ''wait-to-fail'' 문제와 교수의 질을 통제하지 못하는 한계가 있다.',NULL,3,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('asmnt-q50','assessment','cbm','ox','MAZE 검사는 읽기 CBM의 한 유형으로, 지문에서 일정 간격으로 단어를 삭제하고 3개의 선택지 중 올바른 단어를 고르게 하여 읽기 이해력을 측정한다.',NULL,NULL,'O','MAZE(미로) 검사는 읽기 이해력을 측정하는 CBM 유형이다. 연결된 지문에서 매 7번째 단어(첫 문장 제외)를 삭제하고, 삭제된 위치에 정답 1개와 오답 2개(합계 3개)의 선택지를 제시한다. 학생은 2~3분 동안 문맥에 맞는 단어를 선택하며, 정확하게 선택한 단어 수가 점수가 된다. ORF가 음독 유창성을 측정하는 반면, MAZE는 묵독 이해력을 측정하는 데 적합하다.',NULL,2,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('asmnt-q51','assessment','fba','fill_in','FBA의 간접 평가 단계에서 행동의 기능을 추정하기 위해 사용하는 표준화된 설문 도구인 ( )은/는 Durand와 Crimmins가 개발하였으며, 감각 자극, 회피, 관심, 실체적 보상의 4개 하위척도로 구성된다.',NULL,NULL,'MAS(동기평가척도)','MAS(Motivation Assessment Scale)는 Durand와 Crimmins(1988)가 개발한 간접 평가 도구로, 16개 문항으로 구성되어 있다. 감각 자극(sensory), 회피(escape), 관심(attention), 실체적 보상(tangible)의 4개 하위척도에서 점수가 가장 높은 영역이 해당 문제행동의 추정 기능이 된다. 간편하게 실시할 수 있으나, 응답자의 주관적 판단에 의존하므로 직접 관찰로 보완해야 한다.',NULL,2,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('asmnt-q52','assessment','fba','fill_in','FBA의 직접 관찰 방법 중 ( )은/는 관찰 시간을 동일한 시간 간격(예: 10초)으로 나누고, 각 간격 내에서 목표 행동의 발생 여부를 기록하는 방법이다.',NULL,NULL,'간격 기록법','간격 기록법(interval recording)은 관찰 시간을 동일한 간격으로 나누어 행동 발생 여부를 기록하는 방법이다. 부분간격기록(partial interval recording)은 간격 내 한 번이라도 행동이 발생하면 기록하고, 전체간격기록(whole interval recording)은 간격 전체에 걸쳐 행동이 지속되어야 기록한다. 부분간격기록은 행동 발생률을 과대 추정하고, 전체간격기록은 과소 추정하는 경향이 있다.',NULL,2,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('asmnt-q53','assessment','fba','descriptive','다음 사례를 읽고 물음에 답하시오.

초등학교 3학년 민수는 국어 시간에 교사가 읽기 과제를 제시하면 교과서를 바닥에 던지고, 책상을 밀며, "안 해!"라고 소리 지른다. 이에 교사는 민수를 진정시키기 위해 "잠깐 쉬어도 돼"라고 말하며 과제를 회수한다. 민수는 교사가 과제를 회수하면 곧 진정된다.

(1) ABC 분석을 통해 선행사건, 행동, 후속결과를 각각 쓰시오.
(2) 추정되는 행동의 기능을 쓰고 근거를 설명하시오.
(3) 기능에 기반한 대체행동 1가지를 제시하시오.','초등학교 3학년 민수는 국어 시간에 교사가 읽기 과제를 제시하면 교과서를 바닥에 던지고, 책상을 밀며, "안 해!"라고 소리 지른다. 이에 교사는 민수를 진정시키기 위해 "잠깐 쉬어도 돼"라고 말하며 과제를 회수한다. 민수는 교사가 과제를 회수하면 곧 진정된다.',NULL,'(1) ABC 분석: 선행사건(A) - 교사가 읽기 과제를 제시함. 행동(B) - 교과서를 바닥에 던지고, 책상을 밀며, "안 해!"라고 소리 지름. 후속결과(C) - 교사가 과제를 회수하고 쉬게 해줌. (2) 추정 기능: 과제 회피(escape). 근거: 어려운 읽기 과제가 제시될 때(선행사건) 문제행동이 발생하고, 그 결과로 과제가 제거되며(후속결과) 행동이 소거된다(진정됨). 문제행동이 과제 제거라는 부적 강화에 의해 유지되고 있다. (3) 대체행동: ''도움이 필요합니다'' 카드를 교사에게 제시하거나, "어려워요. 도와주세요"라고 말하는 적절한 도움 요청 행동을 교수한다.','이 사례는 FBA의 ABC 분석을 활용한 전형적인 과제 회피 기능 문제행동이다. 대체행동은 문제행동과 동일한 기능(과제 회피/도움 획득)을 수행하면서도 사회적으로 적절한 행동이어야 한다. BSP에서는 선행사건 중재(과제 난이도 조정, 선택권 제공), 대체행동 교수, 후속결과 전략(적절한 요청 시 도움 제공, 문제행동 시 과제 유지)을 함께 적용한다.',NULL,3,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('asmnt-q54','assessment','fba','multiple','기능분석(functional analysis)에서 ''혼자 조건(alone condition)''의 설정과 검증 대상 기능이 올바르게 짝지어진 것은?',NULL,ARRAY['교사가 관심을 철회하다가 문제행동 시 관심을 제공하는 조건 - 관심 획득 기능','자극이 없는 환경에 혼자 있게 하는 조건 - 감각 자극 기능','어려운 과제를 제시하다가 문제행동 시 과제를 제거하는 조건 - 과제 회피 기능','선호 물건을 제거하다가 문제행동 시 제공하는 조건 - 실체적 보상 획득 기능'],'1','Iwata 등(1982/1994)의 기능분석에서 혼자 조건(alone condition)은 자극이 없는 환경에 학생을 혼자 두어, 사회적 매개 없이 자동적으로 강화되는 감각 자극 기능을 검증한다. 이 조건에서 문제행동이 높은 수준으로 발생하면 감각 자극 기능으로 판별한다. 나머지 선택지는 각각 관심 조건, 과제 조건, 실체적 보상 조건의 올바른 설명이지만 혼자 조건이 아니다.','{"0": "이 설명은 관심 조건(attention condition)으로, 혼자 조건이 아니다.", "2": "이 설명은 과제 조건(demand/escape condition)으로, 혼자 조건이 아니다.", "3": "이 설명은 실체적 보상 조건(tangible condition)으로, 혼자 조건이 아니다."}',2,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('asmnt-q55','assessment','fba','ox','순간시간표집법(MTS: Momentary Time Sampling)은 미리 정해진 시간 간격의 끝 순간에만 행동 발생 여부를 관찰·기록하는 방법으로, 부분간격기록법에 비해 행동 발생률을 과대 추정할 가능성이 낮다.',NULL,NULL,'O','순간시간표집법(Momentary Time Sampling)은 미리 정해진 간격의 끝 순간(moment)에만 행동 발생 여부를 기록하는 방법이다. 부분간격기록법(partial interval recording)은 간격 내 한 번이라도 행동이 발생하면 발생으로 기록하기 때문에 행동 발생률을 과대 추정하는 경향이 있다. 반면 MTS는 특정 순간만 관찰하므로 과대 추정 가능성이 상대적으로 낮고, 실제 행동 발생률에 더 가까운 추정치를 제공한다.',NULL,3,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('asmnt-q56','assessment','fba','descriptive','FBA의 3단계 절차를 순서대로 쓰고, 각 단계에서 사용하는 구체적인 방법을 2가지씩 제시하시오. 또한 단계가 진행될수록 변화하는 특성을 서술하시오.',NULL,NULL,'1단계 간접 평가(Indirect Assessment): (1) 교사·부모·학생과의 구조화된 면담(FAI), (2) 설문지/체크리스트(MAS, QABF). 2단계 직접 관찰(Direct Observation): (1) ABC 기록법(선행사건-행동-후속결과 서술 기록), (2) 산포도(scatterplot, 시간대별 행동 발생 패턴 기록). 3단계 기능분석(Functional Analysis): (1) Iwata의 실험 조건(관심, 과제, 혼자, 놀이/통제 조건) 설정, (2) 조건별 행동 발생률 비교를 통한 기능 검증. 단계 진행에 따른 특성 변화: 간접적 방법에서 직접적, 실험적 방법으로 점진적으로 심화되며, 평가의 정확성과 내적 타당도는 높아지지만 시간·비용·전문성 요구 수준도 증가한다.','FBA는 간접 평가에서 기능분석으로 갈수록 정확성이 높아지지만, 실행의 어려움도 증가한다. 실제 학교 현장에서는 간접 평가와 직접 관찰을 통해 행동의 기능을 추정하고, 기능분석은 추정된 기능이 불명확하거나 중재가 효과적이지 않을 때 실시하는 것이 일반적이다. 기능분석은 윤리적 고려(의도적으로 문제행동을 유발)가 필요하므로 전문가의 감독하에 실시해야 한다.',NULL,3,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('bs-q31','behavior-support','aba','fill_in','DRL(낮은 비율의 차별강화)에서 반응간 시간(IRT) 기반 DRL을 적용할 때, 학생이 수업 중 질문 행동을 1시간에 20회 보이고 있다. 목표를 1시간에 10회로 줄이려면, IRT 타이머를 최소 ( )분으로 설정해야 한다.',NULL,NULL,'6','IRT 기반 DRL에서 타이머 설정은 ''목표 시간 ÷ 목표 반응 수''로 계산합니다. 60분 ÷ 10회 = 6분. 즉, 이전 반응 후 최소 6분이 경과한 뒤에 나타난 반응만 강화합니다. DRL은 행동을 완전히 제거하지 않고 적절한 수준으로 감소시킬 때 사용합니다.',NULL,3,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('bs-q32','behavior-support','strategies','descriptive','자기교수법(self-instruction)의 5단계를 순서대로 나열하고, 각 단계에서 교사와 학생의 역할을 설명하시오.','초등학교 특수학급의 박 교사는 ADHD 학생에게 수학 문장제 풀이 시 자기교수법을 적용하려 한다. 학생은 문제를 읽지 않고 바로 숫자만 보고 연산하는 경향이 있다.',NULL,'[모범 답안]

자기교수법 5단계:

1단계. 인지적 모델링(cognitive modeling)
- 교사가 과제를 수행하면서 자기교수 내용을 소리 내어 말함
- 학생은 교사의 시범을 관찰

2단계. 외현적 외적 안내(overt external guidance)
- 학생이 과제를 수행하면서 교사가 언어적으로 안내함
- 교사가 자기교수 내용을 말해주고 학생이 따라 수행

3단계. 외현적 자기 안내(overt self-guidance)
- 학생이 스스로 소리 내어 자기교수를 말하면서 과제 수행
- 교사는 필요시 교정적 피드백 제공

4단계. 약화된 자기 안내(faded self-guidance)
- 학생이 속삭이며 자기교수를 말하면서 과제 수행
- 외현적 언어가 점차 약화됨

5단계. 내현적 자기교수(covert self-instruction)
- 학생이 마음속으로 자기교수를 하면서 독립적으로 과제 수행
- 교사 지원 없이 자기조절적으로 수행','Meichenbaum의 자기교수법은 교사의 외적 언어 통제가 점진적으로 학생의 내적 언어 통제로 전이되는 과정입니다. 인지적 모델링→외현적 외적 안내→외현적 자기 안내→약화된 자기 안내→내현적 자기교수의 5단계로 구성되며, ADHD, 학습장애 학생의 충동성 조절과 과제 수행 전략 습득에 효과적입니다.',NULL,3,'KICE 기출 기반','{"disability": "ADHD"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('bs-q33','behavior-support','assessment','ox','기초선 자료 수집 시, 자료의 경향이 불안정하더라도 최소 3회 이상 측정하였다면 중재를 시작해도 된다.',NULL,NULL,'X','기초선 자료는 안정적 경향(stable trend)을 보일 때까지 수집해야 합니다. 단순히 측정 횟수가 아니라, 자료의 수준(level)과 경향(trend)이 안정적이어야 중재 효과를 비교할 수 있는 기준점이 됩니다. 불안정한 기초선에서 중재를 시작하면 행동 변화가 중재 때문인지 자연적 변동인지 판단할 수 없습니다.',NULL,2,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('bs-q34','behavior-support','strategies','fill_in','토큰경제의 구성요소 3가지는 ( ㉠ ), ( ㉡ ), ( ㉢ )이다. ㉠은 목표행동 수행 시 즉시 제공되는 조건강화제이고, ㉡은 토큰과 교환할 수 있는 활동이나 물건이며, ㉢은 토큰과 후원강화제의 교환 기준이다.',NULL,NULL,'토큰(token) / 후원강화제(backup reinforcer) / 교환비율(exchange rate)','토큰경제는 ①토큰(조건강화제로서 즉각 제공), ②후원강화제(토큰으로 교환 가능한 실제 강화제), ③교환비율(몇 개의 토큰으로 후원강화제를 교환하는지)로 구성됩니다. 토큰은 일반화된 조건강화제로 기능하며, 포만(satiation)에 대한 저항력이 높다는 장점이 있습니다.',NULL,2,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('bs-q35','behavior-support','aba','multiple','촉진(prompting) 위계에서 ''최소 촉진법(least-to-most prompting)''의 올바른 순서는?',NULL,ARRAY['신체적 촉진 → 모델링 → 언어적 촉진 → 제스처 촉진 → 자연적 단서','자연적 단서 → 언어적 촉진 → 제스처 촉진 → 모델링 → 신체적 촉진','자연적 단서 → 제스처 촉진 → 언어적 촉진 → 모델링 → 신체적 촉진','신체적 촉진 → 제스처 촉진 → 모델링 → 언어적 촉진 → 자연적 단서'],'1','최소 촉진법은 가장 적은 도움에서 시작하여 점차 강한 촉진으로 이동합니다. 자연적 단서 → 언어적 촉진 → 제스처 촉진 → 모델링 → 신체적 촉진 순서입니다. 이는 학습자의 독립성을 최대화하기 위한 전략으로, 학생이 최소한의 도움으로 반응할 기회를 먼저 제공합니다.','{"0": "이것은 최대 촉진법(most-to-least)의 순서입니다.", "2": "언어적 촉진과 제스처 촉진의 순서가 뒤바뀌었습니다. 언어적 촉진이 제스처보다 덜 침습적입니다.", "3": "이것은 최대 촉진법의 순서이며, 언어적 촉진과 모델링의 위치도 정확하지 않습니다."}',2,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('bs-q36','behavior-support','strategies','fill_in','과제분석 후 교수법 중, 과제의 마지막 단계부터 먼저 가르치고 나머지 단계는 교사가 수행해 주는 방법을 ( ㉠ )이라 하고, 모든 단계를 매 시행마다 연습하되 독립적으로 수행하지 못하는 단계에서 촉진을 제공하는 방법을 ( ㉡ )이라 한다.',NULL,NULL,'후진연쇄법(backward chaining) / 총과제제시법(total task presentation)','연쇄법에는 전진연쇄(첫 단계부터 순서대로), 후진연쇄(마지막 단계부터 역순으로), 총과제제시법(모든 단계를 매 시행마다 연습)이 있습니다. 후진연쇄는 과제 완성의 성취감을 빨리 경험하게 해주고, 총과제제시법은 과제의 전체 흐름을 매번 경험하게 해주는 장점이 있습니다.',NULL,2,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('bs-q37','behavior-support','aba','descriptive','간헐강화 스케줄 4가지(FR, VR, FI, VI)를 비교하여 설명하고, 각 스케줄의 반응 패턴 특성을 서술하시오.',NULL,NULL,'[모범 답안]

1. 고정비율(FR: Fixed Ratio)
- 정해진 반응 횟수마다 강화 제공 (예: FR5 = 5회 반응 후 강화)
- 반응 패턴: 강화 직후 짧은 휴지(post-reinforcement pause) 후 높은 비율로 반응

2. 변동비율(VR: Variable Ratio)
- 평균 반응 횟수를 기준으로 불규칙하게 강화 (예: VR5 = 평균 5회)
- 반응 패턴: 높고 안정적인 반응률, 휴지 거의 없음, 소거 저항 가장 높음

3. 고정간격(FI: Fixed Interval)
- 정해진 시간 경과 후 첫 반응에 강화 (예: FI3분 = 3분 후 첫 반응)
- 반응 패턴: 가리비 형태(scallop pattern), 간격 초반 낮은 반응→간격 말미 급증

4. 변동간격(VI: Variable Interval)
- 평균 시간 간격을 기준으로 불규칙하게 강화 (예: VI3분)
- 반응 패턴: 낮지만 안정적인 반응률, 소거 저항 비교적 높음','간헐강화 스케줄은 비율(ratio)과 간격(interval), 고정(fixed)과 변동(variable)의 조합으로 4가지입니다. 비율 스케줄이 간격 스케줄보다 높은 반응률을 산출하고, 변동 스케줄이 고정 스케줄보다 소거 저항이 높습니다. 임용고시에서 각 스케줄의 반응 패턴 그래프와 실제 사례를 연결하는 문제가 자주 출제됩니다.',NULL,3,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('cur-q31','curriculum','theory','fill_in','2022 개정 특수교육 교육과정에서 초등학교 1~2학년은 ( ㉠ ) 교육과정, 고등학교 학생이 기본교육과정을 적용받을 경우 ( ㉡ ) 교육과정을 편성하며, 기본교육과정의 교과는 교과(군)별로 수업 시수의 ( ㉢ )% 범위 내에서 시수를 증감할 수 있다.',NULL,NULL,'공통 / 기본 / 20','2022 개정 교육과정에서 초1~2는 공통교육과정, 초3~고교는 공통·선택중심·기본교육과정 중 선택 가능합니다. 기본교육과정은 특수교육대상자를 위한 것으로, 교과(군)별 20% 범위 내 시수 증감이 가능하며, 이는 학생의 장애 특성과 요구에 맞춘 유연한 편성을 위함입니다.',NULL,2,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('cur-q32','curriculum','planning','multiple','다음 중 2022 개정 교육과정에서 제시하는 ''범교과 학습 주제''에 해당하지 않는 것은?',NULL,ARRAY['안전·건강 교육','인성 교육','경제·금융 교육','직업재활 교육'],'3','2022 개정 교육과정의 범교과 학습 주제에는 안전·건강, 인성, 진로, 민주시민, 인권, 다문화, 통일, 독도, 경제·금융, 환경·지속가능발전 등이 포함됩니다. ''직업재활 교육''은 범교과 학습 주제가 아니라 특수교육 전환교육 영역에 해당합니다.','{"0": "안전·건강 교육은 범교과 학습 주제에 포함됩니다.", "1": "인성 교육은 범교과 학습 주제에 포함됩니다.", "2": "경제·금융 교육은 2022 개정에서 새롭게 강조된 범교과 학습 주제입니다."}',2,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('cur-q33','curriculum','theory','descriptive','컴퓨터 보조 수업(CAI)의 5가지 유형을 제시하고, 각 유형의 특징과 적합한 학습 장면을 설명하시오.','특수학교 교사 이 모씨는 지적장애 학생들에게 수학 교과를 지도하기 위해 CAI를 활용하고자 한다.',NULL,'[모범 답안]

CAI 5가지 유형:

1. 개인교수형(Tutorial)
- 특징: 새로운 개념이나 원리를 단계적으로 제시하고 학습자의 반응에 따라 피드백 제공
- 적합 장면: 새로운 수 개념(덧셈 원리) 도입 시

2. 반복연습형(Drill and Practice)
- 특징: 이미 학습한 내용을 반복 연습하여 자동화(유창성) 달성
- 적합 장면: 구구단 암기, 기본 연산 유창성 훈련

3. 시뮬레이션형(Simulation)
- 특징: 실제 상황을 가상으로 재현하여 의사결정 연습
- 적합 장면: 가상 마트에서 물건 구매하며 화폐 사용 연습

4. 게임형(Instructional Game)
- 특징: 게임 요소(경쟁, 보상)를 활용하여 학습 동기 유발
- 적합 장면: 수 크기 비교 게임, 연산 속도 챌린지

5. 문제해결형(Problem Solving)
- 특징: 상위인지 전략을 활용한 복합적 문제 해결 과정
- 적합 장면: 수학 문장제 해결 과정에서 전략 선택 연습','CAI는 컴퓨터를 매개로 한 교수 방법으로, 학습 목적에 따라 5가지 유형으로 분류됩니다. 지적장애 학생에게는 즉각적 피드백과 반복 기회를 제공하는 반복연습형과 개인교수형이 특히 효과적이며, 시뮬레이션형은 일반화에 유리합니다.',NULL,3,'KICE 기출 기반','{"disability": "지적장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('cur-q34','curriculum','planning','fill_in','보편적 학습설계(UDL)의 3가지 원리는 다양한 ( ㉠ ) 수단의 제공, 다양한 ( ㉡ ) 수단의 제공, 다양한 ( ㉢ ) 수단의 제공이다.',NULL,NULL,'표상(representation) / 행동과 표현(action and expression) / 참여(engagement)','UDL(Universal Design for Learning)은 CAST에서 개발한 교육과정 설계 원리로, ①표상(정보 제시 방법의 다양화 - What), ②행동과 표현(학습 결과 표현 방법의 다양화 - How), ③참여(학습 동기 유발 방법의 다양화 - Why)의 3원리로 구성됩니다.',NULL,2,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('cur-q35','curriculum','planning','ox','교수적 수정(instructional modification)의 4요소는 교수환경, 교수방법, 교수내용, 평가방법이며, 이 중 교수내용 수정은 교육과정 자체를 변경하는 것이므로 통합학급에서는 적용할 수 없다.',NULL,NULL,'X','교수적 수정의 4요소(교수환경, 교수방법, 교수내용, 평가방법)는 모두 통합학급에서 적용 가능합니다. 교수내용 수정은 교육과정 자체의 변경이 아니라, 학습량 조절, 내용의 난이도 조절, 대안적 교육과정 활용 등을 통해 동일한 교육과정 내에서 학생의 수준에 맞게 내용을 조정하는 것입니다.',NULL,2,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('cur-q36','curriculum','theory','descriptive','스키마 기반 교수(SBI)의 절차를 단계별로 설명하고, 학습장애 학생의 수학 문장제 해결에 SBI가 효과적인 이유를 서술하시오.','학습장애 학생 민수는 수학 연산 능력은 보통 수준이나, 문장제 문제에서 어떤 연산을 적용해야 하는지 파악하지 못하여 정답률이 매우 낮다.',NULL,'[모범 답안]

1. SBI 절차
① 문제 유형 파악: 문장제를 변화형(change), 집합형(group), 비교형(compare) 등으로 분류
② 도식(schema) 선택: 문제 유형에 맞는 도식(그림/다이어그램)을 선택
③ 도식에 정보 매핑: 문제에서 주어진 수량 정보를 도식에 배치
④ 미지수 확인 및 연산 계획: 빈칸(미지수)을 확인하고 필요한 연산 결정
⑤ 연산 수행 및 검증: 계산 후 문제로 돌아가 답의 합리성 확인

2. 학습장애 학생에게 효과적인 이유
- 문제의 의미적 구조를 시각적으로 표상하여 언어 이해 부담 감소
- 문제 유형별 도식이 연산 선택의 단서를 제공
- 반복 가능한 절차로 전략의 자동화와 일반화 촉진
- 작업기억 부담을 외적 도식으로 분산','SBI는 Jitendra 등이 개발한 교수법으로, 문장제의 의미적 구조(schema)를 파악하는 것에 초점을 둡니다. 학습장애 학생이 문장제에서 어려움을 겪는 주된 이유가 문제의 구조를 파악하지 못하는 것이므로, 도식을 통한 구조 파악이 연산 선택의 핵심 단서가 됩니다.',NULL,3,'KICE 기출 기반','{"disability": "학습장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('cur-q37','curriculum','evaluation','fill_in','RAP 전략은 읽기 이해 전략으로, R은 ( ㉠ ), A는 ( ㉡ ), P는 ( ㉢ )을 의미한다. 이 전략은 ( ㉣ ) 장애 학생의 읽기 이해력 향상에 효과적이다.',NULL,NULL,'Read(읽기) / Ask(질문하기) / Paraphrase(자기 말로 바꾸기) / 학습','RAP 전략은 Schumaker 등이 개발한 읽기 이해 전략으로, Read(단락 읽기) → Ask(주요 아이디어와 세부사항에 대해 자문하기) → Paraphrase(자기 말로 바꾸어 표현하기)의 3단계로 구성됩니다. 학습장애 학생의 읽기 이해, 특히 의미 파악과 정보 재구성 능력 향상에 효과적인 학습전략교수(learning strategy instruction)의 대표적 예입니다.',NULL,2,'KICE 기출 기반','{"disability": "학습장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('inc-q31','inclusive-education','practices','descriptive','협력교수(co-teaching)의 6가지 유형을 제시하고, 각 유형의 특징과 적용 상황을 설명하시오.','통합학급 운영 시 일반교사와 특수교사가 협력교수를 실시하려 한다. 학급에는 학습장애 학생 2명, 지적장애 학생 1명이 통합되어 있다.',NULL,'[모범 답안]

협력교수 6유형:

1. 교수-관찰(one teach, one observe)
- 한 교사가 수업, 다른 교사가 특정 학생의 행동/학습 자료 수집
- 적용: 학기 초 학생 관찰 및 기초선 자료 수집 시

2. 교수-보조(one teach, one assist)
- 한 교사가 수업, 다른 교사가 순회하며 개별 지원
- 적용: 강의식 수업에서 특수교육대상학생에게 보조 제공 시

3. 스테이션 교수(station teaching)
- 학습 내용을 여러 영역으로 나누어 교사별 스테이션에서 교수
- 적용: 수학 단원에서 연산, 문장제, 도형을 스테이션으로 운영 시

4. 평행교수(parallel teaching)
- 학급을 2그룹으로 나누어 동일 내용을 동시에 교수
- 적용: 소그룹 토의, 실험 활동에서 학생 참여 기회 확대 시

5. 대안교수(alternative teaching)
- 소그룹을 분리하여 보충/심화 수업 제공
- 적용: 특수교육대상학생에게 선수학습 보충이 필요한 경우

6. 팀티칭(team teaching)
- 두 교사가 동등하게 수업을 함께 진행
- 적용: 두 교사의 전문성이 모두 필요한 융합 수업 시','협력교수는 Friend & Cook이 체계화한 모델로, 일반교사와 특수교사가 동일 교실에서 함께 수업하는 방식입니다. 6유형은 교수-관찰, 교수-보조, 스테이션, 평행, 대안, 팀티칭이며, 학생의 요구와 수업 목표에 따라 적절한 유형을 선택합니다.',NULL,3,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('inc-q32','inclusive-education','strategies','fill_in','학급전체또래교수(CWPT)에서 학급을 두 팀으로 나누어 ( ㉠ ) 역할을 교대로 수행하며, 또래중재학습전략(PALS)은 ( ㉡ ) 수준의 학생과 ( ㉢ ) 수준의 학생을 짝지어 구조화된 활동을 수행한다.',NULL,NULL,'교수자-학습자(tutor-tutee) / 상위 / 하위','CWPT(Classwide Peer Tutoring)는 Greenwood 등이 개발한 방법으로, 학급 전체가 교수자-학습자 역할을 교대하며 팀 경쟁 요소를 포함합니다. PALS(Peer-Assisted Learning Strategies)는 Fuchs 등이 개발하였으며, 상위 수준과 하위 수준의 학생을 짝지어 구조화된 읽기/수학 활동을 수행합니다.',NULL,2,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('inc-q33','inclusive-education','theory','fill_in','자폐성장애의 인지적 특성 중, 세부 정보 처리에는 강하나 전체적 맥락이나 의미를 통합하는 데 어려움을 보이는 특성을 ( )이라 한다.',NULL,NULL,'약한 중심통합(weak central coherence)','약한 중심통합(weak central coherence)은 Frith(1989)가 제안한 자폐성장애의 인지 이론으로, 정보를 전체적 맥락에서 통합하기보다 부분적·세부적으로 처리하는 경향을 설명합니다. 이로 인해 퍼즐 맞추기나 숨은그림찾기에는 뛰어나지만, 이야기의 주제 파악이나 사회적 맥락 이해에는 어려움을 보입니다.',NULL,2,'KICE 기출 기반','{"disability": "자폐성장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('inc-q34','inclusive-education','theory','multiple','자기결정(self-determination)의 4가지 본질적 특성에 해당하지 않는 것은?',NULL,ARRAY['자율성(autonomy)','자기조절(self-regulation)','자기효능감(self-efficacy)','심리적 역량강화(psychological empowerment)'],'2','Wehmeyer가 제시한 자기결정의 4가지 본질적 특성은 자율성(autonomy), 자기조절(self-regulation), 심리적 역량강화(psychological empowerment), 자기실현(self-realization)입니다. 자기효능감은 Bandura의 사회학습이론 개념으로 자기결정의 본질적 특성에는 포함되지 않습니다.','{"0": "자율성은 자기결정의 4가지 본질적 특성 중 하나입니다.", "1": "자기조절은 자기결정의 4가지 본질적 특성 중 하나입니다.", "3": "심리적 역량강화는 자기결정의 4가지 본질적 특성 중 하나입니다."}',1,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('inc-q35','inclusive-education','strategies','ox','긍정적 행동지원(PBS)의 3단계 모형에서 1단계(보편적 지원)는 전체 학생의 약 80%를 대상으로 하며, 3단계(개별적 지원)는 약 5%의 학생에게 집중적으로 적용된다.',NULL,NULL,'O','PBS의 3단계(RTI와 동일 구조) 모형에서 1단계(보편적/전체) 지원은 전체 학생의 약 80%에게 적용되는 예방적 차원이고, 2단계(소그룹/표적) 지원은 약 15%의 위험군 학생, 3단계(개별적/집중) 지원은 약 5%의 고위험 학생에게 개별화된 집중 지원을 제공합니다.',NULL,1,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('inc-q36','inclusive-education','practices','descriptive','전환교육(transition education)에서 ''자기옹호(self-advocacy)''의 개념을 설명하고, 지역사회 기반 교수(community-based instruction)가 전환교육에서 중요한 이유를 서술하시오.','고등학교 특수학급의 최 교사는 졸업을 앞둔 지적장애 학생의 전환교육 계획을 수립하고 있다. 학생은 지역사회 내 카페에서 바리스타로 취업하기를 희망하고 있다.',NULL,'[모범 답안]

1. 자기옹호의 개념
자기옹호(self-advocacy)란 자신의 권리, 필요, 관심사를 인식하고 이를 타인에게 효과적으로 표현·주장하는 능력이다. 구체적으로:
- 자신의 강점과 약점, 장애 특성에 대한 이해
- 필요한 지원이나 편의를 요청하는 의사소통 능력
- 자신의 권리를 알고 부당한 상황에 대처하는 능력

2. 지역사회 기반 교수의 중요성
① 일반화 촉진: 교실에서 학습한 기술을 실제 환경에서 연습하여 일반화 문제 해결
② 생태학적 타당도: 실제 직무 환경에서의 교수로 현실적 요구 반영
③ 자연적 단서 활용: 실제 환경의 자연적 단서와 결과를 활용한 학습
④ 직업 적합성 평가: 실제 작업 수행을 통해 직업 매칭의 적절성 확인
⑤ 사회적 통합: 지역사회 구성원과의 자연스러운 상호작용 기회 제공','전환교육은 학교에서 성인기 생활로의 이행을 체계적으로 준비하는 교육입니다. 자기옹호는 자기결정의 핵심 하위 기술이며, 지역사회 기반 교수는 교실 내 교수의 일반화 한계를 극복하는 핵심 전략입니다. 카페 취업 희망 사례에서 실제 카페 환경에서의 현장 실습이 대표적인 지역사회 기반 교수에 해당합니다.',NULL,3,'KICE 기출 기반','{"disability": "지적장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('bs-q38','behavior-support','aba','fill_in','행동의 결과로 자극이 추가되어 행동의 빈도가 증가하는 것을 ( ㉠ )이라 하고, 행동의 결과로 혐오 자극이 제거되어 행동의 빈도가 증가하는 것을 ( ㉡ )이라 한다.',NULL,NULL,'정적강화(positive reinforcement) / 부적강화(negative reinforcement)','강화는 행동의 빈도를 증가시키는 결과입니다. 정적강화는 선호 자극의 제시(추가)로 행동이 증가하고, 부적강화는 혐오 자극의 제거로 행동이 증가합니다. ''정적/부적''은 자극의 추가/제거를 의미하며, 두 가지 모두 행동을 증가시킨다는 점에서 ''벌''과 구분됩니다.',NULL,1,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('bs-q39','behavior-support','aba','fill_in','행동의 결과로 혐오 자극이 제시되어 행동의 빈도가 감소하는 것을 ( ㉠ )이라 하고, 행동의 결과로 선호 자극이 제거되어 행동의 빈도가 감소하는 것을 ( ㉡ )이라 한다.',NULL,NULL,'정적벌(positive punishment) / 부적벌(negative punishment)','벌은 행동의 빈도를 감소시키는 결과입니다. 정적벌(Type I 벌)은 혐오 자극의 제시로, 부적벌(Type II 벌)은 선호 자극의 제거로 행동이 감소합니다. 부적벌의 예로는 반응대가(response cost)와 타임아웃(time-out)이 있습니다.',NULL,1,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('bs-q40','behavior-support','aba','ox','소거(extinction) 절차를 처음 적용하면, 목표 행동의 빈도·강도·지속시간이 일시적으로 증가하는 소거폭발(extinction burst)이 나타날 수 있다.',NULL,NULL,'O','소거폭발(extinction burst)은 소거 절차 초기에 강화가 차단되면서 행동이 일시적으로 증가하는 현상입니다. 이전에 강화받던 행동이 더 이상 강화되지 않으면 개체는 더 강하게, 더 자주 행동하여 강화를 얻으려 시도합니다. 소거 적용 시 소거폭발에 대한 사전 계획과 대비가 반드시 필요합니다.',NULL,1,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('bs-q41','behavior-support','aba','fill_in','특정 자극 조건에서만 행동이 강화되고 다른 조건에서는 강화되지 않을 때, 행동을 유발하는 선행자극을 ( ㉠ )이라 하고, 이 자극이 있을 때만 행동이 나타나는 현상을 ( ㉡ )이라 한다.',NULL,NULL,'변별자극(SD, discriminative stimulus) / 자극변별(stimulus discrimination)','변별자극(SD)은 강화가 가능함을 알리는 선행자극으로, 행동의 원인이 아니라 강화의 가용성을 알려주는 신호입니다. 자극변별은 특정 SD가 있을 때만 반응하고, SD가 없을 때(SΔ)는 반응하지 않는 것을 의미합니다. 3항 수반성(SD → 반응 → 강화)의 핵심 요소입니다.',NULL,2,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('bs-q42','behavior-support','aba','multiple','다음 중 자극일반화(stimulus generalization)의 사례로 가장 적절한 것은?',NULL,ARRAY['교실에서 손 들기를 배운 학생이 도서관에서도 손을 들어 질문한다.','손 들기를 배운 학생이 추가로 차례 기다리기도 수행한다.','교실에서 손 들기를 하던 학생이 강화를 중단하자 손 들기를 멈추었다.','교실에서 손 들기를 배운 학생이 쉬는 시간에는 손을 들지 않는다.'],'0','자극일반화는 훈련된 환경(교실)이 아닌 다른 환경(도서관)에서도 동일한 행동이 나타나는 것입니다. 보기 ②는 반응일반화(한 행동에서 다른 관련 행동으로 확장), ③은 소거, ④는 자극변별에 해당합니다.','{"1": "이것은 반응일반화(response generalization)의 사례입니다. 한 가지 행동의 습득이 다른 관련 행동으로 확장되는 것입니다.", "2": "이것은 소거(extinction)의 사례입니다. 강화가 중단되어 행동이 감소한 것입니다.", "3": "이것은 자극변별(stimulus discrimination)의 사례입니다. 특정 상황에서만 행동이 나타나는 것입니다."}',2,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('bs-q43','behavior-support','aba','descriptive','촉진 용암법(prompt fading)의 개념을 설명하고, 최대-최소 촉진법(most-to-least prompting)의 절차와 교육적 장점을 서술하시오.','중도 지적장애 학생 수현이에게 손씻기를 교수하고 있다. 수현이는 새로운 과제 학습 시 오류에 대한 좌절감이 매우 크고, 오류 경험 후 과제를 거부하는 경향이 있다.',NULL,'[모범 답안]

1. 촉진 용암법의 개념
촉진 용암법(prompt fading)이란 학습자가 올바른 반응을 할 수 있도록 제공하던 촉진(prompt)을 점진적으로 줄여나가 최종적으로 자연적 단서만으로 독립적 수행이 가능하도록 하는 절차이다.

2. 최대-최소 촉진법의 절차
① 신체적 촉진(full physical prompt): 교사가 수현이의 손을 잡고 손씻기 전 과정을 함께 수행
② 부분 신체적 촉진: 손목을 가볍게 터치하여 동작 방향 안내
③ 모델링: 교사가 시범을 보이며 수현이가 따라 수행
④ 제스처 촉진: 비누를 가리키는 등 손짓으로 안내
⑤ 언어적 촉진: "비누를 잡아볼까?" 등 언어적 단서 제공
⑥ 자연적 단서: 촉진 없이 수도꼭지를 보고 독립적으로 수행

3. 교육적 장점
- 무오류 학습(errorless learning): 처음부터 강한 촉진으로 시작하여 오류 발생을 최소화
- 좌절 경험 감소: 오류에 민감한 학생의 과제 거부 행동 예방
- 성공 경험 보장: 매 시행에서 정반응을 경험하여 학습 동기 유지','최대-최소 촉진법은 가장 강한 촉진에서 시작하여 점차 촉진을 줄여나가는 방법으로, 무오류 학습을 지향합니다. 오류에 대한 좌절감이 큰 학생이나 중도장애 학생에게 특히 적합하며, 반대로 최소-최대 촉진법은 학습자의 독립성을 먼저 시도하게 하는 방법입니다.',NULL,2,'KICE 기출 기반','{"disability": "지적장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('bs-q44','behavior-support','aba','fill_in','과제분석(task analysis)에서 복잡한 행동을 구성 단계로 세분화한 후, 첫 번째 단계부터 순서대로 교수하며 학생이 독립적으로 수행할 때까지 가르친 후 다음 단계로 넘어가는 방법을 ( )이라 한다.',NULL,NULL,'전진연쇄법(forward chaining)','전진연쇄법은 과제의 첫 번째 단계부터 순서대로 교수하는 방법입니다. 학생이 1단계를 독립 수행하면 2단계를 추가하고, 이후 단계는 교사가 완성해 줍니다. 후진연쇄법(마지막 단계부터), 총과제제시법(모든 단계를 매 시행마다 연습)과 함께 연쇄법의 3가지 유형을 구성합니다.',NULL,2,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('bs-q45','behavior-support','pbs','fill_in','PBS 3단계 모형에서 전체 학생의 약 80%를 대상으로 하는 1단계를 ( ㉠ ) 지원, 약 15%의 위험군 학생을 대상으로 하는 2단계를 ( ㉡ ) 지원, 약 5%의 고위험 학생을 대상으로 하는 3단계를 ( ㉢ ) 지원이라 한다.',NULL,NULL,'보편적(universal) / 소그룹(targeted/group) / 개별적(intensive/individual)','PBS의 3단계 예방 모형은 RTI(중재반응모형)와 동일한 다층 구조입니다. 1단계 보편적 지원은 학교 전체 규칙·기대행동 교수, 2단계 소그룹 지원은 위험군 학생 대상 사회적 기술 훈련 등, 3단계 개별적 지원은 기능적 행동평가 기반 개별 행동지원계획(BSP) 수립·실행을 포함합니다.',NULL,1,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('bs-q46','behavior-support','pbs','descriptive','행동지원계획(BSP)의 주요 구성요소를 제시하고, 각 요소의 내용을 설명하시오.','자폐성장애 학생 준서는 수업 시간에 과제가 주어지면 과제물을 바닥에 던지고 소리를 지르는 행동을 보인다. 기능적 행동평가 결과, 이 행동의 기능은 과제 회피(부적강화)로 파악되었다.',NULL,'[모범 답안]

BSP(행동지원계획)의 주요 구성요소:

1. 행동에 대한 조작적 정의
- 목표 행동을 관찰·측정 가능하게 정의
- 예: ''과제물을 손으로 밀거나 바닥에 던지는 행동'', ''2초 이상 70dB 이상의 소리를 내는 행동''

2. 기능적 행동평가(FBA) 결과 요약
- 배경사건, 선행사건, 행동, 후속결과 분석
- 행동의 기능: 과제 회피(부적강화)

3. 선행사건 중재(예방 전략)
- 과제 난이도 조절 및 선택 기회 제공
- 과제를 소단위로 분할하여 제시
- 시각적 일과표로 예측 가능성 증가

4. 대체행동 교수
- 기능적 의사소통 훈련(FCT): ''도와주세요'' 카드 사용 교수
- 동일한 기능(과제 회피)을 적절한 방식으로 달성

5. 후속결과 전략
- 대체행동에 대한 즉각적 강화(도움 요청 시 과제 지원 제공)
- 문제행동에 대한 소거(과제 던져도 과제 제거하지 않음)
- 적절한 과제 수행 시 정적강화 제공

6. 위기관리 계획
- 행동이 심각할 때의 안전 절차
- 자해·타해 발생 시 대응 매뉴얼

7. 평가 및 수정 계획
- 행동 자료의 지속적 수집 및 분석
- BSP 효과 점검 주기 및 수정 기준 설정','BSP는 FBA 결과를 기반으로 수립되며, 문제행동의 기능을 충족하는 대체행동 교수가 핵심입니다. 선행사건 중재(예방), 대체행동 교수(교육), 후속결과 전략(반응)의 세 축으로 구성되며, 벌 중심이 아닌 교육적·예방적 접근을 강조합니다.',NULL,3,'KICE 기출 기반','{"disability": "자폐성장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('bs-q47','behavior-support','pbs','ox','긍정적 행동지원(PBS)에서 문제행동의 기능이 관심 획득인 경우, 문제행동 발생 시 즉시 언어적으로 행동을 제지하는 것이 효과적인 소거 전략이다.',NULL,NULL,'X','관심 획득 기능의 문제행동에 대한 소거는 문제행동 발생 시 관심을 제공하지 않는 것(계획적 무시)입니다. 언어적 제지("하지 마", "그만해")도 관심의 한 형태이므로 오히려 문제행동을 강화할 수 있습니다. 소거는 문제행동의 기능에 따라 달라지며, 관심 기능에는 계획적 무시, 과제 회피 기능에는 과제 지속이 소거 전략입니다.',NULL,2,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('bs-q48','behavior-support','pbs','fill_in','기능적 의사소통 훈련(FCT)은 문제행동과 동일한 ( ㉠ )을 충족하는 적절한 의사소통 행동을 교수하는 중재 방법으로, 대체행동은 문제행동보다 ( ㉡ )이 적고, 동일하거나 더 빠르게 ( ㉢ )을 얻을 수 있어야 한다.',NULL,NULL,'기능(function) / 반응노력(response effort) / 강화(reinforcement)','FCT(Functional Communication Training)는 Carr & Durand(1985)가 개발한 중재로, 문제행동의 기능을 대체할 수 있는 적절한 의사소통 행동을 가르칩니다. 효과적인 대체행동의 조건은 ①동일한 기능 충족, ②낮은 반응노력, ③동등하거나 더 빠른 강화 접근, ④사회적으로 수용 가능한 행동입니다.',NULL,2,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('bs-q49','behavior-support','pbs','multiple','PBS에서 선행사건 기반 중재(antecedent-based intervention)에 해당하지 않는 것은?',NULL,ARRAY['교실 환경을 재배치하여 문제행동 유발 자극을 제거한다.','과제 전에 2~3가지 선택지를 제공하여 자율성을 높인다.','문제행동 발생 후 선호 활동을 제거하는 반응대가를 적용한다.','시각적 일과표를 제공하여 활동 전환의 예측 가능성을 높인다.'],'2','반응대가(response cost)는 문제행동 ''후''에 적용하는 후속결과 전략(부적벌)이며 선행사건 중재가 아닙니다. 선행사건 기반 중재는 문제행동이 발생하기 ''전''에 환경을 수정하는 예방적 전략으로, 환경 재배치, 선택 제공, 시각적 지원, 선호 활동 삽입, 사전 예고 등이 포함됩니다.','{"0": "환경 재배치는 대표적인 선행사건 중재입니다. 문제행동을 유발하는 자극을 사전에 제거하는 예방 전략입니다.", "1": "선택 제공은 선행사건 중재의 하나로, 학생의 자율성과 통제감을 높여 문제행동을 예방합니다.", "3": "시각적 일과표는 선행사건 중재입니다. 예측 가능성을 높여 불안이나 저항을 줄이는 예방 전략입니다."}',2,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('bs-q50','behavior-support','pbs','descriptive','PBS의 보편적 지원(1단계)에서 학교 차원의 기대행동 교수 절차를 단계별로 설명하시오.','A 특수학교에서 학교 차원의 긍정적 행동지원(SWPBS)을 도입하려 한다. 전체 학생의 복도 이동 시 뛰어다니기, 소리 지르기 등의 행동이 문제로 보고되었다.',NULL,'[모범 답안]

보편적 지원(1단계) 기대행동 교수 절차:

1. 기대행동 선정
- 학교 공동체가 3~5가지 핵심 기대행동을 선정
- 예: ''안전하게'', ''존중하며'', ''책임감 있게''
- 긍정적 용어로 진술(~하지 않기 ✕ → ~하기 ○)

2. 행동 매트릭스 개발
- 장소별(교실, 복도, 식당, 운영장 등) 기대행동의 구체적 예시 명시
- 복도 + 안전하게 = ''걸어서 이동한다'', 복도 + 존중하며 = ''작은 목소리로 대화한다''

3. 직접 교수
- 기대행동을 명시적으로 교수(설명, 시범, 연습, 피드백)
- 바람직한 예시와 비례(非例)를 함께 제시
- 학기 초 집중 교수 후 정기적 재교수

4. 강화 체계 구축
- 기대행동 수행 시 즉각적이고 구체적인 칭찬
- 학교 차원의 보상 체계(토큰, 인정 카드 등) 운영
- 4:1 비율(긍정적 상호작용 : 교정적 상호작용) 유지

5. 자료 기반 의사결정
- 행동 사건 보고서(ODR) 등 자료 수집
- 정기적으로 데이터 분석하여 중재 효과 평가
- 2단계·3단계 지원 대상 학생 선별','SWPBS의 1단계 보편적 지원은 전체 학생을 대상으로 한 예방적 접근입니다. 핵심은 기대행동의 명시적 교수, 일관된 강화 체계, 자료 기반 의사결정이며, 이를 통해 80%의 학생이 적절한 행동을 보이도록 지원합니다. 복도 행동 문제의 경우, 벌 중심이 아닌 기대행동 교수와 강화가 우선됩니다.',NULL,3,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('bs-q51','behavior-support','pbs','fill_in','PBS에서 문제행동의 기능을 파악하기 위해 실시하는 기능적 행동평가(FBA)의 3가지 방법은 ( ㉠ ), ( ㉡ ), ( ㉢ )이며, 이 중 선행사건과 후속결과를 체계적으로 조작하여 행동의 기능을 검증하는 방법은 ( ㉢ )이다.',NULL,NULL,'간접 평가(indirect assessment) / 직접 관찰(direct observation) / 기능분석(functional analysis)','FBA의 3가지 방법은 ①간접 평가(면담, 체크리스트, 평정척도 등), ②직접 관찰(ABC 관찰, 산점도 분석 등), ③기능분석(실험적 조작을 통한 인과관계 검증)입니다. 기능분석(FA)은 Iwata 등(1982/1994)이 개발한 방법으로, 조건(관심, 과제, 혼자, 통제)을 체계적으로 조작하여 행동의 기능을 실험적으로 검증합니다.',NULL,2,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('bs-q52','behavior-support','intervention','fill_in','차별강화 중 목표 문제행동 대신 구체적으로 지정한 바람직한 대체행동을 강화하는 것을 ( ㉠ )이라 하고, 문제행동과 물리적으로 양립할 수 없는 행동을 강화하는 것을 ( ㉡ )이라 한다.',NULL,NULL,'대체행동 차별강화(DRA) / 상반행동 차별강화(DRI)','DRA(Differential Reinforcement of Alternative behavior)는 문제행동 대신 적절한 대체행동을 강화합니다. DRI(Differential Reinforcement of Incompatible behavior)는 DRA의 특수한 형태로, 문제행동과 동시에 수행할 수 없는 행동을 강화합니다. 예를 들어 이탈 행동에 대해 착석(양립 불가능)을 강화하는 것이 DRI입니다.',NULL,2,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('bs-q53','behavior-support','intervention','multiple','다음 사례에서 적용된 차별강화 유형은?

"교사는 민지가 수업 중 소리를 지르지 않고 5분간 조용히 있으면 스티커를 제공한다. 시간 간격은 점차 10분, 15분으로 늘려간다."',NULL,ARRAY['DRA(대체행동 차별강화)','DRI(상반행동 차별강화)','DRO(타행동 차별강화)','DRL(저율행동 차별강화)'],'2','DRO(Differential Reinforcement of Other behavior)는 일정 시간 동안 목표 문제행동이 발생하지 않으면 강화를 제공하는 방법입니다. 이 사례에서 소리 지르기(문제행동)가 5분간 발생하지 않으면 강화(스티커)를 제공하므로 DRO에 해당합니다. DRO는 특정 대체행동이 아니라 ''문제행동의 부재''를 강화합니다.','{"0": "DRA는 구체적인 대체행동을 지정하여 강화합니다. 이 사례에서는 특정 대체행동을 강화하는 것이 아니라 문제행동의 부재를 강화하고 있습니다.", "1": "DRI는 문제행동과 양립 불가능한 행동을 강화합니다. ''조용히 있기''는 소리 지르기와 양립 불가능하지만, 이 사례는 시간 간격 기반으로 문제행동 부재를 강화하는 DRO 절차입니다.", "3": "DRL은 행동의 빈도를 줄이되 완전히 제거하지 않을 때 사용합니다. 이 사례는 일정 시간 동안 행동이 전혀 발생하지 않는 것을 조건으로 합니다."}',2,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('bs-q54','behavior-support','intervention','descriptive','자기관리(self-management) 전략의 구성요소를 제시하고, 자기관리 전략이 특수교육에서 중요한 이유를 서술하시오.','ADHD 학생 지호는 수업 중 자리 이탈 행동이 빈번하다. 교사는 지호에게 자기관리 전략을 교수하여 자리 이탈을 줄이고자 한다.',NULL,'[모범 답안]

1. 자기관리 전략의 구성요소

① 자기점검(self-monitoring)
- 자신의 행동 발생 여부를 스스로 관찰하고 기록
- 예: 타이머가 울릴 때 ''나는 자리에 앉아 있는가?''를 체크리스트에 표시

② 자기평가(self-evaluation)
- 자신의 행동을 기준과 비교하여 판단
- 예: ''오늘 체크 횟수 중 착석 비율이 80% 이상인가?'' 평가

③ 자기강화(self-reinforcement)
- 목표 달성 시 스스로 강화를 제공
- 예: 80% 이상 착석 시 쉬는 시간에 선호 활동 선택

④ 자기교수(self-instruction)
- 행동 수행을 위한 언어적 자기 지시
- 예: ''지금은 수업 시간이니까 자리에 앉아있자''

⑤ 목표 설정(goal setting)
- 구체적이고 달성 가능한 행동 목표 수립
- 예: ''오늘 수업 중 자리 이탈 2회 이하''

2. 특수교육에서 중요한 이유
- 교사 의존성 감소: 외적 통제에서 내적 통제로의 전환
- 일반화 촉진: 다양한 환경에서 자율적으로 행동 조절 가능
- 자기결정 역량 향상: 자신의 행동에 대한 주도성과 책임감 증진
- 통합환경 적응: 일반학급에서 교사의 개별 지원 없이도 적절한 행동 유지
- 성인기 전환 준비: 직업·생활 환경에서의 독립적 행동 관리 기반 마련','자기관리 전략은 행동 조절의 주체를 교사에서 학생으로 전환하는 핵심 중재입니다. 자기점검, 자기평가, 자기강화, 자기교수, 목표 설정이 주요 구성요소이며, 외적 강화 체계에서 점진적으로 자기관리로 이행하는 것이 중요합니다. ADHD, 학습장애, 지적장애 학생 모두에게 적용 가능합니다.',NULL,3,'KICE 기출 기반','{"disability": "ADHD"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('bs-q55','behavior-support','intervention','ox','DRO(타행동 차별강화)에서 설정 시간 간격 동안 어떤 행동이든 문제행동만 나타나지 않으면 강화를 제공하므로, 다른 부적절한 행동도 우연히 강화될 가능성이 있다.',NULL,NULL,'O','DRO의 제한점 중 하나는 문제행동의 ''부재''를 강화하므로, 설정 시간 간격 종료 시점에 우연히 나타난 다른 부적절한 행동이 함께 강화될 수 있다는 것입니다. 이를 보완하기 위해 DRA(특정 대체행동 강화)와 병행하거나, 강화 시점에 적절한 행동을 하고 있는지 확인하는 절차를 추가합니다.',NULL,2,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('bs-q56','behavior-support','intervention','descriptive','사회적 기술 교수의 직접교수법 절차를 단계별로 설명하고, 사회적 기술의 습득 결함(acquisition deficit)과 수행 결함(performance deficit)에 따른 중재 전략의 차이를 서술하시오.','자폐성장애 학생 하윤이는 또래와의 놀이 상황에서 놀이 참여 요청 방법을 전혀 모르고 있으며(습득 결함), 경도 지적장애 학생 서준이는 놀이 참여 요청 방법을 알고 있지만 실제 상황에서 적용하지 못한다(수행 결함).',NULL,'[모범 답안]

1. 사회적 기술 직접교수법 절차
① 목표 기술 선정 및 정의: 구체적이고 관찰 가능한 사회적 기술 선정
② 교수 근거 설명: 이 기술이 왜 중요한지 학생이 이해할 수 있게 설명
③ 시범(modeling): 교사 또는 또래가 목표 기술을 시범으로 보여줌
④ 역할극(role-play): 학생이 모의 상황에서 기술을 연습
⑤ 수행 피드백: 구체적이고 교정적인 피드백 제공
⑥ 일반화 훈련: 다양한 사람, 장소, 상황에서 기술 적용 연습

2. 습득 결함과 수행 결함에 따른 중재 차이

가. 습득 결함(acquisition deficit) — 하윤이
- 기술 자체를 모르는 상태
- 중재: 직접교수(시범, 역할극, 피드백), 사회적 이야기(social stories), 비디오 모델링, 또래 중재
- 초점: 기술의 단계별 교수와 반복 연습

나. 수행 결함(performance deficit) — 서준이
- 기술을 알지만 실제 상황에서 사용하지 않는 상태
- 중재: 선행단서 제공(촉진, 사전 리허설), 자기점검, 강화 체계 수정, 일반화 전략
- 초점: 수행 동기 강화 및 자연스러운 상황에서의 실행 지원','Gresham(1981)은 사회적 기술 결함을 습득 결함(can''t do)과 수행 결함(won''t do)으로 구분했습니다. 습득 결함은 기술 교수가 핵심이고, 수행 결함은 동기·환경 조정이 핵심입니다. 또한 유창성 결함(fluency deficit)을 추가하여 3유형으로 분류하기도 합니다.',NULL,3,'KICE 기출 기반','{"disability": "자폐성장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('bs-q57','behavior-support','intervention','ox','선행사건 중재에서 ''선택 제공(choice-making)''은 학생에게 과제 자체의 수행 여부를 선택하게 하는 것이 아니라, 과제의 순서, 재료, 장소 등을 선택하게 하여 통제감을 높이는 전략이다.',NULL,NULL,'O','선택 제공은 학생에게 과제를 ''안 할'' 선택지를 주는 것이 아니라, 과제 수행 조건(순서, 재료, 장소, 함께 할 사람 등)에 대한 선택 기회를 제공하는 것입니다. 이를 통해 학생의 자율성과 통제감이 증가하여 과제 참여와 과제 수행 행동이 향상되고, 문제행동이 감소하는 효과가 있습니다. Shogren 등의 메타분석에서 선택 제공이 문제행동 감소에 효과적임이 입증되었습니다.',NULL,2,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('cd-q21','communication-disorder','articulation','fill_in','아동이 ''사탕''을 ''타탕''으로, ''소리''를 ''토리''로 발음할 때, 이 음운변동의 유형은 무엇인가?',NULL,NULL,'파열음화','파열음화는 마찰음이나 파찰음이 파열음으로 대치되는 음운변동이다. 사탕→타탕에서 /ㅅ/→/ㅌ/, 소리→토리에서 /ㅅ/→/ㅌ/로 마찰음이 파열음으로 대치되었다. 이는 조음 방법의 변화에 해당하며, 일반적으로 2세 6개월 이후에는 소거되어야 하는 음운변동이다. 마찰음은 기류를 좁은 틈 사이로 통과시켜야 하므로 조음 난이도가 높아 파열음으로 대치하는 경향이 나타난다.',NULL,2,'KICE 기출 기반','{"disability": "의사소통장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('cd-q22','communication-disorder','articulation','multiple','다음 중 음운변동 유형과 예시가 올바르게 연결된 것은?',NULL,ARRAY['생략 - ''풍선''을 ''풍썬''으로 발음','대치 - ''기차''를 ''디차''로 발음','왜곡 - ''사과''를 ''과''로 발음','첨가 - ''코''를 ''토''로 발음'],'2','대치는 목표 음소가 다른 음소로 바뀌는 현상이다. ''기차''→''디차''에서 /ㄱ/이 /ㄷ/으로 대치된 것은 연구개음의 치조음화에 해당한다. 선택지 1은 첨가의 예시가 아닌 대치에 해당하고, 선택지 3은 생략의 예시이며, 선택지 4도 대치의 예시이다. 음운변동 분석 시 목표 음소와 실현 음소를 정확히 비교하는 것이 중요하다.','{"1": "''풍선''을 ''풍썬''으로 발음하는 것은 생략이 아니라 경음화(긴장음화)에 해당한다.", "3": "''사과''를 ''과''로 발음하는 것은 왜곡이 아니라 음절 생략에 해당한다.", "4": "''코''를 ''토''로 발음하는 것은 첨가가 아니라 연구개음의 치조음화(대치)에 해당한다."}',2,'KICE 기출 기반','{"disability": "의사소통장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('cd-q23','communication-disorder','articulation','ox','한국어 말소리 발달에서 파열음(/ㅂ, ㅃ, ㅍ, ㄷ, ㄸ, ㅌ, ㄱ, ㄲ, ㅋ/)은 마찰음(/ㅅ, ㅆ/)보다 먼저 습득된다.',NULL,NULL,'O','한국어 말소리 발달 순서에서 파열음은 비교적 이른 시기인 2세경에 습득되기 시작하며, 마찰음(/ㅅ, ㅆ/)은 상대적으로 늦은 시기인 3세 6개월~4세 이후에 완전히 습득된다. 이는 마찰음이 기류를 좁은 통로로 정밀하게 조절해야 하므로 조음 운동의 난이도가 높기 때문이다. 일반적으로 비음, 파열음이 가장 먼저 습득되고, 유음과 마찰음이 가장 늦게 습득된다.',NULL,1,'교재 참고','{"disability": "의사소통장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('cd-q24','communication-disorder','articulation','descriptive','음운인식(phonological awareness)의 정의를 설명하고, 음운인식 능력을 평가하기 위한 과제 유형 3가지를 예시와 함께 서술하시오.',NULL,NULL,'음운인식이란 말소리의 구조를 인식하고 조작할 수 있는 메타언어적 능력을 말한다. 평가 과제 유형으로는 첫째, 음절 합성 과제(예: ''사''와 ''과''를 합치면 ''사과'')가 있다. 둘째, 음소 탈락 과제(예: ''바람''에서 /ㅂ/을 빼면 ''아람'')가 있다. 셋째, 음소 변별 과제(예: ''달''과 ''발'' 중 첫소리가 다른 것 찾기)가 있다. 이 외에도 각운 인식, 음소 분리, 음소 대치 과제 등이 활용된다. 음운인식은 읽기 발달의 핵심 선행 능력으로, 조음음운장애 아동은 이 능력에 어려움을 보이는 경우가 많다.','음운인식이란 말소리의 구조를 인식하고 조작할 수 있는 메타언어적 능력을 말한다. 평가 과제 유형으로는 첫째, 음절 합성 과제(예: ''사''와 ''과''를 합치면 ''사과'')가 있다. 둘째, 음소 탈락 과제(예: ''바람''에서 /ㅂ/을 빼면 ''아람'')가 있다. 셋째, 음소 변별 과제(예: ''달''과 ''발'' 중 첫소리가 다른 것 찾기)가 있다. 이 외에도 각운 인식, 음 (자동 생성 해설)',NULL,3,'교재 참고','{"disability": "의사소통장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('cd-q25','communication-disorder','aac','multiple','PECS(그림교환 의사소통 체계)의 6단계 중 3단계에서 학습하는 핵심 내용은?',NULL,ARRAY['그림 카드를 의사소통 상대에게 건네기','의사소통판에서 그림을 변별하여 선택하기','문장 띠를 사용하여 ''나는 ~을/를 원해요'' 구성하기','속성어(색깔, 크기 등)를 사용하여 문장 확장하기'],'2','PECS 3단계(그림 변별)에서는 여러 그림 카드 중에서 원하는 항목의 그림을 정확하게 변별하여 선택하는 것을 학습한다. 1단계는 그림 교환의 기본(물리적 교환), 2단계는 거리와 지속성 확장, 4단계는 문장 띠 사용, 5단계는 ''뭐 원해?'' 질문에 반응하기, 6단계는 자발적 논평이다. 단계별 체계적 교수가 PECS의 핵심 원리이다.','{"1": "그림 카드를 상대에게 건네는 것은 PECS 1단계(물리적 교환)의 핵심 내용이다.", "3": "문장 띠를 사용하여 ''나는 ~을/를 원해요''를 구성하는 것은 PECS 4단계(문장 구조)의 핵심 내용이다.", "4": "속성어를 사용한 문장 확장은 PECS 6단계 또는 4단계 확장 과정에서 다루어지는 내용이다."}',2,'KICE 기출 기반','{"disability": "의사소통장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('cd-q26','communication-disorder','aac','ox','하이테크 AAC 기기는 음성출력장치(SGD)를 포함하며, 의사소통판과 그림카드는 로우테크 AAC에 해당한다.',NULL,NULL,'O','AAC 도구는 테크놀로지 수준에 따라 분류된다. 로우테크(low-tech)는 전자 장치가 필요 없는 도구로 의사소통판, 그림카드, 의사소통 책 등이 해당한다. 하이테크(high-tech)는 전자 기술을 활용하는 도구로 음성출력장치(SGD), 태블릿 기반 AAC 앱, 시선추적 장치 등이 포함된다. 중간 수준인 미드테크(mid-tech)로 녹음 버튼형 기기 등도 있다. 아동의 능력과 환경에 맞는 적절한 기술 수준을 선택하는 것이 중요하다.',NULL,1,'교재 참고','{"disability": "의사소통장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('cd-q27','communication-disorder','aac','fill_in','AAC 상징체계에서 실제 사물이나 사진처럼 지시 대상과 유사성이 높은 상징을 ( ) 상징이라 하고, 글자처럼 지시 대상과 유사성이 없는 상징을 ( ) 상징이라 한다.',NULL,NULL,'도상적(iconic), 자의적(arbitrary)','AAC 상징체계는 도상성(iconicity)의 정도에 따라 분류된다. 도상적(iconic) 상징은 지시 대상과의 시각적 유사성이 높아 의미를 추측하기 쉬우며, 실물, 사진, 그림 등이 이에 해당한다. 자의적(arbitrary) 상징은 지시 대상과의 유사성이 없어 학습이 필요하며, 문자, 블리스심볼(일부) 등이 이에 해당한다. AAC 중재 시 사용자의 인지 수준에 따라 도상성이 높은 상징에서 낮은 상징으로 점진적으로 전환하는 것이 권장된다.',NULL,2,'교재 참고','{"disability": "의사소통장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('cd-q28','communication-disorder','aac','descriptive','의사소통판(communication board) 구성 시 고려해야 할 요소 4가지를 설명하시오.',NULL,NULL,'의사소통판 구성 시 고려해야 할 요소는 다음과 같다. 첫째, 어휘 선정으로 사용자의 일상생활에서 빈번하게 필요한 핵심어휘(core vocabulary)와 개인적으로 의미 있는 부수어휘(fringe vocabulary)를 균형 있게 포함해야 한다. 둘째, 배치 방식으로 자주 사용하는 어휘는 접근이 쉬운 위치에, 의미 범주별로 색상 코딩(Fitzgerald Key 등)을 적용하여 탐색 효율성을 높인다. 셋째, 상징 유형으로 사용자의 인지 및 시지각 수준에 맞는 상징(사진, PCS, 글자 등)을 선택한다. 넷째, 물리적 접근성으로 사용자의 운동 능력을 고려하여 칸의 크기, 간격, 보호대(keyguard) 사용 여부를 결정한다.','의사소통판 구성 시 고려해야 할 요소는 다음과 같다. 첫째, 어휘 선정으로 사용자의 일상생활에서 빈번하게 필요한 핵심어휘(core vocabulary)와 개인적으로 의미 있는 부수어휘(fringe vocabulary)를 균형 있게 포함해야 한다. 둘째, 배치 방식으로 자주 사용하는 어휘는 접근이 쉬운 위치에, 의미 범주별로 색상 코딩(Fitzgerald K (자동 생성 해설)',NULL,3,'KICE 기출 기반','{"disability": "의사소통장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('cd-q29','communication-disorder','spontaneous-speech','multiple','평균발화길이(MLU)를 형태소 단위로 계산할 때, 다음 발화의 MLU 값은? 
발화 1: 엄마 밥 줘 (3형태소)
발화 2: 나 학교 갔어 (4형태소)
발화 3: 이거 뭐야 (3형태소)',NULL,ARRAY['2.33','3.00','3.33','4.00'],'3','MLU(Mean Length of Utterance)는 총 형태소 수를 총 발화 수로 나누어 계산한다. 발화 1은 ''엄마/밥/줘''로 3형태소, 발화 2는 ''나/학교/가/았/어'' 중 ''갔어''를 ''가+았+어''로 분석하면 5형태소이나, 문제에서 4형태소로 제시되었으므로 이를 따른다. 발화 3은 ''이거/뭐/야''로 3형태소이다. 따라서 MLU = (3+4+3) / 3 = 10 / 3 = 3.33이다. MLU는 아동의 표현언어 발달 수준을 나타내는 대표적인 양적 지표이다.','{"1": "2.33은 총 형태소 수를 잘못 계산하거나 형태소가 아닌 낱말 단위로 일부를 계산한 경우의 오답이다.", "2": "3.00은 각 발화의 형태소 수를 모두 3으로 동일하게 계산한 경우의 오답이다.", "4": "4.00은 총 형태소 수를 12로 잘못 계산하거나 발화 수를 잘못 적용한 경우의 오답이다."}',2,'KICE 기출 기반','{"disability": "의사소통장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('cd-q30','communication-disorder','spontaneous-speech','fill_in','언어표본 분석에서 아동이 사용한 서로 다른 낱말 수(NDW)를 전체 낱말 수(TNW)로 나눈 비율을 ( )(이)라 하며, 어휘 다양도를 나타내는 지표이다.',NULL,NULL,'어휘다양도(TTR, Type-Token Ratio)','TTR(Type-Token Ratio, 어휘다양도)은 아동의 표현어휘 다양성을 측정하는 지표이다. 서로 다른 낱말 유형(type)의 수를 전체 낱말(token) 수로 나누어 계산한다. 예를 들어 50개 낱말 중 서로 다른 낱말이 30개이면 TTR은 0.6이다. TTR이 높을수록 어휘 사용이 다양하다는 것을 의미한다. 다만 TTR은 발화 표본의 크기에 영향을 받으므로, 동일한 크기의 표본으로 비교해야 한다.',NULL,1,'교재 참고','{"disability": "의사소통장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('cd-q31','communication-disorder','spontaneous-speech','ox','자발화 언어표본 수집 시 최소 50개 이상의 완전하고 이해 가능한 발화를 수집하는 것이 권장된다.',NULL,NULL,'O','자발화 언어표본 분석의 신뢰도를 확보하기 위해서는 최소 50~100개의 완전하고 이해 가능한 발화를 수집하는 것이 권장된다. 불완전한 발화, 모방 발화, 노래 가사 등은 분석 대상에서 제외한다. 표본 수집 시 자연스러운 대화 상황을 유도하며, 다양한 의사소통 기능이 나타나도록 놀이, 일상 활동, 그림 설명 등 복수의 맥락에서 수집하는 것이 바람직하다.',NULL,1,'교재 참고','{"disability": "의사소통장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('cd-q32','communication-disorder','spontaneous-speech','descriptive','자발화 언어표본 분석의 절차를 수집부터 해석까지 단계별로 서술하시오.',NULL,NULL,'자발화 언어표본 분석은 다음 단계로 진행된다. 첫째, 수집 단계에서 자연스러운 대화 상황(자유놀이, 일상 대화 등)에서 최소 50~100개의 발화를 녹음 및 녹화한다. 둘째, 전사(transcription) 단계에서 녹음된 자료를 문자로 옮기되, 발화 경계, 비유창성, 비언어적 행동도 기록한다. 셋째, 분석 단계에서 MLU(평균발화길이), TTR(어휘다양도), 구문 구조, 의미관계, 화용 기능 등 다양한 지표를 산출한다. 넷째, 해석 단계에서 또래 규준과 비교하여 언어 발달 수준을 판단하고, 강점과 약점을 파악하여 중재 목표 수립에 반영한다.','자발화 언어표본 분석은 다음 단계로 진행된다. 첫째, 수집 단계에서 자연스러운 대화 상황(자유놀이, 일상 대화 등)에서 최소 50~100개의 발화를 녹음 및 녹화한다. 둘째, 전사(transcription) 단계에서 녹음된 자료를 문자로 옮기되, 발화 경계, 비유창성, 비언어적 행동도 기록한다. 셋째, 분석 단계에서 MLU(평균발화길이), TTR(어휘다양도 (자동 생성 해설)',NULL,3,'KICE 기출 기반','{"disability": "의사소통장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('cd-q33','communication-disorder','emt','multiple','환경중심 언어중재(EMT)의 4가지 전략에 해당하지 않는 것은?',NULL,ARRAY['모방(modeling)','요구-모방(mand-model)','시간지연(time delay)','직접교수(direct instruction)'],'4','환경중심 언어중재(EMT)의 4가지 핵심 전략은 모방(modeling), 요구-모방(mand-model), 시간지연(time delay), 우발교수(incidental teaching)이다. 직접교수(direct instruction)는 구조화된 교수 방법으로 EMT의 전략에 포함되지 않는다. EMT는 아동의 자연스러운 의사소통 시도를 활용하여 일상 환경에서 언어를 촉진하는 자연주의적 중재 접근이다.','{"1": "모방(modeling)은 EMT의 핵심 전략 중 하나로, 성인이 아동의 관심사에 맞춰 목표 언어 모델을 제시하는 방법이다.", "2": "요구-모방(mand-model)은 EMT의 핵심 전략 중 하나로, 아동에게 언어적 반응을 요구한 후 모델을 제시하는 방법이다.", "3": "시간지연(time delay)은 EMT의 핵심 전략 중 하나로, 아동이 원하는 것을 제공하기 전에 의도적으로 기다려 의사소통을 유도하는 방법이다."}',1,'교재 참고','{"disability": "의사소통장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('cd-q34','communication-disorder','emt','fill_in','EMT에서 ( ) 전략은 아동이 원하는 물건이나 활동이 있을 때 성인이 의도적으로 반응을 지연시켜 아동이 먼저 의사소통을 시도하도록 유도하는 방법이다.',NULL,NULL,'시간지연(time delay)','시간지연(time delay) 전략은 아동이 원하는 사물이나 활동에 대한 동기가 있을 때 성인이 의도적으로 5~15초 정도 기다리면서 기대하는 표정으로 아동을 바라보는 방법이다. 이를 통해 아동이 자발적으로 의사소통을 시도하도록 유도한다. 아동이 반응하지 않으면 모델링이나 요구-모방 등 다른 전략으로 전환한다. 이 전략은 아동의 의사소통 주도성을 높이는 데 효과적이다.',NULL,2,'KICE 기출 기반','{"disability": "의사소통장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('cd-q35','communication-disorder','emt','ox','우발교수(incidental teaching)는 성인이 미리 계획한 활동에서 구조화된 반복 연습을 통해 언어를 교수하는 전략이다.',NULL,NULL,'X','우발교수(incidental teaching)는 구조화된 반복 연습이 아니라 아동이 자연스러운 환경에서 자발적으로 의사소통을 시도할 때 이를 활용하여 언어를 확장하는 전략이다. 성인은 아동의 관심과 주도를 따르며, 아동이 시작한 상호작용에서 보다 정교한 언어 사용을 촉진한다. 미리 정해진 시행(trial)을 반복하는 것이 아니라 일상 맥락에서 자연스럽게 교수 기회를 포착하는 것이 핵심이다.',NULL,2,'교재 참고','{"disability": "의사소통장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('cd-q36','communication-disorder','emt','descriptive','환경중심 언어중재(EMT)의 요구-모방(mand-model) 전략의 실행 절차를 구체적인 예시 상황과 함께 서술하시오.',NULL,NULL,'요구-모방(mand-model) 전략은 다음 절차로 실행된다. 먼저, 아동이 관심을 보이는 사물이나 활동이 있는 상황을 확인한다. 예를 들어 아동이 선반 위의 장난감 자동차를 쳐다보고 있을 때, 성인이 ''뭐 갖고 싶어?''라고 요구(mand)한다. 아동이 적절하게 ''자동차''라고 반응하면 즉시 자동차를 제공하며 ''자동차 줄게, 빨간 자동차!''와 같이 확장된 모델을 제시한다. 아동이 반응하지 않거나 부적절하게 반응하면 ''자동차''라고 모델(model)을 제시하고 아동의 모방을 유도한다. 아동이 모방하면 즉시 강화(자동차 제공)하고, 모방하지 못하면 자동차를 제공하면서 다시 모델을 들려준다.','요구-모방(mand-model) 전략은 다음 절차로 실행된다. 먼저, 아동이 관심을 보이는 사물이나 활동이 있는 상황을 확인한다. 예를 들어 아동이 선반 위의 장난감 자동차를 쳐다보고 있을 때, 성인이 ''뭐 갖고 싶어?''라고 요구(mand)한다. 아동이 적절하게 ''자동차''라고 반응하면 즉시 자동차를 제공하며 ''자동차 줄게, 빨간 자동차!''와 같이 확장된 모 (자동 생성 해설)',NULL,3,'KICE 기출 기반','{"disability": "의사소통장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('cd-q37','communication-disorder','fluency','multiple','말더듬의 핵심행동(core behavior)에 해당하는 것을 모두 고른 것은?
ㄱ. 반복(repetition)
ㄴ. 연장(prolongation)
ㄷ. 회피(avoidance)
ㄹ. 막힘(block)',NULL,ARRAY['ㄱ, ㄴ','ㄱ, ㄴ, ㄹ','ㄱ, ㄷ, ㄹ','ㄱ, ㄴ, ㄷ, ㄹ'],'2','말더듬의 핵심행동(core behavior)은 반복(소리, 음절, 단어의 반복), 연장(소리를 길게 늘임), 막힘(기류나 발성이 차단되는 현상)의 세 가지이다. 회피(avoidance)는 핵심행동이 아니라 부수행동(secondary behavior)에 해당하며, 말더듬에 대한 부정적 반응으로 나타나는 학습된 행동이다. 핵심행동은 말더듬의 본질적 특성이며, 부수행동은 핵심행동에 대한 대처로 발전하는 것이다.','{"1": "반복과 연장만 포함하고 막힘(block)을 빠뜨렸다. 막힘도 핵심행동에 해당한다.", "3": "회피(avoidance)는 핵심행동이 아니라 부수행동에 해당한다.", "4": "회피(avoidance)가 포함되어 있으나 이는 부수행동이므로 핵심행동에 해당하지 않는다."}',2,'KICE 기출 기반','{"disability": "의사소통장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('cd-q38','communication-disorder','fluency','fill_in','유창성장애 치료에서 ( )은/는 말더듬이 발생한 후 이를 수정하는 접근법으로, ''취소하기(cancellation)'', ''빼기(pull-out)'', ''준비하기(preparatory set)''의 세 가지 기법을 포함한다.',NULL,NULL,'말더듬 수정법(stuttering modification)','말더듬 수정법은 Van Riper가 개발한 치료 접근법으로, 말더듬을 완전히 없애는 것이 아니라 보다 쉬운 말더듬(easier stuttering)으로 변화시키는 것을 목표로 한다. 취소하기는 말더듬이 끝난 후 잠시 멈추고 부드럽게 다시 말하는 기법이다. 빼기는 말더듬이 진행 중일 때 긴장을 줄이면서 빠져나오는 기법이다. 준비하기는 말더듬이 예상될 때 미리 조음기관의 긴장을 줄이고 부드럽게 시작하는 기법이다.',NULL,2,'KICE 기출 기반','{"disability": "의사소통장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('cd-q39','communication-disorder','fluency','ox','유창성완성법(fluency shaping)은 말더듬 발생 자체를 예방하여 처음부터 유창하게 말하는 것을 목표로 하는 치료 접근법이다.',NULL,NULL,'O','유창성완성법(fluency shaping)은 말더듬 발생 자체를 예방하고 처음부터 유창한 말을 산출하는 것을 목표로 한다. 이 접근법에서는 부드러운 발성 시작(gentle onset), 느린 말속도, 연속적 발성(continuous phonation), 가벼운 조음 접촉(light articulatory contact) 등의 기법을 사용한다. 말더듬 수정법이 말더듬을 수정하는 데 초점을 두는 반면, 유창성완성법은 유창한 말 산출 기술을 체계적으로 훈련하는 데 초점을 둔다.',NULL,1,'교재 참고','{"disability": "의사소통장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('cd-q40','communication-disorder','fluency','descriptive','말더듬의 부수행동(secondary behavior)의 유형을 탈출행동과 회피행동으로 나누어 각각의 정의와 구체적인 예시를 서술하시오.',NULL,NULL,'말더듬의 부수행동은 핵심행동(반복, 연장, 막힘)에 대한 반응으로 학습된 행동이며, 탈출행동과 회피행동으로 나뉜다. 탈출행동(escape behavior)은 말더듬이 발생하고 있는 순간에 그 상태에서 벗어나기 위해 나타나는 행동이다. 예를 들어 말더듬 중에 눈을 감거나, 고개를 흔들거나, 발을 구르거나, ''음'', ''그'' 같은 삽입어를 넣는 것이 해당한다. 회피행동(avoidance behavior)은 말더듬이 발생하기 전에 이를 예방하기 위해 나타나는 행동이다. 예를 들어 특정 단어를 다른 단어로 바꾸어 말하거나(단어 대치), 말해야 할 상황 자체를 피하거나(상황 회피), 말하기 전에 불필요한 소리나 단어를 삽입하는 것(시작 지연) 등이 해당한다.','말더듬의 부수행동은 핵심행동(반복, 연장, 막힘)에 대한 반응으로 학습된 행동이며, 탈출행동과 회피행동으로 나뉜다. 탈출행동(escape behavior)은 말더듬이 발생하고 있는 순간에 그 상태에서 벗어나기 위해 나타나는 행동이다. 예를 들어 말더듬 중에 눈을 감거나, 고개를 흔들거나, 발을 구르거나, ''음'', ''그'' 같은 삽입어를 넣는 것이 해당한다.  (자동 생성 해설)',NULL,3,'KICE 기출 기반','{"disability": "의사소통장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('cd-q1','communication-disorder','articulation','fill_in','조음오류의 4가지 유형은 대치(substitution), 생략(omission), ______, 첨가(addition)이다.',NULL,NULL,'왜곡(distortion)','조음오류의 4가지 유형은 대치, 생략, 왜곡, 첨가이다. 왜곡은 목표 음소와 유사하지만 정확하지 않은 소리를 산출하는 오류로, 목표 음소가 해당 언어의 음소 목록에 없는 소리로 대체될 때 발생한다.',NULL,1,'KICE 기출 기반','{"disability": "의사소통장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('cd-q2','communication-disorder','articulation','multiple','아동이 /사과/를 [타과]로 발음했다. 이 조음오류 유형은?',NULL,ARRAY['대치','생략','왜곡','첨가'],'대치','대치(substitution)는 목표 음소를 해당 언어의 다른 음소로 바꾸어 산출하는 오류이다. /ㅅ/→[ㅌ]는 한국어 음소 /ㅌ/로 대체한 것이므로 대치에 해당한다.','{"생략": "생략은 목표 음소를 산출하지 않는 경우로, /ㅅ/가 아예 빠져야 한다.", "왜곡": "왜곡은 목표 음소가 해당 언어 음소 목록에 없는 소리로 산출되는 경우이다.", "첨가": "첨가는 목표 단어에 없는 음소가 추가되는 경우이다."}',1,'KICE 기출 기반','{"disability": "의사소통장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('cd-q3','communication-disorder','articulation','descriptive','아동이 /시계/를 [ʃi게]로 발음했다. 이 오류가 ''대치''가 아닌 ''왜곡''으로 분류되는 이유를 설명하시오.','2026학년도 전공B 4번 관련 출제 포인트',NULL,'[ʃ](권설 마찰음)는 한국어 음소 목록에 존재하지 않는 소리이므로 왜곡에 해당한다. 대치는 목표 음소가 해당 언어의 ''다른 음소''로 바뀌는 경우이고, 왜곡은 해당 언어 음소 목록에 없는 소리로 산출되는 경우이다.','왜곡과 대치의 핵심 구분 기준은 산출된 소리가 해당 언어의 음소 목록에 존재하는지 여부이다. [ʃ]는 영어에는 있으나 한국어 음소 체계에는 없으므로 왜곡으로 분류한다. 이 구분은 2026 임용시험에서 직접 출제되었다.',NULL,3,'KICE 기출 기반','{"disability": "의사소통장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('cd-q4','communication-disorder','articulation','fill_in','아동이 /가방/을 [다방], /고래/를 [도래]로 발음하는 음운변동은 연구개음이 치경음으로 바뀌는 ______이다.',NULL,NULL,'전설음화(fronting)','전설음화(fronting)는 연구개음(/ㄱ/, /ㅋ/)이 더 앞쪽 조음 위치인 치경음(/ㄷ/, /ㅌ/)으로 대치되는 음운변동이다. 조음 위치가 뒤(연구개)에서 앞(치경)으로 이동하므로 전설음화라고 한다.',NULL,2,'KICE 기출 기반','{"disability": "의사소통장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('cd-q5','communication-disorder','articulation','ox','조음치료에서 전통적 접근법(Van Riper)은 감각-지각 훈련 → 음 산출 → 음 안정화 → 전이·유지의 순서로 진행된다.',NULL,NULL,'O','Van Riper의 전통적 조음치료 접근법은 감각-지각 훈련(귀 훈련), 음 산출(산출 훈련), 음 안정화(다양한 음성적 맥락에서 연습), 전이·유지(일상생활 일반화)의 4단계로 구성된다.',NULL,2,'KICE 기출 기반','{"disability": "의사소통장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('cd-q6','communication-disorder','aac','fill_in','AAC 참여모델에서 장벽은 크게 기회 장벽과 ______ 장벽으로 구분된다.',NULL,NULL,'접근(access)','AAC 참여모델(Participation Model)은 의사소통 참여를 저해하는 요인을 기회 장벽(opportunity barriers)과 접근 장벽(access barriers)으로 구분한다. 기회 장벽은 정책, 실제, 태도, 지식, 기술 장벽을 포함하며, 접근 장벽은 AAC 체계 자체에 대한 접근성 문제이다.',NULL,2,'KICE 기출 기반','{"disability": "의사소통장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('cd-q7','communication-disorder','aac','descriptive','AAC 참여모델의 기회 장벽 5가지 하위 유형을 쓰고, ''태도 장벽''의 예를 1가지 서술하시오.','2026학년도 전공B 4번 관련 출제 포인트',NULL,'기회 장벽의 5가지 하위 유형: 정책 장벽, 실제 장벽, 태도 장벽, 지식 장벽, 기술 장벽. 태도 장벽 예시: 교사나 또래가 AAC 사용자는 의사소통 능력이 부족하다고 여겨 대화 시도를 하지 않거나, AAC 기기를 사용하는 것이 부자연스럽다고 생각하여 상호작용을 회피하는 경우.','태도 장벽은 주변 사람들의 부정적 인식이나 편견으로 인해 AAC 사용자의 의사소통 참여가 제한되는 것이다. 2026 임용시험에서 태도 장벽이 직접 출제되었으므로 각 장벽 유형의 정의와 구체적 예시를 숙지해야 한다.',NULL,3,'KICE 기출 기반','{"disability": "의사소통장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('cd-q8','communication-disorder','aac','fill_in','AAC 상징의 도상성(iconicity) 수준은 투명(transparent), ______, 불투명(opaque)의 3단계로 구분된다.',NULL,NULL,'반투명(translucent)','도상성은 상징이 지시 대상과 얼마나 닮았는지를 나타내는 정도이다. 투명(transparent)은 상징만 보고 의미를 알 수 있는 수준, 반투명(translucent)은 의미를 알고 나면 상징과의 관계를 이해할 수 있는 수준, 불투명(opaque)은 상징과 의미 사이에 시각적 유사성이 없는 수준이다.',NULL,2,'KICE 기출 기반','{"disability": "의사소통장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('cd-q9','communication-disorder','aac','descriptive','음성출력 의사소통 기기(VOCA/SGD)의 장점 중 ''의사소통 상대자 훈련이 불필요하다''는 것이 왜 중요한 장점인지 설명하시오.',NULL,NULL,'비도움 AAC(수어, 제스처 등)는 상대자도 해당 체계를 알아야 의사소통이 가능하여 상대자 훈련이 필수적이다. 반면 VOCA/SGD는 음성으로 메시지를 출력하므로 상대자가 별도의 훈련 없이도 메시지를 이해할 수 있다. 이는 낯선 사람과도 즉시 의사소통할 수 있어 사회적 참여 범위를 넓힌다.','VOCA/SGD는 합성 또는 녹음된 음성을 출력하여 누구나 메시지를 이해할 수 있게 한다. 이는 의사소통 상대자의 범위를 훈련받은 사람에 한정하지 않으므로, 통합 환경에서 특히 중요한 장점이다.',NULL,2,'KICE 기출 기반','{"disability": "의사소통장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('cd-q10','communication-disorder','aac','multiple','AAC 상징 중 도상성이 가장 높은 것은?',NULL,ARRAY['블리스 상징(Blissymbols)','실물 사진','PCS(Picture Communication Symbols)','글자(text)'],'실물 사진','실물 사진은 지시 대상을 직접 촬영한 것으로 도상성이 가장 높다(투명). PCS는 그림 상징으로 비교적 높은 도상성을 가지지만 사진보다는 낮다. 블리스 상징과 글자는 추상적이므로 도상성이 낮다(불투명).','{"블리스 상징(Blissymbols)": "블리스 상징은 의미 기반의 추상적 상징 체계로, 도상성이 낮아 불투명에 가깝다.", "PCS(Picture Communication Symbols)": "PCS는 그림 상징으로 비교적 높은 도상성을 가지나, 실물 사진보다는 추상화되어 있다.", "글자(text)": "글자는 소리와 의미의 관계가 자의적이므로 도상성이 가장 낮다."}',1,'KICE 기출 기반','{"disability": "의사소통장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('cd-q11','communication-disorder','spontaneous-speech','fill_in','평균발화길이(MLU)의 계산 공식은 총 ______ 수 ÷ 총 발화 수이다.',NULL,NULL,'형태소','MLU(Mean Length of Utterance, 평균발화길이)는 총 형태소 수를 총 발화 수로 나눈 값이다. 한국어에서는 어절 기준 MLUw와 형태소 기준 MLUm을 모두 사용하나, 전통적으로 형태소 단위(MLUm)가 기본이다.',NULL,1,'KICE 기출 기반','{"disability": "의사소통장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('cd-q12','communication-disorder','spontaneous-speech','descriptive','자발화 분석에서 NDW(Number of Different Words)와 TNW(Total Number of Words)의 차이를 설명하고, NDW/TNW 비율이 낮을 때 의미하는 바를 서술하시오.',NULL,NULL,'NDW는 아동이 산출한 서로 다른 낱말의 수(중복 제외)이고, TNW는 산출한 전체 낱말 수(중복 포함)이다. NDW/TNW 비율(TTR: Type-Token Ratio)이 낮으면 아동이 제한된 어휘를 반복적으로 사용하고 있음을 의미하며, 어휘 다양성이 낮다는 것을 나타낸다.','TTR(Type-Token Ratio)은 어휘 다양성의 지표로, 비율이 낮을수록 동일한 단어를 반복 사용하는 경향이 크다. 언어발달 지연 아동은 일반 아동에 비해 TTR이 낮은 경향이 있다.',NULL,2,'KICE 기출 기반','{"disability": "의사소통장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('cd-q13','communication-disorder','spontaneous-speech','ox','자발화 분석 시 MLU 산출을 위해서는 최소 50개 이상의 완전한 발화를 수집하는 것이 권장된다.',NULL,NULL,'O','자발화 분석에서 MLU의 대표성을 확보하기 위해 최소 50~100개의 완전한 발화 표본을 수집하는 것이 권장된다. 표본이 너무 적으면 아동의 언어 능력을 정확하게 반영하지 못할 수 있다.',NULL,2,'KICE 기출 기반','{"disability": "의사소통장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('cd-q14','communication-disorder','emt','fill_in','환경중심 언어중재(EMT)의 4가지 기법은 모델링, 요구-모델, ______, 우발교수이다.',NULL,NULL,'시간지연(time delay)','EMT의 4가지 기법은 모델링(modeling), 요구-모델(mand-model), 시간지연(time delay), 우발교수(incidental teaching)이다. 시간지연은 아동이 원하는 것이 있을 때 성인이 일정 시간 기다려 아동의 자발적 의사소통을 유도하는 기법이다.',NULL,2,'KICE 기출 기반','{"disability": "의사소통장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('cd-q15','communication-disorder','emt','descriptive','환경중심 언어중재에서 ''요구-모델(mand-model)'' 기법의 절차를 단계별로 설명하시오.',NULL,NULL,'1단계: 아동의 관심이나 요구를 관찰하여 의사소통 기회를 포착한다. 2단계: 아동에게 언어적 요구(mand)를 한다(예: ''뭐 갖고 싶어?'', ''이름이 뭐야?''). 3단계: 아동이 적절히 반응하면 원하는 것을 제공하고, 반응이 없거나 부적절하면 목표 언어를 모델링한다. 4단계: 아동이 모델을 모방하면 강화(원하는 것 제공)하고, 모방하지 못해도 원하는 것을 제공하되 목표 언어를 한 번 더 들려준다.','요구-모델 기법은 아동의 자연스러운 동기를 활용하되, 먼저 언어적 요구(질문)를 통해 자발적 산출을 유도하고, 실패 시 모델링으로 전환하는 촉진 계층 구조를 가진다.',NULL,3,'KICE 기출 기반','{"disability": "의사소통장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('cd-q16','communication-disorder','emt','multiple','환경중심 언어중재 기법 중, 성인이 아동이 원하는 물건을 보여주고 아무 말 없이 일정 시간 기다려 아동의 자발적 발화를 유도하는 기법은?',NULL,ARRAY['모델링','요구-모델','시간지연','우발교수'],'시간지연','시간지연(time delay)은 아동이 원하는 상황에서 성인이 기대하는 표정으로 일정 시간(보통 5~15초) 기다려 아동의 자발적 의사소통 시도를 유도하는 기법이다. 언어적 촉진 없이 비언어적 단서(시선, 기대 표정)만 제공하는 것이 특징이다.','{"모델링": "모델링은 성인이 먼저 목표 언어를 들려주는 기법으로, 기다리지 않고 즉시 모델을 제공한다.", "요구-모델": "요구-모델은 성인이 언어적 질문(''뭐야?'')으로 반응을 요구하는 기법이다.", "우발교수": "우발교수는 아동이 먼저 시도한 후 성인이 더 정교한 반응을 요구하는 기법이다."}',2,'KICE 기출 기반','{"disability": "의사소통장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('cd-q17','communication-disorder','emt','fill_in','환경중심 언어중재에서 ______ 기법은 아동이 먼저 원하는 것을 요청(시작)한 후, 성인이 더 정교화된 언어 반응을 요구하는 방식이다.',NULL,NULL,'우발교수(incidental teaching)','우발교수는 아동이 자발적으로 의사소통을 시작했을 때 성인이 더 구체적이거나 정교한 언어 표현을 요구하는 기법이다. 아동의 자발적 시작이 전제 조건이라는 점에서 다른 EMT 기법과 구별된다.',NULL,2,'KICE 기출 기반','{"disability": "의사소통장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('cd-q18','communication-disorder','fluency','fill_in','말더듬의 핵심행동(core behaviors) 3가지는 반복(part-word repetition), 연장(prolongation), ______이다.',NULL,NULL,'막힘(block)','말더듬의 핵심행동은 반복(음절이나 음소 단위의 반복), 연장(소리를 길게 늘이는 것), 막힘(공기 흐름이나 발성이 일시적으로 차단되는 것)의 3가지이다. 이는 부수행동(탈출행동, 회피행동)과 구별되는 말더듬의 본질적 특성이다.',NULL,2,'KICE 기출 기반','{"disability": "의사소통장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('cd-q19','communication-disorder','fluency','descriptive','유창성완성법(fluency shaping)과 말더듬수정법(stuttering modification)의 치료 목표와 접근 방식의 차이를 비교 설명하시오.',NULL,NULL,'유창성완성법은 유창한 말을 증진하는 것이 목표로, 말더듬을 직접 다루기보다 부드러운 발성 시작, 느린 말 속도, 연속적 발성 등 유창성을 촉진하는 새로운 말 패턴을 훈련한다. 말더듬수정법은 말더듬 자체를 수정하는 것이 목표로, 말더듬에 대한 두려움과 회피를 줄이고, 더 쉬운 말더듬(easier stuttering)으로 변환하는 것을 추구한다. 말더듬수정법의 4단계는 확인(identification), 둔감화(desensitization), 수정(modification), 안정화(stabilization)이다.','유창성완성법은 말더듬을 피하고 유창성을 만드는 접근이고, 말더듬수정법은 말더듬을 수용하되 더 편하게 더듬도록 하는 접근이다. 현대 치료에서는 두 접근을 통합적으로 사용하는 경향이 있다.',NULL,3,'KICE 기출 기반','{"disability": "의사소통장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('cd-q20','communication-disorder','fluency','ox','말더듬에서 머리를 흔들거나 눈을 깜빡이는 행동은 핵심행동(core behaviors)에 해당한다.',NULL,NULL,'X','머리 흔들기, 눈 깜빡이기 등은 부수행동(secondary behaviors) 중 탈출행동에 해당한다. 핵심행동은 반복, 연장, 막힘의 3가지이며, 부수행동은 말더듬 순간에서 벗어나기 위한 탈출행동과 말더듬 상황을 미리 피하려는 회피행동으로 나뉜다.',NULL,1,'KICE 기출 기반','{"disability": "의사소통장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('cur-q38','curriculum','basic-curriculum','fill_in','2022 개정 기본교육과정에서 초등학교 교과(군)는 국어, 수학, ( ㉠ ), 체육, 예술(음악/미술), ( ㉡ )의 6개 교과(군)으로 편성되며, 중학교에서는 여기에 ( ㉢ ) 교과(군)이 추가된다.',NULL,NULL,'사회/과학/실과 / 자립생활 / 진로와 직업','2022 개정 기본교육과정 초등학교는 국어, 수학, 사회/과학/실과, 체육, 예술(음악/미술), 자립생활의 6개 교과(군)으로 편성됩니다. 중학교에서는 이에 진로와 직업 교과(군)이 추가되어 7개 교과(군)으로 운영됩니다. 자립생활은 기본교육과정에만 있는 고유 교과로, 특수교육대상자의 일상생활 기능 향상을 목적으로 합니다.',NULL,1,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('cur-q39','curriculum','basic-curriculum','ox','2022 개정 기본교육과정에서 고등학교의 교과(군)별 수업 시수는 20% 범위 내에서 증감하여 편성할 수 있으나, 창의적 체험활동 시수는 증감할 수 없다.',NULL,NULL,'X','2022 개정 기본교육과정에서 교과(군)별 20% 범위 내 시수 증감이 가능할 뿐 아니라, 창의적 체험활동 시수도 학생의 장애 특성과 학교 여건에 따라 증감이 가능합니다. 기본교육과정은 특수교육대상자를 위한 유연한 편성·운영을 원칙으로 하며, 교과와 창의적 체험활동 모두 학교 자율성이 보장됩니다.',NULL,1,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('cur-q40','curriculum','basic-curriculum','fill_in','기본교육과정 성취기준 적용 시, 학생의 현재 수행 수준에 맞추어 성취기준을 ( ㉠ )하거나, 성취기준의 일부 요소를 ( ㉡ )하여 적용할 수 있으며, 이를 통해 개별화교육계획(IEP)의 ( ㉢ )를 설정한다.',NULL,NULL,'재구성 / 분해(세분화) / 교육목표(연간목표)','기본교육과정 성취기준은 학생의 장애 유형·정도와 현재 수행 수준에 따라 재구성하거나 세분화하여 적용합니다. 성취기준 재구성이란 학년군 간 성취기준을 통합하거나 난이도를 조정하는 것이며, 분해(세분화)란 하나의 성취기준을 하위 단계로 나누는 것입니다. 이렇게 조정된 성취기준을 기반으로 IEP의 연간목표와 단기목표를 설정합니다.',NULL,2,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('cur-q41','curriculum','basic-curriculum','multiple','2022 개정 기본교육과정의 편제에 관한 설명으로 옳지 않은 것은?',NULL,ARRAY['초등학교 1~2학년에서도 기본교육과정을 적용할 수 있다','고등학교 기본교육과정은 교과(군)와 창의적 체험활동으로 편성된다','기본교육과정 고등학교에 ''진로와 직업'' 교과(군)이 포함된다','기본교육과정의 교과(군)별 시수 증감 범위는 20%이다'],'0','2022 개정 교육과정에서 초등학교 1~2학년은 공통교육과정을 적용하며, 기본교육과정은 초등학교 3학년부터 고등학교까지 적용할 수 있습니다. 즉, 1~2학년에는 기본교육과정을 별도로 적용하지 않고 공통교육과정 내에서 개별화 지원을 합니다.','{"1": "기본교육과정 고등학교도 교과(군)와 창의적 체험활동으로 편성됩니다.", "2": "기본교육과정 중·고등학교에는 진로와 직업 교과(군)이 포함되어 있습니다.", "3": "기본교육과정에서 교과(군)별 수업 시수의 20% 범위 내 증감이 가능합니다."}',2,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('cur-q42','curriculum','basic-curriculum','descriptive','기본교육과정의 성취기준을 활용하여 중도·중복장애 학생의 교육과정을 편성하는 방법을 설명하고, 교과 간 통합 편성의 구체적 예시를 1가지 제시하시오.','특수학교 초등부 5학년 학급에 중도·중복장애(지적장애 및 지체장애 중복) 학생 A가 배치되어 있다. 학생 A는 의사소통에 AAC를 사용하며, 일상생활 기능 중 식사와 이동에 전반적 지원이 필요하다.',NULL,'[모범 답안]

1. 기본교육과정 성취기준 활용 방법
① 학년군 간 성취기준 하향 적용: 학생 A의 현행 수준에 맞는 하위 학년군 성취기준을 선택하여 적용
② 성취기준 세분화: 하나의 성취기준을 과제분석하여 하위 단계로 나누어 단기목표 설정
③ 성취기준 통합: 여러 교과의 성취기준을 일상생활 맥락에서 통합하여 재구성
④ 핵심기능 중심 재구성: 성취기준에서 학생의 생활 기능 향상에 필요한 핵심 요소를 추출

2. 교과 간 통합 편성 예시
주제: ''급식 시간 활동''
- 국어: AAC를 활용하여 원하는 음식 선택 표현하기(의사소통 성취기준)
- 수학: 음식 수량 세기, 1:1 대응하기(수와 연산 성취기준)
- 자립생활: 수저 사용하기, 식사 후 정리하기(식생활 성취기준)
- 체육: 식당까지 이동하기(이동 활동 성취기준)
→ 하나의 일과를 중심으로 4개 교과 성취기준을 통합하여 기능적 교육과정으로 편성','중도·중복장애 학생의 교육과정 편성에서는 기본교육과정 성취기준을 기반으로 하되, 학생의 현행 수준과 생활 기능에 초점을 둔 재구성이 필요합니다. 교과 간 통합은 학생의 일상생활 맥락을 중심으로 여러 교과의 성취기준을 연결하여 의미 있는 학습 기회를 제공하는 방법입니다.',NULL,3,'KICE 기출 기반','{"disability": "중도·중복장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('cur-q43','curriculum','basic-curriculum','fill_in','2022 개정 기본교육과정에서 고등학교 선택 교과에는 직업생활, 정보통신활용, 생활영어, ( ㉠ ), ( ㉡ ) 등이 포함된다.',NULL,NULL,'여가활용 / 보건','2022 개정 기본교육과정 고등학교에서는 공통 교과 외에 선택 교과를 편성할 수 있으며, 직업생활, 정보통신활용, 생활영어, 여가활용, 보건 등이 선택 교과에 해당합니다. 이는 특수교육대상 학생의 전환기 역량(직업, 여가, 건강, 일상생활)을 강화하기 위한 것입니다.',NULL,2,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('cur-q44','curriculum','basic-curriculum','ox','기본교육과정은 특수교육대상자만 적용받을 수 있으며, 일반학교 특수학급에서는 기본교육과정을 편성·운영할 수 없다.',NULL,NULL,'X','기본교육과정은 특수학교뿐 아니라 일반학교 특수학급에서도 편성·운영할 수 있습니다. 개별화교육계획(IEP)에 의해 기본교육과정의 적용이 결정된 학생은 배치 형태에 관계없이 해당 교육과정을 적용받을 수 있으며, 통합학급에서도 교과에 따라 기본교육과정 성취기준을 활용할 수 있습니다.',NULL,1,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('cur-q45','curriculum','general-curriculum','fill_in','2022 개정 교육과정에서 초등학교 3학년~중학교 3학년에 적용되는 ( ㉠ ) 교육과정과 고등학교에 적용되는 ( ㉡ ) 교육과정을 합하여 일반교육과정이라 하며, 특수교육대상자는 이 일반교육과정 또는 ( ㉢ ) 교육과정을 적용받을 수 있다.',NULL,NULL,'공통 / 선택중심 / 기본','2022 개정 교육과정 체제에서 초3~중3은 공통교육과정, 고등학교는 선택중심교육과정으로 편성됩니다. 특수교육대상자는 학생의 장애 특성과 교육적 요구에 따라 공통·선택중심교육과정(일반교육과정)을 적용하거나, 기본교육과정을 적용받을 수 있으며, 이는 IEP 팀의 협의를 통해 결정합니다.',NULL,1,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('cur-q46','curriculum','general-curriculum','multiple','공통교육과정과 기본교육과정의 차이에 대한 설명으로 옳은 것은?',NULL,ARRAY['공통교육과정에는 자립생활 교과가 포함되어 있다','기본교육과정의 성취기준은 공통교육과정의 성취기준을 단순히 축소한 것이다','공통교육과정 적용 학생도 일부 교과에서 기본교육과정 성취기준을 활용할 수 있다','기본교육과정 적용 학생은 공통교육과정의 어떤 교과도 이수할 수 없다'],'2','특수교육대상자는 IEP 팀의 협의에 따라 교과별로 공통교육과정 또는 기본교육과정의 성취기준을 선택적으로 적용받을 수 있습니다. 예를 들어 국어는 공통교육과정, 수학은 기본교육과정 성취기준을 적용하는 것이 가능합니다.','{"0": "자립생활 교과는 기본교육과정에만 있는 고유 교과이며, 공통교육과정에는 포함되지 않습니다.", "1": "기본교육과정의 성취기준은 공통교육과정의 단순 축소가 아니라, 특수교육대상자의 특성과 요구에 맞게 별도로 개발된 것입니다.", "3": "기본교육과정 적용 학생도 일부 교과에서 공통교육과정 성취기준을 적용받을 수 있습니다. 교과별 유연한 적용이 가능합니다."}',2,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('cur-q47','curriculum','general-curriculum','descriptive','교육과정 수정(curriculum modification)의 4가지 유형(동일 교육과정, 수정 교육과정, 중복 교육과정, 대안 교육과정)을 각각 설명하고, 통합학급 사회 수업에서 지적장애 학생에게 적용하는 구체적 예시를 유형별로 1가지씩 제시하시오.','통합학급에서 ''지역사회의 공공기관'' 단원을 학습하고 있다. 학급에는 경도 지적장애 학생 B가 포함되어 있으며, B는 읽기 능력이 또래보다 2학년 정도 낮고, 구체적 경험 중심의 학습에 강점이 있다.',NULL,'[모범 답안]

1. 동일 교육과정(same curriculum)
- 정의: 동일한 교육목표와 활동을 동일한 수준으로 참여
- 예시: 공공기관의 명칭과 역할을 학급 전체와 동일한 활동지로 학습 (추가 지원 없이 참여 가능한 활동)

2. 수정 교육과정(modified curriculum)
- 정의: 동일한 교육과정 내에서 난이도, 학습량, 참여 방법 등을 조정
- 예시: 공공기관 역할을 텍스트 대신 그림 카드와 사진으로 학습하고, 기관 수를 5개에서 3개로 줄여 학습량을 조정

3. 중복 교육과정(overlapping curriculum)
- 정의: 동일한 활동에 참여하되 학생의 IEP 목표(다른 교과 또는 기능적 목표)를 함께 추구
- 예시: 공공기관 현장체험학습 시, 또래는 기관의 기능을 탐구하는 동안 B는 대중교통 이용하기(자립생활 목표)와 기관 이름 읽기(국어 목표)를 동시에 연습

4. 대안 교육과정(alternative curriculum)
- 정의: 교육과정 내용이 학생의 요구와 맞지 않을 때 완전히 다른 기능적 활동을 제공
- 예시: 학급이 공공기관의 행정 체계를 학습하는 동안, B는 실제 우체국에서 편지 보내기 등 생활 기능 중심의 지역사회 참여 활동을 수행','교육과정 수정 4유형은 통합교육 상황에서 특수교육대상자의 교육과정 접근성을 보장하기 위한 연속체(continuum)적 접근입니다. 동일→수정→중복→대안 순으로 원래 교육과정으로부터의 변화 정도가 커지며, 가능한 한 동일 또는 수정 교육과정을 우선 적용하고 필요에 따라 중복·대안을 고려하는 것이 통합교육의 원칙입니다.',NULL,3,'KICE 기출 기반','{"disability": "지적장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('cur-q48','curriculum','general-curriculum','fill_in','보편적 학습설계(UDL)에서 다양한 참여(engagement) 수단의 제공은 학습의 ( ㉠ )적 네트워크와 관련되며, 학습자의 흥미 유발, 노력과 ( ㉡ )의 지속, ( ㉢ ) 조절의 3가지 하위 지침으로 구성된다.',NULL,NULL,'정의(affective) / 끈기(persistence) / 자기(self-regulation)','UDL의 참여 원리는 뇌의 정의적 네트워크(why of learning)와 관련됩니다. 하위 지침은 ①흥미 유발(개인 선택 기회 제공, 관련성 강조), ②노력과 끈기 지속(목표 강조, 협력 촉진, 피드백 제공), ③자기 조절(동기 유지, 대처 전략, 자기 평가)로 구성됩니다. 이는 학습자가 학습에 몰입하고 동기를 유지하는 데 필요한 다양한 방법을 제공하기 위한 것입니다.',NULL,2,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('cur-q49','curriculum','general-curriculum','ox','선택중심교육과정에서 특수교육대상 고등학생이 기본교육과정을 적용받을 경우, 해당 학생은 일반교육과정의 선택 과목을 이수할 수 없으므로 졸업 시 일반 고등학교 졸업장이 아닌 특수학교 졸업장을 받는다.',NULL,NULL,'X','기본교육과정을 적용받는 학생도 일반학교에 배치되어 있다면 일반 고등학교 졸업장을 받을 수 있습니다. 또한 기본교육과정 적용 학생도 일부 선택 과목을 일반교육과정으로 이수할 수 있으며, 졸업장의 종류는 적용 교육과정이 아니라 배치된 학교에 따라 결정됩니다.',NULL,2,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('cur-q50','curriculum','general-curriculum','descriptive','진단-처방적 교수 모델의 절차를 단계별로 설명하고, 이 모델이 특수교육대상자의 교육과정 운영에서 갖는 의의와 한계를 각각 2가지씩 서술하시오.',NULL,NULL,'[모범 답안]

1. 진단-처방적 교수 모델 절차
① 진단(Diagnosis): 학생의 현재 수행 수준, 강점, 요구를 다양한 평가 도구(표준화 검사, 교육과정 중심 측정, 관찰 등)로 파악
② 처방(Prescription): 진단 결과에 기초하여 교수목표, 교수방법, 교수자료, 교수환경 등을 포함한 개별화된 교수 계획 수립
③ 교수(Instruction): 처방에 따라 체계적으로 교수 실행
④ 평가(Evaluation): 교수 결과를 평가하여 목표 달성 여부 확인
⑤ 재진단 및 수정: 평가 결과에 따라 재진단하고 처방을 수정하는 순환적 과정

2. 의의
① 개별화: 학생의 고유한 교육적 요구에 맞춘 체계적 교수 계획이 가능하여 IEP 운영의 이론적 기반이 됨
② 책무성: 진단→처방→교수→평가의 순환 구조로 교수 효과에 대한 객관적 근거를 확보할 수 있음

3. 한계
① 결손 중심 관점: 학생의 부족한 부분을 진단·교정하는 데 초점을 두어 강점 기반 접근이 약함
② 맥락 경시: 학생 개인의 능력에만 초점을 두어 환경적 요인(교수환경, 또래관계 등)의 영향을 충분히 고려하지 못함','진단-처방적 교수 모델은 의학 모델에 기반한 교수 접근으로, 특수교육에서 IEP 수립의 이론적 토대가 됩니다. 그러나 생태학적 관점에서의 한계가 지적되며, 최근에는 강점 기반 접근과 환경 중심 접근을 병행하는 추세입니다.',NULL,3,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('cur-q51','curriculum','general-curriculum','fill_in','교육과정 재구성의 방법 중, 여러 교과의 성취기준을 하나의 주제 중심으로 통합하여 지도하는 방법을 ( ㉠ )이라 하고, 같은 교과 내에서 학년군 간 성취기준의 순서를 재배열하는 방법을 ( ㉡ )이라 한다.',NULL,NULL,'주제 중심 통합(주제통합) / 재배열(재조직)','교육과정 재구성 방법에는 ①주제 중심 통합(여러 교과의 성취기준을 하나의 주제로 통합), ②재배열(교과 내 성취기준 순서 변경), ③축소·확대(학습 내용의 범위·깊이 조절), ④대체(성취기준의 활동이나 자료를 학생에게 적합한 것으로 변경) 등이 있습니다. 주제 중심 통합은 교과 간 연계를 강화하고, 재배열은 선수학습 보장에 효과적입니다.',NULL,2,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('cur-q52','curriculum','general-curriculum','multiple','교수적 수정(instructional modification)의 4요소 중 ''교수환경'' 수정에 해당하는 것은?',NULL,ARRAY['평가 시 시간을 연장하여 제공한다','읽기 자료의 글자 크기를 확대한다','좌석을 교사 가까이로 배치하고 소음을 줄인다','학습 내용의 양을 줄여 핵심 개념만 다룬다'],'2','교수적 수정 4요소 중 교수환경 수정은 물리적·사회적 환경을 조정하는 것으로, 좌석 배치 변경, 소음 감소, 조명 조절, 집단 구성 변경 등이 포함됩니다. 시간 연장은 평가 수정, 글자 크기 확대는 교수방법(자료) 수정, 학습량 축소는 교수내용 수정에 해당합니다.','{"0": "평가 시 시간 연장은 교수적 수정의 4요소 중 ''평가방법'' 수정에 해당합니다.", "1": "읽기 자료의 글자 크기 확대는 ''교수방법'' 수정(교수자료 조정)에 해당합니다.", "3": "학습 내용의 양 축소는 ''교수내용'' 수정에 해당합니다."}',2,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('cur-q53','curriculum','iep','fill_in','「장애인 등에 대한 특수교육법」 제22조에 따른 개별화교육계획(IEP)의 필수 구성요소는 인적사항, 현재 학습 수행 수준, 교육목표, 교육내용, ( ㉠ ), ( ㉡ ), 교육 지원 내용이다.',NULL,NULL,'교육방법 / 평가계획','장애인 등에 대한 특수교육법 제22조 및 시행규칙에 따르면, IEP에는 ①인적사항, ②현재 학습 수행 수준, ③교육목표, ④교육내용, ⑤교육방법, ⑥평가계획, ⑦교육 지원 내용(특수교육 관련서비스 등)이 반드시 포함되어야 합니다. 이는 체계적이고 법적 근거 있는 개별화 교육을 보장하기 위한 것입니다.',NULL,2,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('cur-q54','curriculum','iep','fill_in','「장애인 등에 대한 특수교육법」에 따라 개별화교육지원팀은 매 학기 시작일부터 ( ㉠ ) 이내에 IEP를 작성해야 하며, 매 학기마다 ( ㉡ )을 실시하고 그 결과를 학생의 ( ㉢ )에게 통보해야 한다.',NULL,NULL,'30일(1개월) / 평가 / 보호자','장애인 등에 대한 특수교육법 제22조에 따르면, 개별화교육지원팀은 매 학기 시작일로부터 30일 이내에 IEP를 작성해야 합니다. 또한 매 학기마다 IEP에 따른 학생의 학업 성취도 등에 대한 평가를 실시하고, 그 결과를 보호자에게 통보해야 합니다.',NULL,2,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('cur-q55','curriculum','iep','descriptive','IEP 팀(개별화교육지원팀)의 구성원을 법적 근거에 따라 제시하고, 각 구성원의 역할을 설명하시오.','일반 초등학교 특수학급에 배치된 자폐성장애 학생 C의 IEP를 수립하기 위해 개별화교육지원팀 회의를 개최하려 한다.',NULL,'[모범 답안]

「장애인 등에 대한 특수교육법」 제22조에 따른 IEP 팀 구성원과 역할:

1. 보호자: 가정에서의 학생 행동·특성 정보 제공, 교육목표 협의, IEP 동의 및 참여
2. 특수교육교원: IEP 작성 주도, 교육목표·내용·방법 계획, 교육과정 재구성, 직접 교수 실행
3. 일반교육교원: 통합학급에서의 학생 수행 정보 제공, 교수적 수정 협의, 통합교육 환경 조성
4. 진로 및 직업교육 담당 교원: 전환교육 계획 수립 (중등 이상 해당)
5. 특수교육 관련서비스 담당 인력: 치료지원, 보조인력 등 관련서비스 계획 및 제공 (치료사, 보조공학사 등)

※ 학생 C(자폐성장애) 사례에서의 추가 고려:
- 행동 중재 전문가 또는 관련 전문가의 자문 참여 가능
- 학생의 의사소통 특성을 고려한 AAC 전문가 참여 검토
- 보호자의 적극적 참여를 통해 가정-학교 일관성 있는 중재 계획 수립','IEP 팀 구성은 장애인 등에 대한 특수교육법 제22조에 법적 근거를 두고 있으며, 보호자, 특수교육교원, 일반교육교원, 진로·직업교육 담당 교원, 관련서비스 담당 인력이 필수 구성원입니다. 학교장이 팀을 구성하며, 필요 시 외부 전문가를 초빙할 수 있습니다.',NULL,2,'KICE 기출 기반','{"disability": "자폐성장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('cur-q56','curriculum','iep','ox','개별화전환교육계획(ITP)은 「장애인 등에 대한 특수교육법」에 따라 특수교육대상자가 고등학교 과정에 진입한 시점부터 수립하며, 중학교 과정에서는 수립 의무가 없다.',NULL,NULL,'X','「장애인 등에 대한 특수교육법」 제23조에 따르면, 중학교 과정 이상의 각급 학교의 장은 개별화전환교육계획을 수립하여야 합니다. 즉, 중학교 과정부터 ITP 수립 의무가 있으며, 이는 졸업 후 진로(진학, 취업, 자립생활 등)를 조기에 계획하고 준비하기 위한 것입니다.',NULL,2,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('cur-q57','curriculum','iep','descriptive','개별화전환교육계획(ITP)의 필수 포함 내용을 제시하고, 지적장애 고등학생을 위한 ITP 수립 시 고려해야 할 영역별 핵심 내용을 서술하시오.','특수학교 고등부 2학년 지적장애 학생 D는 졸업 후 지역사회 카페에서 바리스타로 취업하기를 희망하고 있다. 부모는 학생의 자립생활 능력 향상과 직업 훈련을 중요하게 여기고 있다.',NULL,'[모범 답안]

1. ITP 필수 포함 내용 (장애인 등에 대한 특수교육법 시행규칙)
① 학생의 인적사항 및 장애 특성
② 학생의 흥미, 선호, 강점 및 진로 희망
③ 전환교육 관련 학생의 현재 수행 수준
④ 전환교육 목표 (진학, 취업, 자립생활 등)
⑤ 전환교육 내용 및 방법
⑥ 전환교육 지원 체계 (유관기관 연계 포함)
⑦ 추수지도 계획

2. 학생 D를 위한 영역별 핵심 내용

가. 직업 영역
- 바리스타 직무 분석에 기초한 직업 훈련 계획(주문 접수, 음료 제조, 위생 관리 등)
- 지역사회 카페 현장 실습 기회 확보
- 장애인 고용 관련 기관(한국장애인고용공단) 연계
- 직업적 사회기술(동료·고객과의 상호작용) 훈련

나. 자립생활 영역
- 출퇴근을 위한 대중교통 이용 훈련
- 금전 관리(임금 관리, 용돈 사용) 기술
- 일상생활 기술(식사 준비, 개인 위생 관리) 강화

다. 지역사회 참여 영역
- 여가 활동 탐색 및 참여 기회 확대
- 지역사회 자원 활용 능력(복지관, 평생교육기관 등)

라. 추수지도 계획
- 졸업 후 6개월~1년간 직업 적응 지원
- 직업재활시설, 장애인복지관 등과의 연계 체계 구축','ITP는 장애인 등에 대한 특수교육법 제23조에 근거하며, 학생의 졸업 후 삶의 질을 위해 직업, 자립생활, 지역사회 참여 등을 종합적으로 계획하는 문서입니다. 학생의 흥미와 선호를 존중하되, 현실적인 직업 환경 분석과 지원 체계 구축이 핵심이며, 유관기관과의 협력적 전환 지원이 강조됩니다.',NULL,3,'KICE 기출 기반','{"disability": "지적장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('hi-q21','hearing-impairment','audiogram','multiple','순음청력검사에서 기도-골도 차이(Air-Bone Gap)가 15dB 이상 나타날 때 의심할 수 있는 청력손실 유형은?',NULL,ARRAY['감각신경성 난청','전음성 난청','중추성 난청','기능성 난청'],'2','기도-골도 차이(Air-Bone Gap)는 기도 청력역치와 골도 청력역치의 차이를 의미한다. 이 차이가 15dB 이상이면 외이 또는 중이의 문제로 인한 전음성 난청을 의심할 수 있다. 감각신경성 난청의 경우 기도와 골도 청력역치가 비슷하게 저하되므로 기도-골도 차이가 거의 나타나지 않는다. 전음성 난청은 의학적 치료나 수술로 개선 가능성이 높다는 특징이 있다.','{"1": "감각신경성 난청은 기도와 골도 역치가 모두 저하되어 기도-골도 차이가 거의 없다.", "3": "중추성 난청은 뇌의 청각 처리 경로 문제로, 순음청력검사 결과만으로는 진단이 어렵다.", "4": "기능성 난청은 기질적 원인이 없는 경우로, 청력도상 일관성 없는 결과가 나타난다."}',1,'KICE 기출 기반','{"disability": "청각장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('hi-q22','hearing-impairment','audiogram','ox','청력도에서 250Hz와 500Hz 영역의 청력손실이 심하고 고주파수로 갈수록 청력이 양호한 형태를 ''상승형(rising) 청력도''라 한다.',NULL,NULL,'O','상승형 청력도는 저주파수 영역에서 청력손실이 크고 고주파수로 갈수록 청력이 좋아지는 형태를 말한다. 이는 주로 메니에르병 초기나 이경화증 등에서 나타날 수 있다. 반대로 고주파수에서 청력손실이 심한 형태는 하강형(sloping) 청력도라 하며, 노인성 난청이나 소음성 난청에서 흔히 관찰된다. 청력도 유형 파악은 보청기 적합이나 교육적 배치 결정에 중요한 정보를 제공한다.',NULL,2,'교재 참고','{"disability": "청각장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('hi-q23','hearing-impairment','audiogram','fill_in','순음청력검사에서 어음 주파수 대역이라 불리는, 말소리 인식에 가장 중요한 주파수 범위는 (   )Hz ~ (   )Hz이다.',NULL,NULL,'500Hz ~ 2000Hz','어음 주파수 대역(speech frequency range)은 일반적으로 500Hz에서 2000Hz 사이를 말하며, 이 범위는 말소리의 핵심 정보가 집중되어 있다. 3분법에서는 500Hz, 1000Hz, 2000Hz의 청력역치 평균을 구하여 청력손실 정도를 산출한다. 이 대역의 청력손실은 말소리 변별력에 직접적 영향을 미치므로 교육적 중재 계획 수립 시 가장 먼저 확인해야 한다. 6분법에서는 500Hz, 1000Hz(×2), 2000Hz(×2), 4000Hz를 사용하기도 한다.',NULL,1,'KICE 기출 기반','{"disability": "청각장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('hi-q24','hearing-impairment','audiogram','descriptive','혼합성 난청(mixed hearing loss)의 청력도 특징을 기도-골도 역치와 관련지어 설명하고, 교육적 중재 시 고려할 점을 서술하시오.',NULL,NULL,'혼합성 난청은 전음성 난청과 감각신경성 난청이 동시에 존재하는 경우로, 청력도에서 골도 역치와 기도 역치가 모두 정상 범위 이하로 저하되어 있으면서 기도-골도 차이(Air-Bone Gap)도 존재한다. 즉, 골도 역치가 정상보다 낮아 내이의 감각신경성 손상을 나타내고, 기도 역치는 골도 역치보다 더 낮아 외이 또는 중이의 전음성 문제가 추가로 있음을 보여준다. 교육적 중재 시에는 의학적 치료를 통해 전음성 요소를 먼저 개선하고, 잔여 감각신경성 손실에 대해서는 보청기 또는 인공와우 적합, 청능훈련, 그리고 교실 내 FM 시스템 활용 등 복합적인 접근이 필요하다.','혼합성 난청은 전음성과 감각신경성 난청이 복합적으로 나타나는 유형이다. 청력도에서 골도 역치가 정상 이하로 저하되어 있고, 기도 역치는 골도보다 더 저하되어 기도-골도 차이가 발생한다. 전음성 요소는 의학적 치료로 개선 가능하지만, 감각신경성 요소는 보청기나 인공와우 등의 보조기기와 청능재활이 필요하다. 교육 현장에서는 두 가지 요소를 모두 고려한 다중적 접근이 요구된다.',NULL,3,'교재 참고','{"disability": "청각장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('hi-q25','hearing-impairment','cochlear-implant','multiple','인공와우 이식 후 어음처리기의 전극별 자극 수준을 조정하는 과정을 무엇이라 하는가?',NULL,ARRAY['피팅(fitting)','매핑(mapping)','모니터링(monitoring)','캘리브레이션(calibration)'],'2','매핑(mapping)은 인공와우 이식 후 어음처리기의 각 전극에 대한 자극 수준(T-level, C-level)을 설정하는 과정이다. T-level은 소리를 처음 감지하는 최소 자극 수준이고, C-level은 편안하게 들을 수 있는 최대 자극 수준이다. 매핑은 이식 후 초기에 자주 실시하며, 이후에도 정기적으로 재조정이 필요하다. 아동의 경우 행동반응 관찰이나 전기적 청성뇌간반응(EABR) 등을 활용하여 매핑을 진행한다.','{"1": "피팅은 보청기를 개인의 청력에 맞게 조정하는 과정에 주로 사용되는 용어이다.", "3": "모니터링은 이식 후 청각 발달 상태를 지속적으로 관찰·추적하는 과정이다.", "4": "캘리브레이션은 검사 장비의 정확도를 기준에 맞춰 보정하는 절차이다."}',1,'KICE 기출 기반','{"disability": "청각장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('hi-q26','hearing-impairment','cochlear-implant','ox','인공와우는 외이와 중이를 거치지 않고 직접 청신경을 전기적으로 자극하여 소리를 전달하므로, 전음성 난청보다는 감각신경성 난청에 적용된다.',NULL,NULL,'O','인공와우는 손상된 와우(달팽이관)의 유모세포를 우회하여 전극을 통해 청신경을 직접 전기적으로 자극하는 장치이다. 따라서 와우의 유모세포가 손상된 감각신경성 난청 환자에게 적용된다. 전음성 난청은 외이나 중이의 문제로 발생하며, 의학적 치료나 보청기로 충분히 개선 가능한 경우가 많아 인공와우 이식 대상이 아니다. 일반적으로 양측 고도 이상의 감각신경성 난청으로 보청기 효과가 제한적일 때 인공와우를 고려한다.',NULL,1,'교재 참고','{"disability": "청각장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('hi-q27','hearing-impairment','cochlear-implant','fill_in','인공와우 매핑 시, 소리를 처음 감지하는 최소 자극 수준을 (   ), 편안하게 들을 수 있는 최대 자극 수준을 (   )이라 한다.',NULL,NULL,'T-level(역치 수준), C-level(쾌적 수준)','T-level(Threshold level)은 전극 자극 시 소리를 처음 감지하는 최소 수준으로, 역치 수준이라고도 한다. C-level(Comfort level)은 불편함 없이 편안하게 들을 수 있는 최대 자극 수준으로, 쾌적 수준이라 한다. 이 두 수준 사이의 범위를 역동 범위(dynamic range)라 하며, 이 범위가 넓을수록 다양한 크기의 소리를 잘 변별할 수 있다. 정확한 매핑은 인공와우 사용자의 말소리 지각 능력에 직접적인 영향을 미친다.',NULL,2,'KICE 기출 기반','{"disability": "청각장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('hi-q28','hearing-impairment','cochlear-implant','descriptive','인공와우 이식 아동의 청각재활 프로그램에서 청각적 위계(auditory hierarchy)의 4단계를 순서대로 제시하고, 각 단계의 특징과 지도 방법을 서술하시오.',NULL,NULL,'청각적 위계의 4단계는 탐지(detection), 변별(discrimination), 확인(identification), 이해(comprehension)이다. 첫째, 탐지 단계에서는 소리의 유무를 인식하는 것으로, 다양한 환경음과 말소리에 대해 소리가 있는지 없는지를 판단하는 활동을 한다. 둘째, 변별 단계에서는 두 가지 이상의 소리가 같은지 다른지를 판단하는 것으로, 초분절적 요소(길이, 강도, 높낮이)의 차이를 구분하는 연습을 한다. 셋째, 확인 단계에서는 제한된 선택지 중에서 들은 소리를 정확하게 가려내는 것으로, 그림 카드나 사물 중 들은 단어에 해당하는 것을 고르는 활동을 실시한다. 넷째, 이해 단계에서는 개방형 상황에서 말소리의 의미를 파악하는 것으로, 질문에 대답하기, 지시 따르기, 대화 참여하기 등의 활동을 통해 청각적 이해력을 발달시킨다.','청각적 위계는 청각재활의 기본 틀로서 탐지, 변별, 확인, 이해의 4단계로 구성된다. 각 단계는 하위 단계의 능력을 기반으로 하므로 순차적으로 지도해야 한다. 인공와우 이식 아동은 이식 후 즉시 말소리를 이해하는 것이 아니라 이 위계를 따라 점진적으로 청각 능력을 발달시킨다. 교사는 아동의 현재 수준을 정확히 파악하고 적절한 단계에서 체계적인 청능훈련을 제공해야 한다.',NULL,3,'KICE 기출 기반','{"disability": "청각장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('hi-q29','hearing-impairment','hearing-aid','multiple','보청기의 종류 중 귀걸이형(BTE)의 장점으로 적절하지 않은 것은?',NULL,ARRAY['다양한 청력손실 정도에 적용 가능하다','외부에서 보이지 않아 심미적으로 우수하다','어린 아동의 성장에 따라 귀꽂이만 교체하면 된다','출력이 커서 고도 난청에도 사용할 수 있다'],'2','귀걸이형(BTE) 보청기는 귀 뒤에 착용하는 형태로 외부에서 비교적 잘 보이는 편이다. 따라서 심미적으로 우수하다는 설명은 적절하지 않다. BTE 보청기의 실제 장점은 다양한 청력손실 정도에 적용 가능하고, 출력이 커서 고도·심도 난청에도 사용할 수 있으며, 아동의 경우 귀가 성장해도 귀꽂이(이어몰드)만 교체하면 되므로 경제적이라는 점이다. 심미성이 우수한 보청기는 고막형(CIC)이나 외이도형(ITC) 등 귀 안에 삽입하는 형태이다.','{"1": "BTE 보청기는 경도부터 심도 난청까지 폭넓게 적용 가능한 것이 맞다.", "3": "아동의 외이도가 성장하면 귀꽂이만 다시 제작하면 되므로 이 설명은 BTE의 실제 장점이다.", "4": "BTE는 기기 크기가 커서 충분한 출력을 제공할 수 있어 고도 난청에 적합하다."}',2,'교재 참고','{"disability": "청각장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('hi-q30','hearing-impairment','hearing-aid','ox','보청기의 음향 피드백(acoustic feedback)은 증폭된 소리가 보청기 마이크로 다시 유입되어 ''삐~'' 하는 고주파음이 발생하는 현상이다.',NULL,NULL,'O','음향 피드백은 보청기 리시버에서 출력된 증폭음이 귀꽂이와 외이도 사이의 틈 등을 통해 다시 마이크로 유입되면서 재증폭되어 발생하는 고주파 발진음이다. 이는 귀꽂이의 밀착도가 낮거나, 이득이 과도하게 설정되었을 때 잘 발생한다. 해결 방법으로는 귀꽂이 재제작, 통기구 크기 조절, 이득 감소, 피드백 제거 기능 활용 등이 있다. 음향 피드백은 보청기 착용 아동의 수업 참여를 방해할 수 있으므로 신속한 해결이 필요하다.',NULL,1,'KICE 기출 기반','{"disability": "청각장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('hi-q31','hearing-impairment','hearing-aid','fill_in','보청기 적합 과정에서 실이측정(Real Ear Measurement)을 통해 확인하는 것은 외이도 내에서의 실제 (   )이다.',NULL,NULL,'음압(또는 이득)','실이측정(REM)은 프로브 마이크로폰을 외이도에 삽입하여 보청기 착용 시 외이도 내에서 실제로 도달하는 음압(Sound Pressure Level)을 측정하는 방법이다. 이를 통해 처방된 이득 목표치와 실제 이득을 비교하여 보청기 적합의 정확성을 확인할 수 있다. 2cc 커플러 측정만으로는 개인의 외이도 크기, 잔여 용적 등의 차이를 반영하지 못하므로 실이측정이 보다 정확한 적합 검증 방법으로 권장된다.',NULL,2,'교재 참고','{"disability": "청각장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('hi-q32','hearing-impairment','hearing-aid','descriptive','보청기 적합(fitting) 과정의 주요 단계를 순서대로 나열하고, 각 단계에서 교사가 확인해야 할 사항을 서술하시오.',NULL,NULL,'보청기 적합 과정은 크게 청력평가, 보청기 선정, 이어몰드 제작, 초기 적합, 검증 및 확인, 사후 관리의 단계로 진행된다. 첫째, 청력평가 단계에서는 순음·어음청력검사를 실시하여 청력손실의 유형과 정도를 정확히 파악한다. 둘째, 보청기 선정 단계에서는 청력손실 정도, 아동의 연령, 활동 수준 등을 고려하여 적절한 형태와 기능의 보청기를 선택한다. 셋째, 이어몰드 제작 단계에서는 외이도 인상을 채취하여 개인 맞춤형 귀꽂이를 제작하며, 밀착도와 편안함을 확인한다. 넷째, 초기 적합에서는 처방공식(예: DSL, NAL-NL2)에 따라 이득과 출력을 설정한다. 다섯째, 검증 단계에서는 실이측정과 기능이득검사를 통해 목표 이득 달성 여부를 확인하고, 어음인지검사로 말소리 지각 향상을 평가한다. 교사는 아동의 보청기 착용 상태, 피드백 발생 여부, 배터리 관리, 그리고 교실 환경에서의 의사소통 개선 여부를 지속적으로 모니터링해야 한다.','보청기 적합은 단순히 기기를 제공하는 것이 아니라 체계적인 과정을 거쳐야 한다. 청력평가부터 사후 관리까지 각 단계가 유기적으로 연결되며, 특히 아동의 경우 성장에 따른 주기적 재적합이 필수적이다. 교사는 보청기의 기본 관리 방법과 고장 징후를 알고 있어야 하며, 교실에서 아동의 듣기 행동을 관찰하여 문제를 조기에 발견해야 한다.',NULL,3,'KICE 기출 기반','{"disability": "청각장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('hi-q33','hearing-impairment','sign-language','multiple','한국수어의 문법적 특징으로 옳은 것은?',NULL,ARRAY['한국어와 동일한 어순(SOV)을 따른다','비수지 신호(표정, 고개 움직임 등)는 문법적 기능이 없다','공간 활용을 통해 주어와 목적어의 관계를 나타낼 수 있다','수지한국어와 동일한 문법 체계를 사용한다'],'3','한국수어는 수화 공간(signing space)을 활용하여 지시 대상의 위치를 설정하고, 동사의 방향성을 통해 주어와 목적어의 관계를 표현할 수 있다. 이를 공간 참조(spatial referencing)라 한다. 한국수어는 한국어와 독립된 고유한 문법 체계를 가지며, 어순이 한국어와 반드시 일치하지 않는다. 비수지 신호는 의문문, 부정문, 조건문 등을 표시하는 중요한 문법적 기능을 수행한다. 수지한국어는 한국어 어순에 수어 어휘를 대응시킨 것으로 한국수어와 다르다.','{"1": "한국수어는 한국어와 독립된 문법 체계를 가지며, 반드시 SOV 어순을 따르지 않는다.", "2": "비수지 신호는 의문문 표지, 부정, 강조 등 핵심적인 문법적 기능을 담당한다.", "4": "수지한국어는 한국어 문법에 수어 어휘를 대입한 것으로, 한국수어와 문법 체계가 다르다."}',2,'KICE 기출 기반','{"disability": "청각장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('hi-q34','hearing-impairment','sign-language','ox','수지한국어(Signed Korean)는 한국수어와 동일한 언어로, 한국어의 문법 체계를 따르면서도 한국수어의 고유한 문법 규칙을 유지한다.',NULL,NULL,'X','수지한국어와 한국수어는 서로 다른 의사소통 체계이다. 수지한국어는 한국어의 어순과 문법 구조를 따르면서 수어 어휘를 대응시킨 인위적 체계로, 조사나 어미를 지문자로 표현하기도 한다. 반면 한국수어는 독립된 자연언어로서 고유한 문법 규칙(공간 활용, 비수지 신호의 문법적 기능, 동시적 구조 등)을 가진다. 수지한국어는 한국수어의 고유 문법을 유지하지 않으며, 두 체계를 혼동해서는 안 된다.',NULL,2,'교재 참고','{"disability": "청각장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('hi-q35','hearing-impairment','sign-language','fill_in','한국수어에서 손의 모양, 위치, 움직임과 함께 얼굴 표정이나 고개 움직임 등 손이 아닌 요소로 문법 기능을 하는 것을 (   ) 신호라 한다.',NULL,NULL,'비수지(非手指)','비수지 신호(non-manual signal)는 얼굴 표정, 눈썹 움직임, 고개 끄덕임/흔들림, 입 모양, 시선 방향, 몸의 기울기 등 손 이외의 신체 부위를 사용하여 전달하는 언어적 정보이다. 한국수어에서 비수지 신호는 의문문 표시(눈썹 올리기/내리기), 부정 표현(고개 흔들기), 강조, 조건절 표시 등 핵심적인 문법적 기능을 수행한다. 수지 신호만으로는 완전한 수어 문장을 구성할 수 없으며, 비수지 신호는 수어의 필수 구성 요소이다.',NULL,1,'KICE 기출 기반','{"disability": "청각장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('hi-q36','hearing-impairment','sign-language','descriptive','한국수어와 수지한국어의 차이를 문법 구조, 사용 목적, 교육적 적용의 측면에서 비교하여 서술하시오.',NULL,NULL,'한국수어는 농인 공동체에서 자연적으로 발달한 독립된 언어로, 고유한 문법 구조를 가진다. 공간 활용, 동시적 표현, 비수지 신호의 문법적 기능, 분류사 활용 등이 특징이며, 한국어 어순과 일치하지 않는다. 반면 수지한국어는 한국어의 어순과 문법을 따르면서 수어 어휘를 대응시킨 인위적 체계로, 조사와 어미를 지문자로 추가 표현하기도 한다. 사용 목적 면에서 한국수어는 농인 간 자연스러운 의사소통 수단이며, 수지한국어는 청인 교사와 농학생 간 교육 장면에서 한국어 습득을 지원하기 위해 활용되어 왔다. 교육적 적용에서 한국수어는 이중언어-이중문화(Bi-Bi) 접근법의 핵심으로서 농학생의 제1언어로 인정되며, 수지한국어는 한국어 문법 학습을 보조하는 도구로 활용될 수 있으나 한국수어를 대체할 수는 없다.','한국수어와 수지한국어는 언어적 지위, 문법 체계, 사용 맥락이 근본적으로 다르다. 한국수어법(2016) 제정 이후 한국수어는 공식 언어로 인정받았으며, 농학생 교육에서 한국수어를 통한 교수가 강조되고 있다. 교사는 두 체계의 차이를 명확히 이해하고, 교육 목표와 학생 특성에 맞는 의사소통 방법을 선택해야 한다.',NULL,3,'교재 참고','{"disability": "청각장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('hi-q37','hearing-impairment','classroom','multiple','FM 보청 시스템의 작동 원리로 옳은 것은?',NULL,ARRAY['교사의 음성을 적외선으로 변환하여 학생에게 전달한다','교사의 음성을 FM 주파수로 송신하여 학생의 수신기에 직접 전달한다','교실 전체의 소리를 균일하게 증폭하는 음장 확대 장치이다','학생의 보청기 이득을 원격으로 조절하는 시스템이다'],'2','FM 보청 시스템은 교사가 착용한 송신기(transmitter)의 마이크로 입력된 음성을 FM 무선 주파수로 변환하여, 학생이 착용한 수신기(receiver)로 직접 전달하는 시스템이다. 이를 통해 교사와 학생 사이의 거리, 교실 소음, 잔향 등의 부정적 영향을 극복하고 양호한 신호대잡음비(SNR)를 확보할 수 있다. FM 시스템은 개인용 보청기나 인공와우에 연결하여 사용하거나, 음장(sound field) 시스템으로 교실 전체에 음성을 전달할 수도 있다.','{"1": "적외선 시스템은 FM 시스템과 다른 방식으로, 직선 경로가 필요하다는 단점이 있다.", "3": "음장 확대 장치는 FM 시스템의 한 활용 형태이지만, FM 시스템의 핵심 원리는 개인 송수신이다.", "4": "FM 시스템은 보청기 이득을 조절하는 것이 아니라, 교사 음성을 직접 전달하는 보조 장치이다."}',1,'KICE 기출 기반','{"disability": "청각장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('hi-q38','hearing-impairment','classroom','ox','청각장애 학생의 교실 좌석은 교사의 얼굴과 입 모양을 잘 볼 수 있도록 교실 뒤쪽에 배치하는 것이 바람직하다.',NULL,NULL,'X','청각장애 학생은 독화(speechreading)를 위해 교사의 얼굴과 입 모양을 명확하게 볼 수 있어야 하므로, 교실 뒤쪽이 아니라 앞쪽에 좌석을 배치해야 한다. 일반적으로 교사로부터 1.5~2m 이내, 교사의 정면 또는 잔청이 좋은 귀 쪽으로 배치하는 것이 권장된다. 또한 창문에서 들어오는 빛이 교사의 얼굴에 역광이 되지 않도록 학생의 좌석을 조정해야 한다. U자형 또는 반원형 좌석 배치도 청각장애 학생에게 유리하다.',NULL,1,'교재 참고','{"disability": "청각장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('hi-q39','hearing-impairment','classroom','fill_in','교실 환경에서 청각장애 학생의 듣기를 방해하는 두 가지 주요 음향 요인은 배경 (   )과 (   )이다.',NULL,NULL,'소음, 잔향(반향)','교실의 음향 환경에서 청각장애 학생의 듣기에 부정적 영향을 미치는 두 가지 핵심 요인은 배경 소음(background noise)과 잔향(reverberation)이다. 배경 소음은 신호대잡음비(SNR)를 낮추어 말소리 인지를 어렵게 하며, 잔향은 소리가 벽, 천장, 바닥 등에 반사되어 말소리가 겹치는 현상으로 명료도를 저하시킨다. 이상적인 교실은 배경 소음 35dBA 이하, 잔향 시간 0.4~0.6초 이하가 권장된다.',NULL,2,'KICE 기출 기반','{"disability": "청각장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('hi-q40','hearing-impairment','classroom','descriptive','통합교육 환경에서 청각장애 학생의 학습 접근성을 높이기 위한 교실 환경 수정 방안을 물리적 환경, 교수 전략, 보조공학 활용의 세 측면에서 서술하시오.',NULL,NULL,'물리적 환경 측면에서는 교실 소음을 줄이기 위해 카펫 설치, 의자 다리 펠트 부착, 방음 커튼 설치 등을 하고, 잔향을 줄이기 위해 흡음재를 벽면이나 천장에 부착한다. 좌석은 교사의 얼굴이 잘 보이는 앞쪽에 배치하며, 역광을 피하도록 조명을 조정한다. 교수 전략 측면에서는 교사가 학생을 정면으로 향한 상태에서 명확하게 발화하고, 판서 중 말하기를 피한다. 핵심 어휘를 미리 제시하고, 시각적 자료(PPT, 그림, 판서)를 적극 활용하며, 또래 노트테이커를 지정할 수 있다. 보조공학 활용 측면에서는 FM 보청 시스템이나 로저(Roger) 시스템을 사용하여 교사 음성의 신호대잡음비를 높이고, 실시간 문자통역(CART) 서비스나 음성인식 자막 앱을 활용하여 청각 정보를 시각적으로 보완한다. 이러한 다각적 접근을 통해 청각장애 학생의 교육 참여를 보장해야 한다.','통합교육에서 청각장애 학생의 학습권 보장을 위해서는 물리적 환경 개선, 교사의 교수법 수정, 보조공학 활용이 복합적으로 이루어져야 한다. 한 가지 방법만으로는 충분하지 않으며, 학생의 청력 수준, 의사소통 방법, 학습 요구에 맞는 맞춤형 지원이 필요하다. 교사는 정기적으로 학생의 참여도와 이해도를 점검하여 지원 방법을 조정해야 한다.',NULL,3,'교재 참고','{"disability": "청각장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('hi-q1','hearing-impairment','audiogram','fill_in','순음청력검사에서 기도청력역치와 골도청력역치의 차이를 ( )(이)라 하며, 이 값이 10dB 이상일 경우 전음성 난청을 의심할 수 있다.',NULL,NULL,'기도-골도 차이(air-bone gap)','기도검사는 외이→중이→내이를 거치는 전체 청각 경로를, 골도검사는 중이를 우회하여 내이 기능만을 평가한다. 따라서 기도-골도 차이(air-bone gap)가 10dB 이상이면 중이에 문제가 있는 전음성 난청을 시사한다.',NULL,1,'KICE 기출 기반','{"disability": "청각장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('hi-q2','hearing-impairment','audiogram','fill_in','청력손실 정도 분류에서 순음청력역치 평균이 71~90dB HL인 경우 ( ) 난청으로 분류한다.',NULL,NULL,'고도(severe)','청력손실 정도 분류: 경도 26~40dB, 중등도 41~55dB, 중고도 56~70dB, 고도 71~90dB, 최고도 91dB 이상이다. 고도 난청 학생은 보청기를 착용해도 말소리 지각에 상당한 어려움이 있어 시각적 의사소통 수단의 보완이 필요하다.',NULL,1,'KICE 기출 기반','{"disability": "청각장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('hi-q3','hearing-impairment','audiogram','multiple','다음 중 감각신경성 난청의 청력도 특성으로 옳은 것은?',NULL,ARRAY['기도역치는 정상이나 골도역치만 저하되어 있다.','기도역치와 골도역치가 모두 저하되어 있으며, 기도-골도 차이가 거의 없다.','기도역치만 저하되어 있고 골도역치는 정상 범위이다.','저주파 영역에서만 역치가 저하되고 고주파는 정상이다.'],'기도역치와 골도역치가 모두 저하되어 있으며, 기도-골도 차이가 거의 없다.','감각신경성 난청은 내이(와우) 또는 청신경의 손상으로 발생하므로, 기도와 골도 모두 역치가 저하되며 기도-골도 차이가 10dB 미만으로 거의 나타나지 않는다. 선택지 ③은 전음성 난청의 특성이고, 선택지 ①은 검사상 나타날 수 없는 패턴이다.','{"기도역치는 정상이나 골도역치만 저하되어 있다.": "골도역치가 기도역치보다 나쁠 수 없다. 골도는 중이를 우회하므로 기도역치보다 항상 같거나 더 좋다.", "기도역치만 저하되어 있고 골도역치는 정상 범위이다.": "이는 전음성 난청의 전형적 패턴이다. 감각신경성 난청에서는 골도역치도 함께 저하된다.", "저주파 영역에서만 역치가 저하되고 고주파는 정상이다.": "감각신경성 난청은 오히려 고주파 영역에서 역치 저하가 심한 경우가 많으며, 전 주파수에 걸쳐 나타날 수 있다."}',2,'KICE 기출 기반','{"disability": "청각장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('hi-q4','hearing-impairment','audiogram','descriptive','다음 사례를 읽고 물음에 답하시오.','초등학교 3학년 민수의 순음청력검사 결과, 우측 귀의 기도청력역치는 500Hz 55dB, 1000Hz 60dB, 2000Hz 65dB이고, 골도청력역치는 500Hz 50dB, 1000Hz 55dB, 2000Hz 60dB이다. 좌측 귀의 기도청력역치는 500Hz 30dB, 1000Hz 35dB, 2000Hz 40dB이고, 골도청력역치는 500Hz 15dB, 1000Hz 15dB, 2000Hz 20dB이다.',NULL,'(1) 우측 귀: 3분법 평균 청력역치 = (55+60+65)/3 = 60dB → 중고도 난청. 기도-골도 차이가 5dB로 감각신경성 난청이다.
(2) 좌측 귀: 3분법 평균 청력역치 = (30+35+40)/3 = 35dB → 경도 난청. 기도-골도 차이가 15~20dB로 전음성 요소가 포함된 혼합성 난청이다.
(3) 양 귀의 난청 유형이 다르므로, 좌측 귀의 전음성 요소에 대해 이비인후과적 치료 가능성을 탐색하고, 우측 귀에는 보청기 적합을 우선 고려해야 한다.','3분법(500Hz, 1000Hz, 2000Hz 평균)은 어음 주파수대 청력을 대표하는 지표이다. 기도-골도 차이가 10dB 이상이면 전음성 요소가 있음을 의미하며, 좌측 귀는 혼합성 난청으로 판단한다. 양이 비대칭 난청인 경우 각 귀에 대한 개별적 중재 계획이 필요하다.',NULL,3,'KICE 기출 기반','{"disability": "청각장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('hi-q5','hearing-impairment','audiogram','ox','순음청력검사에서 주파수(Hz)는 청력도의 세로축에, 청력역치(dB HL)는 가로축에 표시한다.',NULL,NULL,'X','청력도(audiogram)에서 가로축은 주파수(Hz)를, 세로축은 청력역치(dB HL)를 나타낸다. 세로축은 위쪽이 0dB(좋은 청력)이고 아래로 갈수록 숫자가 커져 청력손실이 심함을 의미한다. 가로축은 왼쪽에서 오른쪽으로 갈수록 저주파에서 고주파로 이동한다.',NULL,1,'KICE 기출 기반','{"disability": "청각장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('hi-q6','hearing-impairment','cochlear-implant','fill_in','인공와우 수술 후 외부장치의 전극별 자극량을 청각적 반응에 맞추어 조절하는 과정을 ( )(이)라 한다.',NULL,NULL,'매핑(mapping)','매핑(mapping)은 인공와우 착용자가 편안하고 적절한 소리를 들을 수 있도록 각 전극의 최소 자극량(T-level)과 최대 안락 수준(C-level)을 설정하는 과정이다. 수술 후 초기에는 자주, 이후 점차 간격을 두고 실시하며, 특히 영유아의 경우 행동반응 관찰이 중요하다.',NULL,2,'KICE 기출 기반','{"disability": "청각장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('hi-q7','hearing-impairment','cochlear-implant','descriptive','다음 사례를 읽고 물음에 답하시오.','만 2세 영아 지은이는 양측 고도 감각신경성 난청(양이 평균 95dB HL)으로 진단받았다. 6개월간 보청기를 착용하였으나 어음변별력이 10% 미만이다. 부모는 인공와우 수술을 고려하고 있으며, 특수교사에게 인공와우에 대한 정보를 요청하였다.',NULL,'(1) 인공와우 적응증: 양측 고도 이상 난청, 보청기로 충분한 효과를 얻지 못하는 경우, 청각재활 의지가 있는 경우에 해당하며 지은이는 이 조건을 충족한다.
(2) 조기 수술의 이점: 청각 발달의 결정적 시기(3세 이전)에 수술하면 청각 피질의 가소성을 활용하여 듣기 및 구어 발달에 유리하다.
(3) 수술 후 재활: 매핑을 통한 기기 조절, 청각구어법(AVT) 등 체계적인 청능훈련이 필수적이며, 가정에서의 풍부한 언어 입력 환경 조성이 중요하다.
(4) 부모에게 안내할 사항: 인공와우는 정상 청력을 회복시키는 것이 아니며, 장기적인 재활과 기기 관리가 필요하다는 현실적 기대를 갖도록 안내한다.','인공와우는 와우 내 전극을 삽입하여 청신경을 직접 전기 자극하는 장치이다. 보청기와 달리 소리를 증폭하는 것이 아니라 전기 신호로 변환하여 전달한다. 영유아기 조기 이식은 청각-언어 발달의 결정적 시기를 활용할 수 있어 효과적이며, 수술 후 체계적인 청능재활이 성과를 좌우한다.',NULL,3,'KICE 기출 기반','{"disability": "청각장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('hi-q8','hearing-impairment','cochlear-implant','ox','인공와우는 소리를 증폭하여 잔존 유모세포를 자극하는 원리로 작동한다.',NULL,NULL,'X','인공와우는 소리를 증폭하는 것이 아니라, 음향 신호를 전기 신호로 변환하여 와우 내 삽입된 전극을 통해 청신경을 직접 자극하는 장치이다. 유모세포를 우회(bypass)하여 작동하므로 유모세포의 손상 여부와 관계없이 청신경이 기능하면 사용할 수 있다. 소리를 증폭하여 유모세포를 자극하는 것은 보청기의 원리이다.',NULL,2,'KICE 기출 기반','{"disability": "청각장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('hi-q9','hearing-impairment','hearing-aid','fill_in','보청기 이득(gain) 계산에서, 청력역치의 1/2에 해당하는 이득을 처방하는 방식을 ( ) 규칙이라 한다.',NULL,NULL,'1/2 이득 규칙(half-gain rule)','1/2 이득 규칙은 Lybarger가 제안한 보청기 이득 처방 공식으로, 각 주파수에서 청력역치의 절반에 해당하는 이득을 제공한다. 예를 들어 1000Hz에서 역치가 60dB이면 30dB의 이득을 처방한다. 간편하여 널리 사용되나, 개인의 쾌적 수준과 어음 명료도를 고려한 미세 조정이 필요하다.',NULL,2,'KICE 기출 기반','{"disability": "청각장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('hi-q10','hearing-impairment','hearing-aid','fill_in','보청기 유형 중 귀걸이형 보청기의 본체에서 리시버(수화기)를 분리하여 외이도 내에 직접 배치하는 방식을 ( ) 보청기라 한다.',NULL,NULL,'RIC(Receiver-In-Canal)','RIC(Receiver-In-Canal) 보청기는 귀걸이형(BTE)과 유사하지만, 리시버를 본체에서 분리하여 외이도 안에 배치한다. 이로써 본체가 소형화되고, 음향 피드백(하울링)이 감소하며, 자연스러운 음질을 제공할 수 있다. 현재 가장 많이 처방되는 보청기 유형 중 하나이다.',NULL,2,'KICE 기출 기반','{"disability": "청각장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('hi-q11','hearing-impairment','hearing-aid','multiple','보청기 관리에 대한 설명으로 옳지 않은 것은?',NULL,ARRAY['이어몰드는 미지근한 비눗물로 세척한 후 완전히 건조시킨다.','보청기 본체는 물로 세척하지 않고 부드러운 천으로 닦는다.','사용하지 않을 때는 배터리를 넣은 채 배터리 문을 닫아 보관한다.','습기 제거를 위해 건조기(드라이 키트)에 보관하는 것이 좋다.'],'사용하지 않을 때는 배터리를 넣은 채 배터리 문을 닫아 보관한다.','보청기를 사용하지 않을 때는 배터리 문을 열어두거나 배터리를 분리하여 보관해야 한다. 배터리 문을 닫아두면 전력이 소모되고 습기가 차서 내부 부품이 손상될 수 있다. 이어몰드는 보청기 본체에서 분리한 후 비눗물로 세척 가능하나, 보청기 본체 자체는 물에 접촉시키면 안 된다.','{"이어몰드는 미지근한 비눗물로 세척한 후 완전히 건조시킨다.": "이어몰드는 보청기 본체에서 분리하여 비눗물로 세척할 수 있다. 완전 건조 후 다시 연결한다.", "보청기 본체는 물로 세척하지 않고 부드러운 천으로 닦는다.": "보청기 본체에는 전자 부품이 있어 물에 접촉하면 고장의 원인이 된다. 부드러운 천이나 전용 브러시로 관리한다.", "습기 제거를 위해 건조기(드라이 키트)에 보관하는 것이 좋다.": "보청기는 습기에 취약하므로 매일 밤 건조기에 넣어 습기를 제거하는 것이 권장된다."}',2,'KICE 기출 기반','{"disability": "청각장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('hi-q12','hearing-impairment','hearing-aid','descriptive','보청기의 주요 유형(BTE, RIC, ITE, ITC, CIC) 중 3가지를 선택하여 각각의 특징, 장점, 적합 대상을 비교·설명하시오.',NULL,NULL,'(1) BTE(귀걸이형): 본체가 귓바퀴 뒤에 위치하며 튜브를 통해 이어몰드와 연결된다. 출력이 크고 조작이 용이하여 경도~최고도 난청까지 폭넓게 적합하다. 소아는 귀 성장에 따라 이어몰드만 교체하면 되므로 경제적이다.
(2) RIC(외이도 내 리시버형): 리시버가 외이도 안에 위치하여 BTE보다 소형이고 음질이 자연스럽다. 경도~고도 난청에 적합하며 피드백이 적다.
(3) CIC(고막형): 외이도 깊숙이 삽입되어 외부에서 거의 보이지 않는다. 미용적 장점이 크나 출력이 제한적이어서 경도~중등도 난청에 적합하고, 소형이라 조작과 관리가 어려울 수 있다.','보청기 유형 선택 시 난청 정도, 외이도 크기, 조작 능력, 미용적 선호도, 연령 등을 종합적으로 고려해야 한다. 소아에게는 안전성과 성장 대응이 용이한 BTE가 주로 권장되며, 성인은 생활양식과 난청 정도에 따라 RIC, ITE, CIC 등을 선택한다.',NULL,2,'KICE 기출 기반','{"disability": "청각장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('hi-q13','hearing-impairment','sign-language','fill_in','한국수어의 음운에 해당하는 5가지 매개변수는 수형, 수위, 수동, ( ), 비수지 신호이다.',NULL,NULL,'수향(手向, palm orientation)','한국수어의 수어소(cheremes)는 수형(handshape), 수위(location), 수동(movement), 수향(palm orientation), 비수지 신호(non-manual signals)의 5가지 매개변수로 구성된다. 수향은 손바닥이 향하는 방향을 의미하며, 동일한 수형·수위·수동이라도 수향이 달라지면 다른 의미를 나타낼 수 있다.',NULL,1,'KICE 기출 기반','{"disability": "청각장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('hi-q14','hearing-impairment','sign-language','fill_in','청각장애인이 고유명사, 외래어 등 수어 어휘가 없는 단어를 표현할 때 자모 하나하나를 손 모양으로 나타내는 것을 ( )(이)라 한다.',NULL,NULL,'지문자(fingerspelling)','지문자는 한글 자모(ㄱ, ㄴ, ㄷ… / ㅏ, ㅓ, ㅗ…)를 각각 고유한 손 모양으로 표현하는 체계이다. 한국 지문자는 한 손으로 표현하며, 수어 어휘가 존재하지 않는 고유명사, 외래어, 전문 용어 등을 표기할 때 주로 사용한다.',NULL,3,'KICE 기출 기반','{"disability": "청각장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('hi-q15','hearing-impairment','sign-language','multiple','한국수어에 대한 설명으로 옳은 것은?',NULL,ARRAY['한국수어는 한국어의 어순을 그대로 따르는 수단적 체계이다.','한국수어법(2016)에 의해 한국수어는 한국어와 동등한 자격을 가진 농인의 공용어로 인정되었다.','한국수어는 음운에 해당하는 변별적 단위가 존재하지 않는 몸짓 언어이다.','한국수어의 문법은 영어 수어(ASL)와 동일한 구조를 가진다.'],'한국수어법(2016)에 의해 한국수어는 한국어와 동등한 자격을 가진 농인의 공용어로 인정되었다.','2016년 제정된 한국수어법은 한국수어를 대한민국 농인의 공용어로 인정하고, 한국어와 동등한 자격을 부여하였다. 한국수어는 한국어와 독립된 문법 체계(SOV 경향이 있으나 한국어와 다른 어순 규칙)를 가진 자연언어이며, 수형·수위·수동·수향·비수지 신호라는 변별적 단위(수어소)를 갖추고 있다.','{"한국수어는 한국어의 어순을 그대로 따르는 수단적 체계이다.": "한국어 어순을 따르는 것은 한국어 대응 수어(수지한국어)이다. 한국수어는 독자적 문법 구조를 가진 자연언어이다.", "한국수어는 음운에 해당하는 변별적 단위가 존재하지 않는 몸짓 언어이다.": "한국수어는 수형, 수위, 수동, 수향, 비수지 신호의 5가지 매개변수로 구성된 이중분절 체계를 갖춘 자연언어이다.", "한국수어의 문법은 영어 수어(ASL)와 동일한 구조를 가진다.": "각 나라의 수어는 독립적으로 발달한 자연언어로, 한국수어와 ASL은 서로 다른 문법 구조를 가진다."}',2,'KICE 기출 기반','{"disability": "청각장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('hi-q16','hearing-impairment','sign-language','descriptive','청각장애 학생의 의사소통 교육 접근법인 구화법, 수어법, 토탈커뮤니케이션(TC)을 각각 설명하고, 장단점을 비교하시오.',NULL,NULL,'(1) 구화법(oral method): 독화(입 읽기), 잔존청력 활용, 발화 훈련을 통해 음성언어로 의사소통하는 방법이다. 장점은 건청인과의 직접 소통이 가능하다는 것이나, 고도 이상 난청 학생에게는 습득이 어렵고 독화만으로는 정보 수용에 한계가 있다.
(2) 수어법(manual method): 수어와 지문자를 주된 의사소통 수단으로 사용한다. 시각 언어이므로 청력 수준과 관계없이 습득 가능하고, 농문화 정체성 형성에 기여한다. 그러나 건청인 사회와의 소통에 통역이 필요하고, 한국어 문해력과 직접 연결되지 않을 수 있다.
(3) 토탈커뮤니케이션(TC): 구어, 수어, 지문자, 독화, 필담, 몸짓 등 활용 가능한 모든 의사소통 수단을 사용하는 접근법이다. 학생의 개별 요구에 유연하게 대응할 수 있으나, 두 언어를 동시에 제시하면 각각의 완전한 모형 입력이 어려울 수 있다.','의사소통 접근법 선택은 학생의 청력 수준, 보장구 착용 효과, 인지 능력, 가정 환경, 농문화 정체성 등을 종합적으로 고려해야 한다. 최근에는 이중언어-이중문화(Bi-Bi) 접근이 주목받고 있으며, 수어를 제1언어로, 한국어(문어)를 제2언어로 교육하는 방법이다.',NULL,3,'KICE 기출 기반','{"disability": "청각장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('hi-q17','hearing-impairment','sign-language','descriptive','이중언어-이중문화(Bi-Bi) 접근법의 개념과 원리를 설명하고, 청각장애 학생 교육에서의 적용 방안을 2가지 서술하시오.',NULL,NULL,'(1) 개념: 이중언어-이중문화(Bilingual-Bicultural, Bi-Bi) 접근법은 수어를 청각장애 학생의 제1언어(L1)로, 해당 국가의 음성/문자 언어(한국어)를 제2언어(L2)로 교육하는 방법이다. 동시에 농문화와 건청 문화 모두에 대한 이해와 정체성을 형성하도록 한다.
(2) 적용 방안 ①: 수어를 교수 언어로 사용하여 교과 내용을 전달하고, 한국어 문해력은 읽기·쓰기를 통해 별도로 지도한다. L1의 언어 능력이 L2 학습의 기반이 된다는 상호의존가설(Cummins)에 근거한다.
(3) 적용 방안 ②: 농인 교사 또는 농인 보조인력을 배치하여 수어 모형(language model)을 제공하고, 건청 교사는 한국어 문해력 지도를 담당하는 협력 교수 체계를 구축한다.','Bi-Bi 접근은 농인을 언어적·문화적 소수자로 보는 관점에 기반하며, 수어를 결함 보상 수단이 아닌 완전한 자연언어로 인정한다. 한국수어법(2016) 제정 이후 이중언어 교육에 대한 법적 근거가 마련되었다.',NULL,3,'KICE 기출 기반','{"disability": "청각장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('hi-q18','hearing-impairment','classroom','fill_in','교실에서 청각장애 학생의 말소리 지각을 돕기 위해 교사의 음성을 무선으로 전달하여 ( )를 개선하는 보조공학 기기를 FM 보청시스템이라 한다.',NULL,NULL,'신호대잡음비(SNR, Signal-to-Noise Ratio)','FM 보청시스템은 교사가 송신기(마이크)를 착용하고 학생이 수신기를 보청기/인공와우에 연결하여 사용한다. 교사의 음성(신호)을 직접 전달함으로써 교실 소음(잡음)에 비해 신호를 크게 하여 신호대잡음비(SNR)를 약 15~20dB 개선한다. 이를 통해 거리와 소음으로 인한 말소리 왜곡 문제를 극복할 수 있다.',NULL,2,'KICE 기출 기반','{"disability": "청각장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('hi-q19','hearing-impairment','classroom','ox','청각장애 학생의 좌석은 교실 맨 뒷자리에 배치하여 전체 학급 학생의 입 모양을 볼 수 있도록 하는 것이 가장 효과적이다.',NULL,NULL,'X','청각장애 학생은 교사의 얼굴(입 모양, 표정)을 가까이에서 명확하게 볼 수 있도록 교실 앞쪽에 배치하는 것이 원칙이다. 말소리 강도는 거리의 제곱에 반비례하여 감소하므로(역자승 법칙), 뒷자리에서는 신호대잡음비가 크게 저하된다. 또한 교사와 급우의 발언을 모두 볼 수 있는 반원형(말굽형) 좌석 배치가 효과적이다.',NULL,2,'KICE 기출 기반','{"disability": "청각장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('hi-q20','hearing-impairment','classroom','descriptive','다음 사례를 읽고 물음에 답하시오.','통합학급 담임교사 김 교사는 중고도 난청(양이 평균 62dB HL)으로 보청기를 착용한 초등 4학년 수진이를 담당하고 있다. 교실은 30명 학생이 있으며, 복도 쪽 창문을 열어두면 소음이 유입된다. 김 교사는 수진이의 수업 참여도가 낮다는 것을 발견하였다.',NULL,'(1) 물리적 환경 조성: 복도 쪽 창문에 방음 조치를 하거나 수업 중 창문을 닫아 외부 소음을 차단한다. 교실 바닥에 카펫을 깔거나 의자 다리에 테니스공을 부착하여 실내 소음을 감소시킨다.
(2) 보조공학 활용: FM 보청시스템을 도입하여 교사 음성을 직접 전달함으로써 신호대잡음비를 개선한다. 사운드필드 시스템도 학급 전체에 도움이 된다.
(3) 좌석 배치: 수진이를 교사 가까이 앞쪽에 배치하되, 교사의 얼굴을 정면으로 볼 수 있는 위치에 둔다. 토론 시에는 반원형 배치로 전환한다.
(4) 교수 전략: 핵심 어휘를 칠판에 미리 판서하고, 시각 자료(PPT, 그림, 자막)를 적극 활용한다. 또래 노트테이커를 지정하여 수업 내용을 보완한다.','청각장애 학생의 통합교육에서는 음향 환경 개선, 보조공학 활용, 좌석 배치, 교수 방법 수정 등 다차원적 지원이 필요하다. 소음 관리는 가장 기본적이면서도 효과적인 지원이며, 교실 소음을 35dB(A) 이하로 유지하고 잔향 시간을 0.6초 이내로 관리하는 것이 권장된다.',NULL,3,'KICE 기출 기반','{"disability": "청각장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('inc-q37','inclusive-education','theory','fill_in','「장애인 등에 대한 특수교육법」 제2조 제6호에 따르면, ( )이란 특수교육대상자가 일반학교에서 장애 유형·장애 정도에 따라 차별을 받지 아니하고 ( )와 함께 개개인의 교육적 요구에 적합한 교육을 받는 것을 말한다.',NULL,NULL,'통합교육 / 또래','특수교육법 제2조 제6호의 통합교육 정의는 임용고시 기입형 단골 출제 지문입니다. ''일반학교'', ''차별을 받지 아니하고'', ''또래와 함께'', ''교육적 요구에 적합한 교육''이 핵심 키워드이며, 이 중 ''또래''와 ''통합교육''이 빈칸으로 자주 출제됩니다.',NULL,1,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('inc-q38','inclusive-education','theory','fill_in','최소제한환경(LRE)은 미국 ( ㉠ ) 법에서 처음 법적으로 명시되었으며, 장애학생의 배치는 일반학급에서 시설까지의 ( ㉡ )을 전제로 한다.',NULL,NULL,'P.L. 94-142(전장애아교육법) / 배치의 연속성(continuum of placements)','최소제한환경(LRE)은 1975년 미국 P.L. 94-142(전장애아교육법, 현 IDEA)에서 법제화되었습니다. LRE의 핵심은 가능한 한 비장애학생과 함께 교육받아야 한다는 것이며, 이를 위해 일반학급→특수학급(시간제/전일제)→특수학교→시설로 이어지는 배치의 연속성(continuum of alternative placements)을 보장해야 합니다.',NULL,2,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('inc-q39','inclusive-education','theory','multiple','다음 중 통합교육의 이론적 배경에 대한 설명으로 올바르지 않은 것은?',NULL,ARRAY['정상화 원리는 Bank-Mikkelsen(1959)이 덴마크에서 처음 제창하였다.','Wolfensberger(1972)는 정상화 원리를 북미에서 이론적으로 체계화하였다.','Will(1986)은 모든 장애학생의 완전통합(full inclusion)을 주장하였다.','Stainback & Stainback은 REI 이후 완전통합을 주장하였다.'],'2','Will(1986)은 일반교육이니셔티브(REI)를 제안하여 ''경도 장애학생''의 일반학급 통합을 주장하였지, 모든 장애학생의 완전통합을 주장한 것은 아닙니다. 완전통합(full inclusion)은 이후 Stainback & Stainback 등이 한 단계 더 나아가 주장한 것으로, 모든 장애학생이 일반학급에서 전일 교육받아야 한다는 입장입니다.','{"0": "정상화 원리는 Bank-Mikkelsen이 1959년 덴마크에서 처음 제창한 것이 맞습니다.", "1": "Wolfensberger가 1972년 정상화 원리를 북미에서 이론적으로 체계화한 것은 정확한 설명입니다.", "3": "Stainback & Stainback은 REI 이후 완전통합을 주장한 학자로 맞습니다."}',2,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('inc-q40','inclusive-education','theory','ox','완전통합(full inclusion)은 배치의 연속성(continuum of placements)을 전제로 하며, 장애의 정도에 따라 특수학급이나 특수학교 배치를 허용한다.',NULL,NULL,'X','완전통합(full inclusion)은 모든 장애학생이 장애 유형이나 정도와 관계없이 일반학급에서 전일 교육받아야 한다는 입장입니다. 따라서 배치의 연속성을 전제로 하지 않으며, 오히려 분리 배치를 반대합니다. 배치의 연속성은 최소제한환경(LRE) 원리의 전제 조건이며, 완전통합 반대론자들은 배치의 연속성 훼손을 우려합니다.',NULL,2,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('inc-q41','inclusive-education','theory','descriptive','통합교육의 이론적 배경인 정상화 원리, 최소제한환경(LRE), 일반교육이니셔티브(REI)의 개념을 각각 설명하고, 이 세 가지가 통합교육으로 이어지는 흐름을 서술하시오.','특수교육학개론 강의에서 교수가 ''통합교육의 이론적 발전 과정''이라는 주제로 발표 과제를 부여하였다.',NULL,'[모범 답안]

1. 정상화 원리 (Normalization Principle)
- Bank-Mikkelsen(1959)이 덴마크에서 처음 제창, Wolfensberger(1972)가 북미에서 체계화
- 핵심: 장애인도 비장애인과 가능한 한 동일한 생활방식과 환경을 경험할 권리가 있음
- 교육적 함의: 장애학생을 분리 시설이 아닌 지역사회·일반학교에서 교육해야 함

2. 최소제한환경 (LRE)
- 미국 P.L. 94-142(1975)에서 법적으로 명시
- 핵심: 장애학생이 비장애학생과 가능한 한 최대로 함께 교육받을 수 있는 환경 보장
- 배치의 연속성을 전제로 함(일반학급→특수학급→특수학교→시설)

3. 일반교육이니셔티브 (REI)
- Will(1986)이 미국 교육부 특수교육국장으로서 제안
- 핵심: 경도 장애학생을 일반학급에 통합하고, 일반교사와 특수교사가 협력하여 지도

4. 통합교육으로의 흐름
정상화 원리(1950~60년대)가 장애인의 지역사회 참여 철학을 제공 → LRE(1970년대)가 교육 배치에서의 통합을 법적으로 보장 → REI(1980년대)가 일반교육과 특수교육의 협력적 통합을 구체화 → 이후 Stainback & Stainback 등이 완전통합(full inclusion)으로 발전시킴','통합교육의 이론적 배경은 정상화→LRE→REI→완전통합의 역사적 흐름으로 발전하였습니다. 임용고시에서는 이 세 가지 개념의 제창자, 핵심 내용, 발전 순서를 연결하여 서술하는 문제가 자주 출제됩니다. 특히 REI와 완전통합의 차이점(경도 장애 vs. 모든 장애)을 명확히 구분해야 합니다.',NULL,3,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('inc-q42','inclusive-education','theory','fill_in','특수교육실무사는 교사의 ( ㉠ ) 하에 활동하며, 수업 중 장애학생의 ( ㉡ ) 지원, 교수-학습 활동 보조, 등하교 지원 등을 수행한다. 특수교육실무사가 독자적으로 수업을 진행하거나 ( ㉢ )을 수립하는 것은 허용되지 않는다.',NULL,NULL,'지시·감독 / 신변처리(신변 자립) / 교육계획(IEP)','특수교육실무사(보조인력)는 특수교사나 일반교사의 지시·감독 하에 활동하는 보조 인력입니다. 주요 역할은 장애학생의 신변처리 지원, 교수-학습 활동 보조, 등하교 지원 등이며, 독자적인 수업 진행이나 교육계획(IEP) 수립은 교사의 고유 역할이므로 허용되지 않습니다. 보조인력의 역할 범위와 한계는 임용고시에서 자주 출제됩니다.',NULL,2,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('inc-q43','inclusive-education','theory','ox','장애인식개선 프로그램에서 모의 장애 체험(눈가리기, 휠체어 타기 등)은 장애에 대한 올바른 이해를 촉진하는 가장 효과적인 방법이므로 단독으로 실시해도 충분하다.',NULL,NULL,'X','모의 장애 체험만 단독으로 실시하면 오히려 장애에 대한 부정적 인식(동정, 두려움)을 강화할 수 있다는 연구 결과가 있습니다. 효과적인 장애인식개선 프로그램은 ①정보적 접근(장애에 대한 정확한 정보 제공), ②직접 접촉(장애인과의 긍정적 상호작용), ③사회적 학습(장애인 성공 모델 제시), ④시뮬레이션(모의 체험) 등을 통합적으로 구성해야 합니다.',NULL,2,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('inc-q44','inclusive-education','co-teaching','fill_in','Friend & Cook이 체계화한 협력교수의 정의에 따르면, 협력교수란 두 명 이상의 전문가가 다양한 교육적 요구를 가진 학생들이 포함된 하나의 ( ㉠ )에서 실질적으로 함께 교수 활동을 수행하는 것이며, 이는 단순 보조가 아닌 ( ㉡ )·공동 교수·공동 평가를 전제로 한다.',NULL,NULL,'물리적 공간(동일 교실) / 공동 계획(co-planning)','Friend & Cook(2007)의 협력교수 정의에서 핵심 요소는 ①두 명 이상의 전문가, ②하나의 물리적 공간(동일 교실), ③다양한 교육적 요구를 가진 학생 포함, ④실질적인 공동 교수 활동입니다. 특히 공동 계획(co-planning)이 전제되어야 하며, 최소 주 1회 이상의 공동 계획 시간 확보가 권장됩니다.',NULL,2,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('inc-q45','inclusive-education','co-teaching','fill_in','협력교수 유형 중 ( ㉠ )은/는 한 교사가 대집단을 지도하고 다른 교사가 소집단을 별도로 집중 지도하는 유형으로, 소집단 구성원이 고정될 경우 ( ㉡ ) 효과가 발생할 수 있다. 이를 방지하기 위해 소집단 구성원을 ( ㉢ )하고, 비장애학생도 소집단에 포함해야 한다.',NULL,NULL,'대안교수(alternative teaching) / 낙인(stigma) / 순환(교체)','대안교수는 소집단에 대한 집중 지도가 가능하다는 장점이 있지만, 소집단이 항상 장애학생으로만 구성되면 낙인 효과가 발생합니다. 이를 방지하려면 ①소집단 구성원을 순환시키고, ②비장애학생도 소집단에 포함하며, ③사전학습·심화학습 등 다양한 목적으로 소집단을 활용해야 합니다. 대안교수의 낙인 효과 방지 전략은 서술형 단골 출제 포인트입니다.',NULL,2,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('inc-q46','inclusive-education','co-teaching','multiple','다음 통합학급 상황에 가장 적합한 협력교수 유형은?

[상황] 학기 초, 특수교사가 통합학급에 배치된 ADHD 학생의 수업 참여도와 주의집중 패턴을 파악하기 위해 체계적인 자료 수집이 필요하다.',NULL,ARRAY['스테이션교수 - 여러 스테이션에서 학생을 순환시켜 관찰한다.','교수-관찰 - 일반교사가 수업하고 특수교사가 체계적으로 관찰·기록한다.','팀티칭 - 두 교사가 동등하게 수업하면서 동시에 관찰한다.','교수-지원 - 특수교사가 순회하며 ADHD 학생 옆에서 직접 지원한다.'],'1','학기 초 학생의 행동 패턴을 체계적으로 파악해야 하는 상황에서는 교수-관찰(One Teach, One Observe)이 가장 적합합니다. 이 유형에서 한 교사(일반교사)가 수업을 진행하고, 다른 교사(특수교사)가 사전에 합의된 관찰 기준에 따라 학생의 행동, 수업 참여도, 상호작용 등을 체계적으로 관찰·기록합니다. FBA(기능적 행동평가) 등의 자료 수집에도 활용됩니다.','{"0": "스테이션교수는 학습 내용을 스테이션별로 나누어 소그룹 지도하는 유형으로, 체계적 관찰·자료 수집이 주 목적인 상황에는 적합하지 않습니다.", "2": "팀티칭은 두 교사가 수업을 함께 진행하는 데 집중하므로, 한 교사가 관찰에 전념해야 하는 상황에는 적합하지 않습니다.", "3": "교수-지원은 개별 학생에게 직접적 도움을 제공하는 유형으로, 체계적인 행동 관찰·기록이 주 목적인 상황에는 교수-관찰이 더 적합합니다."}',2,'KICE 기출 기반','{"disability": "ADHD"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('inc-q47','inclusive-education','co-teaching','descriptive','Gately & Gately(2001)의 협력교수 발전 3단계를 제시하고, 각 단계의 특징과 교사 간 의사소통 수준을 설명하시오.','올해 처음 협력교수를 시작하게 된 일반교사 A와 특수교사 B가 있다. 두 교사는 서로의 교수 스타일을 아직 잘 모르며, 역할 분담에 대한 논의가 표면적인 수준에 머물러 있다.',NULL,'[모범 답안]

Gately & Gately(2001)의 협력교수 발전 3단계:

1단계. 시작 단계(Beginning Stage)
- 두 교사가 서로의 교수 스타일, 교육 철학, 학생 관리 방식을 탐색함
- 의사소통이 표면적이고 조심스러운 수준에 머무름
- 역할 경계가 명확하지 않고, 교수 활동에서 어색함이 존재함
- 사례의 A교사와 B교사가 현재 이 단계에 해당함

2단계. 타협 단계(Compromising Stage)
- 두 교사가 서로의 스타일에 점진적으로 적응해 나감
- 개방적 의사소통이 증가하고, 교수 활동에 대한 솔직한 피드백이 이루어짐
- 역할 분담이 구체화되고, 수업 운영에 대한 합의가 형성됨
- 갈등이 발생하더라도 조율하려는 노력이 나타남

3단계. 협력 단계(Collaborative Stage)
- 높은 수준의 상호 신뢰를 바탕으로 자연스러운 역할 교대가 이루어짐
- 의사소통이 개방적이고 솔직하며, 비언어적 신호까지 읽을 수 있음
- 학생의 필요에 따라 유연하게 협력교수 유형을 전환함
- 두 교사가 동등한 전문가로서 상호 보완적 관계를 형성함','Gately & Gately(2001)의 협력교수 발전 3단계는 시작→타협→협력 단계로 진행됩니다. 핵심은 교사 간 의사소통의 깊이와 신뢰 수준이 점진적으로 향상된다는 것입니다. 임용고시에서는 각 단계의 명칭과 특징, 특히 의사소통 수준의 변화를 묻는 문제가 출제됩니다.',NULL,3,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('inc-q48','inclusive-education','co-teaching','ox','협력교수에서 ''동등한 전문성(parity)'' 원칙이란 일반교사와 특수교사가 동일한 교과 내용 지식을 갖추어야 한다는 의미이다.',NULL,NULL,'X','동등한 전문성(parity)은 두 교사가 동일한 지식을 갖추어야 한다는 의미가 아니라, 각자의 전문성(일반교사의 교과 전문성 vs. 특수교사의 특수교육 전문성)을 대등한 위치에서 발휘해야 한다는 원칙입니다. 특수교사가 보조교사 역할에 머무르지 않고, 교수 활동에서 동등한 파트너로서 역할을 수행하는 것이 핵심입니다.',NULL,1,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('inc-q49','inclusive-education','co-teaching','descriptive','다음 사례를 읽고, 적합한 협력교수 유형 2가지를 선택하여 각 유형에서의 일반교사와 특수교사의 역할, 선택 이유를 서술하시오.','초등학교 3학년 통합학급에 학습장애 학생 2명과 지적장애 학생 1명이 포함되어 있다. 수학 ''분수'' 단원을 학습하는데, 학습장애 학생들은 분수 개념에 대한 선수학습이 부족하고, 지적장애 학생은 기초 연산 수준에 머물러 있다. 일반교사와 특수교사는 올해 처음 협력교수를 시작하였으며, 아직 충분한 신뢰 관계가 형성되지 않은 상태이다.',NULL,'[모범 답안]

1. 대안교수(Alternative Teaching)
- 일반교사 역할: 대집단(비장애학생)을 대상으로 분수 개념 본 수업 진행
- 특수교사 역할: 학습장애 2명+지적장애 1명의 소집단을 분리하여 분수의 선수학습(등분할 개념, 부분-전체 관계)을 보충 지도
- 선택 이유: 특수교육대상학생에게 선수학습 보충이 필요하므로, 소집단 집중 지도가 가능한 대안교수가 적합함. 협력 초기 단계에서도 비교적 실행이 용이함
- 유의점: 소집단이 항상 같은 학생으로 구성되지 않도록 비장애학생도 포함하여 낙인 효과 방지

2. 스테이션교수(Station Teaching)
- 일반교사 역할: 분수 개념 설명 스테이션 운영 (구체물을 활용한 분수 이해)
- 특수교사 역할: 분수 기초 연습 스테이션 운영 (분수막대, 분수 타일을 활용한 수준별 연습)
- 독립학습 스테이션: 분수 카드게임 등 자율 학습 활동
- 선택 이유: 소그룹으로 운영하여 학생-교사 비율을 낮추고, 특수교육대상학생이 자연스럽게 모든 스테이션을 순환하므로 낙인 효과가 적음','본 사례에서는 ①선수학습 보충 필요, ②수준차가 큰 학생 구성, ③협력 초기 단계라는 세 가지 조건을 고려해야 합니다. 대안교수는 선수학습 보충에, 스테이션교수는 수준별 소그룹 지도에 적합합니다. 팀티칭은 높은 신뢰가 필요하므로 협력 초기 단계에서는 권장되지 않습니다.',NULL,3,'KICE 기출 기반','{"disability": "학습장애, 지적장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('inc-q50','inclusive-education','co-teaching','fill_in','또래교수 프로그램 중 학급전체또래교수(CWPT)는 ( ㉠ ) 등이 개발하였고, 또래중재학습전략(PALS)은 ( ㉡ ) 등이 개발하였다. CWPT의 특징적인 요소는 학급을 두 팀으로 나누어 실시하는 ( ㉢ )이다.',NULL,NULL,'Greenwood / Fuchs / 팀 경쟁(team competition)','CWPT(Classwide Peer Tutoring)는 Greenwood 등이 개발한 학급전체 또래교수 프로그램으로, 학급을 두 팀으로 나누고 교수자-학습자 역할을 교대하면서 팀 경쟁 요소를 포함합니다. PALS(Peer-Assisted Learning Strategies)는 Fuchs 부부가 개발하였으며, 상위-하위 수준의 학생을 짝지어 구조화된 읽기/수학 활동을 수행합니다.',NULL,2,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('inc-q51','inclusive-education','co-teaching','ox','또래지원(peer support) 프로그램에서 또래지원 학생은 장애학생의 학습을 직접 교수하는 역할보다는 사회적 상호작용 촉진, 수업 참여 지원, 일상적 도움 제공 등의 역할을 수행한다.',NULL,NULL,'O','또래지원(peer support)은 또래교수(peer tutoring)와 구별됩니다. 또래지원은 비장애 또래가 장애학생의 사회적 참여, 교실 내 활동 참여, 일상적 상호작용을 지원하는 것이 주 목적입니다. 반면, 또래교수는 학습 내용을 직접 가르치는 데 초점을 둡니다. 또래지원은 장애학생의 사회적 통합과 소속감 형성에 특히 효과적입니다.',NULL,1,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('inc-q52','inclusive-education','udl','fill_in','UDL의 3원리는 뇌의 세 가지 학습 네트워크에 대응한다. 다양한 표상수단 제공은 ( ㉠ ) 네트워크(학습의 ''무엇''), 다양한 행동과 표현수단 제공은 ( ㉡ ) 네트워크(학습의 ''어떻게''), 다양한 참여수단 제공은 ( ㉢ ) 네트워크(학습의 ''왜'')에 각각 대응한다.',NULL,NULL,'인식(recognition) / 전략(strategic) / 정서(affective)','UDL(CAST)은 신경과학에 기반하여 뇌의 세 가지 학습 네트워크에 대응하는 3원리를 제시합니다. 인식 네트워크(What)=정보 수집·분류 → 표상수단, 전략 네트워크(How)=계획·수행 → 행동·표현수단, 정서 네트워크(Why)=동기·참여 → 참여수단입니다. 각 원리와 네트워크의 대응 관계는 기입형 단골 출제 포인트입니다.',NULL,2,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('inc-q53','inclusive-education','udl','multiple','다음 중 UDL의 ''다양한 행동과 표현수단 제공'' 원리에 해당하는 적용 사례는?',NULL,ARRAY['동일한 텍스트를 인쇄물, 오디오북, 확대 텍스트 등 다양한 형태로 제공한다.','학습 과제의 주제를 학생이 직접 선택할 수 있도록 선택권을 부여한다.','독후감을 글쓰기, 그림, 녹음, 구술 발표 등 다양한 방식으로 제출할 수 있게 한다.','수업 시작 전 사전 조직자(advance organizer)를 활용하여 핵심 개념을 안내한다.'],'2','다양한 행동과 표현수단 제공(Multiple Means of Action and Expression)은 학습자가 자신이 아는 것을 다양한 방식으로 표현할 수 있게 하는 원리입니다. 독후감을 글쓰기, 그림, 녹음, 구술 발표 등으로 표현하게 하는 것이 이에 해당합니다.','{"0": "다양한 형태의 자료 제공은 ''다양한 표상수단 제공'' 원리에 해당합니다.", "1": "과제 주제 선택권 부여는 ''다양한 참여수단 제공'' 원리(흥미 유발, 자율성 보장)에 해당합니다.", "3": "사전 조직자 활용은 ''다양한 표상수단 제공'' 원리(이해를 위한 선택지)에 해당합니다."}',2,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('inc-q54','inclusive-education','udl','descriptive','UDL과 교수적 수정의 차이점을 설계 시점, 대상, 접근 방식 측면에서 비교하고, 통합학급에서 두 접근이 보완적으로 활용되어야 하는 이유를 서술하시오.','초등학교 통합학급 교사 김 모씨는 수업을 설계할 때 UDL을 적용하려 하지만, 중도 지적장애 학생에게는 UDL만으로 충분한 지원이 되지 않아 추가적인 개별 조정이 필요하다고 느끼고 있다.',NULL,'[모범 답안]

1. UDL과 교수적 수정의 비교

(1) 설계 시점
- UDL: 교육과정 설계 단계에서 사전적으로 적용 (건물 설계 시 처음부터 경사로 설치)
- 교수적 수정: 교육과정 실행 단계에서 사후적으로 조정 (건물 완공 후 경사로 추가 설치)

(2) 대상
- UDL: 모든 학습자를 위한 보편적 접근
- 교수적 수정: 특정 장애학생을 위한 개별적 조정

(3) 접근 방식
- UDL: 처음부터 다양한 선택지를 교육과정에 내장
- 교수적 수정: 기존의 고정된 교육과정을 개별 학생의 요구에 맞게 수정(교수환경·교수내용·교수방법·평가방법의 4요소)

2. 보완적 활용의 필요성
- UDL은 대부분의 학습자에게 접근 가능한 수업을 설계하지만, 중도 장애학생에게는 UDL의 선택지만으로 충분하지 않을 수 있음
- 교수적 수정은 UDL이 제공하는 선택지로 충족되지 않는 개별적 요구에 대응
- UDL이 사전적·보편적 1차 지원이라면, 교수적 수정은 개별적·맞춤형 2차 지원으로 기능
- 두 접근의 보완적 활용으로 통합학급 내 모든 학생의 교육과정 접근성을 최대화할 수 있음','UDL과 교수적 수정의 비교는 임용고시 서술형 빈출 주제입니다. 핵심은 사전적(UDL) vs. 사후적(교수적 수정), 보편적 vs. 개별적이라는 차이점과, 두 접근이 상호 배타적이 아닌 보완적 관계라는 점을 명확히 서술하는 것입니다.',NULL,3,'KICE 기출 기반','{"disability": "지적장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('inc-q55','inclusive-education','udl','fill_in','교수적 수정의 4가지 유형은 ( ㉠ ) 수정, ( ㉡ ) 수정, ( ㉢ ) 수정, ( ㉣ ) 수정이다. 이 중 시험 시간 연장, 대체 평가 등은 ( ㉣ ) 수정에 해당한다.',NULL,NULL,'교수환경 / 교수내용 / 교수방법 / 평가방법','교수적 수정(instructional modification)의 4가지 유형은 교수환경(물리적 환경, 좌석 배치 등), 교수내용(학습량·난이도 조절 등), 교수방법(교수 전략, 교재·교구 변경 등), 평가방법(시험 시간 연장, 대체 평가, 평가 기준 조정 등)입니다. 이 4가지 유형은 통합학급에서 모두 적용 가능하며, 기입형에서 빈칸으로 자주 출제됩니다.',NULL,1,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('inc-q56','inclusive-education','udl','descriptive','다음 통합학급 수업 상황에서 UDL 3원리를 각각 적용하는 구체적 방안을 제시하시오.','초등학교 4학년 통합학급에서 사회과 ''우리 지역의 문화유산'' 단원을 학습한다. 학급에는 시각장애 학생 1명(저시력), 학습장애 학생 1명(읽기 이해 곤란), ADHD 학생 1명이 통합되어 있다.',NULL,'[모범 답안]

1. 다양한 표상수단 제공 (인식 네트워크 - What)
- 문화유산 관련 텍스트를 확대 인쇄물, 오디오 자료, 디지털 텍스트(음성 지원 가능) 등으로 제공 → 저시력 학생의 시각적 접근성 확보
- 핵심 용어(문화유산, 보존, 전통 등)에 대한 용어 사전과 시각적 개념도 제공 → 학습장애 학생의 어휘 이해 지원
- 문화유산 사진·영상·실물 모형 등 다감각 자료 활용 → 모든 학생의 이해 촉진

2. 다양한 행동과 표현수단 제공 (전략 네트워크 - How)
- 조사 보고서를 글쓰기, 그림, 사진 콜라주, 구술 발표, 영상 제작 등 다양한 방식으로 제출 가능
- 과제 수행 단계를 체크리스트로 제공 → ADHD 학생의 실행 기능 지원
- 디지털 도구(음성 입력, 확대 편집기 등) 활용 허용 → 저시력 학생의 표현 접근성 확보

3. 다양한 참여수단 제공 (정서 네트워크 - Why)
- 우리 지역의 문화유산 중 관심 있는 주제를 학생이 직접 선택할 수 있도록 자율성 부여
- 현장 체험학습이나 지역 문화유산 탐방 활동으로 일상생활과 연계 → 동기 유발
- 모둠별 협동학습을 통한 역할 분담과 또래 상호작용 촉진 → ADHD 학생의 참여 지속
- 단계별 즉각적 피드백과 자기평가 기회 제공 → 노력과 끈기 유지','UDL 3원리의 구체적 적용 방안을 서술할 때는 ①각 원리의 명칭과 대응 뇌 네트워크를 명시하고, ②사례에 제시된 학생들의 특성(시각장애, 학습장애, ADHD)을 고려한 구체적 방법을 제시하며, ③특정 학생만이 아닌 모든 학생에게 혜택이 되는 보편적 접근임을 보여주어야 합니다.',NULL,3,'KICE 기출 기반','{"disability": "시각장애, 학습장애, ADHD"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('intro-q31','introduction','understanding','fill_in','「장애인 등에 대한 특수교육법」 제2조에서 정의하는 통합교육이란, 특수교육대상자가 일반학교에서 장애 유형·장애 정도에 따라 차별을 받지 아니하고 ( )과/와 함께 개개인의 교육적 요구에 적합한 교육을 받는 것을 말한다.',NULL,NULL,'또래','「장애인 등에 대한 특수교육법」 제2조 제6호에 따르면, 통합교육이란 특수교육대상자가 일반학교에서 장애 유형·장애 정도에 따라 차별을 받지 아니하고 또래와 함께 개개인의 교육적 요구에 적합한 교육을 받는 것을 의미한다.',NULL,1,'장애인 등에 대한 특수교육법 제2조','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('intro-q32','introduction','understanding','multiple','개별화교육계획(IEP)의 법적 구성요소로 「장애인 등에 대한 특수교육법」 시행규칙에 명시되지 않은 것은?',NULL,ARRAY['특수교육대상자의 인적사항과 현재 학습 수행 수준','장·단기 교육목표와 교육의 시작일 및 종료일','특수교육 관련서비스의 내용과 방법','특수교육대상자의 지능지수 및 적응행동 검사 원점수'],'3','IEP의 법적 구성요소에는 인적사항, 현재 학습 수행 수준, 장·단기 교육목표, 교육 시작·종료일, 특수교육 관련서비스의 내용과 방법, 교육목표 달성 평가방법 등이 포함된다. 지능지수나 적응행동 검사의 원점수는 IEP 구성요소에 해당하지 않으며, 이는 선정·배치 과정에서 활용되는 정보이다.','{"0": "인적사항과 현재 학습 수행 수준은 IEP의 핵심 구성요소로 시행규칙에 명시되어 있다.", "1": "장·단기 교육목표와 교육 기간은 IEP의 필수 구성요소이다.", "2": "특수교육 관련서비스의 내용과 방법은 IEP에 반드시 포함되어야 하는 법적 구성요소이다."}',2,'장애인 등에 대한 특수교육법 시행규칙 제4조','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('intro-q33','introduction','understanding','ox','「장애인 등에 대한 특수교육법」에 따르면, 특수교육대상자의 선정은 보호자 또는 각급학교의 장이 진단·평가를 교육장 또는 교육감에게 의뢰하고, 특수교육지원센터에서 진단·평가를 실시한 후 교육장 또는 교육감이 특수교육대상자 선정 여부 및 학교 지정·배치를 결정한다.',NULL,NULL,'O','「장애인 등에 대한 특수교육법」 제15~17조에 따르면, 보호자 또는 각급학교의 장이 교육장 또는 교육감에게 진단·평가를 의뢰하면, 특수교육지원센터가 진단·평가를 실시하고, 그 결과를 바탕으로 교육장 또는 교육감이 특수교육대상자 선정 여부 및 학교 지정·배치를 결정한다.',NULL,1,'장애인 등에 대한 특수교육법 제15~17조','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('intro-q34','introduction','understanding','descriptive','정상화 원리(Normalization Principle)의 개념과 특수교육에의 시사점을 설명하시오.','Wolfensberger(1972)는 정상화 원리를 재개념화하여 ''사회적 역할 가치화(Social Role Valorization)''라는 개념을 제시하였다. 그는 장애인에 대한 사회적 인식 변화가 통합의 전제 조건임을 강조하였다.',NULL,'1. 정상화 원리의 개념: Bank-Mikkelsen(1969)이 처음 제안하고, Nirje(1969)가 체계화한 원리로, 장애인의 일상생활 조건과 양식을 사회의 주류 규범과 가능한 한 가깝게 만드는 것을 의미한다.
2. Wolfensberger의 재개념화: 정상화 원리를 ''사회적 역할 가치화(SRV)''로 발전시켜, 사회적으로 가치 있는 역할을 부여함으로써 장애인의 사회적 이미지를 향상시키는 것을 강조하였다.
3. 특수교육에의 시사점:
  (1) 분리교육에서 통합교육으로의 전환 근거 제공
  (2) 장애인도 비장애인과 동일한 생활 리듬, 일과, 환경을 경험할 권리가 있음을 강조
  (3) 탈시설화와 지역사회 중심 서비스의 이론적 기반
  (4) 장애 학생에게 사회적으로 가치 있는 역할을 부여하는 교육과정 운영의 필요성','정상화 원리는 통합교육의 이론적 토대가 된 핵심 개념으로, 장애인의 생활 조건을 비장애인의 그것과 가능한 한 유사하게 만들 것을 주장한다. 이는 탈시설화, 최소제한환경(LRE), 통합교육의 철학적 기반이 되었다.',NULL,3,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('intro-q35','introduction','understanding','fill_in','「장애인 등에 대한 특수교육법」에서 규정하는 특수교육대상자의 장애 유형 10가지는 시각장애, 청각장애, 지적장애, 지체장애, 정서·행동장애, 자폐성장애, 의사소통장애, 학습장애, 건강장애, ( )이다.',NULL,NULL,'발달지체','「장애인 등에 대한 특수교육법」 제15조에 따른 특수교육대상자의 장애 유형은 시각장애, 청각장애, 지적장애, 지체장애, 정서·행동장애, 자폐성장애, 의사소통장애, 학습장애, 건강장애, 발달지체의 10가지이다. 발달지체는 만 9세 미만의 아동에게 적용된다.',NULL,1,'장애인 등에 대한 특수교육법 제15조','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('intro-q36','introduction','understanding','fill_in','IDEA(Individuals with Disabilities Education Act)에서 규정하는 13가지 장애 범주 중, 한국의 「장애인 등에 대한 특수교육법」에는 별도 범주로 포함되지 않는 것은 ( ), 중복장애(Multiple Disabilities), 외상성 뇌손상(Traumatic Brain Injury)이다.',NULL,NULL,'농-맹(Deaf-Blindness)','IDEA의 13가지 장애 범주는 학습장애, 지적장애, 정서장애, 언어장애, 자폐, 청각장애, 시각장애, 농-맹, 지체장애, 기타 건강장애, 중복장애, 외상성 뇌손상, 발달지체이다. 이 중 농-맹, 중복장애, 외상성 뇌손상은 한국 특수교육법에 별도 범주로 규정되어 있지 않다.',NULL,2,'IDEA 2004','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('intro-q37','introduction','understanding','ox','개별화교육계획(IEP)은 매 학기 시작일로부터 30일 이내에 작성하여야 하며, 매 학기마다 개별화교육지원팀에서 평가하여야 한다.',NULL,NULL,'X','「장애인 등에 대한 특수교육법」 제22조 제2항에 따르면, 개별화교육계획은 매 학기 시작일로부터 30일 이내가 아니라 14일 이내에 각각의 특수교육대상자에 대한 개별화교육계획을 작성하여야 한다.',NULL,2,'장애인 등에 대한 특수교육법 제22조','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('intro-q38','introduction','disability-types','fill_in','미국지적및발달장애학회(AAIDD)의 12차 정의(2021)에 따르면, 지적장애는 지적 기능과 ( ) 모두에서 유의미한 제한이 있으며, 이러한 제한은 22세 이전의 발달기에 나타나는 것을 특징으로 한다.',NULL,NULL,'적응행동','AAIDD 12차 정의(Schalock et al., 2021)에서 지적장애는 지적 기능(intellectual functioning)과 적응행동(adaptive behavior) 모두에서 유의미한 제한이 있으며, 이는 22세 이전 발달기에 나타나는 것으로 정의된다. 적응행동은 개념적, 사회적, 실제적 적응기술로 구성된다.',NULL,1,'AAIDD 12th Edition (2021)','{"disability": "intellectual"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('intro-q39','introduction','disability-types','multiple','DSM-5에서 자폐스펙트럼장애(ASD)의 진단기준에 대한 설명으로 옳은 것은?',NULL,ARRAY['사회적 의사소통 및 사회적 상호작용, 제한적·반복적 행동의 두 가지 핵심 영역에서 결함을 보여야 한다.','DSM-IV와 동일하게 사회적 상호작용, 의사소통, 제한적·반복적 행동의 세 가지 영역으로 구분된다.','감각 자극에 대한 과잉 또는 과소 반응성은 진단기준에 포함되지 않는다.','증상은 반드시 만 3세 이전에 나타나야 진단이 가능하다.'],'0','DSM-5에서 자폐스펙트럼장애는 기존 DSM-IV의 세 영역(사회적 상호작용, 의사소통, 제한적·반복적 행동)에서 두 영역(사회적 의사소통 및 사회적 상호작용의 결함, 제한적·반복적 행동·관심·활동)으로 재구조화되었다. 감각 반응 이상은 제한적·반복적 행동 영역의 하위 기준에 새롭게 포함되었으며, 증상은 ''초기 발달기''에 나타나야 하지만 만 3세라는 구체적 연령 제한은 삭제되었다.','{"1": "DSM-5에서는 세 영역이 아닌 두 영역으로 재구조화되었다. 사회적 상호작용과 의사소통이 하나의 영역으로 통합되었다.", "2": "감각 자극에 대한 과잉·과소 반응성은 DSM-5에서 제한적·반복적 행동 영역의 하위 기준으로 새롭게 추가되었다.", "3": "DSM-5에서는 ''만 3세 이전''이라는 구체적 연령 제한 대신 ''초기 발달기(early developmental period)''라는 표현을 사용한다."}',2,'DSM-5 (APA, 2013)','{"disability": "autism"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('intro-q40','introduction','disability-types','fill_in','학습장애의 판별 모델 중 ( ) 모델은 학생의 지능과 학업 성취 간의 유의미한 차이를 기준으로 학습장애를 판별하며, ( ) 모델은 과학적 근거에 기반한 중재를 제공한 후에도 반응하지 않는 학생을 학습장애로 판별한다.',NULL,NULL,'능력-성취 불일치(IQ-Achievement Discrepancy) / 중재반응(RTI)','능력-성취 불일치 모델은 지능검사 점수와 학업 성취도 간의 유의미한 차이(보통 1~2 표준편차)를 학습장애 판별 기준으로 사용한다. 중재반응(RTI) 모델은 다층적 중재(보통 3단계)를 체계적으로 제공하고, 중재에 적절히 반응하지 않는 학생을 학습장애로 판별한다. IDEA 2004에서는 RTI를 학습장애 판별의 대안적 방법으로 허용하였다.',NULL,2,'KICE 기출 기반','{"disability": "learning"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('intro-q41','introduction','disability-types','descriptive','IDEA와 한국 「장애인 등에 대한 특수교육법」에서의 정서·행동장애 정의를 비교하여 설명하시오.','미국에서는 1975년 전장애아교육법(PL 94-142) 이래로 ''심한 정서장애(Seriously Emotionally Disturbed)''라는 용어를 사용하다가 IDEA 1997에서 ''Emotional Disturbance''로 변경하였다. 한국에서는 2007년 「장애인 등에 대한 특수교육법」에서 ''정서·행동장애''라는 용어를 사용하기 시작하였다.',NULL,'1. IDEA의 정서장애(Emotional Disturbance) 정의:
  (1) 장기간에 걸쳐, 현저한 정도로 교육적 수행에 불리한 영향을 미치는 다음 특성 중 하나 이상을 보이는 상태
  (2) 5가지 특성: ① 지적·감각적·건강 요인으로 설명할 수 없는 학습 무능력, ② 또래·교사와 만족스러운 대인관계를 형성·유지하지 못함, ③ 정상적 상황에서 부적절한 행동이나 감정, ④ 전반적인 불행감이나 우울, ⑤ 개인적·학교 문제에 관련된 신체적 증상이나 공포
  (3) 조현병(schizophrenia) 포함, 사회적 부적응(socially maladjusted)만 해당하는 아동은 제외
2. 한국법의 정서·행동장애 정의:
  (1) 지적·감각적·건강상의 이유로 설명할 수 없는 학습상의 어려움
  (2) 또래나 교사와의 대인관계에 어려움
  (3) 일반적인 상황에서 부적절한 행동이나 감정
  (4) 전반적인 불행감이나 우울증
  (5) 학교나 개인 문제에 관련된 신체적인 통증이나 공포
3. 주요 비교:
  (1) 한국법은 IDEA의 정의를 상당 부분 수용하되, ''사회적 부적응 제외'' 조항이 명시적으로 없음
  (2) 용어 차이: 미국 ''Emotional Disturbance'' vs 한국 ''정서·행동장애''로, 한국이 행동 측면을 더 명시적으로 포함
  (3) 두 정의 모두 장기간, 현저한 정도, 교육적 수행에의 부정적 영향을 공통 요건으로 함','정서·행동장애의 정의는 미국 IDEA의 영향을 크게 받았으나, 한국법에서는 ''사회적 부적응 제외'' 조항이 명시되지 않은 것이 주요 차이점이다. 이 조항의 부재는 정서·행동장애 판별 시 논쟁의 여지를 남긴다.',NULL,3,'KICE 기출 기반','{"disability": "emotional-behavioral"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('intro-q42','introduction','disability-types','ox','AAIDD 12차 정의(2021)에서 지적장애의 적응행동은 개념적 기술, 사회적 기술, 실제적 기술의 세 가지 유형으로 구분되며, 세 유형 모두에서 유의미한 제한이 있어야 지적장애로 진단된다.',NULL,NULL,'X','AAIDD 12차 정의에서 적응행동은 개념적, 사회적, 실제적 기술의 세 유형으로 구분되지만, 세 유형 모두에서 제한을 보일 필요는 없다. 적응행동 전체(overall adaptive behavior)에서 유의미한 제한이 있으면 되며, 이는 세 유형 중 하나 또는 전체 적응행동 표준화 점수에서 평균보다 약 2 표준편차 이하인 경우에 해당한다.',NULL,2,'AAIDD 12th Edition (2021)','{"disability": "intellectual"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('intro-q43','introduction','disability-types','fill_in','학습장애의 중재반응(RTI) 모델은 일반적으로 3단계로 구성된다. 1단계는 ( )에서의 보편적 중재, 2단계는 소집단 보충 중재, 3단계는 집중적 개별화 중재이다.',NULL,NULL,'일반학급(일반교육)','RTI의 3단계 모델에서 1단계는 일반학급에서 과학적 근거 기반의 질 높은 교수를 모든 학생에게 제공하는 보편적 중재이다. 2단계는 1단계에서 충분히 반응하지 못한 학생에게 소집단 보충 중재를 제공하며, 3단계는 2단계에서도 반응하지 못한 학생에게 집중적이고 개별화된 중재를 제공한다.',NULL,2,'KICE 기출 기반','{"disability": "learning"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('intro-q44','introduction','disability-types','descriptive','DSM-5의 자폐스펙트럼장애(ASD) 진단기준에서 제시하는 두 가지 핵심 영역과 각 영역의 하위 기준을 설명하시오.','DSM-5(APA, 2013)에서는 기존의 자폐성 장애, 아스퍼거 장애, PDD-NOS를 자폐스펙트럼장애(ASD)라는 단일 진단명으로 통합하고, 심각도를 3단계(Level 1~3)로 구분하였다.',NULL,'1. 영역 A: 사회적 의사소통 및 사회적 상호작용의 지속적 결함 (3가지 하위 기준 모두 충족)
  (1) 사회적-정서적 상호성의 결함: 비정상적인 사회적 접근, 정상적인 대화의 실패, 관심·감정·정서의 공유 감소
  (2) 사회적 상호작용에 사용되는 비언어적 의사소통 행동의 결함: 언어적·비언어적 의사소통의 통합 부족, 눈 맞춤과 신체 언어의 이상, 제스처 이해와 사용의 결함, 표정과 비언어적 의사소통의 전반적 부재
  (3) 관계 발전, 유지 및 이해의 결함: 다양한 사회적 맥락에 적합한 행동 조절의 어려움, 상상놀이 공유나 친구 사귀기의 어려움, 또래에 대한 관심 부재
2. 영역 B: 제한적·반복적 행동, 관심, 활동 (4가지 중 2가지 이상 충족)
  (1) 상동적이거나 반복적인 운동 동작, 사물 사용, 또는 말
  (2) 동일성에 대한 고집, 일상의 변화에 대한 저항, 의례적인 언어적·비언어적 행동 패턴
  (3) 강도나 초점에서 비정상적으로 제한적이고 고정된 관심
  (4) 감각 입력에 대한 과잉 또는 과소 반응성, 환경의 감각적 측면에 대한 비정상적 관심','DSM-5에서 ASD는 두 핵심 영역으로 구성된다. 영역 A(사회적 의사소통)의 3가지 하위 기준은 모두 충족해야 하고, 영역 B(제한적·반복적 행동)의 4가지 중 2가지 이상 충족해야 한다. 특히 감각 반응 이상이 영역 B에 새롭게 추가된 것이 DSM-IV와의 주요 차이점이다.',NULL,3,'DSM-5 (APA, 2013)','{"disability": "autism"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('intro-q45','introduction','history','fill_in','장애 패러다임의 변천에서, ( ) 모델은 장애를 개인의 병리로 보고 치료·재활을 강조하는 반면, ( ) 모델은 장애를 사회적 장벽과 차별의 결과로 보고 환경의 변화를 강조한다.',NULL,NULL,'의료(의학) / 사회','의료 모델(Medical Model)은 장애를 개인의 신체적·정신적 손상으로 보고, 전문가 주도의 치료·재활을 통해 개인을 ''정상''에 가깝게 만드는 것을 목표로 한다. 사회 모델(Social Model)은 장애를 사회적·환경적 장벽의 결과로 보고, 물리적·제도적 장벽의 제거를 통해 장애인의 완전한 사회 참여를 추구한다.',NULL,2,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('intro-q46','introduction','history','multiple','WHO의 ICIDH(1980)와 ICF(2001)에 대한 비교 설명으로 옳지 않은 것은?',NULL,ARRAY['ICIDH는 손상(Impairment)-능력장애(Disability)-사회적 불리(Handicap)의 일방향적 모델을 제시한다.','ICF는 신체 기능 및 구조, 활동, 참여의 세 차원과 환경요인·개인요인을 포함하는 상호작용 모델이다.','ICF는 장애를 부정적 용어 대신 중립적·긍정적 용어로 기술하며, 건강 상태의 구성요소를 분류한다.','ICIDH는 환경적 요인과 개인적 요인을 모두 포함하여 장애의 사회적 맥락을 충분히 반영한다.'],'3','ICIDH(국제장애분류)는 손상→능력장애→사회적 불리의 일방향적(선형적) 모델로, 환경적 요인을 체계적으로 포함하지 않았다는 한계가 있다. 이를 보완하여 ICF(국제기능장애건강분류)는 건강 상태, 신체 기능 및 구조, 활동, 참여, 환경요인, 개인요인 간의 상호작용 모델을 제시하였다.','{"0": "ICIDH는 실제로 손상-능력장애-사회적 불리의 일방향적(선형적) 인과관계 모델을 제시한 것이 맞다.", "1": "ICF는 신체 기능 및 구조, 활동, 참여를 핵심 차원으로 하고, 맥락 요인(환경요인, 개인요인)을 포함하는 상호작용 모델이 맞다.", "2": "ICF는 ICIDH의 부정적 용어(장애, 불리) 대신 중립적 용어(활동, 참여)를 사용하며, 장애뿐 아니라 모든 사람의 건강 상태를 분류하는 보편적 틀이 맞다."}',2,'WHO ICF (2001)','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('intro-q47','introduction','history','descriptive','ICIDH와 ICF의 장애 개념 모델을 비교하고, ICF 모델이 특수교육에 미친 영향을 서술하시오.','WHO는 1980년 ICIDH(국제장애분류)를 발표하여 장애를 손상, 능력장애, 사회적 불리의 세 차원으로 분류하였다. 이후 2001년 ICF(국제기능장애건강분류)를 발표하여 장애 개념을 전면 개편하였다.',NULL,'1. ICIDH(1980) 모델:
  (1) 구성: 손상(Impairment) → 능력장애(Disability) → 사회적 불리(Handicap)
  (2) 특성: 일방향적(선형적) 인과관계 모델
  (3) 관점: 의료 모델 중심, 장애를 개인의 문제로 봄
  (4) 한계: 환경적 요인 미반영, 부정적 용어 사용, 장애인만을 대상으로 한 분류
2. ICF(2001) 모델:
  (1) 구성: 건강 상태, 신체 기능 및 구조, 활동, 참여, 환경요인, 개인요인의 6개 요소
  (2) 특성: 상호작용적(양방향) 모델, 각 요소가 서로 영향을 주고받음
  (3) 관점: 생물심리사회적 모델(Bio-Psycho-Social Model), 의료 모델과 사회 모델의 통합
  (4) 용어: 중립적·긍정적 용어 사용 (능력장애→활동, 사회적 불리→참여)
3. ICF가 특수교육에 미친 영향:
  (1) 장애 학생의 교육적 요구를 기능적 관점에서 파악하는 틀 제공
  (2) 환경요인(물리적·사회적·태도적)의 중요성을 강조하여 통합교육 환경 조성의 근거 마련
  (3) 참여(Participation) 개념을 통해 교육 성과를 학업 성취뿐 아니라 사회 참여까지 확대
  (4) 개별화교육계획(IEP)에서 환경 수정 및 지원 계획의 이론적 근거 제공','ICIDH에서 ICF로의 전환은 장애를 보는 관점의 근본적 변화를 반영한다. ICF의 상호작용 모델은 장애를 개인과 환경의 상호작용 결과로 보며, 이는 특수교육에서 환경 수정과 지원 중심의 접근을 강화하는 데 기여하였다.',NULL,3,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('intro-q48','introduction','history','fill_in','미국 특수교육 관련 법률의 발전 과정에서, 1975년에 제정된 ( )(PL 94-142)는 모든 장애 아동에게 무상의 적절한 공교육(FAPE)과 최소제한환경(LRE)을 보장하였으며, 이후 1990년에 ( )(으)로 명칭이 변경되었다.',NULL,NULL,'전장애아교육법(Education for All Handicapped Children Act) / 장애인교육법(IDEA, Individuals with Disabilities Education Act)','1975년 전장애아교육법(EHA, PL 94-142)은 미국 특수교육의 기본 원리인 FAPE, LRE, IEP, 비차별 평가, 적법 절차, 부모 참여를 확립하였다. 1990년 PL 101-476으로 IDEA로 명칭이 변경되면서 자폐와 외상성 뇌손상이 별도 장애 범주로 추가되었으며, 전환교육 계획이 의무화되었다.',NULL,2,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('intro-q49','introduction','history','ox','Wolfensberger의 사회적 역할 가치화(Social Role Valorization)는 장애인에게 사회적으로 가치 있는 역할을 부여함으로써 사회적 이미지와 개인적 능력을 동시에 향상시키는 것을 목표로 한다.',NULL,NULL,'O','Wolfensberger(1983)는 정상화 원리를 발전시켜 사회적 역할 가치화(SRV) 이론을 제시하였다. SRV는 사회적으로 가치 절하된 사람들에게 가치 있는 사회적 역할을 부여·지원함으로써, 두 가지 목표를 달성하고자 한다: (1) 사회적 이미지(social image)의 향상, (2) 개인적 역량(personal competencies)의 향상.',NULL,2,'Wolfensberger (1983)','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('intro-q50','introduction','history','descriptive','한국 특수교육의 법적 발전 과정을 시대순으로 정리하고, 각 법률의 주요 의의를 설명하시오.','한국의 특수교육은 1977년 「특수교육진흥법」 제정을 시작으로, 1994년 전면 개정, 2007년 「장애인 등에 대한 특수교육법」 제정에 이르기까지 큰 변화를 거쳐왔다.',NULL,'1. 1977년 「특수교육진흥법」 제정:
  (1) 한국 최초의 특수교육 단독 법률
  (2) 특수교육의 법적 기반 마련
  (3) 한계: 의무교육 규정 미비, 통합교육 개념 부재
2. 1994년 「특수교육진흥법」 전면 개정:
  (1) 통합교육 개념 최초 도입
  (2) 개별화교육계획(IEP) 의무화
  (3) 특수교육대상자의 범위 확대
  (4) 특수교육 관련서비스 규정
3. 2007년 「장애인 등에 대한 특수교육법」 제정 (2008년 시행):
  (1) 장애 영유아(만 3세 미만) 무상교육 규정
  (2) 의무교육 대상 확대: 유치원~고등학교(만 3세~17세)
  (3) 장애인 고등교육 및 평생교육 지원 근거 마련
  (4) 특수교육지원센터 설치·운영 법제화
  (5) 장애 유형 10가지 명시 (발달지체 포함)
  (6) 통합교육의 법적 정의와 시행 의무 강화
  (7) 순회교육, 진로 및 직업교육 규정 강화','한국 특수교육법의 발전은 특수교육의 대상과 범위가 점진적으로 확대되어 온 과정이다. 1977년 법적 기반 마련, 1994년 통합교육과 IEP 도입, 2007년 영유아~고등학교 의무교육 및 고등교육·평생교육까지 확대되었다. 현행 「장애인 등에 대한 특수교육법」은 특수교육의 권리성을 강화한 것이 핵심 의의이다.',NULL,3,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('laws-q38','laws','special-education-act','fill_in','「장애인 등에 대한 특수교육법」 제2조(정의)에 따르면, ''특수교육''이란 특수교육대상자의 교육적 요구를 충족시키기 위하여 특성에 적합한 ( ① ), 교육방법 및 ( ② )을/를 제공하는 교육을 말한다. ①과 ②를 순서대로 쓰시오.',NULL,NULL,'① 교육과정 / ② 교육매체','특수교육법 제2조 제1호에 따르면, ''특수교육''이란 특수교육대상자의 교육적 요구를 충족시키기 위하여 특성에 적합한 교육과정 및 제2호에 따른 특수교육 관련서비스 제공을 포함하여 이루어지는 교육을 말하며, 동법 시행령에서 교육과정, 교육방법, 교육매체를 특성에 적합하게 제공하는 것으로 구체화한다.',NULL,1,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('laws-q39','laws','special-education-act','fill_in','「장애인 등에 대한 특수교육법」 제3조(의무교육 등)에 따르면, 특수교육대상자에 대한 의무교육은 ( ① ) 과정과 ( ② ) 과정이며, 유치원 과정과 고등학교 과정은 무상교육으로 규정된다. ①과 ②를 순서대로 쓰시오.',NULL,NULL,'① 초등학교 / ② 중학교','특수교육법 제3조 제1항에 따르면, 특수교육대상자에 대한 의무교육은 「초·중등교육법」 제2조에 따른 초등학교·중학교 과정(의무교육)이다. 유치원 과정과 고등학교 과정은 무상교육으로 규정되어, 일반 학생(초·중 의무교육)보다 확대된 교육 기회를 보장한다. 만 3세 미만의 장애영아도 무상교육 대상이다.',NULL,1,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('laws-q40','laws','special-education-act','ox','「장애인 등에 대한 특수교육법」에 따르면, 특수교육운영위원회는 교육감 소속으로만 설치하며, 교육장 소속으로는 설치하지 않는다.',NULL,NULL,'X','특수교육법 제10조에 따르면, 특수교육운영위원회는 교육부장관 소속(중앙특수교육운영위원회), 시·도 교육감 소속(시·도 특수교육운영위원회), 교육장 소속(시·군·구 특수교육운영위원회)으로 각각 설치한다. 교육장 소속 특수교육운영위원회는 특수교육대상자의 선정·배치 심사 등의 기능을 수행한다.',NULL,2,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('laws-q41','laws','special-education-act','multiple','「장애인 등에 대한 특수교육법」 제23조(전환교육)에 관한 설명으로 옳은 것은?',NULL,ARRAY['전환교육은 초등학교 과정부터 실시하여야 한다.','전환교육계획은 개별화교육계획과 별도로 수립하여야 한다.','중학교 과정 이상의 각급학교의 장은 특수교육대상자의 전환교육을 위한 직업교육 실시에 필요한 시설·설비를 마련하여야 한다.','전환교육에는 직업교육만 포함되며 자립생활훈련은 포함되지 않는다.'],'3','특수교육법 제23조 제2항에 따르면, 중학교 과정 이상의 각급학교의 장은 대통령령으로 정하는 바에 따라 전환교육의 실시에 필요한 직업교육 시설·설비를 마련하여야 한다. 전환교육은 초등학교가 아닌 중학교 과정 이상에서 실시하며, IEP에 포함하여 수립하고, 직업재활훈련·자립생활훈련 등을 포함한다.','{"0": "전환교육은 초등학교가 아닌 중학교 과정 이상에서 실시한다.", "1": "전환교육계획은 별도 문서가 아니라 개별화교육계획(IEP)에 포함하여 수립한다.", "3": "전환교육에는 직업교육뿐 아니라 자립생활훈련, 지역사회참여 등도 포함된다."}',2,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('laws-q42','laws','special-education-act','descriptive','「장애인 등에 대한 특수교육법」 제25조에 규정된 순회교육에 대해 다음을 서술하시오: (1) 순회교육의 대상, (2) 순회교육의 운영 방법, (3) 순회교육을 담당하는 기관.','A 교육지원청 관내에 가정에서 생활하고 있는 중증 지체장애 학생 민수가 있다. 민수의 보호자는 민수가 학교에 통학하기 어려우므로 교육 지원을 요청하였다.',NULL,'(1) 대상: 일반학교에서 통합교육을 받고 있는 특수교육대상자, 장애 정도가 심하여 장·단기 결석이 불가피한 특수교육대상자, 이동이나 운동 기능의 심한 장애로 각급학교에의 통학이 어려운 특수교육대상자 등이 해당된다. (2) 운영 방법: 순회교육을 받는 특수교육대상자의 능력, 장애 정도 및 교육 환경 등을 고려하여 교육과정의 내용을 조정하여 운영하며, 순회교사가 가정 또는 시설 등을 방문하여 교육한다. (3) 담당 기관: 특수교육지원센터가 순회교육을 담당하며, 교육감 또는 교육장이 순회교육의 실시를 명할 수 있다.','특수교육법 제25조에 따르면, 교육장 또는 교육감은 일반학교에서 통합교육을 받고 있는 특수교육대상자를 지원하기 위하여 순회교육을 실시하여야 한다. 순회교육은 특수교육지원센터 소속 순회교사가 담당하며, 통학이 어려운 중증장애 학생에게 가정이나 시설을 방문하여 교육을 제공하는 것이 핵심이다.',NULL,3,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('laws-q43','laws','special-education-act','fill_in','「장애인 등에 대한 특수교육법」 제2조 제10호에 따르면, ''특수교육 관련서비스''란 특수교육대상자의 교육을 효율적으로 실시하기 위하여 필요한 ( ① )·가족지원·치료지원·보조인력지원·보조공학기기지원·통학지원 및 ( ② ) 지원 등을 말한다. ①과 ②를 쓰시오.',NULL,NULL,'① 상담지원 / ② 정보접근','특수교육법 제2조 제10호는 특수교육 관련서비스를 정의하면서 상담지원, 가족지원, 치료지원, 보조인력지원, 보조공학기기지원, 통학지원, 정보접근지원 등을 열거하고 있다. 정보접근지원은 특수교육대상자가 정보에 동등하게 접근할 수 있도록 점자, 수어통역, 보완대체의사소통 등을 제공하는 것을 포함한다.',NULL,2,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('laws-q44','laws','special-education-act','ox','「장애인 등에 대한 특수교육법」에 따르면, 영아(만 3세 미만)의 보호자는 조기교육이 필요한 경우 교육장 또는 교육감에게 교육을 요구할 수 있으며, 이 경우 무상교육이 제공된다.',NULL,NULL,'O','특수교육법 제3조 제3항에 따르면, 만 3세 미만의 장애영아 교육은 무상으로 한다. 또한 제18조에 따르면, 만 3세 미만의 장애영아의 보호자는 조기교육이 필요한 경우 교육장 또는 교육감에게 교육을 요구할 수 있다. 장애영아 교육은 특수교육지원센터 등에서 제공된다.',NULL,2,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('laws-q45','laws','welfare-act','fill_in','「장애인복지법」 제2조에 따르면, ''장애인''이란 신체적·정신적 장애로 오랫동안 일상생활이나 사회생활에서 상당한 ( )을/를 받는 자를 말한다. 빈칸에 들어갈 용어를 쓰시오.',NULL,NULL,'제약','장애인복지법 제2조 제1항에 따르면, ''장애인''이란 신체적·정신적 장애로 오랫동안 일상생활이나 사회생활에서 상당한 제약을 받는 자를 말한다. 이는 장애를 개인의 손상뿐 아니라 사회적 제약의 관점에서도 바라보는 정의이다.',NULL,1,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('laws-q46','laws','welfare-act','multiple','「장애인복지법 시행령」에 따른 장애 유형 분류에서 ''정신적 장애''에 해당하는 것만을 모두 고른 것은?
ㄱ. 지적장애  ㄴ. 뇌병변장애  ㄷ. 자폐성장애  ㄹ. 정신장애',NULL,ARRAY['ㄱ, ㄴ','ㄱ, ㄷ, ㄹ','ㄴ, ㄷ, ㄹ','ㄱ, ㄴ, ㄷ, ㄹ'],'2','장애인복지법 시행령 별표1에 따르면, 장애는 크게 ''신체적 장애''와 ''정신적 장애''로 분류된다. 정신적 장애에는 지적장애, 자폐성장애, 정신장애가 포함된다. 뇌병변장애는 신체적 장애 중 ''외부 신체기능의 장애''에 해당한다. 신체적 장애는 다시 외부 신체기능의 장애(지체, 뇌병변, 시각, 청각, 언어, 안면)와 내부기관의 장애(신장, 심장, 간, 호흡기, 장루·요루, 뇌전증)로 나뉜다.','{"0": "ㄴ(뇌병변장애)은 정신적 장애가 아닌 신체적 장애(외부 신체기능의 장애)에 해당한다.", "2": "ㄴ(뇌병변장애)은 신체적 장애에 해당하므로 정신적 장애 분류에 포함되지 않는다.", "3": "ㄴ(뇌병변장애)은 신체적 장애에 해당하여 정신적 장애가 아니다."}',2,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('laws-q47','laws','welfare-act','descriptive','「장애인복지법」과 「장애인 등에 대한 특수교육법」의 장애 분류 체계를 비교하여 다음을 서술하시오: (1) 각 법의 장애 유형 수, (2) 특수교육법에는 있지만 장애인복지법에는 없는 장애 유형 2가지, (3) 장애인복지법에는 있지만 특수교육법에는 없는 장애 유형 3가지.',NULL,NULL,'(1) 장애인복지법은 15종, 특수교육법은 10종으로 분류한다. (2) 특수교육법에는 있지만 장애인복지법에는 없는 유형: 학습장애, 발달지체. 학습장애는 교육적 맥락에서만 의미를 갖는 장애 유형이고, 발달지체는 만 9세 미만 영유아에게 적용되는 교육적 진단 범주이다. (3) 장애인복지법에는 있지만 특수교육법에는 없는 유형: 신장장애, 심장장애, 호흡기장애(또는 간장애, 안면장애, 장루·요루장애, 뇌전증장애 중 3가지). 이들은 의료적 장애로서 교육적 분류보다 복지적 분류에 해당한다.','두 법은 목적이 다르기 때문에 장애 분류 체계도 다르다. 장애인복지법은 복지서비스 제공을 위해 의료적·기능적 관점에서 15종으로 세분화하고, 특수교육법은 교육적 지원을 위해 교육적 필요에 기반한 10종으로 분류한다. 특히 학습장애와 발달지체는 순수하게 교육적 맥락에서만 존재하는 범주이다.',NULL,3,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('laws-q48','laws','welfare-act','fill_in','「장애인복지법」 제15조에 따르면, 장애인의 장애 인정과 등급사정을 위하여 장애 진단 및 판정 업무를 담당하는 기관은 ( )이다. 빈칸에 들어갈 기관을 쓰시오.',NULL,NULL,'국민연금공단','장애인복지법 제32조의4에 따르면, 장애 정도에 관한 심사 업무는 국민연금공단에 위탁하여 실시한다. 2019년 7월 장애등급제 폐지 이후 장애 정도를 ''심한 장애''와 ''심하지 않은 장애''의 2단계로 구분하고 있으며, 국민연금공단이 장애 정도 심사를 담당한다.',NULL,2,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('laws-q49','laws','welfare-act','ox','「장애인복지법」에 따른 장애등급제는 2019년 7월 폐지되었으며, 현재는 장애 정도를 ''심한 장애''와 ''심하지 않은 장애''의 2단계로 구분한다.',NULL,NULL,'O','2019년 7월 1일부터 기존의 1~6급 장애등급제가 폐지되고, 장애 정도를 ''장애의 정도가 심한 장애인''(종전 1~3급)과 ''장애의 정도가 심하지 않은 장애인''(종전 4~6급)으로 구분하게 되었다. 이는 등급에 따른 획일적 서비스 제공에서 벗어나 개인의 필요에 기반한 맞춤형 서비스를 제공하기 위한 제도 변화이다.',NULL,2,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('laws-q50','laws','welfare-act','fill_in','「장애인복지법」 시행령에 따른 장애 유형 중 내부기관의 장애에 해당하는 6가지를 모두 쓰시오.',NULL,NULL,'신장장애 / 심장장애 / 간장애 / 호흡기장애 / 장루·요루장애 / 뇌전증장애','장애인복지법 시행령 별표1에 따르면, 신체적 장애는 외부 신체기능의 장애와 내부기관의 장애로 구분된다. 내부기관의 장애에는 신장장애, 심장장애, 간장애, 호흡기장애, 장루·요루장애, 뇌전증장애의 6가지가 포함된다. 이들은 외형적으로 드러나지 않는 장애로서, 복지 서비스의 사각지대에 놓이기 쉽다.',NULL,2,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('laws-q51','laws','welfare-act','descriptive','「장애인복지법」에서 규정하는 장애인 자립생활 지원 제도에 대해 다음을 서술하시오: (1) 활동지원서비스의 목적, (2) 활동지원급여의 종류 3가지.','성인 지적장애인 지호(만 25세)는 그룹홈에서 생활하고 있다. 지호의 보호자는 지호가 지역사회에서 독립적으로 생활할 수 있도록 활동지원서비스를 신청하고자 한다.',NULL,'(1) 목적: 장애인활동지원서비스는 신체적·정신적 장애 등의 사유로 혼자서 일상생활과 사회생활을 하기 어려운 장애인에게 활동보조, 방문목욕, 방문간호 등의 서비스를 제공하여 자립생활을 지원하고 사회참여를 증진하는 것을 목적으로 한다. (2) 활동지원급여의 종류: 활동보조(개인위생, 식사보조, 이동보조 등), 방문목욕, 방문간호의 3가지가 있다.','장애인활동지원에 관한 법률(장애인복지법 관련 법률)에 따르면, 만 6세 이상 만 65세 미만의 장애인이 활동지원급여를 신청할 수 있다. 활동보조는 가장 핵심적인 서비스로, 신체활동지원(세면, 식사, 실내이동 등), 가사활동지원(청소, 세탁, 취사 등), 사회활동지원(외출, 통원, 여가활동 등)을 포함한다.',NULL,3,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('laws-q52','laws','anti-discrimination-act','fill_in','「장애인차별금지 및 권리구제 등에 관한 법률」에서는 장애인에 대한 차별을 크게 세 가지 유형으로 구분한다: ( ① ) 차별, ( ② ) 차별, 정당한 편의 제공 거부에 의한 차별이다. ①과 ②를 쓰시오.',NULL,NULL,'① 직접 / ② 간접','장애인차별금지법 제4조에 따르면, 차별행위는 직접차별(장애를 사유로 정당한 사유 없이 불리하게 대하는 것), 간접차별(형식적으로는 동일한 기준을 적용하지만 장애인에게 불리한 결과를 초래하는 것), 정당한 편의 제공 거부에 의한 차별의 세 가지로 구분된다. 또한 광고에 의한 차별도 별도로 규정하고 있다.',NULL,2,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('laws-q53','laws','anti-discrimination-act','descriptive','「장애인차별금지법」에서 규정하는 ''정당한 편의(reasonable accommodation)'' 제공 의무에 대해 다음을 서술하시오: (1) 정당한 편의의 정의, (2) 교육 영역에서의 정당한 편의 제공 사례 3가지.','시각장애 학생 수현이가 일반 대학교에 입학하였다. 대학 측은 수현이에게 적절한 학습 환경을 제공해야 할 의무가 있다.',NULL,'(1) 정의: 정당한 편의란 장애인이 장애가 없는 사람과 동등하게 같은 활동에 참여할 수 있도록 장애인의 성별, 장애의 유형 및 정도, 특성 등을 고려한 편의시설·장비·도구·서비스 등 인적·물적 제반 수단과 조치를 말한다. (2) 교육 영역 사례: 시험 시간 연장 및 별도의 시험실 제공, 점자 교재·확대 교재·전자 교재 등 대체자료 제공, 수어통역·문자통역·속기 등의 의사소통 지원 서비스 제공.','장애인차별금지법 제4조 제1항 제3호 및 제14조(정당한 편의 제공 의무)에 따르면, 교육기관은 장애인의 교육 참여를 보장하기 위해 정당한 편의를 제공해야 한다. 정당한 편의 제공 거부는 차별행위에 해당하며, 과도한 부담이나 현저히 곤란한 사정이 있는 경우에만 예외가 인정되고, 이에 대한 입증 책임은 편의 제공 의무자에게 있다.',NULL,3,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('laws-q54','laws','anti-discrimination-act','multiple','「장애인차별금지법」 제13조(차별금지-교육)에 관한 설명으로 옳지 않은 것은?',NULL,ARRAY['교육기관은 장애인의 입학 지원 및 입학을 거부할 수 없다.','교육기관은 장애를 이유로 전학을 강요할 수 없다.','교육기관은 장애학생의 교육활동에 불이익이 없도록 정당한 편의를 제공하여야 한다.','교육기관은 장애학생에 대한 편의 제공 비용을 보호자에게 전액 부담시킬 수 있다.'],'4','장애인차별금지법 제13조 및 제14조에 따르면, 교육기관은 장애인에게 정당한 편의를 제공하여야 하며, 이에 필요한 비용을 장애학생 또는 보호자에게 전가할 수 없다. 정당한 편의 제공은 교육기관의 의무이며, 그 비용을 보호자에게 전액 부담시키는 것은 실질적인 차별행위에 해당한다.','{"0": "제13조 제1항에 따라 교육기관은 장애인의 입학 지원이나 입학을 거부해서는 안 된다.", "1": "제13조 제3항에 따라 장애를 이유로 전학을 강요하는 것은 금지된다.", "2": "제14조에 따라 교육기관은 장애학생에게 정당한 편의를 제공할 의무가 있다."}',2,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('laws-q55','laws','anti-discrimination-act','ox','「장애인차별금지법」에 따르면, 장애인 차별에 대한 입증 책임은 차별을 주장하는 장애인 본인에게 있다.',NULL,NULL,'X','장애인차별금지법 제47조에 따르면, 차별행위가 있었다는 사실은 차별을 당했다고 주장하는 자가 입증하되, 그 행위가 장애를 이유로 한 차별이 아니라거나 정당한 사유가 있었다는 점은 차별행위를 한 자가 입증하여야 한다. 즉, 차별의 존재에 대한 기본적 사실은 주장자가 입증하지만, 차별이 아님을 항변하는 입증 책임은 피주장자(차별행위자)에게 있는 ''입증 책임의 전환''이 적용된다.',NULL,3,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('laws-q56','laws','anti-discrimination-act','fill_in','UN「장애인 권리협약(CRPD)」 제24조에 따르면, 당사국은 장애인이 일반 교육체제에서 배제되지 않도록 ( ① ) 교육체제를 보장하여야 하며, 이를 위해 ( ② )을/를 제공하여야 한다. ①과 ②를 쓰시오.',NULL,NULL,'① 통합적(inclusive) / ② 합리적 조정(reasonable accommodation)','CRPD 제24조(교육)는 당사국에 통합적(inclusive) 교육체제를 보장할 것을 규정하고, 개인에게 필요한 합리적 조정(reasonable accommodation)을 제공하도록 명시한다. 합리적 조정이란 특정 상황에서 장애인이 다른 사람과 동등하게 모든 인권과 기본적 자유를 향유할 수 있도록 보장하기 위한 필요하고 적절한 변경과 조정을 의미한다.',NULL,2,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('laws-q57','laws','anti-discrimination-act','descriptive','UN「장애인 권리협약(CRPD)」의 주요 원칙과 교육권(제24조)에 대해 다음을 서술하시오: (1) CRPD의 일반원칙 3가지, (2) 제24조에서 당사국에 요구하는 교육 관련 의무 2가지.',NULL,NULL,'(1) 일반원칙(제3조): 고유한 존엄성과 자율성(개인적 자율 포함) 및 독립의 존중, 비차별, 완전하고 효과적인 사회 참여와 통합(또는: 기회의 균등, 접근성, 장애인과 비장애인의 평등, 장애아동의 역량 존중 중 3가지). (2) 제24조 교육 의무: 장애인이 장애를 이유로 일반 교육체제에서 배제되지 않도록 통합적 교육체제를 보장할 것, 장애인의 개별적 필요에 따른 합리적 조정(reasonable accommodation)을 제공할 것.','CRPD는 2006년 UN 총회에서 채택되었으며, 한국은 2008년 비준하였다. 제3조에 8가지 일반원칙(존엄성, 비차별, 참여·통합, 차이 존중, 기회균등, 접근성, 남녀평등, 장애아동 존중)을 규정하고 있다. 제24조(교육)는 통합교육(inclusive education)을 국제적 규범으로 확립한 핵심 조항이며, 합리적 조정의 거부를 차별로 명시하고 있다.',NULL,3,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('laws-q58','laws','theory','multiple','「장애인 등에 대한 특수교육법」에서 규정하는 특수교육대상자의 의무교육 범위로 올바른 것은?',NULL,ARRAY['유치원부터 고등학교까지','초등학교부터 중학교까지','유치원부터 중학교까지','초등학교부터 고등학교까지'],'1','「장애인 등에 대한 특수교육법」 제3조 제1항에 따르면, 특수교육대상자에 대하여는 「교육기본법」 제8조에도 불구하고 유치원·초등학교·중학교 및 고등학교 과정의 교육은 의무교육으로 한다. 이는 일반교육에서의 의무교육 범위(초등학교~중학교)보다 확대된 것으로, 장애학생의 교육기회를 보다 폭넓게 보장하기 위한 것이다. 만 3세 미만의 장애영아와 전공과 교육은 무상교육에 해당한다.','{"2": "초등학교부터 중학교까지는 일반교육의 의무교육 범위이며, 특수교육대상자에게는 유치원과 고등학교 과정까지 확대 적용된다.", "3": "유치원부터 중학교까지는 고등학교 과정이 빠져 있어 특수교육법상 의무교육 범위에 해당하지 않는다.", "4": "초등학교부터 고등학교까지는 유치원 과정이 빠져 있으며, 특수교육대상자의 의무교육에는 유치원 과정도 포함된다."}',1,'KICE 기출 기반','{"category": "법령"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('laws-q59','laws','theory','ox','「장애인 등에 대한 특수교육법」에 따르면, 만 3세 미만의 장애영아에 대한 교육은 무상교육으로 실시한다.',NULL,NULL,'O','「장애인 등에 대한 특수교육법」 제3조 제2항에 따르면, 만 3세 미만의 장애영아교육은 무상으로 실시한다. 의무교육은 유치원부터 고등학교까지이고, 만 3세 미만 장애영아와 전공과 과정은 무상교육으로 구분된다. 무상교육은 의무교육과 달리 보호자에게 취학 의무가 부과되지 않으나, 교육비를 국가가 부담한다는 점에서 교육기회를 보장한다.',NULL,1,'KICE 기출 기반','{"category": "법령"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('laws-q60','laws','practices','multiple','「장애인 등에 대한 특수교육법」상 개별화교육계획(IEP)의 작성 시기로 올바른 것은?',NULL,ARRAY['매 학기 시작일로부터 30일 이내','매 학년 시작일로부터 30일 이내','매 학기 시작일로부터 14일 이내','매 학년 시작일로부터 60일 이내'],'1','「장애인 등에 대한 특수교육법」 제22조 제2항에 따르면, 개별화교육지원팀은 매 학기의 시작일부터 30일 이내에 개별화교육계획을 작성하여야 한다. 이는 학기 단위로 학생의 변화된 교육적 요구를 반영하기 위한 것이다. 개별화교육계획에는 특수교육대상자의 인적사항, 현재 학습 수행수준, 교육목표, 교육내용 및 방법, 평가계획 등이 포함된다.','{"2": "매 학년이 아닌 매 학기 시작일로부터 30일 이내에 작성해야 한다. 학기 단위로 교육계획을 수립하여 학생의 변화를 적시에 반영한다.", "3": "14일이 아닌 30일 이내에 작성해야 한다. 14일은 개별화교육지원팀 구성 시한(2주)과 혼동하기 쉽다.", "4": "매 학년이 아닌 매 학기이며, 60일이 아닌 30일 이내에 작성해야 한다."}',2,'KICE 기출 기반','{"category": "법령"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('laws-q61','laws','practices','fill_in','「장애인 등에 대한 특수교육법」에 따르면, 각급학교의 장은 특수교육대상자가 배치된 때에는 (   ) 이내에 개별화교육지원팀을 구성하여야 한다.',NULL,NULL,'2주','「장애인 등에 대한 특수교육법」 제22조 제1항에 따르면, 각급학교의 장은 특수교육대상자에 대한 교육지원 내용을 추진하기 위하여 보호자, 특수교육교원, 일반교육교원, 진로 및 직업교육 담당 교원, 특수교육 관련서비스 담당 인력 등으로 개별화교육지원팀을 구성한다. 이 팀은 대상자가 배치된 날로부터 2주 이내에 구성해야 하며, 매 학기 시작일로부터 30일 이내에 개별화교육계획을 작성해야 한다.',NULL,2,'KICE 기출 기반','{"category": "법령"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('laws-q62','laws','theory','multiple','「장애인 등에 대한 특수교육법」에서 규정하는 특수교육 관련서비스에 해당하지 않는 것은?',NULL,ARRAY['상담지원','가족지원','학원비 지원','보조인력 지원'],'3','「장애인 등에 대한 특수교육법」 제2조 제2호에 따르면, 특수교육 관련서비스란 특수교육대상자의 교육을 효율적으로 실시하기 위하여 필요한 인적·물적 자원을 제공하는 서비스를 말한다. 여기에는 상담지원, 가족지원, 치료지원, 보조인력지원, 보조공학기기지원, 학습보조기기지원, 통학지원, 정보접근지원 등이 포함된다. 학원비 지원은 특수교육 관련서비스에 해당하지 않는다.','{"1": "상담지원은 특수교육법 제28조에 규정된 특수교육 관련서비스에 해당한다.", "2": "가족지원은 특수교육법 제28조에 규정된 특수교육 관련서비스에 해당하며, 가족상담, 양육상담 등을 포함한다.", "4": "보조인력 지원은 특수교육법 제28조에 규정된 특수교육 관련서비스에 해당한다."}',1,'KICE 기출 기반','{"category": "법령"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('laws-q63','laws','strategies','descriptive','「장애인 등에 대한 특수교육법」에 따른 통합교육의 법적 정의와, 일반학교 장이 통합교육을 실시하기 위해 수행해야 하는 의무를 3가지 이상 서술하시오.',NULL,NULL,'통합교육이란 특수교육대상자가 일반학교에서 장애 유형·장애 정도에 따라 차별을 받지 아니하고 또래와 함께 개개인의 교육적 요구에 적합한 교육을 받는 것을 말한다(제2조 제6호). 일반학교의 장이 수행해야 하는 의무로는 첫째, 특수교육대상자의 통합교육을 위해 일반학교 교원 및 특수교육 관련서비스 담당 인력에 대한 연수를 실시해야 한다. 둘째, 통합교육 실시에 필요한 시설·설비 및 교재·교구를 갖추어야 한다. 셋째, 통합학급 편성 시 통합학급에 배치된 특수교육대상자의 수를 고려하여 학급당 학생 수를 조정해야 한다. 넷째, 교육과정 운영에 있어 통합교육을 받는 특수교육대상자의 특성을 고려한 교육과정 조정 및 교수·학습 방법의 변경이 필요하다.','통합교육이란 특수교육대상자가 일반학교에서 장애 유형·장애 정도에 따라 차별을 받지 아니하고 또래와 함께 개개인의 교육적 요구에 적합한 교육을 받는 것을 말한다(제2조 제6호). 일반학교의 장이 수행해야 하는 의무로는 첫째, 특수교육대상자의 통합교육을 위해 일반학교 교원 및 특수교육 관련서비스 담당 인력에 대한 연수를 실시해야 한다. 둘째, 통합교육 실시에  (자동 생성 해설)',NULL,3,'KICE 기출 기반','{"category": "법령"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('laws-q64','laws','practices','multiple','「장애인 등에 대한 특수교육법 시행령」에 따라, 특수교육대상자의 학교 배치를 결정하는 기관은?',NULL,ARRAY['교육감 또는 교육장','학교장','특수교육지원센터장','교육부장관'],'1','「장애인 등에 대한 특수교육법」 제17조에 따르면, 교육장 또는 교육감은 특수교육대상자로 선정된 자를 해당 특수교육운영위원회의 심사를 거쳐 적절한 학교에 배치하여야 한다. 배치 시에는 특수교육대상자의 장애 정도, 능력, 보호자의 의견 등을 종합적으로 고려하며, 거주지에서 가장 가까운 곳에 배치하는 것을 원칙으로 한다.','{"2": "학교장은 배치된 특수교육대상자의 교육을 실시하는 역할을 하지만, 배치를 결정하는 권한은 교육감 또는 교육장에게 있다.", "3": "특수교육지원센터는 진단·평가 업무를 담당하며, 배치 결정 권한은 교육감 또는 교육장에게 있다.", "4": "교육부장관은 특수교육 정책을 총괄하지만, 개별 학생의 배치 결정은 교육감 또는 교육장이 담당한다."}',2,'KICE 기출 기반','{"category": "법령"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('laws-q65','laws','theory','ox','「장애인차별금지 및 권리구제 등에 관한 법률」에 따르면, 정당한 사유 없이 장애인의 입학 지원을 거부하는 것은 차별행위에 해당한다.',NULL,NULL,'O','「장애인차별금지 및 권리구제 등에 관한 법률」 제13조 제1항에 따르면, 교육기관은 장애인의 입학 지원 및 입학을 거부하거나, 전학을 강요하는 등 장애를 이유로 교육에서 차별해서는 안 된다. 이는 교육에서의 차별금지 조항으로, 모든 교육기관에 적용된다. 정당한 사유 없이 장애를 이유로 입학을 거부하는 것은 명백한 차별행위에 해당하며, 국가인권위원회에 진정할 수 있다.',NULL,1,'교재 참고','{"category": "법령"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('laws-q66','laws','strategies','multiple','「장애인 등에 대한 특수교육법」에 따른 순회교육의 대상으로 가장 적절한 것은?',NULL,ARRAY['일반학교에 배치된 경도 장애학생','장·단기 결석이 불가피한 특수교육대상자','영재교육 대상 장애학생','직업재활 대상 성인 장애인'],'2','「장애인 등에 대한 특수교육법」 제25조에 따르면, 교육장 또는 교육감은 일반학교에서 통합교육을 받고 있는 특수교육대상자를 지원하기 위하여 순회교육을 실시하여야 한다. 또한 장·단기의 결석이 불가피하거나, 이동이나 운동기능의 심한 장애로 인하여 각급학교에서 교육을 받기 곤란하거나 불가능하여 복지시설·의료기관 또는 가정 등에 거주하는 특수교육대상자에게도 순회교육을 실시한다.','{"1": "일반학교에 배치된 경도 장애학생은 통합교육 환경에서 교육을 받으며, 순회교육의 주된 대상은 학교 출석이 곤란한 학생이다.", "3": "영재교육은 「영재교육진흥법」에 따라 별도로 운영되며, 순회교육의 대상과는 구분된다.", "4": "직업재활 대상 성인 장애인은 「장애인복지법」 등에 따른 직업재활 서비스 대상이며, 특수교육법상 순회교육 대상과 다르다."}',2,'KICE 기출 기반','{"category": "법령"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('laws-q67','laws','practices','fill_in','「장애인 등에 대한 특수교육법」에 따르면, 교육장 또는 교육감은 진단·평가 의뢰를 받은 후 (   ) 이내에 진단·평가를 시행하고, 그 결과를 보호자에게 통보하여야 한다.',NULL,NULL,'30일','「장애인 등에 대한 특수교육법」 제16조에 따르면, 교육장 또는 교육감은 진단·평가 의뢰를 받은 후 30일 이내에 특수교육지원센터에서 진단·평가를 실시하고, 그 결과를 보호자에게 통보해야 한다. 이 기간 내에 선정 여부와 교육지원 내용이 결정되어 보호자에게 서면으로 통지된다. 신속한 절차를 통해 교육적 조치가 지연되지 않도록 하고 있다.',NULL,2,'KICE 기출 기반','{"category": "법령"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('laws-q68','laws','theory','multiple','「장애인 등에 대한 특수교육법」에서 규정하는 특수교육대상자 장애 유형에 해당하지 않는 것은?',NULL,ARRAY['자폐성장애','의사소통장애','사회부적응','발달지체'],'3','「장애인 등에 대한 특수교육법」 제15조에서는 특수교육대상자의 선정 기준으로 시각장애, 청각장애, 지적장애, 지체장애, 정서·행동장애, 자폐성장애, 의사소통장애, 학습장애, 건강장애, 발달지체 등을 규정하고 있다. 사회부적응은 정서·행동장애의 판별 기준에서 명시적으로 제외되는 항목으로, 독립적인 장애 유형에 해당하지 않는다.','{"1": "자폐성장애는 특수교육법 제15조에 규정된 특수교육대상자 장애 유형 중 하나이다.", "2": "의사소통장애는 특수교육법 제15조에 규정된 특수교육대상자 장애 유형 중 하나이다.", "4": "발달지체는 특수교육법 제15조에 규정된 특수교육대상자 장애 유형 중 하나로, 만 9세 미만의 아동에게 적용된다."}',1,'KICE 기출 기반','{"category": "법령"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('laws-q69','laws','strategies','descriptive','「장애인 등에 대한 특수교육법」에 규정된 특수교육운영위원회의 설치 단위(수준)와 각 수준별 주요 심의 사항을 설명하시오.',NULL,NULL,'특수교육운영위원회는 세 가지 수준에서 설치·운영된다. 첫째, 교육부에 중앙특수교육운영위원회를 두어 특수교육에 관한 주요 정책 및 계획의 수립, 특수교육 관련 법령의 제·개정에 관한 사항 등을 심의한다. 둘째, 시·도 교육청에 시·도 특수교육운영위원회를 두어 해당 지역의 특수교육대상자 배치, 특수교육 지원 관련 사항 등을 심의한다. 셋째, 하급교육행정기관(교육지원청)에도 특수교육운영위원회를 두어 특수교육대상자의 선정·배치에 관한 실무적 심의를 담당한다. 각 위원회는 해당 수준에서 특수교육대상자의 권익 보호와 교육의 질적 향상을 위한 심의·자문 기능을 수행한다.','특수교육운영위원회는 세 가지 수준에서 설치·운영된다. 첫째, 교육부에 중앙특수교육운영위원회를 두어 특수교육에 관한 주요 정책 및 계획의 수립, 특수교육 관련 법령의 제·개정에 관한 사항 등을 심의한다. 둘째, 시·도 교육청에 시·도 특수교육운영위원회를 두어 해당 지역의 특수교육대상자 배치, 특수교육 지원 관련 사항 등을 심의한다. 셋째, 하급교육행정기관(교 (자동 생성 해설)',NULL,3,'교재 참고','{"category": "법령"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('laws-q70','laws','practices','ox','「장애인 등에 대한 특수교육법」에 따르면, 보호자가 특수교육대상자의 배치에 이의가 있을 때에는 심사청구를 할 수 있으며, 심사청구는 그 사유를 안 날로부터 90일 이내에 해야 한다.',NULL,NULL,'O','「장애인 등에 대한 특수교육법」 제36조에 따르면, 특수교육대상자 또는 그 보호자는 배치 등에 이의가 있을 때 해당 시·도 특수교육운영위원회에 심사청구를 할 수 있다. 심사청구 기한은 그 사유를 안 날로부터 90일 이내이다. 이는 특수교육대상자의 권리구제를 위한 절차적 장치로, 행정심판이나 행정소송과는 별도의 특수교육법상 고유한 불복절차이다.',NULL,2,'KICE 기출 기반','{"category": "법령"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('laws-q71','laws','theory','fill_in','「장애인 등에 대한 특수교육법」 제2조에 따르면, ''통합교육''이란 특수교육대상자가 일반학교에서 장애 유형·장애 정도에 따라 차별을 받지 아니하고 (   )와/과 함께 개개인의 교육적 요구에 적합한 교육을 받는 것을 말한다.',NULL,NULL,'또래','「장애인 등에 대한 특수교육법」 제2조 제6호에서 통합교육의 정의를 규정하고 있다. 통합교육이란 특수교육대상자가 일반학교에서 장애 유형·장애 정도에 따라 차별을 받지 아니하고 또래와 함께 개개인의 교육적 요구에 적합한 교육을 받는 것을 말한다. ''또래''라는 표현은 같은 연령대의 비장애 학생과 함께 교육받는 것을 강조하는 핵심 개념이다.',NULL,1,'교재 참고','{"category": "법령"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('laws-q72','laws','strategies','multiple','「장애인복지법」에서 규정하는 장애인 등록 절차에 대한 설명으로 올바른 것은?',NULL,ARRAY['장애인 본인만 등록 신청이 가능하다','특별자치시장·특별자치도지사·시장·군수·구청장에게 등록하여야 한다','등록 시 반드시 국립병원에서 진단을 받아야 한다','장애 등급은 교육감이 결정한다'],'2','「장애인복지법」 제32조에 따르면, 장애인은 특별자치시장·특별자치도지사·시장·군수·구청장에게 장애인 등록을 신청하여야 한다. 등록 신청은 본인뿐 아니라 보호자도 할 수 있으며, 진단은 「장애인복지법 시행규칙」에 따라 의료기관에서 받되 반드시 국립병원일 필요는 없다. 장애 정도 판정은 국민연금공단 등에서 심사하며, 교육감의 업무가 아니다.','{"1": "장애인복지법에 따르면 본인뿐 아니라 보호자(법정대리인)도 장애인 등록을 신청할 수 있다.", "3": "진단은 의료기관에서 받으며, 반드시 국립병원에서 받을 필요는 없다.", "4": "장애 정도는 교육감이 아닌 특별자치시장·특별자치도지사·시장·군수·구청장이 국민연금공단의 심사를 거쳐 결정한다."}',2,'교재 참고','{"category": "법령"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('laws-q73','laws','practices','multiple','「장애인 등에 대한 특수교육법」에 따른 진단·평가 의뢰 절차에 대한 설명으로 올바르지 않은 것은?',NULL,ARRAY['보호자 또는 각급학교의 장이 교육장 또는 교육감에게 진단·평가를 의뢰할 수 있다','교육장 또는 교육감은 즉시 특수교육지원센터에 진단·평가를 의뢰하여야 한다','진단·평가 시 보호자의 사전 동의가 필요하다','진단·평가 결과는 60일 이내에 보호자에게 통보한다'],'4','「장애인 등에 대한 특수교육법」 제16조에 따르면, 보호자 또는 각급학교의 장이 진단·평가를 의뢰할 수 있으며, 교육장 또는 교육감은 즉시 특수교육지원센터에 회부하여야 한다. 진단·평가 시 보호자의 사전 동의를 받아야 하며, 전체 과정은 30일 이내에 완료되어야 한다. 60일이 아닌 30일 이내이므로 4번이 올바르지 않은 설명이다.','{"1": "특수교육법 제16조 제1항에 따라 보호자 또는 각급학교의 장이 교육장 또는 교육감에게 진단·평가를 의뢰할 수 있으므로 올바른 설명이다.", "2": "특수교육법 제16조 제2항에 따라 교육장 또는 교육감은 진단·평가 의뢰를 받으면 즉시 특수교육지원센터에 회부하여야 하므로 올바른 설명이다.", "3": "진단·평가 시 보호자의 사전 서면 동의가 필요하며, 이는 특수교육대상자의 권리보호를 위한 절차적 요건이다."}',2,'KICE 기출 기반','{"category": "법령"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('laws-q74','laws','strategies','fill_in','「장애인차별금지 및 권리구제 등에 관한 법률」에 따르면, 교육기관은 장애인이 교육활동에 불이익이 없도록 (   )을/를 제공하여야 한다.',NULL,NULL,'정당한 편의','「장애인차별금지 및 권리구제 등에 관한 법률」 제14조에 따르면, 교육기관은 해당 교육기관에 재학 중인 장애인의 교육활동에 불이익이 없도록 정당한 편의를 제공하여야 한다. 정당한 편의에는 교육보조인력 배치, 교재·교구의 수정 및 보완, 시험시간 연장, 보조공학기기 제공, 교육과정 및 평가방법의 조정 등이 포함된다. 정당한 편의 제공 거부는 차별행위에 해당한다.',NULL,2,'교재 참고','{"category": "법령"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('laws-q75','laws','theory','ox','「장애인 등에 대한 특수교육법」에 따르면, 특수교육대상자가 일반학교에 배치된 경우 해당 학교의 장은 특수교육대상자 수에 관계없이 반드시 특수학급을 설치하여야 한다.',NULL,NULL,'X','「장애인 등에 대한 특수교육법」 제21조 제2항에 따르면, 대통령령이 정하는 일정 수 이상의 특수교육대상자가 배치된 일반학교의 장은 특수학급을 설치하여야 한다. 즉, 모든 경우에 반드시 설치해야 하는 것이 아니라 일정 기준 이상의 특수교육대상자가 배치된 경우에 설치 의무가 발생한다. 소수의 특수교육대상자가 배치된 경우에는 특수학급 없이 통합학급에서 교육받을 수 있다.',NULL,2,'KICE 기출 기반','{"category": "법령"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('laws-q76','laws','practices','descriptive','「장애인 등에 대한 특수교육법」에 따른 개별화교육계획(IEP)에 포함되어야 하는 법정 기재사항을 5가지 이상 서술하고, 개별화교육지원팀의 구성원을 설명하시오.',NULL,NULL,'개별화교육계획에 포함되어야 하는 법정 기재사항은 다음과 같다. 첫째, 대상 학생의 인적사항이다. 둘째, 특별한 교육지원이 필요한 영역의 현재 학습 수행수준이다. 셋째, 교육목표이다. 넷째, 교육내용이다. 다섯째, 교육방법이다. 여섯째, 평가계획이다. 일곱째, 제공할 특수교육 관련서비스의 내용과 방법이다. 개별화교육지원팀은 보호자, 특수교육교원, 일반교육교원, 진로 및 직업교육 담당 교원, 특수교육 관련서비스 담당 인력 등으로 구성된다. 학교의 장은 특수교육대상자가 배치된 날로부터 2주일 이내에 개별화교육지원팀을 구성하고, 매 학기 시작일로부터 30일 이내에 개별화교육계획을 작성하여야 한다.','개별화교육계획에 포함되어야 하는 법정 기재사항은 다음과 같다. 첫째, 대상 학생의 인적사항이다. 둘째, 특별한 교육지원이 필요한 영역의 현재 학습 수행수준이다. 셋째, 교육목표이다. 넷째, 교육내용이다. 다섯째, 교육방법이다. 여섯째, 평가계획이다. 일곱째, 제공할 특수교육 관련서비스의 내용과 방법이다. 개별화교육지원팀은 보호자, 특수교육교원, 일반교육교원 (자동 생성 해설)',NULL,3,'KICE 기출 기반','{"category": "법령"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('laws-q77','laws','strategies','multiple','「장애인 등에 대한 특수교육법」에 따른 전환교육에 대한 설명으로 올바른 것은?',NULL,ARRAY['전환교육은 초등학교부터 실시한다','전환교육 계획은 개별화교육계획에 포함하여 작성한다','전환교육은 직업교육만을 의미한다','전환교육은 특수학교에서만 실시할 수 있다'],'2','「장애인 등에 대한 특수교육법」 제23조에 따르면, 중학교 과정 이상의 각급학교의 장은 특수교육대상자의 특성 및 요구에 맞는 전환교육 계획을 수립하여 개별화교육계획에 포함하여야 한다. 전환교육은 단순한 직업교육만이 아니라 진로·직업교육을 포함한 사회 적응과 자립생활을 위한 포괄적인 교육을 의미한다. 전환교육은 특수학교뿐만 아니라 일반학교에 배치된 특수교육대상자에게도 실시해야 한다.','{"1": "전환교육은 초등학교부터가 아니라 중학교 과정 이상부터 실시하도록 규정되어 있다.", "3": "전환교육은 직업교육만을 의미하는 것이 아니라, 사회 적응 훈련, 자립생활 훈련, 진로교육 등 포괄적인 교육을 포함한다.", "4": "전환교육은 특수학교에서만 실시하는 것이 아니라, 특수교육대상자가 배치된 모든 중학교 이상 각급학교에서 실시한다."}',2,'KICE 기출 기반','{"category": "법령"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('laws-q31','laws','theory','fill_in','「장애인 등에 대한 특수교육법」 제15조에 따르면, 특수교육대상자의 선정은 ( )의 진단·평가 결과를 기초로 하여 시·도 교육감 또는 교육장이 결정한다. 빈칸에 들어갈 기관을 쓰시오.',NULL,NULL,'특수교육지원센터','특수교육법 제15조 제1항에 따르면, 교육장 또는 교육감은 특수교육지원센터의 진단·평가 결과를 기초로 특수교육대상자를 선정한다. 특수교육지원센터는 진단·평가를 의뢰받은 후 30일 이내에 진단·평가를 시행하여야 한다.',NULL,2,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('laws-q32','laws','theory','multiple','「장애인 등에 대한 특수교육법」 제17조(특수교육대상자의 배치)에 관한 설명으로 옳지 않은 것은?',NULL,ARRAY['교육장 또는 교육감은 특수교육대상자를 일반학교의 일반학급, 일반학교의 특수학급, 특수학교에 배치할 수 있다.','특수교육대상자의 배치는 특수교육대상자의 장애 정도에 따라 특수학교를 우선적으로 고려하여야 한다.','교육장 또는 교육감은 특수교육대상자를 배치할 때 해당 학교의 장과 특수교육대상자에게 각각 통보하여야 한다.','특수교육대상자의 배치 시 특수교육운영위원회의 심사를 거쳐야 한다.'],'2','특수교육법 제17조에 따르면, 특수교육대상자의 배치는 일반학교의 일반학급에 우선 배치하는 통합교육을 원칙으로 한다. 장애 정도에 따라 특수학교를 우선 고려하는 것은 법의 취지에 반한다. 일반학급 → 특수학급 → 특수학교의 최소제한환경(LRE) 원칙을 따른다.','{"1": "제17조 제1항에 명시된 배치 유형으로 정확하다.", "3": "제17조 제2항에 따라 해당 학교의 장과 특수교육대상자에게 통보한다.", "4": "제17조에 따라 배치 시 특수교육운영위원회의 심사를 거쳐야 한다."}',2,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('laws-q33','laws','practices','descriptive','「장애인 등에 대한 특수교육법」 제22조에 규정된 개별화교육계획(IEP)에 대해 다음 세 가지를 서술하시오: (1) 작성 의무 시기, (2) 개별화교육지원팀의 구성원 3인 이상, (3) IEP에 반드시 포함되어야 할 내용 3가지 이상.',NULL,NULL,'(1) 매 학년의 시작일로부터 2주 이내에 개별화교육지원팀을 구성하고, 30일 이내에 개별화교육계획을 작성하여야 한다. (2) 구성원: 보호자, 특수교육교원, 일반교육교원, 진로 및 직업교육 담당 교원, 특수교육 관련서비스 담당 인력 등. (3) 포함 내용: 특수교육대상자의 인적사항, 현재 학습 수행수준, 교육목표, 교육내용, 교육방법, 평가계획, 특수교육 관련서비스의 내용과 방법 등.','특수교육법 제22조에 따라 각급학교의 장은 매 학년 시작일부터 2주 이내에 개별화교육지원팀을 구성하고, 1개월(30일) 이내에 IEP를 작성해야 한다. 개별화교육지원팀은 보호자, 특수교육교원, 일반교육교원, 진로 및 직업교육 담당 교원, 관련서비스 담당 인력 등으로 구성된다.',NULL,3,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('laws-q34','laws','practices','fill_in','「장애인 등에 대한 특수교육법」 제28조에 따른 특수교육 관련서비스에는 상담지원, 가족지원, ( ① )지원, 보조인력지원, 보조공학기기지원, 통학지원, ( ② )지원이 포함된다. ①과 ②를 순서대로 쓰시오.',NULL,NULL,'① 치료, ② 의료적','특수교육법 제28조에 명시된 특수교육 관련서비스 7종: 상담지원, 가족지원, 치료지원, 보조인력지원, 보조공학기기지원, 통학지원, 의료적 지원. 2026 개정에서 의료적 지원이 강조되고 있으며, 건강장애 학생 등에게 제공된다.',NULL,2,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('laws-q35','laws','practices','ox','「장애인 등에 대한 특수교육법 시행령」 제29조에 따르면, 병원학교에서의 수업은 교육과정의 운영상 필요한 경우 한 교시의 수업시간을 40분으로 운영할 수 있다.',NULL,NULL,'X','시행령 제29조에 따르면 병원학교 및 원격수업에서의 한 교시 수업시간은 30분을 원칙으로 한다(40분이 아님). 건강장애 학생의 체력적 한계를 고려하여 일반학교(초 40분, 중 45분, 고 50분)보다 짧게 운영한다.',NULL,2,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('laws-q36','laws','strategies','descriptive','특수교육지원센터의 주요 역할 3가지를 법적 근거와 함께 서술하시오.',NULL,NULL,'특수교육지원센터의 주요 역할: (1) 진단·평가: 특수교육법 제16조에 따라 특수교육대상자에 대한 진단·평가를 실시한다. (2) 순회교육: 특수교육법 제25조에 따라 일반학교에서 통합교육을 받고 있는 특수교육대상자를 지원하기 위해 순회교육을 실시한다. (3) 특수교육 관련서비스 제공: 제28조에 따라 상담지원, 가족지원, 치료지원 등 관련서비스를 제공한다.','특수교육지원센터는 특수교육법 제11조에 근거하여 설치되며, 진단·평가(제16조), 순회교육(제25조), 관련서비스 제공(제28조) 등의 역할을 수행한다. 또한 특수교육대상자 및 보호자에 대한 정보 제공, 특수교육교원 연수 지원 등의 기능도 한다.',NULL,3,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('laws-q37','laws','strategies','ox','「장애인복지법」에서는 장애를 15종으로 분류하고, 「장애인 등에 대한 특수교육법」에서는 장애를 10종으로 분류한다.',NULL,NULL,'O','장애인복지법은 지체, 뇌병변, 시각, 청각, 언어, 지적, 자폐성, 정신, 신장, 심장, 호흡기, 간, 안면, 장루·요루, 뇌전증 등 15종으로 분류한다. 특수교육법은 시각장애, 청각장애, 지적장애, 지체장애, 정서·행동장애, 자폐성장애, 의사소통장애, 학습장애, 건강장애, 발달지체 등 10종으로 분류한다.',NULL,2,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('trans-q31','transition','theory','fill_in','전환교육의 4가지 핵심 구성요소(영역)는 교육, ( ① ), 일상생활, ( ② )이다. ①과 ②를 순서대로 쓰시오.',NULL,NULL,'① 고용, ② 지역사회참여','전환교육의 4대 영역은 교육(education), 고용(employment), 일상생활(daily living), 지역사회참여(community participation)이다. 이는 Halpern(1985)의 모델에 기반하며, 학교에서 성인생활로의 성공적 전환을 위해 이 네 영역에서의 종합적인 지원이 필요하다.',NULL,1,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('trans-q32','transition','theory','descriptive','Wehmeyer의 자기결정(self-determination) 모델에서 제시한 자기결정의 4가지 본질적 특성을 모두 쓰고, 각각을 한 문장으로 설명하시오.',NULL,NULL,'(1) 자율성(autonomy): 자신의 선호와 흥미에 따라 독립적으로 행동하는 것. (2) 자기조절(self-regulation): 자신의 행동을 점검하고 평가하여 조절하는 것. (3) 심리적 역량강화(psychological empowerment): 자신이 통제력을 가지고 있다고 믿는 것. (4) 자기실현(self-realization): 자신의 강점과 약점을 정확히 파악하고 활용하는 것.','Wehmeyer(1999)는 자기결정을 ''자신의 삶의 주된 주체로 행동하고, 외부의 부당한 영향이나 간섭 없이 자신의 삶의 질을 유지·향상시키는 선택과 결정을 하는 것''으로 정의했다. 4가지 본질적 특성(essential characteristics)은 자율성, 자기조절, 심리적 역량강화, 자기실현이다.',NULL,3,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('trans-q33','transition','theory','multiple','자기옹호(self-advocacy)의 구성요소에 해당하지 않는 것은?',NULL,ARRAY['자기지식(knowledge of self)','권리 인식(knowledge of rights)','자기강화(self-reinforcement)','의사소통(communication)'],'3','자기옹호의 구성요소는 자기지식(knowledge of self), 권리 인식(knowledge of rights), 의사소통(communication), 리더십(leadership)이다. 자기강화(self-reinforcement)는 자기관리(self-management) 전략의 구성요소에 해당하며, 자기옹호의 구성요소가 아니다.','{"1": "자기옹호의 핵심 구성요소로, 자신의 강점·약점·필요를 이해하는 것이다.", "2": "자기옹호의 핵심 구성요소로, 자신이 가진 법적·교육적 권리를 아는 것이다.", "4": "자기옹호의 핵심 구성요소로, 자신의 요구를 효과적으로 표현하는 것이다."}',2,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('trans-q34','transition','practices','fill_in','직업평가의 유형 중 ( )은/는 실제 또는 모의 작업환경에서 다양한 직무를 수행하게 하면서 작업 태도, 대인관계, 작업 속도, 작업의 질 등을 체계적으로 관찰·평가하는 방법이다.',NULL,NULL,'상황평가','직업평가의 유형에는 심리검사(표준화 검사), 작업표본평가, 상황평가, 현장평가가 있다. 상황평가(situational assessment)는 실제 또는 모의 작업환경에서 직무를 수행하게 하면서 행동을 관찰·평가하는 방법으로, 표준화 검사로 측정하기 어려운 작업 습관, 대인관계 등을 파악할 수 있다.',NULL,2,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('trans-q35','transition','practices','descriptive','지역사회 기반 교수(CBI: Community-Based Instruction)의 정의를 쓰고, 교실 기반 교수와 비교하여 CBI의 장점 2가지를 서술하시오.',NULL,NULL,'정의: CBI는 학교가 아닌 실제 지역사회 환경(마트, 은행, 대중교통 등)에서 기능적 기술을 직접 교수하는 방법이다. 장점: (1) 일반화 촉진: 실제 환경에서 학습하므로 교실에서 배운 기술을 다른 환경으로 일반화하는 어려움을 줄일 수 있다. (2) 자연적 단서와 결과 활용: 실제 환경의 자연적 자극과 강화를 활용하여 보다 기능적이고 유의미한 학습이 이루어진다.','CBI는 Brown 등(1983)이 제안한 접근으로, 중도장애 학생의 일반화 문제를 해결하기 위해 실제 환경에서 교수하는 것이 핵심이다. 교실 모의학습은 일반화가 어렵고 자연적 맥락이 부족하다는 한계가 있다.',NULL,3,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('trans-q36','transition','strategies','fill_in','개별화전환교육계획(ITP)은 미국 IDEA에서는 만 ( ① )세부터 작성하도록 규정하고 있으며, 한국에서는 특수교육법 시행규칙에 따라 ( ② )학교 과정부터 IEP에 전환교육 내용을 포함하도록 한다. ①과 ②를 쓰시오.',NULL,NULL,'① 16, ② 중학','미국 IDEA 2004에서는 만 16세부터(주에 따라 14세부터) IEP에 전환서비스 관련 내용을 포함하도록 규정한다. 한국에서는 특수교육법 시행규칙에 따라 중학교 과정부터 개별화교육계획에 전환교육 관련 내용을 포함하여야 한다.',NULL,2,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('trans-q37','transition','strategies','descriptive','지원고용(supported employment)의 정의를 쓰고, 지원고용의 핵심 요소인 ''직무코치''와 ''자연적 지원''의 역할을 각각 설명하시오.',NULL,NULL,'정의: 지원고용은 중증장애인이 경쟁고용 환경에서 비장애인과 함께 일하면서 지속적인 지원을 받는 고용 형태이다. 직무코치(job coach): 장애인의 직무 수행을 직접적으로 지원하며, 직무 분석, 과제 분석, 체계적 교수를 통해 직업기술을 훈련시키고, 점차적으로 지원을 소거한다. 자연적 지원(natural supports): 직장 동료나 상사가 일상적인 업무 환경 속에서 자연스럽게 제공하는 도움으로, 직무코치의 지원을 점차 대체하여 고용 유지와 직장 통합을 촉진한다.','지원고용은 ''먼저 배치하고, 그 다음에 훈련한다(place-then-train)''는 원칙에 기반한다. 직무코치가 초기 집중지원을 제공한 후 자연적 지원으로 전환하는 것이 핵심 전략이다. 이는 보호작업장 등의 분리된 환경과 대비되는 통합적 접근이다.',NULL,3,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('asmnt-q31','assessment','theory','fill_in','NISE-K·ABS(국립특수교육원 적응행동검사)는 적응행동을 3개 하위영역으로 측정한다. 이 3개 영역은 ( ① )적 적응행동, ( ② )적 적응행동, ( ③ )적 적응행동이다. 순서대로 쓰시오.',NULL,NULL,'① 개념, ② 사회, ③ 실제','NISE-K·ABS는 AAIDD의 적응행동 개념 모델에 기반하여 개념적(conceptual: 언어, 읽기·쓰기, 돈 개념 등), 사회적(social: 대인관계, 규칙 준수, 자존감 등), 실제적(practical: 일상생활활동, 직업기술, 안전 등) 적응행동의 3개 하위영역으로 구성된다.',NULL,2,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('asmnt-q32','assessment','theory','multiple','K-WISC-V(한국 웩슬러 아동지능검사 5판)의 5개 기본지표에 해당하지 않는 것은?',NULL,ARRAY['언어이해(Verbal Comprehension)','시공간(Visual Spatial)','유동추론(Fluid Reasoning)','장기기억(Long-term Memory)'],'4','K-WISC-V의 5개 기본지표(Primary Index)는 언어이해(VCI), 시공간(VSI), 유동추론(FRI), 작업기억(WMI), 처리속도(PSI)이다. 장기기억은 K-WISC-V의 기본지표에 포함되지 않는다. K-WISC-V는 K-WISC-IV의 지각추론지표를 시공간과 유동추론으로 분리한 것이 주요 변화이다.','{"1": "K-WISC-V의 5개 기본지표 중 하나로, 어휘, 공통성 등의 소검사로 구성된다.", "2": "K-WISC-V의 5개 기본지표 중 하나로, 토막짜기 등의 소검사로 구성된다.", "3": "K-WISC-V의 5개 기본지표 중 하나로, 행렬추론, 무게비교 등으로 구성된다."}',2,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('asmnt-q33','assessment','theory','ox','NISE-B·ACT(기초학력검사)는 읽기, 쓰기, 수학의 3개 영역으로 구성되며, 동형검사를 제공하여 사전-사후 비교가 가능하다.',NULL,NULL,'O','NISE-B·ACT(국립특수교육원 기초학력검사)는 읽기, 쓰기, 수학의 3개 영역으로 구성된 개인검사이다. A형과 B형의 동형검사(parallel form)를 제공하여 사전-사후 검사 비교 시 연습효과를 통제할 수 있다는 장점이 있다.',NULL,1,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('asmnt-q34','assessment','practices','descriptive','규준참조검사(norm-referenced test)와 준거참조검사(criterion-referenced test)를 비교하여, (1) 검사의 목적, (2) 점수 해석 방법, (3) 특수교육 현장에서의 활용 예시를 각각 서술하시오.',NULL,NULL,'(1) 목적 - 규준참조: 개인의 수행을 같은 연령/학년 집단과 비교하여 상대적 위치를 파악. 준거참조: 사전에 설정된 교육 목표나 기준에 비추어 학생이 무엇을 할 수 있는지 파악. (2) 해석 - 규준참조: 백분위, 표준점수, 학력지수 등으로 해석. 준거참조: 도달/미도달, 숙달/미숙달 등으로 해석. (3) 활용 - 규준참조: K-WISC-V, NISE-K·ABS 등 진단·선별 시 활용. 준거참조: 교육과정중심측정(CBM), IEP 목표 달성도 평가 시 활용.','규준참조검사는 ''누가 더 잘하는가''에, 준거참조검사는 ''무엇을 할 수 있는가''에 초점을 둔다. 특수교육에서는 선정·배치 단계에서 규준참조검사를, 교수·학습 계획 및 진전도 모니터링에서 준거참조검사를 주로 활용한다.',NULL,3,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('asmnt-q35','assessment','practices','fill_in','지능검사에서 전체 IQ의 평균은 ( ① )이고 표준편차는 ( ② )이다. 전체 IQ 70 이하(평균에서 표준편차 2 이하)는 지적장애 진단의 지적 기능 기준으로 활용된다. ①과 ②를 쓰시오.',NULL,NULL,'① 100, ② 15','웩슬러 지능검사(K-WISC-V 등)에서 전체 IQ는 평균 100, 표준편차 15의 정규분포를 따른다. IQ 70은 평균에서 -2SD에 해당하며, AAIDD와 DSM-5에서 지적장애의 지적 기능 기준(IQ 약 70 이하)으로 활용된다. 단, 지적 기능만으로 진단하지 않고 적응행동의 제한도 함께 고려해야 한다.',NULL,2,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('asmnt-q36','assessment','strategies','descriptive','RTI(중재반응모델)의 3단계를 각각 설명하고, 각 단계에서의 대상 학생 비율과 교수 방법의 특성을 서술하시오.',NULL,NULL,'1단계(보편적 교수): 전체 학생(약 80%)을 대상으로 과학적으로 검증된 핵심교육과정을 일반교실에서 제공한다. 보편적 선별검사로 진전도를 모니터링한다. 2단계(소그룹 중재): 1단계에서 충분한 진전을 보이지 않는 학생(약 15%)을 대상으로 소그룹(3~5명) 보충교수를 제공한다. 주 2~3회, 20~40분의 표적화된 중재를 실시한다. 3단계(개별 집중 중재): 2단계에서도 충분한 반응을 보이지 않는 학생(약 5%)을 대상으로 개별화된 집중 중재를 제공한다. 빈도와 강도를 높여 매일, 개별 또는 1:2로 실시하며, 이 단계에서 특수교육 의뢰를 고려한다.','RTI는 학습장애 판별의 대안적 모델로, 기존의 능력-성취 불일치 모델의 한계를 보완한다. 단계적으로 중재의 강도를 높이면서 학생의 반응을 모니터링하고, 충분한 중재에도 반응하지 않는 학생을 학습장애로 판별할 수 있다. 진전도 모니터링(progress monitoring)은 RTI의 핵심 요소이다.',NULL,3,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('pd-q21','physical-disability','cp-types','multiple','뇌성마비 유형 중 근긴장도가 증가하여 근육이 뻣뻣해지고, 관절의 가동범위가 제한되며, 빠른 수동적 신전(stretch) 시 저항이 증가하는 특성을 보이는 유형은?',NULL,ARRAY['경직형(spastic type)','불수의운동형(dyskinetic type)','실조형(ataxic type)','저긴장형(hypotonic type)'],'1','경직형 뇌성마비는 상위운동신경원 손상으로 인해 근긴장도가 비정상적으로 증가하는 것이 핵심 특성입니다. 빠른 수동적 신전 시 속도 의존적 저항(velocity-dependent resistance)이 나타나며, 이를 경직(spasticity)이라 합니다. 뇌성마비의 약 70~80%를 차지하는 가장 흔한 유형으로, 대뇌피질 또는 피질척수로(corticospinal tract)의 손상과 관련됩니다. 근육의 과긴장으로 인해 관절 구축과 변형이 발생할 수 있어 조기 중재가 중요합니다.','{"2": "불수의운동형은 근긴장도가 변동하며, 의도하지 않은 비자발적 움직임이 특징입니다. 근긴장도 증가가 주된 특성이 아닙니다.", "3": "실조형은 소뇌 손상으로 인해 균형과 협응에 어려움을 보이며, 근긴장도 증가보다는 운동 조절의 부정확성이 특징입니다.", "4": "저긴장형은 근긴장도가 오히려 감소되어 있어 축 늘어진(floppy) 모습을 보이므로, 근긴장도 증가와는 반대되는 특성입니다."}',1,'KICE 기출 기반','{"disability": "지체장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('pd-q22','physical-disability','cp-types','ox','불수의운동형(dyskinetic type) 뇌성마비는 대뇌 기저핵(basal ganglia) 손상과 관련이 있으며, 아테토시스(athetosis)와 같은 불수의적 움직임이 특징적이다.',NULL,NULL,'O','불수의운동형 뇌성마비는 대뇌 기저핵(basal ganglia)의 손상으로 발생합니다. 아테토시스(athetosis)는 느리고 구불구불한 불수의적 움직임으로, 주로 사지의 원위부에서 나타납니다. 이 유형의 아동은 근긴장도가 변동(fluctuating tone)하는 특성을 보이며, 수면 시에는 불수의적 움직임이 사라집니다. 정서적 흥분이나 긴장 상태에서 불수의 움직임이 증가하는 경향이 있어 안정적인 학습환경 조성이 중요합니다.',NULL,1,'교재 참고','{"disability": "지체장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('pd-q23','physical-disability','cp-types','fill_in','뇌성마비의 마비 부위별 분류에서, 양쪽 하지가 주로 마비되고 상지는 비교적 경미하게 영향을 받는 유형을 ( )(이)라 한다.',NULL,NULL,'양하지마비(diplegia)','양하지마비(diplegia)는 사지가 모두 영향을 받지만 하지가 상지보다 현저하게 더 심한 마비를 보이는 유형입니다. 경직형 뇌성마비에서 가장 흔하며, 미숙아에서 발생하는 뇌실주위 백질연화증(periventricular leukomalacia)과 관련이 깊습니다. 이 아동들은 대개 상지 기능이 비교적 보존되어 학습도구 사용이 가능하지만, 보행 시 가위걸음(scissoring gait) 패턴을 보이는 경우가 많습니다. 조기 물리치료와 적절한 보조기기 활용이 이동 능력 향상에 도움이 됩니다.',NULL,2,'KICE 기출 기반','{"disability": "지체장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('pd-q24','physical-disability','cp-types','descriptive','경직형, 불수의운동형, 실조형 뇌성마비의 손상 부위와 주요 운동 특성을 각각 비교하여 설명하시오.',NULL,NULL,'경직형은 대뇌피질 또는 피질척수로 손상으로 인해 근긴장도가 증가하고, 속도 의존적 저항이 나타나며, 관절 구축과 변형이 발생할 수 있다. 불수의운동형은 기저핵 손상으로 근긴장도가 변동하며, 아테토시스나 디스토니아 같은 불수의적 움직임이 특징이고, 정서 상태에 따라 움직임이 변화한다. 실조형은 소뇌 손상으로 균형과 협응에 어려움을 보이며, 의도떨림(intention tremor), 측정이상(dysmetria), 넓은 보폭의 보행(wide-based gait)이 특징적이다.','세 유형은 손상 부위가 각각 다르기 때문에 구별되는 운동 특성을 보입니다. 경직형은 피라미드계(pyramidal system) 손상으로 근긴장도 증가가 핵심이며, 전체 뇌성마비의 약 70~80%를 차지합니다. 불수의운동형은 추체외로계(extrapyramidal system)인 기저핵 손상으로 근긴장도의 변동과 불수의적 움직임이 나타나며, 핵황달(kernicterus)과 관련이 깊습니다. 실조형은 소뇌 손상으로 운동의 정확성과 균형 유지에 어려움을 보이며, 가장 드문 유형입니다.',NULL,3,'교재 참고','{"disability": "지체장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('pd-q25','physical-disability','gmfcs','multiple','대운동기능분류체계(GMFCS)에서 실내외 보행이 가능하고 계단 오르기가 가능하지만, 달리기나 점프에 제한이 있는 수준은?',NULL,ARRAY['GMFCS 수준 I','GMFCS 수준 II','GMFCS 수준 III','GMFCS 수준 IV'],'2','GMFCS 수준 II의 아동은 실내외에서 보행이 가능하고 난간을 잡고 계단을 오를 수 있지만, 달리기와 점프와 같은 대운동 기능에 제한을 보입니다. 수준 I이 제한 없이 보행하는 것과 달리, 수준 II는 질적인 차이가 있어 불안정한 표면이나 경사면에서 어려움을 경험합니다. 장거리 보행 시 피로감을 느낄 수 있으며, 학교 환경에서 체육 활동 참여 시 활동 수정이 필요할 수 있습니다. GMFCS는 6세 이전과 이후의 기능을 구분하여 기술합니다.','{"1": "GMFCS 수준 I은 보행에 제한이 없으며, 달리기와 점프가 가능합니다. 속도와 균형에 약간의 제한이 있을 수 있으나 일상적 대운동 활동에 참여합니다.", "3": "GMFCS 수준 III은 보조 이동기기(워커, 목발 등)를 사용하여 실내 보행이 가능한 수준이며, 독립적인 실외 보행에 어려움이 있습니다.", "4": "GMFCS 수준 IV는 전동 휠체어나 타인의 도움을 통해 이동하며, 체간 조절이 제한되어 자세 보조 장치가 필요합니다."}',2,'KICE 기출 기반','{"disability": "지체장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('pd-q26','physical-disability','gmfcs','ox','GMFCS 수준 V의 아동은 전동 휠체어를 독립적으로 조작하여 이동할 수 있으며, 머리와 체간의 항중력 자세 조절이 가능하다.',NULL,NULL,'X','GMFCS 수준 V는 가장 중증으로, 모든 환경에서 수동 휠체어로 이동하며 타인에 의해 운반됩니다. 머리와 체간의 항중력(antigravity) 자세 조절에 심한 제한이 있어 틸트형 휠체어나 특수 자세유지장치가 필요합니다. 전동 휠체어의 독립적 조작은 수준 IV에서 시도될 수 있으며, 수준 V에서는 대부분 독립적 이동수단 조작이 어렵습니다. 수준 V의 아동은 일상생활의 모든 영역에서 전적인 지원이 필요합니다.',NULL,2,'교재 참고','{"disability": "지체장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('pd-q27','physical-disability','gmfcs','fill_in','GMFCS 수준 III의 아동은 실내에서 ( )와/과 같은 보조 이동기기를 사용하여 보행하며, 실외 및 지역사회에서는 휠체어를 사용한다.',NULL,NULL,'워커(walker)','GMFCS 수준 III에서는 워커(walker), 목발(crutches) 등의 보조 이동기기를 사용하여 실내 보행이 가능합니다. 그러나 장거리 이동이나 울퉁불퉁한 지면에서는 휠체어를 사용합니다. 이 수준의 아동은 앉은 자세에서 독립적으로 앉기가 가능하지만 바닥에서 일어서기 위해 도움이 필요할 수 있습니다. 학교 환경에서는 교실 내 이동은 워커로, 교실 간 이동은 휠체어를 사용하는 이중 이동 방식이 흔합니다.',NULL,1,'KICE 기출 기반','{"disability": "지체장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('pd-q28','physical-disability','gmfcs','descriptive','GMFCS 수준 I부터 수준 V까지 각 수준의 6~12세 아동의 이동 능력 특성을 간략히 서술하시오.',NULL,NULL,'수준 I: 실내외에서 독립 보행이 가능하며 달리기와 점프도 가능하나 속도와 균형에 약간의 제한이 있다. 수준 II: 실내외 독립 보행이 가능하나 달리기와 점프에 제한이 있고, 불안정한 표면에서 어려움이 있다. 수준 III: 워커 등 보조기기를 이용해 실내 보행이 가능하며, 실외에서는 휠체어를 사용한다. 수준 IV: 자기 이동이 제한되어 휠체어를 사용하며, 전동 휠체어 조작을 학습할 수 있고, 체간 지지가 필요하다. 수준 V: 모든 환경에서 수동 휠체어로 타인에 의해 이동하며, 머리와 체간의 항중력 자세 조절이 심하게 제한된다.','GMFCS(Gross Motor Function Classification System)는 Palisano 등(1997)이 개발한 뇌성마비 아동의 대운동기능 분류체계입니다. 5단계로 구분되며, 연령대별로 기능 수준을 기술합니다. 수준 간의 차이는 기능적 제한의 정도와 보조기기 의존도에 따라 구분됩니다. GMFCS는 예후 예측과 치료 목표 설정에 중요한 도구이며, 특수교육 현장에서 교육적 지원 수준을 결정하는 데 활용됩니다. 각 수준은 고정적이지 않으며, 아동의 성장에 따라 변화할 수 있습니다.',NULL,3,'교재 참고','{"disability": "지체장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('pd-q29','physical-disability','primitive-reflexes','multiple','영아의 머리를 한쪽으로 돌렸을 때, 얼굴 쪽 팔다리는 펴지고 뒤통수 쪽 팔다리는 굽혀지는 반사는?',NULL,ARRAY['모로반사(Moro reflex)','비대칭 긴장성 경반사(ATNR)','대칭 긴장성 경반사(STNR)','긴장성 미로반사(TLR)'],'2','비대칭 긴장성 경반사(ATNR: Asymmetric Tonic Neck Reflex)는 머리를 한쪽으로 돌렸을 때 얼굴 쪽 사지는 신전(extension)되고 후두부 쪽 사지는 굴곡(flexion)되는 반사입니다. 흔히 ''펜싱 자세(fencer''s pose)''라고 불립니다. 정상적으로 출생 시 나타나 생후 4~6개월에 통합(integration)되지만, 뇌성마비 아동에서는 지속될 수 있습니다. ATNR이 지속되면 손-눈 협응, 중앙선 활동, 양손 사용에 어려움이 생겨 읽기와 쓰기 학습에 영향을 미칩니다.','{"1": "모로반사는 갑작스러운 자극(큰 소리, 자세 변화 등)에 의해 양팔을 벌렸다가 안으로 끌어안는 동작으로 나타나며, 머리 회전과 관련된 반사가 아닙니다.", "3": "대칭 긴장성 경반사(STNR)는 머리를 굴곡하면 상지 굴곡/하지 신전, 머리를 신전하면 상지 신전/하지 굴곡이 나타나는 반사입니다.", "4": "긴장성 미로반사(TLR)는 앙와위에서 전신 신전, 복와위에서 전신 굴곡이 나타나는 반사로, 머리 회전이 아닌 중력에 대한 머리 위치에 의해 유발됩니다."}',1,'KICE 기출 기반','{"disability": "지체장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('pd-q30','physical-disability','primitive-reflexes','ox','대칭 긴장성 경반사(STNR)가 지속되는 아동은 네발기기(crawling) 자세 유지에 어려움을 겪을 수 있다.',NULL,NULL,'O','대칭 긴장성 경반사(STNR)는 머리의 굴곡·신전에 따라 상지와 하지의 긴장 패턴이 반대로 나타나는 반사입니다. 머리를 숙이면 상지 굴곡/하지 신전, 머리를 들면 상지 신전/하지 굴곡이 유발됩니다. 이 반사가 지속되면 네발기기 시 머리를 들어 앞을 보려 할 때 팔이 펴지고 다리가 굽혀져 자세가 무너집니다. 정상적으로 생후 6~8개월에 나타나 9~12개월에 통합되며, 지속 시 자세 전환과 이동 발달에 심각한 영향을 줍니다.',NULL,2,'교재 참고','{"disability": "지체장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('pd-q31','physical-disability','primitive-reflexes','fill_in','갑작스러운 큰 소리나 머리 위치의 급격한 변화에 의해 양팔을 벌렸다가 안으로 끌어안는 동작이 나타나는 원시반사를 ( )반사라 한다.',NULL,NULL,'모로(Moro)','모로반사(Moro reflex)는 갑작스러운 자극에 의해 유발되는 원시반사로, 1단계에서 양팔을 외전(abduction)하며 벌리고 손가락을 펴는 동작이 나타나고, 2단계에서 양팔을 안으로 끌어안는 내전(adduction) 동작이 뒤따릅니다. 정상적으로 출생 시 나타나 생후 4~6개월에 통합됩니다. 모로반사가 지속되면 아동은 소음에 과민하고, 갑작스러운 자세 변화에 놀라며, 균형 반응 발달에 영향을 줍니다. 교실 환경에서 예기치 않은 소리에 과도한 경악 반응을 보일 수 있어 안정적인 환경 제공이 중요합니다.',NULL,1,'KICE 기출 기반','{"disability": "지체장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('pd-q32','physical-disability','primitive-reflexes','descriptive','긴장성 미로반사(TLR)의 유발 자극, 반응 패턴, 통합 시기를 설명하고, 이 반사가 지속될 때 아동의 기능에 미치는 영향을 서술하시오.',NULL,NULL,'긴장성 미로반사(TLR)는 중력에 대한 머리 위치 변화에 의해 유발된다. 앙와위(바로 누운 자세)에서는 전신 신전 패턴이, 복와위(엎드린 자세)에서는 전신 굴곡 패턴이 나타난다. 정상적으로 출생 시 나타나 생후 6개월경 통합된다. TLR이 지속되면 앙와위에서 머리를 들거나 앉는 것이 어렵고, 복와위에서 팔로 지지하며 머리를 드는 것이 어렵다. 이로 인해 구르기, 앉기, 서기 등 항중력 자세 발달이 지연되며, 균형 능력과 공간 지각 발달에도 부정적 영향을 미친다.','긴장성 미로반사(TLR: Tonic Labyrinthine Reflex)는 미로기관(전정기관)에서 감지하는 머리의 공간 위치에 의해 유발됩니다. 앙와위에서 신전 패턴이 우세하여 후궁반장(opisthotonus)이 나타날 수 있고, 복와위에서는 굴곡 패턴이 우세하여 머리와 사지를 바닥에서 들어올리기 어렵습니다. TLR 지속은 항중력 자세 조절의 기초가 되는 머리 조절(head control) 발달을 방해합니다. 교실에서는 적절한 자세 보조 장치를 통해 안정적인 자세를 확보해야 학습 활동 참여가 가능합니다.',NULL,3,'교재 참고','{"disability": "지체장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('pd-q33','physical-disability','positioning','multiple','경직형 뇌성마비 아동의 앉은 자세를 지원할 때, 골반의 안정성 확보를 위해 가장 먼저 고려해야 하는 보조기기 요소는?',NULL,ARRAY['머리 지지대(headrest)','골반 벨트(pelvic belt)','발판(footrest)','외측 체간 지지대(lateral trunk support)'],'2','앉은 자세에서의 자세 보조는 ''아래에서 위로(bottom-up)'' 원칙을 따릅니다. 골반은 앉은 자세의 기초(base of support)이므로, 골반의 안정적 위치 확보가 가장 우선시됩니다. 골반 벨트는 45도 각도로 골반을 좌석 뒤쪽에 밀착시켜 골반의 전방 미끄러짐(anterior sliding)을 방지합니다. 골반이 안정되어야 체간과 머리의 조절이 향상되므로, 다른 지지대보다 먼저 적용해야 합니다. 이후 체간 지지, 발판, 머리 지지 순서로 추가합니다.','{"1": "머리 지지대는 머리 조절이 어려운 아동에게 필요하지만, 골반 안정성이 확보되지 않으면 머리 지지대의 효과가 제한됩니다.", "3": "발판은 대퇴부의 체중 분산과 하지 안정에 중요하지만, 골반 안정 후에 고려하는 요소입니다.", "4": "외측 체간 지지대는 체간의 좌우 안정성을 위해 사용되지만, 골반이 먼저 안정되어야 체간 지지의 효과가 나타납니다."}',2,'KICE 기출 기반','{"disability": "지체장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('pd-q34','physical-disability','positioning','ox','서기틀(standing frame)은 체중 부하를 통한 골밀도 유지, 호흡기능 향상, 소화기능 촉진 등의 효과가 있어 GMFCS 수준 IV, V 아동에게 권장된다.',NULL,NULL,'O','서기틀(standing frame)은 독립적으로 서기가 어려운 아동에게 기립 자세를 제공하는 보조기기입니다. 체중 부하(weight bearing)를 통해 골밀도를 유지하고 골다공증을 예방하며, 고관절 탈구 예방에도 기여합니다. 기립 자세는 횡격막의 하강을 촉진하여 폐활량을 증가시키고 호흡 기능을 향상시킵니다. 또한 중력의 영향으로 장운동이 촉진되어 소화 기능과 배변 활동에 긍정적 효과가 있습니다. GMFCS 수준 IV, V 아동에게 하루 일정 시간 서기틀 사용이 권장됩니다.',NULL,2,'교재 참고','{"disability": "지체장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('pd-q35','physical-disability','positioning','fill_in','휠체어 착석 시 엉덩이가 앞으로 미끄러져 나오면서 등이 뒤로 기울어지는 비정상적 앉기 패턴을 ( )(이)라 하며, 이를 방지하기 위해 골반 벨트와 좌석 각도 조절이 필요하다.',NULL,NULL,'천골 앉기(sacral sitting)','천골 앉기(sacral sitting) 또는 후방 골반 경사(posterior pelvic tilt) 자세는 골반이 뒤로 기울면서 천골(sacrum)로 체중을 지지하는 비정상적 앉기 패턴입니다. 이 자세에서는 척추가 후만(kyphosis) 형태를 보이고, 머리가 전방으로 돌출되며, 호흡과 삼킴 기능에 부정적 영향을 줍니다. 예방을 위해 골반 벨트를 45도 각도로 적용하고, 좌석을 약간 경사지게(wedge cushion) 하여 골반의 전방 미끄러짐을 방지합니다. 올바른 착석 자세는 학습 참여와 상지 기능 발휘의 기본 조건입니다.',NULL,3,'KICE 기출 기반','{"disability": "지체장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('pd-q36','physical-disability','positioning','descriptive','뇌성마비 아동의 교실 내 착석 자세 보조에서 ''아래에서 위로(bottom-up)'' 접근 원칙을 설명하고, 각 단계에서 사용하는 보조기기를 서술하시오.',NULL,NULL,'아래에서 위로(bottom-up) 접근은 발 → 골반 → 체간 → 머리 순서로 자세 지지를 제공하는 원칙이다. 첫째, 발판(footrest)으로 발을 지지하여 대퇴부 체중 분산과 하지 안정을 확보한다. 둘째, 골반 벨트와 좌석 쿠션으로 골반의 중립 위치를 유지하고 전방 미끄러짐을 방지한다. 셋째, 외측 체간 지지대(lateral trunk support)로 체간의 좌우 안정을 도모하고, 전방 체간 지지대로 전방 기울어짐을 방지한다. 넷째, 머리 조절이 어려운 경우 머리 지지대(headrest)로 머리를 중립 위치에 유지한다. 각 단계가 안정되어야 다음 단계의 지지가 효과를 발휘한다.','자세 보조의 아래에서 위로 접근은 신체 역학의 기본 원리에 근거합니다. 건물의 기초가 안정되어야 상부 구조물이 안정적인 것처럼, 앉은 자세에서 골반의 안정이 체간과 머리의 조절을 위한 기초가 됩니다. 골반이 불안정하면 아무리 좋은 체간 지지대를 적용해도 자세가 무너집니다. 이 원칙은 물리치료사, 작업치료사, 보조공학사가 협력하여 적용하며, 특수교사는 교실에서 아동의 자세를 모니터링하고 필요 시 조정하는 역할을 합니다.',NULL,3,'교재 참고','{"disability": "지체장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('pd-q37','physical-disability','muscular-dystrophy','multiple','듀센형 근이영양증(DMD)에서 바닥에서 일어설 때 손으로 무릎과 대퇴부를 짚으며 몸을 세우는 특징적인 기립 방식을 무엇이라 하는가?',NULL,ARRAY['롬버그 징후(Romberg sign)','가워스 징후(Gowers'' sign)','트렌델렌부르크 징후(Trendelenburg sign)','바빈스키 징후(Babinski sign)'],'2','가워스 징후(Gowers'' sign)는 듀센형 근이영양증의 대표적인 임상 징후입니다. 근위부 근력 약화로 인해 바닥에서 일어설 때 엎드린 자세에서 시작하여 양손으로 바닥을 짚고, 손을 무릎 위로 옮기고, 대퇴부를 짚으며 몸을 ''기어오르듯'' 세우는 특징적인 패턴을 보입니다. 이는 골반대(pelvic girdle) 근육과 대퇴사두근의 약화를 보상하기 위한 동작입니다. 주로 3~5세경 관찰되기 시작하며, 진단적 가치가 높은 징후입니다.','{"1": "롬버그 징후는 눈을 감았을 때 균형을 유지하지 못하는 것으로, 고유수용성 감각이나 전정 기능 장애를 나타내며 근이영양증과는 관련이 없습니다.", "3": "트렌델렌부르크 징후는 한 발로 서 있을 때 반대쪽 골반이 내려가는 것으로, 중둔근(gluteus medius) 약화를 나타내며 기립 시 보상 동작과는 다릅니다.", "4": "바빈스키 징후는 발바닥 외측을 자극할 때 엄지발가락이 배측 굴곡되는 반사로, 상위운동신경원 손상을 나타내며 근이영양증과는 관련이 없습니다."}',1,'KICE 기출 기반','{"disability": "지체장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('pd-q38','physical-disability','muscular-dystrophy','ox','듀센형 근이영양증(DMD)은 상염색체 우성으로 유전되며, 여아에서 더 높은 발병률을 보인다.',NULL,NULL,'X','듀센형 근이영양증(DMD)은 X염색체 열성(X-linked recessive)으로 유전되므로, 거의 대부분 남아에서 발병합니다. X염색체의 Xp21 위치에 있는 디스트로핀(dystrophin) 유전자의 돌연변이에 의해 발생하며, 여아는 보통 보인자(carrier)로서 증상을 나타내지 않습니다. 이는 여아가 두 개의 X염색체를 가지고 있어 한쪽의 정상 유전자가 결함을 보상하기 때문입니다. 발병률은 남아 약 3,500명 중 1명으로, 가장 흔한 근이영양증 유형입니다.',NULL,2,'교재 참고','{"disability": "지체장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('pd-q39','physical-disability','muscular-dystrophy','fill_in','듀센형 근이영양증(DMD)에서 결핍되는 근육 세포막 단백질의 이름은 ( )이다.',NULL,NULL,'디스트로핀(dystrophin)','디스트로핀(dystrophin)은 근육 세포막(sarcolemma) 안쪽에 위치하는 막대 모양의 세포골격 단백질로, 근섬유의 수축 시 세포막을 안정화시키는 역할을 합니다. DMD에서는 디스트로핀 유전자의 돌연변이로 인해 이 단백질이 거의 생성되지 않아 근섬유가 반복적인 수축-이완 과정에서 손상되고 괴사합니다. 손상된 근섬유는 지방과 결합조직으로 대체되어 가성비대(pseudohypertrophy)가 나타납니다. 벡커형 근이영양증(BMD)은 디스트로핀이 감소하거나 비정상적 형태로 생성되어 증상이 더 경미합니다.',NULL,2,'KICE 기출 기반','{"disability": "지체장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('pd-q40','physical-disability','muscular-dystrophy','descriptive','듀센형 근이영양증(DMD)의 진행 단계를 초기, 중기, 후기로 나누어 각 단계의 운동 기능 변화와 교육적 지원 방안을 서술하시오.',NULL,NULL,'초기(2~6세): 보행이 가능하나 자주 넘어지고 계단 오르기가 어려우며 가워스 징후가 나타난다. 종아리 가성비대가 관찰된다. 이 시기에는 적절한 운동과 활동을 통해 근력을 유지하고, 과도한 피로를 피하면서 또래와의 활동 참여를 지원한다. 중기(6~12세): 점진적으로 보행 능력이 상실되어 대부분 10~12세에 휠체어를 사용하게 된다. 척추 측만이 진행되고 관절 구축이 나타난다. 전동 휠체어, 컴퓨터 보조기기 등을 도입하고 교육과정을 조정하여 학습 참여를 보장한다. 후기(청소년기 이후): 상지 기능이 약화되고 호흡근 약화로 인공호흡기가 필요할 수 있으며 심근병증이 동반될 수 있다. 대체접근 입력장치, 환경조절장치 등 보조공학적 지원을 강화하고 심리·정서적 지원과 전환교육을 실시한다.','듀센형 근이영양증은 진행성 질환으로, 시간이 지남에 따라 근력이 점차 약화됩니다. 근위부에서 원위부 방향으로, 하지에서 상지 방향으로 약화가 진행됩니다. 특수교사는 질환의 진행 단계에 따라 교육적 지원 방안을 지속적으로 수정해야 합니다. 호흡 관리와 심장 관리가 생명 유지에 중요하며, 다학제적 팀 접근이 필수적입니다. 최근 의학의 발전으로 코르티코스테로이드 치료, 유전자 치료 등이 질환의 진행을 늦추는 데 기여하고 있습니다.',NULL,3,'KICE 기출 기반','{"disability": "지체장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('pd-q1','physical-disability','cp-types','fill_in','뇌성마비의 운동 유형 중 근긴장도가 비정상적으로 증가하여 관절의 가동범위가 제한되고, 빠른 수동 운동 시 저항이 속도 의존적으로 나타나는 유형을 ( )형이라 한다.',NULL,NULL,'경직','경직형(spastic type)은 상위운동신경원 손상으로 근긴장도가 증가하며, 수동 운동 시 속도 의존적 저항이 특징이다. 뇌성마비의 약 70~80%를 차지하는 가장 흔한 유형이다.',NULL,1,'KICE 기출 기반','{"disability": "지체장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('pd-q2','physical-disability','cp-types','multiple','경직형 뇌성마비 아동에게서 나타나는 특성으로 적절하지 않은 것은?',NULL,ARRAY['가위걸음(scissors gait) 패턴','관절구축 및 변형 위험','불수의적이고 불규칙한 사지 움직임','첨족(equinus)으로 인한 까치발 보행'],'불수의적이고 불규칙한 사지 움직임','불수의적이고 불규칙한 사지 움직임은 불수의운동형(무정위운동형, athetoid/dyskinetic type)의 특성이다. 경직형은 근긴장도 증가, 가위걸음, 관절구축, 첨족 등이 주요 특성이다.','{"가위걸음(scissors gait) 패턴": "양하지 내전근의 경직으로 인해 나타나는 경직형의 대표적 보행 패턴이다.", "관절구축 및 변형 위험": "지속적 근긴장도 증가로 관절 가동범위가 제한되어 구축이 발생한다.", "첨족(equinus)으로 인한 까치발 보행": "비복근과 가자미근의 경직으로 발목이 저측굴곡 상태를 유지하여 나타난다."}',2,'KICE 기출 기반','{"disability": "지체장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('pd-q3','physical-disability','cp-types','descriptive','뇌성마비의 마비 부위에 따른 분류 중 ''양하지마비(diplegia)''와 ''사지마비(quadriplegia)''의 차이를 운동 기능 관점에서 설명하시오.',NULL,NULL,'양하지마비는 하지가 상지보다 심하게 영향을 받는 유형으로, 상지 기능이 비교적 보존되어 독립적 식사나 조작 활동이 가능한 경우가 많다. 사지마비는 사지 모두가 심하게 영향을 받으며 체간 조절도 어려워 일상생활 전반에 걸쳐 전적인 지원이 필요하다.','양하지마비(diplegia)는 경직형에서 가장 흔하며 미숙아와 관련이 깊다. 상지 기능이 상대적으로 양호하여 휠체어 자가 추진이나 보행보조기를 이용한 보행이 가능할 수 있다. 사지마비(quadriplegia)는 사지와 체간 모두 심하게 영향을 받아 GMFCS IV~V 수준인 경우가 많다.',NULL,2,'KICE 기출 기반','{"disability": "지체장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('pd-q4','physical-disability','cp-types','ox','불수의운동형(무정위운동형) 뇌성마비는 대뇌피질의 운동영역 손상이 주된 원인이다.',NULL,NULL,'X','불수의운동형 뇌성마비는 기저핵(basal ganglia) 손상이 주된 원인이다. 대뇌피질 운동영역 손상은 경직형의 원인이며, 소뇌 손상은 실조형의 원인이다.',NULL,2,'KICE 기출 기반','{"disability": "지체장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('pd-q5','physical-disability','cp-types','fill_in','뇌성마비의 운동 유형 중 소뇌 손상으로 인해 균형과 협응에 어려움을 보이며, 의도적 움직임 시 떨림(의도진전)이 나타나는 유형을 ( )형이라 한다.',NULL,NULL,'실조','실조형(ataxic type)은 소뇌 손상으로 인해 균형 유지, 협응 동작, 심도 지각에 어려움을 보인다. 의도진전(intention tremor), 넓은 보폭의 불안정한 보행, 측정이상(dysmetria) 등이 특징이다.',NULL,1,'KICE 기출 기반','{"disability": "지체장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('pd-q6','physical-disability','gmfcs','descriptive','대운동기능분류체계(GMFCS) 레벨 III과 레벨 IV의 이동 능력 차이를 보조기기 사용과 관련지어 설명하시오.',NULL,NULL,'GMFCS 레벨 III은 손으로 잡는 이동 보조기구(워커, 목발 등)를 사용하여 실내에서 독립 보행이 가능하며, 긴 거리나 실외에서는 휠체어를 사용한다. 레벨 IV는 체간 조절이 제한되어 자가 이동에 심한 제한이 있으며, 전동 휠체어를 사용하거나 타인이 밀어주는 수동 휠체어로 이동한다.','GMFCS는 뇌성마비 아동의 대운동 기능을 5단계로 분류하는 체계이다. 레벨 III은 보조기기를 사용한 독립 보행이 핵심이고, 레벨 IV는 앉기도 외부 지지가 필요하며 독립 보행이 불가능한 수준이다. 두 레벨 모두 휠체어를 사용하지만, 자가 이동의 독립성에서 차이가 난다.',NULL,3,'KICE 기출 기반','{"disability": "지체장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('pd-q7','physical-disability','gmfcs','multiple','GMFCS 레벨 I에 해당하는 아동의 이동 능력에 대한 설명으로 가장 적절한 것은?',NULL,ARRAY['보조기기 없이 독립 보행이 가능하나 속도와 균형에 제한이 있다','실내에서 손잡이형 보행기를 사용하여 보행한다','전동 휠체어로 독립적 이동이 가능하다','바닥에서 기기와 구르기로 이동하며 보행은 불가능하다'],'보조기기 없이 독립 보행이 가능하나 속도와 균형에 제한이 있다','GMFCS 레벨 I은 보조기기 없이 독립 보행이 가능한 수준이다. 달리기와 점프 등 고급 대운동 기술에서 속도, 균형, 협응의 제한이 나타날 수 있다.','{"실내에서 손잡이형 보행기를 사용하여 보행한다": "이는 GMFCS 레벨 III에 해당하는 설명이다.", "전동 휠체어로 독립적 이동이 가능하다": "이는 GMFCS 레벨 IV~V에 해당하는 설명이다.", "바닥에서 기기와 구르기로 이동하며 보행은 불가능하다": "이는 GMFCS 레벨 V에 해당하는 설명이다."}',1,'KICE 기출 기반','{"disability": "지체장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('pd-q8','physical-disability','gmfcs','fill_in','GMFCS 레벨 V에 해당하는 뇌성마비 아동은 모든 환경에서 ( )를 사용하여 이동하며, 항중력 자세 조절에 심한 제한이 있어 머리와 체간의 조절이 어렵다.',NULL,NULL,'수동 휠체어(타인 보조)','GMFCS 레벨 V는 가장 중증 단계로, 항중력 자세 유지가 어려워 머리와 체간 조절이 제한된다. 모든 이동에 타인의 도움이 필요하며, 틸트형 휠체어 등 전면적 자세 지지가 필요한 수동 휠체어를 타인이 밀어서 이동한다.',NULL,2,'KICE 기출 기반','{"disability": "지체장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('pd-q9','physical-disability','primitive-reflexes','fill_in','비대칭긴장성경반사(ATNR)는 머리를 한쪽으로 회전하면 안면쪽 팔다리가 ( )하고 후두쪽 팔다리가 ( )하는 반사이다.',NULL,NULL,'신전(펴짐), 굴곡(구부러짐)','ATNR은 ''펜싱 자세''라고도 하며, 머리 회전 시 안면쪽 사지는 신전(extension), 후두쪽 사지는 굴곡(flexion)된다. 정상적으로 생후 6개월경 소실되며, 잔존 시 중선 활동(중앙에서의 양손 사용, 시각적 주시 등)을 방해한다.',NULL,2,'KICE 기출 기반','{"disability": "지체장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('pd-q10','physical-disability','primitive-reflexes','descriptive','비대칭긴장성경반사(ATNR)가 잔존하는 뇌성마비 아동에게 나타날 수 있는 학습 활동상의 어려움을 2가지 설명하시오.',NULL,NULL,'첫째, 중선에서 양손을 모아 사용하는 활동(가위질, 종이 잡고 쓰기 등)이 어렵다. 머리를 한쪽으로 돌리면 안면쪽 팔이 펴지므로 양손 협응이 방해된다. 둘째, 읽기와 쓰기 시 시선을 옆으로 이동하면 머리가 함께 회전하면서 팔의 긴장이 변화하여 글씨를 쓰는 손의 조절이 불안정해진다.','ATNR 잔존은 중선 활동 전반에 영향을 미친다. 머리 위치에 따라 사지 긴장도가 변하므로 식사(숟가락을 입으로 가져오기), 책 읽기(시선 추적 시 머리 회전), 키보드 사용 등 학교생활 전반의 과제 수행에 어려움이 발생한다.',NULL,3,'KICE 기출 기반','{"disability": "지체장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('pd-q11','physical-disability','primitive-reflexes','ox','대칭긴장성경반사(STNR)는 머리를 굴곡(숙임)하면 상지가 굴곡되고 하지가 신전되는 반사이다.',NULL,NULL,'O','STNR은 머리 굴곡 시 상지 굴곡 + 하지 신전, 머리 신전(들어올림) 시 상지 신전 + 하지 굴곡이 나타나는 반사이다. 잔존 시 네발기기(crawling)에서 상하지 분리 동작이 어려워 독립적 이동 발달을 방해한다.',NULL,2,'KICE 기출 기반','{"disability": "지체장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('pd-q12','physical-disability','primitive-reflexes','multiple','다음 중 모로반사(Moro reflex)에 대한 설명으로 옳은 것은?',NULL,ARRAY['갑작스러운 자극에 양팔을 벌렸다가 포옹하듯 오므리는 반응이다','발바닥의 외측을 긁으면 엄지발가락이 배측굴곡되는 반응이다','손바닥에 물체가 닿으면 자동으로 쥐는 반응이다','머리를 한쪽으로 돌리면 펜싱 자세가 나타나는 반응이다'],'갑작스러운 자극에 양팔을 벌렸다가 포옹하듯 오므리는 반응이다','모로반사는 갑작스러운 소리, 위치 변화 등의 자극에 양팔을 외전·신전했다가 내전·굴곡하는 두 단계 반응이다. 정상적으로 생후 4~6개월에 소실된다.','{"발바닥의 외측을 긁으면 엄지발가락이 배측굴곡되는 반응이다": "이는 바빈스키 반사(Babinski reflex)에 대한 설명이다.", "손바닥에 물체가 닿으면 자동으로 쥐는 반응이다": "이는 잡기반사(grasp reflex)에 대한 설명이다.", "머리를 한쪽으로 돌리면 펜싱 자세가 나타나는 반응이다": "이는 비대칭긴장성경반사(ATNR)에 대한 설명이다."}',1,'KICE 기출 기반','{"disability": "지체장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('pd-q13','physical-disability','positioning','fill_in','뇌성마비 아동의 기립 자세 보조기기 중, 머리 조절(head control)이 가능한 아동에게는 ( )스탠더를, 머리 조절이 어려운 아동에게는 ( )스탠더를 사용한다.',NULL,NULL,'프론(prone), 수파인(supine)','프론스탠더(prone stander)는 엎드린 자세로 기립하므로 머리를 들어 올릴 수 있는 head control이 전제된다. 수파인스탠더(supine stander)는 누운 자세에서 점차 세우는 형태로 머리 조절이 어려운 아동도 후방 지지를 받아 기립 자세를 경험할 수 있다.',NULL,2,'KICE 기출 기반','{"disability": "지체장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('pd-q14','physical-disability','positioning','descriptive','웨지(wedge)를 사용할 때 겨드랑이(axilla) 높이를 기준으로 설정하는 이유를 상지 기능 확보와 관련지어 설명하시오.',NULL,NULL,'웨지의 높은 쪽 끝이 겨드랑이 높이에 오도록 설정하면 체중이 웨지에 의해 지지되면서도 양 팔이 웨지 위로 자유롭게 나올 수 있다. 이를 통해 아동은 엎드린 자세에서 상지를 사용한 놀이, 조작 활동, 쓰기 등의 과제를 수행할 수 있게 된다.','웨지는 경사면을 이용하여 아동의 상체를 들어올리는 자세보조기기이다. 겨드랑이 이상 높이면 팔이 끼어 움직임이 제한되고, 너무 낮으면 상체 지지가 불충분하다. 겨드랑이 높이 기준은 체간 지지와 상지 자유를 동시에 확보하는 최적점이다.',NULL,3,'KICE 기출 기반','{"disability": "지체장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('pd-q15','physical-disability','positioning','ox','코너의자(corner chair)는 아동의 골반과 체간을 양쪽 측면에서 지지하여 대칭적 앉기 자세를 유도하는 자세보조기기이다.',NULL,NULL,'O','코너의자는 두 면이 직각으로 만나는 구조로 아동의 체간 양측을 지지하여 좌우 대칭적 자세를 유도한다. 체간 조절이 미숙한 아동에게 안정적 앉기 자세를 제공하여 상지를 사용한 활동을 가능하게 한다.',NULL,1,'KICE 기출 기반','{"disability": "지체장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('pd-q16','physical-disability','positioning','descriptive','단하지보조기(AFO)와 장하지보조기(KAFO)의 적용 부위와 주요 기능 차이를 설명하시오.',NULL,NULL,'AFO(Ankle-Foot Orthosis)는 발목과 발을 감싸는 보조기로, 족하수(foot drop)를 방지하고 발목의 안정성을 제공한다. KAFO(Knee-Ankle-Foot Orthosis)는 무릎까지 포함하여 무릎의 과신전이나 굴곡을 조절하며 발목 안정을 동시에 제공한다. AFO는 무릎 조절이 가능한 아동에게, KAFO는 무릎 조절도 어려운 아동에게 적용한다.','AFO는 경직형 뇌성마비에서 첨족(equinus)으로 인한 까치발 보행을 교정하는 데 가장 흔히 사용된다. KAFO는 더 넓은 범위의 하지 조절이 필요한 경우 사용하며, 근이영양증 등 진행성 질환에서도 보행 유지를 위해 활용된다.',NULL,2,'KICE 기출 기반','{"disability": "지체장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('pd-q17','physical-disability','positioning','fill_in','경직형 양하지마비 아동이 보행 시 발목이 저측굴곡(plantar flexion)되어 까치발로 걷는 현상을 ( )(이)라 하며, 이를 교정하기 위해 ( )를 착용한다.',NULL,NULL,'족하수(foot drop) 또는 첨족(equinus), AFO(단하지보조기)','족하수(foot drop) 또는 첨족(equinus)은 비복근·가자미근의 경직으로 발목이 지속적으로 저측굴곡되는 상태이다. AFO는 발목을 중립 위치에 고정하여 정상에 가까운 발 딛기(heel strike)를 가능하게 한다.',NULL,2,'KICE 기출 기반','{"disability": "지체장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('pd-q18','physical-disability','muscular-dystrophy','descriptive','듀센형 근이영양증(Duchenne Muscular Dystrophy)에서 나타나는 가워스 징후(Gowers'' sign)의 구체적 양상과 이것이 의미하는 근력 약화 부위를 설명하시오.',NULL,NULL,'가워스 징후는 바닥에서 일어날 때 양손을 바닥에 짚고 무릎을 편 후 양손으로 허벅지를 짚으며 몸을 밀어 올리듯 일어서는 양상이다. 이는 골반대(pelvic girdle)와 근위부 하지 근육(대퇴사두근, 둔근)의 심한 약화를 의미하며, 중력에 대항하여 체중을 들어올리는 힘이 부족하기 때문에 상지로 보상하는 것이다.','가워스 징후는 듀센형 근이영양증의 초기 임상 징후 중 하나로, 대개 3~5세경부터 관찰된다. 근위부 근육에서 원위부 근육으로 진행하는 질환의 특성을 반영하며, 진단의 중요한 단서가 된다.',NULL,3,'KICE 기출 기반','{"disability": "지체장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('pd-q19','physical-disability','muscular-dystrophy','fill_in','듀센형 근이영양증은 ( ) 유전 방식으로 유전되며, ( ) 단백질의 결핍으로 인해 근섬유가 점진적으로 파괴된다.',NULL,NULL,'X-연관 열성(X-linked recessive), 디스트로핀(dystrophin)','듀센형 근이영양증은 X염색체에 위치한 디스트로핀 유전자의 돌연변이로 발생하며, X-연관 열성 유전이므로 주로 남아에게 발병한다. 디스트로핀 단백질이 결핍되면 근세포막의 안정성이 저하되어 반복적 근수축 시 근섬유가 손상된다.',NULL,2,'KICE 기출 기반','{"disability": "지체장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('pd-q20','physical-disability','muscular-dystrophy','descriptive','듀센형 근이영양증의 진행 양상을 시기별로 나누어 설명하고, 각 시기에 적합한 교육적 지원 방안을 1가지씩 제시하시오.',NULL,NULL,'초기(3~7세)에는 보행이 가능하지만 잦은 넘어짐과 계단 오르기 곤란이 나타나며, 체육 활동의 난이도 조절과 안전한 환경을 제공한다. 중기(8~12세)에는 보행 능력이 상실되어 휠체어를 사용하게 되며, 접근 가능한 교실 배치와 보조공학 기기 제공이 필요하다. 후기(13세 이후)에는 상지 기능도 저하되고 호흡·심장 기능 관리가 중요해지며, 대체 입력 장치(시선 추적, 음성 입력 등)를 통한 학습 참여를 지원한다.','듀센형 근이영양증은 근위부에서 원위부로, 하지에서 상지로 진행하는 양상을 보인다. 대개 10~12세경 보행 불가, 20대 초반에 호흡 부전이 주요 합병증이 된다. 각 시기별 잔존 기능에 맞춘 교육 환경 조정과 보조공학 지원이 핵심이다.',NULL,3,'KICE 기출 기반','{"disability": "지체장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('trans-q38','transition','planning','fill_in','개별화전환교육계획(ITP)에 포함되어야 할 핵심 구성요소 중, 학생의 현재 수행 수준을 파악하기 위해 실시하는 ( ① )과/와, 졸업 후 희망하는 고용·교육·독립생활 등의 목표를 기술한 ( ② )이/가 있다. ①과 ②를 순서대로 쓰시오.',NULL,NULL,'① 전환평가 / ② 전환목표(졸업 후 성과목표)','ITP의 핵심 구성요소에는 전환평가(transition assessment), 전환목표(measurable postsecondary goals), 전환서비스(transition services), 연계기관 참여(interagency linkages) 등이 포함된다. 전환평가를 통해 학생의 강점·선호·흥미·요구를 파악하고, 이를 토대로 졸업 후 고용·교육·독립생활에 관한 측정 가능한 전환목표를 설정한다.',NULL,2,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('trans-q39','transition','planning','ox','전환평가의 비공식적 방법에는 면접, 관찰, 교육과정중심평가(CBA) 등이 있으며, 공식적 방법에는 적성검사, 흥미검사, 적응행동검사 등이 포함된다.',NULL,NULL,'O','전환평가는 공식적(formal) 방법과 비공식적(informal) 방법으로 구분된다. 공식적 방법에는 표준화된 적성검사, 흥미검사(예: 직업흥미검사), 적응행동검사 등이 있고, 비공식적 방법에는 면접, 관찰, 교육과정중심평가, 상황평가, 포트폴리오 등이 있다.',NULL,1,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('trans-q40','transition','planning','descriptive','다음 사례를 읽고 물음에 답하시오.

고등학교 2학년에 재학 중인 지적장애 학생 민수의 ITP를 작성하려고 한다. 민수는 요리에 관심이 많고, 학교 내 카페 실습에서 음료 제조를 성공적으로 수행하고 있다. 그러나 금전 계산에 어려움이 있으며, 대중교통 이용 경험이 없다.

(1) 민수의 전환평가에 적합한 공식적 평가도구 1가지와 비공식적 평가방법 1가지를 쓰시오.
(2) 민수의 ITP에 포함될 고용 영역의 전환목표 1가지와 이를 달성하기 위한 전환서비스 2가지를 쓰시오.','고등학교 2학년 지적장애 학생 민수는 요리에 관심이 많고 카페 실습에서 음료 제조를 성공적으로 수행하나, 금전 계산에 어려움이 있고 대중교통 이용 경험이 없다.',NULL,'(1) 공식적 평가도구: 직업적성검사(예: 장애인직업적성검사, GATB) 또는 지역사회적응검사(CIS-A). 비공식적 평가방법: 카페 실습 장면에서의 직접 관찰법 또는 학생·보호자 면담. (2) 전환목표: 졸업 후 외식업 분야(카페, 식당 등)에서 지원고용을 통해 취업한다. 전환서비스: ① 지역사회 카페/식당에서의 현장실습(CBI) 프로그램 제공, ② 금전관리 기술 교수(거스름돈 계산, 가격 비교 등) 및 대중교통 이용 훈련.','ITP 작성 시에는 학생의 강점(요리 관심, 음료 제조 능력)과 요구(금전 계산, 대중교통)를 모두 고려하여 전환평가를 실시하고, 이에 기반하여 현실적이고 측정 가능한 전환목표를 설정해야 한다. 전환서비스는 학교 교육과정, 지역사회 기관, 직업재활기관 등과 연계하여 제공한다.',NULL,3,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('trans-q41','transition','planning','multiple','전환교육 계획에서 학생 중심 계획(person-centered planning)에 관한 설명으로 옳지 않은 것은?',NULL,ARRAY['학생의 꿈, 선호, 강점에 초점을 맞추어 미래를 계획한다.','교사와 전문가가 학생의 장애 특성을 중심으로 목표를 결정한다.','학생, 가족, 친구, 관련 서비스 제공자 등이 팀으로 참여한다.','MAPS(Making Action Plans)와 PATH(Planning Alternative Tomorrows with Hope)가 대표적 모델이다.'],'1','학생 중심 계획(person-centered planning)의 핵심 원리는 전문가가 장애 특성 중심으로 목표를 결정하는 것이 아니라, 학생 본인의 꿈·선호·강점에 기반하여 학생이 주도적으로 미래를 계획하는 것이다. 전문가 중심의 결함 모델(deficit model)과 대비되는 강점 중심 접근이다.','{"0": "학생 중심 계획의 핵심 원리로, 장애가 아닌 학생의 강점과 꿈에 초점을 둔다.", "2": "학생 중심 계획은 다양한 관계자가 팀으로 참여하는 협력적 과정이다.", "3": "MAPS와 PATH는 학생 중심 계획의 대표적 모델이며, 그 외에 Personal Futures Planning 등이 있다."}',2,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('trans-q42','transition','planning','fill_in','전환서비스 연계에서, 학생이 학교 교육을 마친 후 직업재활 서비스를 받기 위해 연계하는 기관은 ( ① )이며, 복지 서비스 연계를 위해서는 ( ② )에 장애인 등록 후 서비스를 신청해야 한다. ①과 ②를 쓰시오.',NULL,NULL,'① 한국장애인고용공단(또는 직업재활시설) / ② 주민센터(읍·면·동 행정복지센터)','전환교육에서는 졸업 후 성인기 서비스로의 원활한 전환을 위해 관련 기관과의 연계가 필수적이다. 직업재활 서비스는 한국장애인고용공단, 직업재활시설, 장애인복지관 등을 통해 제공되며, 복지 서비스는 주민센터(읍·면·동 행정복지센터)에 장애인 등록 후 신청하여 활동지원, 주거지원 등을 받을 수 있다.',NULL,2,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('trans-q43','transition','planning','ox','직업재활 과정은 일반적으로 ''직업평가 → 직업적응훈련 → 직업배치 → 추후지도''의 순서로 진행된다.',NULL,NULL,'O','직업재활 과정은 직업평가(vocational evaluation) → 직업적응훈련(work adjustment training) → 직업배치(job placement) → 추후지도(follow-up)의 체계적 순서로 진행된다. 직업평가를 통해 능력·적성을 파악하고, 직업적응훈련으로 작업기술·습관을 훈련한 후, 적절한 직장에 배치하며, 배치 후에도 지속적으로 적응을 지원하는 추후지도를 실시한다.',NULL,1,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('trans-q44','transition','self-determination','fill_in','Wehmeyer가 제시한 자기결정의 4가지 본질적 특성은 자율성, ( ① ), 심리적 역량강화, ( ② )이다. ①과 ②를 순서대로 쓰시오.',NULL,NULL,'① 자기조절(self-regulation) / ② 자기실현(self-realization)','Wehmeyer(1999)의 자기결정 기능 모델에서 4가지 본질적 특성(essential characteristics)은 자율성(autonomy), 자기조절(self-regulation), 심리적 역량강화(psychological empowerment), 자기실현(self-realization)이다. 이 네 가지가 함께 작용할 때 자기결정 행동이 나타난다.',NULL,2,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('trans-q45','transition','self-determination','descriptive','자기결정 교수학습모델(SDLMI: Self-Determined Learning Model of Instruction)의 3단계를 순서대로 쓰고, 각 단계에서 학생이 답해야 할 핵심 질문을 1가지씩 서술하시오.',NULL,NULL,'1단계 ''목표 설정(Set a Goal)'': 학생이 답할 질문 - ''나는 무엇을 배우고 싶은가?'' 2단계 ''행동 계획(Take Action)'': 학생이 답할 질문 - ''나의 계획은 무엇인가?'' 또는 ''목표 달성을 위해 무엇을 해야 하는가?'' 3단계 ''목표 조정(Adjust Goal or Plan)'': 학생이 답할 질문 - ''나는 무엇을 배웠는가?'' 또는 ''목표를 달성했는가?''','SDLMI는 Wehmeyer 등이 개발한 교수모델로, 학생 스스로가 자신의 학습 목표를 설정하고, 실행 계획을 수립하며, 결과를 평가·조정하는 3단계 과정을 거친다. 각 단계에서 교사는 학생이 스스로 질문에 답하면서 자기결정 행동을 실천할 수 있도록 교수적 지원을 제공한다.',NULL,3,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('trans-q46','transition','self-determination','multiple','다음 중 자기결정 교수 프로그램과 그 주요 내용의 연결이 옳지 않은 것은?',NULL,ARRAY['ChoiceMaker - 선택하기, 자기관리, 자기옹호의 3개 영역으로 구성된 자기결정 교육과정','Whose Future Is It Anyway? - 학생 주도 IEP/전환 계획 참여를 위한 프로그램','SDLMI - 교사가 학생의 행동을 직접 통제하여 자기조절을 촉진하는 모델','TAKE CHARGE for the Future - 학생의 성취동기, 자기조절, 멘토링을 통한 전환 계획 프로그램'],'2','SDLMI(자기결정 교수학습모델)는 교사가 학생의 행동을 직접 통제하는 것이 아니라, 학생 스스로가 목표를 설정하고 행동 계획을 수립·실행·조정하도록 교수적 지원을 제공하는 모델이다. 학생의 자기주도성(self-directed learning)이 핵심 원리이다.','{"0": "ChoiceMaker는 선택하기(choosing), 자기관리(self-directed IEP), 자기옹호(self-advocacy) 3개 영역으로 구성된 자기결정 교육과정이다.", "1": "Whose Future Is It Anyway?는 Wehmeyer 등이 개발한 프로그램으로, 학생이 자신의 IEP/전환 회의에 주도적으로 참여하도록 돕는다.", "3": "TAKE CHARGE for the Future는 Powers 등이 개발한 프로그램으로, 성취동기·자기조절·멘토링·부모지원을 통해 전환 계획 참여를 촉진한다."}',2,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('trans-q47','transition','self-determination','fill_in','자기옹호(self-advocacy)의 4가지 구성요소는 자기지식(knowledge of self), ( ① ), 의사소통(communication), ( ② )이다. ①과 ②를 쓰시오.',NULL,NULL,'① 권리 인식(knowledge of rights) / ② 리더십(leadership)','Test 등(2005)이 제시한 자기옹호의 4가지 구성요소는 자기지식(자신의 강점·약점·요구를 이해), 권리 인식(자신의 법적·교육적 권리를 앎), 의사소통(자신의 요구를 효과적으로 표현), 리더십(팀 활동에서 주도적 역할 수행)이다.',NULL,2,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('trans-q48','transition','self-determination','ox','ChoiceMaker 자기결정 교육과정은 선택하기(choosing goals), 표현하기(expressing goals), 행동하기(taking action)의 3개 영역으로 구성된다.',NULL,NULL,'O','Martin & Marshall(1995)이 개발한 ChoiceMaker 자기결정 교육과정은 3개 영역으로 구성된다: (1) 선택하기(choosing goals) - 목표를 선택하는 기술, (2) 표현하기(expressing goals) - IEP 회의에서 자신의 목표를 표현하는 기술, (3) 행동하기(taking action) - 목표 달성을 위해 계획을 실행하는 기술.',NULL,2,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('trans-q49','transition','self-determination','descriptive','다음 사례를 읽고 물음에 답하시오.

특수학교 고등부 1학년 학생 지영이는 자신의 장애 특성과 강점을 잘 모르며, IEP 회의에 참석하지만 발언하지 않고 교사와 부모의 결정에 따른다. 담임교사는 지영이의 자기결정 능력을 향상시키고자 한다.

(1) 지영이에게 부족한 자기결정의 구성요소 2가지를 Wehmeyer의 모델에 근거하여 쓰시오.
(2) 지영이의 자기결정 향상을 위한 구체적 교수 프로그램 1가지를 선택하고, 그 프로그램의 적용 방법을 서술하시오.','특수학교 고등부 1학년 학생 지영이는 자신의 장애 특성과 강점을 잘 모르고, IEP 회의에서 발언하지 않으며, 교사와 부모의 결정에 따른다.',NULL,'(1) 부족한 구성요소: ① 자기실현(self-realization) - 자신의 장애 특성과 강점을 알지 못한다. ② 자율성(autonomy) - 자신의 선호에 따라 독립적으로 결정하지 못하고 타인의 결정에 따른다. (2) 적용 프로그램: ''Whose Future Is It Anyway?'' 프로그램 적용. 이 프로그램은 36개 세션으로 구성되며, 지영이가 자신의 강점·약점·흥미를 탐색하고(자기인식 활동), IEP 회의에서 자신의 목표를 직접 발표하고 의견을 표현하는 연습을 단계적으로 진행한다. 역할극, 워크시트, 동영상 등을 활용하여 IEP 참여 기술을 훈련한다.','Wehmeyer의 자기결정 모델에 비추어 볼 때, 자신을 잘 모르는 것은 자기실현의 부족이고, 타인의 결정에 따르는 것은 자율성의 부족이다. ''Whose Future Is It Anyway?''는 학생이 IEP/전환 계획에 주도적으로 참여하도록 준비시키는 프로그램으로, 중등 전환기 학생에게 적합하다.',NULL,3,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('trans-q50','transition','self-determination','fill_in','Wehmeyer의 자기결정 기능 모델에서, 자기결정의 구성요소 행동(component elements)에는 선택하기, 의사결정, 문제해결, ( ① ), 자기옹호, 자기관리, 자기인식, ( ② ) 등이 포함된다. ①과 ②를 쓰시오.',NULL,NULL,'① 목표설정 및 달성(goal setting and attainment) / ② 자기효능감(self-efficacy) 또는 내적 통제소(internal locus of control)','Wehmeyer의 자기결정 기능 모델에서 구성요소 행동(component elements)은 선택하기, 의사결정, 문제해결, 목표설정 및 달성, 자기옹호, 자기관리(자기관찰·자기평가·자기강화), 자기인식, 자기효능감과 내적 통제소 등이다. 이 구성요소들이 발달하면서 4가지 본질적 특성이 나타나게 된다.',NULL,2,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('trans-q51','transition','cbi','fill_in','지역사회 적응검사(CIS-A: Community Integration Skills-Assessment)는 ( ① )적 기술, ( ② )적 기술, 직업생활, 자기관리 등의 하위영역으로 구성되며, 지역사회 적응 수준을 평가하는 데 활용된다. ①과 ②를 쓰시오.',NULL,NULL,'① 기본생활(기초개념) / ② 사회자립(사회적응)','지역사회 적응검사(CIS-A)는 장애학생의 지역사회 적응 수준을 평가하는 도구로, 기본생활(기초개념: 시간, 수, 화폐 등), 사회자립(사회적응: 지역사회 이용, 대인관계 등), 직업생활, 자기관리 등의 하위영역으로 구성된다. 전환교육 계획 수립 시 학생의 현재 수행 수준을 파악하는 전환평가 도구로 활용된다.',NULL,2,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('trans-q52','transition','cbi','descriptive','지역사회 중심 교수(CBI)를 실시할 때, 교사가 수행해야 할 사전 계획 단계의 절차를 3가지 이상 서술하시오.',NULL,NULL,'(1) 생태학적 조사(ecological inventory): 교수가 이루어질 지역사회 환경을 사전에 방문하여 해당 환경에서 요구되는 기술, 자연적 단서, 자연적 결과 등을 분석한다. (2) 과제분석(task analysis): 목표 기술을 세부 단계로 분석하여 교수 순서를 결정한다. (3) 안전 확보 및 이동 계획: 이동 경로, 교통수단, 안전 관리 계획, 비상 연락망 등을 수립한다. (4) 사전 교실 교수: 지역사회 환경에 나가기 전에 교실에서 모의 연습(simulation)을 통해 기본 기술을 사전 훈련한다.','CBI의 효과적 실시를 위해서는 체계적인 사전 계획이 필수적이다. 생태학적 조사를 통해 환경을 분석하고, 과제분석으로 교수 절차를 구조화하며, 안전 계획을 수립하고, 교실 사전 교수로 기초 기술을 훈련한 후 지역사회 환경에서 실제 교수를 실시한다.',NULL,3,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('trans-q53','transition','cbi','multiple','성인기 주거 유형을 최소제한환경 원칙에 따라 독립적인 순서로 바르게 나열한 것은?',NULL,ARRAY['독립생활 → 지원생활(supported living) → 그룹홈 → 시설(거주시설)','지원생활 → 독립생활 → 시설(거주시설) → 그룹홈','그룹홈 → 독립생활 → 지원생활 → 시설(거주시설)','독립생활 → 그룹홈 → 시설(거주시설) → 지원생활'],'0','성인기 주거 유형을 최소제한환경(가장 독립적)에서 최대제한환경 순으로 나열하면: 독립생활(independent living) → 지원생활(supported living: 자기 집에서 필요한 지원을 받음) → 그룹홈(group home: 소규모 공동생활) → 거주시설(residential facility: 대규모 시설) 순이다.','{"1": "독립생활이 지원생활보다 더 독립적이며, 시설이 그룹홈보다 더 제한적인 환경이므로 순서가 틀렸다.", "2": "그룹홈은 독립생활보다 제한적인 환경이므로 첫 번째에 올 수 없다.", "3": "지원생활은 그룹홈보다 더 독립적인 환경이므로 마지막에 올 수 없다."}',2,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('trans-q54','transition','cbi','ox','지역사회 중심 교수(CBI)에서는 일반화를 촉진하기 위해 하나의 고정된 지역사회 환경에서 반복 훈련하는 것이 가장 효과적이다.',NULL,NULL,'X','CBI에서 일반화를 촉진하기 위해서는 하나의 고정된 환경이 아니라, 다양한 지역사회 환경(예: 여러 마트, 여러 식당)에서 훈련하는 것이 효과적이다. 이를 ''다수 범례 교수(multiple exemplar training)'' 또는 ''일반사례 전략(general case strategy)''이라 하며, 다양한 환경에서의 경험을 통해 기술의 일반화를 촉진한다.',NULL,2,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('trans-q55','transition','cbi','fill_in','생활기술 교수 영역 중 금전관리 기술에서, 학생이 물건의 가격보다 큰 다음 단위의 화폐를 제시하는 전략을 ( )전략이라 한다. 예를 들어, 2,300원짜리 물건을 살 때 3,000원을 내는 것이다.',NULL,NULL,'다음 달러(next-dollar) 또는 다음 화폐 단위','다음 달러 전략(next-dollar strategy)은 물건의 가격보다 큰 바로 다음 단위의 화폐를 제시하는 방법으로, 정확한 거스름돈 계산이 어려운 지적장애 학생에게 효과적인 금전관리 교수 전략이다. 예를 들어 가격이 2,300원이면 천 원짜리 3장(3,000원)을 제시하고 거스름돈을 받는 방식이다.',NULL,1,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('trans-q56','transition','cbi','descriptive','다음 사례를 읽고 물음에 답하시오.

특수학교 고등부 학생 현우는 중도 지적장애로, 대중교통(시내버스) 이용 기술을 학습하고 있다. 교사는 CBI를 활용하여 현우에게 버스 탑승부터 하차까지의 기술을 교수하고자 한다.

(1) 교사가 대중교통 이용 기술을 과제분석한 결과를 5단계 이상으로 쓰시오.
(2) CBI 적용 시 교실 내 사전 교수와 지역사회 현장 교수를 어떻게 연계할 수 있는지 구체적으로 서술하시오.','특수학교 고등부 중도 지적장애 학생 현우에게 CBI를 활용하여 시내버스 이용 기술을 교수하려 한다.',NULL,'(1) 과제분석: ① 버스 정류장까지 이동한다. ② 버스 노선 번호를 확인하고 해당 버스가 오면 손을 들어 신호한다. ③ 버스에 탑승하여 교통카드를 단말기에 태그한다. ④ 빈 좌석에 앉거나 손잡이를 잡고 선다. ⑤ 하차 정류장 안내방송을 듣고 하차 벨을 누른다. ⑥ 뒷문으로 이동하여 교통카드를 태그하고 하차한다. (2) 교실-현장 연계: 먼저 교실에서 사진·동영상·모의 버스 환경을 활용하여 각 단계를 시뮬레이션으로 연습한다(예: 교실에 모의 단말기 설치, 역할극으로 탑승·하차 연습). 교실 사전 교수에서 80% 이상 정확도를 달성하면 실제 버스 노선에서 교사와 함께 현장 교수를 실시한다. 현장에서는 최소 촉구(least prompts) 전략을 사용하여 자립도를 높이고, 점차 다른 노선·시간대로 확대하여 일반화를 촉진한다.','CBI에서 과제분석은 교수의 기본 골격이 되며, 교실 사전 교수(모의학습)와 현장 교수를 체계적으로 연계하는 것이 효과적이다. 교실에서 기초 기술을 먼저 훈련하고, 현장에서 실제 환경의 자연적 단서와 결과를 활용하여 일반화를 촉진하는 것이 CBI의 핵심 원리이다.',NULL,3,'KICE 기출 기반','{}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('vi-q21','visual-impairment','orientation-mobility','fill_in','인도보행에서 닫힌 문을 통과할 때, 시각장애인은 안내자가 잡힌 팔 쪽에 위치한 (   )으로 문의 경첩 쪽을 확인한 뒤, 문을 잡고 통과한다.',NULL,NULL,'손(자유로운 손 / free hand)','인도보행 중 문 통과법에서 시각장애인은 안내자의 팔을 잡고 있지 않은 자유로운 손(free hand)으로 문의 위치와 경첩 방향을 확인한다. 안내자는 문이 있음을 알리고, 시각장애인이 경첩 쪽에 위치하도록 필요시 좌우를 바꾼다. 문을 통과한 뒤에는 시각장애인이 뒤쪽 손으로 문을 닫는다. Hill & Ponder(1976)의 O&M 교육 원리에 기반한다.',NULL,2,'KICE 기출 기반','{"disability": "시각장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('vi-q22','visual-impairment','orientation-mobility','fill_in','흰지팡이 보행 기법 중, 지팡이를 지면에서 떼지 않고 좌우로 미끄러뜨리며 노면의 변화를 감지하는 기법을 (   )이라 한다.',NULL,NULL,'슬라이드법(slide technique)','슬라이드법(slide technique, constant contact technique)은 지팡이 끝(tip)을 지면에서 떼지 않고 좌우로 미끄러뜨리며 이동하는 기법이다. 터치법과 달리 지면과의 접촉을 유지하므로 노면의 질감 변화(포장 → 잔디, 평면 → 경사 등)를 민감하게 감지할 수 있다. 주로 노면 상태 파악이 중요한 환경(울퉁불퉁한 보도, 경사로 등)에서 사용한다. 터치법보다 탐지 범위가 넓어 바닥의 작은 장애물도 놓치지 않는 장점이 있다.',NULL,1,'KICE 기출 기반','{"disability": "시각장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('vi-q23','visual-impairment','orientation-mobility','ox','사선법(diagonal technique)은 실외 독립보행 시 가장 많이 사용되는 흰지팡이 기법이다.',NULL,NULL,'X','사선법(diagonal technique, diagonal cane technique)은 주로 실내나 익숙한 환경에서 사용하는 기법이다. 지팡이를 몸 앞 대각선 방향으로 고정하여 발 앞쪽 장애물을 탐지한다. 실외 독립보행에서 가장 많이 사용되는 기법은 터치법(touch technique)이다. 터치법은 좌우로 호를 그리며 어깨 너비보다 넓은 범위를 탐지하므로 실외의 다양한 장애물과 노면 변화를 효과적으로 감지할 수 있다.',NULL,1,'KICE 기출 기반','{"disability": "시각장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('vi-q24','visual-impairment','orientation-mobility','multiple','인도보행(sighted guide)에서 계단을 내려갈 때의 방법으로 가장 적절한 것은?',NULL,ARRAY['안내자가 계단 시작 전에 멈추고, 시각장애인이 발끝으로 계단 모서리를 확인한 뒤 안내자가 먼저 한 칸 내려간다.','안내자와 시각장애인이 동시에 같은 계단에 발을 딛고 나란히 내려간다.','시각장애인이 안내자보다 먼저 한 칸 내려가고, 안내자가 뒤따른다.','안내자가 시각장애인의 허리를 잡고 뒤에서 밀어주며 내려간다.'],'1','인도보행 시 계단(상행·하행 모두)에서는 안내자가 계단 시작점에서 일단 정지하여 계단이 있음을 알린다. 시각장애인은 발끝으로 계단의 모서리(edge)를 확인한다. 안내자가 먼저 한 칸 내려가고, 시각장애인이 한 칸 뒤에서 따라 내려간다. 이 반 보 차이를 유지하면 안내자의 신체 움직임(어깨 높이 변화)을 통해 다음 계단의 정보를 미리 파악할 수 있다.','{"2": "나란히 같은 계단에 서서 내려가면 안내자의 신체 움직임을 통한 정보 전달이 불가능하고, 균형 유지가 어렵다.", "3": "시각장애인이 먼저 내려가는 것은 인도보행의 기본 원칙(안내자가 선행)에 위배되며, 안전하지 않다.", "4": "뒤에서 밀어주는 것은 인도보행 원칙에 위배된다. 시각장애인이 안내자의 팔을 잡고 안내자의 움직임을 촉각으로 감지하는 것이 원칙이다."}',2,'KICE 기출 기반','{"disability": "시각장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('vi-q25','visual-impairment','orientation-mobility','descriptive','다음 사례를 읽고 물음에 답하시오.','전맹 중학생 K는 최근 흰지팡이 보행 훈련을 시작했다. K는 터치법은 어느 정도 익혔지만 실외 보행 시 연석(curb)이나 경사로를 만나면 당황하여 멈춘다. 보행 훈련 교사 L은 K에게 다양한 지형에서의 보행 기술을 체계적으로 지도하려 한다.

(1) 터치법 수행 시 지팡이 호(arc)의 적정 너비와 보행 리듬(step-touch coordination)을 설명하시오.
(2) 연석(curb) 상행 시와 하행 시의 흰지팡이 탐지 방법을 각각 서술하시오.
(3) 실외 보행에서 쇼어라인(shoreline) 기법의 정의와 활용 상황을 설명하시오.',NULL,'(1) 터치법의 호 너비는 양쪽 어깨 바깥으로 약 2.5cm(1인치)씩 넘는 정도가 적정하다. 보행 리듬은 왼발을 내딛을 때 오른쪽 지면을 터치하고, 오른발을 내딛을 때 왼쪽 지면을 터치하는 반대 보행 리듬(in-step)을 유지한다. 이로써 발이 닿기 전에 해당 지면의 안전을 먼저 확인할 수 있다.
(2) 상행 시: 지팡이 끝이 연석의 수직면에 부딪히면 상승 연석임을 감지한다. 지팡이로 연석 높이와 윗면을 확인한 뒤 발을 올려 딛는다. 하행 시: 지팡이 끝이 지면에서 갑자기 아래로 떨어지는 감각(drop-off)을 통해 하강 연석임을 감지한다. 지팡이로 아래 지면의 상태를 확인한 뒤 내려선다.
(3) 쇼어라인(shoreline) 기법은 보도와 잔디, 포장도로와 비포장도로 등 두 가지 노면이 만나는 경계선을 지팡이로 추적하며 방향을 유지하는 기법이다. 실외에서 직선 보행을 유지하기 어려울 때 노면 경계선을 단서(cue)로 활용하여 일정한 방향으로 이동할 수 있게 해준다.','터치법의 보행 리듬(in-step pattern)과 연석 탐지는 독립보행의 핵심 기술이며, 쇼어라인 기법은 실외 보행에서 방향 정위를 유지하는 중요한 전략이다. Jacobson(1993)의 O&M 교수법에 근거한다.',NULL,3,'KICE 기출 기반','{"disability": "시각장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('vi-q26','visual-impairment','orientation-mobility','ox','방향정위(orientation)의 세 가지 기본 요소는 자기 위치(self-to-object), 대상 간 관계(object-to-object), 환경 내 방향 체계(environmental directions) 파악이다.',NULL,NULL,'O','방향정위(orientation)는 환경 속에서 자신의 위치를 파악하는 인지적 과정으로, 세 가지 기본 요소로 구성된다. ① 자기와 대상의 관계(self-to-object): 자신과 주변 대상 간의 거리·방향을 파악한다. ② 대상 간 관계(object-to-object): 환경 내 사물들의 상호 위치 관계를 파악한다. ③ 방향 체계(environmental directions): 동서남북, 실내 좌표 등 환경의 방향 체계를 이해한다. Hill & Ponder(1976)는 이 세 요소가 효과적인 독립 보행의 인지적 기반이라고 설명했다.',NULL,2,'KICE 기출 기반','{"disability": "시각장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('vi-q27','visual-impairment','orientation-mobility','descriptive','다음 사례를 읽고 물음에 답하시오.','시각장애 특수학교 초등부 교사 M은 전맹 학생 N(초등 3학년)에게 학교에서 집까지의 독립보행을 훈련시키려 한다. 경로에는 인도, 횡단보도 1개소, 주거 단지 진입로가 포함된다.

(1) 독립보행 훈련의 3단계(실내 → 반통제 환경 → 실외)를 설명하시오.
(2) 정신지도(mental map / cognitive map)의 개념과, 학생 N이 경로의 정신지도를 형성하기 위한 교수 전략 2가지를 서술하시오.',NULL,'(1) ① 실내 단계: 교실, 복도 등 통제된 실내 환경에서 자기보호법, 벽 따라 걷기(trailing), 방향 전환 등 기본 기술을 훈련한다. ② 반통제 환경 단계: 학교 운동장, 교내 야외 공간 등 통제 가능하지만 변수가 있는 환경에서 흰지팡이 기법을 연습한다. ③ 실외 단계: 실제 도로, 횡단보도 등 통제되지 않은 환경에서 교통 소리 분석, 독립 횡단, 경로 탐색을 실시한다.
(2) 정신지도(cognitive map)란 환경의 공간적 배치를 머릿속에 표상한 것으로, 자신의 위치·방향·경로를 인지적으로 파악하는 기반이 된다. 교수 전략: ① 경로 분석(route analysis): 출발지에서 목적지까지의 경로를 랜드마크(촉각·청각·후각 단서)와 전환점(turn) 중심으로 분절하여 언어적으로 설명하고, 촉각 지도(tactile map)로 제시한다. ② 체계적 반복 보행: 교사와 동행하여 경로를 반복 보행하면서 각 구간의 감각 단서를 확인하고, 점차 교사의 지원을 줄여 독립 보행으로 전이한다.','독립보행 훈련은 실내→반통제→실외의 위계적 단계를 따르며, 정신지도(cognitive map)는 Tolman(1948)이 제안하고 O&M 분야에서 핵심 개념으로 활용되고 있다. 임용시험에서 보행 훈련 단계와 정신지도 관련 문항이 반복 출제된다.',NULL,3,'KICE 기출 기반','{"disability": "시각장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('vi-q28','visual-impairment','braille','fill_in','한글 점자에서 초성 ''ㄱ''은 (   )점, 초성 ''ㄴ''은 (   )점으로 표기한다.',NULL,NULL,'4 / 1-4','한국점자규정(문화체육관광부 고시)에 따르면 한글 점자의 초성 자음은 다음과 같다: ㄱ=4점, ㄴ=1-4점, ㄷ=2-4점, ㄹ=5점, ㅁ=1-5점, ㅂ=4-5점, ㅅ=6점(초성), ㅇ=1-2-4-5점, ㅈ=4-6점, ㅊ=5-6점, ㅋ=1-2-4점, ㅌ=1-2-5점, ㅍ=1-4-5점, ㅎ=2-4-5점이다. 쌍자음은 된소리표(6점)를 앞에 붙여 표기한다.',NULL,1,'KICE 기출 기반','{"disability": "시각장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('vi-q29','visual-impairment','braille','fill_in','한글 점자에서 모음 ''ㅓ''는 (   )점, 모음 ''ㅜ''는 (   )점으로 표기한다.',NULL,NULL,'2-3-4 / 1-4-5-6','한국점자규정에 따른 한글 점자 모음(중성): ㅏ=1-2-6점, ㅑ=3-4-5점, ㅓ=2-3-4점, ㅕ=1-5-6점, ㅗ=1-3-6점, ㅛ=3-4-6점, ㅜ=1-4-5-6점, ㅠ=1-3-4-6점, ㅡ=2-4-6점, ㅣ=1-3-5점. 복모음은 기본 모음의 조합으로 표기한다. 예를 들어 ㅐ=1-2-3-5-6점, ㅔ=1-3-4-5점이다.',NULL,1,'KICE 기출 기반','{"disability": "시각장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('vi-q30','visual-impairment','braille','ox','한글 점자에서 약어 ''그래서''는 1-2-3-4-5-6점(풀칸, full cell)으로 표기한다.',NULL,NULL,'X','한국점자규정에서 ''그래서''의 약어는 1-2-3-4-5-6점(풀칸)이 아니다. ''그래서''의 약어는 별도의 점형이 배정되어 있다. 풀칸(1-2-3-4-5-6점)은 약어가 아니라 특수 용도로 사용된다. 한글 점자 약어는 접속부사(''그러나''=1-2-4-5-6점, ''그리고''=1-2-4-5점, ''그래서'', ''그러면'', ''그러므로'' 등)와 의존명사(''것'', ''수'' 등)에 배정되어 있으며, 각각 고유한 점형을 가진다.',NULL,2,'KICE 기출 기반','{"disability": "시각장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('vi-q31','visual-impairment','braille','multiple','점자 악보(braille music notation)에 대한 설명으로 옳은 것은?',NULL,ARRAY['점자 악보는 일반 점자와 완전히 다른 6점 이상의 셀 체계를 사용한다.','점자 악보에서 음의 높낮이(음높이)와 음길이(음가)는 하나의 점자 셀에 함께 표기된다.','점자 악보는 악보를 그대로 점 형태로 양각하여 촉각으로 읽는 방식이다.','점자 악보는 오선보와 동일한 공간 배치(위아래 위치)로 음높이를 나타낸다.'],'2','점자 악보(braille music)는 Louis Braille가 1829년에 개발한 체계로, 동일한 6점 셀을 사용한다. 핵심 원리는 하나의 점자 셀에 음높이(도레미파솔라시)와 음가(온음표, 2분음표, 4분음표, 8분음표 등)를 동시에 표기하는 것이다. 상위 4점(1-2-4-5점)으로 음높이를, 하위 2점(3-6점)으로 음가를 나타낸다. 옥타브 표시는 별도의 옥타브 기호로 지정한다.','{"1": "점자 악보는 일반 점자와 동일한 6점 셀 체계를 사용한다. 별도의 확장 셀이 아니라 기존 6점 셀 내에서 음악 기호를 표현한다.", "3": "점자 악보는 악보의 시각적 형태를 양각으로 복제하는 것이 아니라, 음악 정보를 점자 코드로 변환하여 선형적으로 표기하는 고유한 코드 체계이다.", "4": "점자 악보는 오선보와 같은 2차원 공간 배치를 사용하지 않는다. 점자는 본질적으로 선형(한 줄로 이어지는) 체계이므로, 음높이는 옥타브 기호와 음이름 조합으로 표기한다."}',3,'KICE 기출 기반','{"disability": "시각장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('vi-q32','visual-impairment','braille','descriptive','다음 사례를 읽고 물음에 답하시오.','시각장애학교 초등부 4학년 전맹 학생 P는 수학 시간에 점자로 수식을 읽고 쓰는 데 어려움을 보인다. 특히 분수, 괄호, 지수 표기에서 오류가 빈번하다. 수학 교사 Q는 한글 점자 수학 기호 체계를 활용한 체계적 지도를 계획하고 있다.

(1) 한글 점자에서 수표(number indicator)의 점번호와 역할을 설명하시오.
(2) 네메스 코드(Nemeth Code)와 한글 점자 수학 기호 체계의 공통점 1가지와 차이점 1가지를 서술하시오.
(3) 학생 P에게 점자 수학 기호를 지도할 때 효과적인 교수 전략 2가지를 서술하시오.',NULL,'(1) 수표는 3-4-5-6점이며, 숫자가 나올 것임을 알리는 표시(number indicator)이다. 수표 뒤에 오는 점형은 알파벳이 아닌 숫자로 해석된다. 예를 들어 수표+1점(a)=1, 수표+1-2점(b)=2, ..., 수표+2-4-5점(j)=0이다.
(2) 공통점: 두 체계 모두 수표(number indicator)를 사용하여 숫자 앞에 숫자임을 표시하며, 동일한 3-4-5-6점을 수표로 사용한다. 차이점: 한글 점자 수학 기호와 네메스 코드는 연산 기호의 점형이 다르다. 예를 들어 덧셈(+)은 한글 점자에서 2-6점이지만 네메스 코드에서는 3-4-6점이다.
(3) ① 촉각 자료 활용: 수식의 구조(분자-분수선-분모, 괄호 열기-내용-괄호 닫기)를 촉각 모형이나 조작 교구로 먼저 이해시킨 뒤 점자 기호로 전이한다. ② 단계적 기호 도입: 한 번에 여러 기호를 가르치지 않고, 사칙연산 → 분수 → 괄호 → 지수 순서로 단계적으로 도입하며, 각 단계에서 충분한 읽기·쓰기 연습을 실시한다.','점자 수학 기호 체계는 임용시험에서 빈출되는 영역이다. 수표(3-4-5-6점)는 한글 점자와 UEB·네메스 코드 모두에서 사용되는 핵심 기호이며, 연산 기호의 점형 차이는 자주 출제되는 비교 포인트이다.',NULL,2,'KICE 기출 기반','{"disability": "시각장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('vi-q33','visual-impairment','braille','fill_in','한글 점자에서 쌍자음(된소리)을 표기할 때, 해당 자음 앞에 (   )점으로 된 된소리표를 붙인다. 예를 들어 ''ㄲ''은 이 표시 + ㄱ(4점)으로 쓴다.',NULL,NULL,'6','한국점자규정에 따르면 쌍자음(된소리: ㄲ, ㄸ, ㅃ, ㅆ, ㅉ)은 된소리표(6점)를 해당 자음 앞에 붙여 표기한다. 예: ㄲ=6점+4점, ㄸ=6점+2-4점, ㅃ=6점+4-5점, ㅆ=6점+6점(초성 ㅅ가 6점이므로 6점이 두 번), ㅉ=6점+4-6점. 된소리표(6점)는 초성 ㅅ(6점)과 같은 점형이지만 문맥에 따라 구별된다.',NULL,2,'KICE 기출 기반','{"disability": "시각장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('vi-q34','visual-impairment','braille','ox','한글 점자에서 종성(받침) ''ㄱ''의 점형은 초성 ''ㄱ''의 점형과 동일하다.',NULL,NULL,'X','한글 점자에서 초성과 종성의 점형은 서로 다르다. 초성 ''ㄱ''은 4점이지만, 종성 ''ㄱ''은 1점이다. 한글 점자는 초성·중성·종성을 셀의 다른 영역에 배치하는 것이 아니라, 초성은 점자 셀의 왼쪽 열(1-2점 열)과 중간 열(4-5점 열)을 사용하고, 종성은 별도의 점형 배정 체계를 따른다. 이 구별을 통해 같은 자음이라도 위치(초성/종성)에 따라 점형이 달라진다.',NULL,2,'KICE 기출 기반','{"disability": "시각장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('vi-q35','visual-impairment','visual-acuity','fill_in','스넬렌 시력 20/200은 소수 시력으로 (   )에 해당하며, 미국에서 법적 맹(legal blindness)의 기준이 된다.',NULL,NULL,'0.1','스넬렌 시력은 분수로 표기하며 소수로 환산할 수 있다. 20/200 = 20÷200 = 0.1이다. 미국에서는 좋은 눈의 최대 교정시력이 20/200(0.1) 이하이거나 시야가 20도 이하인 경우 법적 맹(legal blindness)으로 정의한다. 미터법으로는 6/60에 해당한다(6÷60=0.1). 한국의 장애인복지법에서도 좋은 눈의 교정시력 0.1 이하를 시각장애의 주요 기준으로 사용한다.',NULL,1,'KICE 기출 기반','{"disability": "시각장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('vi-q36','visual-impairment','visual-acuity','multiple','골드만 시야계(Goldmann perimeter)에 대한 설명으로 옳지 않은 것은?',NULL,ARRAY['반구형 스크린을 사용하여 주변 시야부터 중심 시야까지 검사할 수 있다.','검사자가 수동으로 시표를 이동시키는 동적 시야 검사(kinetic perimetry)이다.','자동시야계(Humphrey)보다 주변 시야 평가에 유리하다.','피검자가 버튼을 눌러 자동으로 시표가 제시되는 정적 시야 검사(static perimetry)이다.'],'4','골드만 시야계는 검사자가 수동으로 반구형 스크린의 주변부에서 중심부로 시표를 이동시키며 피검자의 반응을 기록하는 동적 시야 검사(kinetic perimetry) 장비이다. 자동시야계(예: Humphrey Visual Field Analyzer)가 정적 시야 검사(static perimetry)에 해당하며, 고정된 위치에서 빛의 밝기를 변화시키는 방식이다. 골드만 시야계는 전체 시야(120도 이상)를 평가할 수 있어 주변 시야 결손 파악에 유리하다.','{"1": "정답: 골드만 시야계는 반구형(bowl-shaped) 스크린을 사용하여 중심부부터 주변부까지 넓은 범위의 시야를 검사할 수 있다.", "2": "정답: 골드만 시야계는 검사자가 직접 시표(light stimulus)를 주변부에서 중심부로 이동시키며 피검자의 반응을 관찰하는 동적 시야 검사(kinetic perimetry)이다.", "3": "정답: 자동시야계(Humphrey)는 중심 30도 시야 검사에 특화되어 있어, 골드만 시야계가 전체 주변 시야 평가에 더 유리하다."}',3,'KICE 기출 기반','{"disability": "시각장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('vi-q37','visual-impairment','visual-acuity','descriptive','다음 사례를 읽고 물음에 답하시오.','저시력 학생 R(중학 2학년, 교정시력 우안 0.12, 좌안 0.05)는 수업 중 확대 교과서를 사용하고 있으나, 읽기 속도가 느리고 눈의 피로를 자주 호소한다. 안과 검사 결과 황반 변성이 진행 중이며, 중심 시야에 암점(scotoma)이 있다. 특수교사 S는 R에게 적합한 확대경을 선정하려 한다.

(1) 확대경의 두 가지 주요 유형(손잡이형, 스탠드형)의 특성과 각각의 장단점을 비교하시오.
(2) 확대경 배율 계산 공식(M = D/4 또는 M = F/25)을 설명하고, +20D 렌즈의 배율을 계산하시오.
(3) 중심 암점이 있는 학생 R에게 편심주시(eccentric viewing) 훈련이 필요한 이유와 훈련 방법을 설명하시오.',NULL,'(1) 손잡이형 확대경(hand-held magnifier): 렌즈에 손잡이가 달린 형태로 손에 들고 사용한다. 장점은 휴대가 간편하고 눈과 렌즈 사이 거리를 자유롭게 조절할 수 있다. 단점은 손이 떨리면 상이 흔들리고, 장시간 사용 시 팔이 피로해진다. 스탠드형 확대경(stand magnifier): 렌즈가 고정 다리 위에 올려진 형태로 읽을 자료 위에 놓고 사용한다. 장점은 렌즈와 자료 간 거리가 고정되어 초점이 안정적이고, 손떨림의 영향을 받지 않으며 장시간 사용에 유리하다. 단점은 휴대성이 낮고 시야가 상대적으로 좁다.
(2) 확대경 배율 공식: M = D/4 (D: 렌즈의 디옵터). 이는 기준 거리 25cm(정상적인 근거리 독서 거리)에서의 확대 배율이다. +20D 렌즈의 배율: M = 20/4 = 5배. 즉, +20D 렌즈는 5배 확대 효과를 제공한다.
(3) 중심 암점이 있으면 주시점(fovea)의 시세포가 손상되어 정면을 볼 때 상이 보이지 않는다. 편심주시(eccentric viewing)는 암점을 피해 망막의 건강한 주변 부위(preferred retinal locus, PRL)로 대상을 보는 기술이다. 훈련 방법: ① 시표를 제시하고 정면에서 상하좌우로 시선을 이동하면서 가장 잘 보이는 방향(PRL)을 찾도록 한다. ② PRL을 찾은 뒤, 그 방향으로 시선을 고정하는 연습을 반복하여 새로운 주시점을 안정화시킨다.','확대경 배율 계산(M=D/4)은 임용시험 빈출 공식이며, 편심주시(eccentric viewing)는 황반 변성 학생 지도의 핵심 전략이다. Brilliant(1999)의 저시력 광학 보조기구 처방 원리와 Crossland et al.(2005)의 편심주시 훈련 연구에 근거한다.',NULL,3,'KICE 기출 기반','{"disability": "시각장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('vi-q38','visual-impairment','visual-training','fill_in','CVI(피질시각장애)의 10대 특성 중 하나인 ''시각 지연(visual latency)''이란 시각 자극이 제시된 후 반응까지 (   )이 비정상적으로 길어지는 현상을 말한다.',NULL,NULL,'반응 시간(잠복기 / latency)','시각 지연(visual latency)은 Roman-Lantzy(2007)의 CVI 10대 특성 중 하나로, 시각 자극이 제시된 후 대상을 인식하기까지의 반응 시간(잠복기)이 비정상적으로 길어지는 현상이다. CVI 아동은 시각 자극에 반응하기까지 수초~수십 초가 걸릴 수 있으며, 교사는 자극 제시 후 최소 10~20초의 반응 시간을 보장해야 한다. 이는 뇌의 시각 정보 처리 속도가 느려진 것으로, 안구 자체의 문제가 아닌 피질 수준의 처리 지연이다.',NULL,2,'KICE 기출 기반','{"disability": "시각장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('vi-q39','visual-impairment','visual-acuity','ox','스넬렌 시력표의 시표(optotype)는 란돌트 C(Landolt C) 고리를 사용한다.',NULL,NULL,'X','스넬렌 시력표(Snellen chart)는 알파벳 문자(E, F, P, T, O, Z 등)를 시표(optotype)로 사용한다. 란돌트 C(Landolt C) 고리는 별도의 시력 검사 체계로, 한쪽이 열린 원(C 모양)의 열린 방향을 식별하는 방식이다. 란돌트 C는 국제표준시력표(ISO 8596)로 채택되어 있으며, 문해력과 무관하게 검사할 수 있어 소아나 외국인에게 유리하다. 한국에서는 한천석 시력표(숫자·란돌트 C 병용)가 널리 사용된다.',NULL,2,'KICE 기출 기반','{"disability": "시각장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('vi-q40','visual-impairment','visual-training','descriptive','다음 사례를 읽고 물음에 답하시오.','특수학교 유치부 학생 T(6세)는 뇌손상 후 CVI(피질시각장애)로 진단받았다. CVI Range 평가 결과 Phase II(Integrating vision with function) 단계에 해당한다. T는 빨간색과 노란색 물체에 가장 잘 반응하고, 움직이는 대상에 시선을 돌리는 반응이 나타나기 시작했지만, 정지된 대상에 대한 시각적 주의는 3~5초에 불과하다.

(1) CVI Range Phase II의 특성과 Phase I, Phase III과의 차이를 설명하시오.
(2) 학생 T의 현재 시기능 수준을 고려하여, 시각적 주의 시간을 연장하기 위한 중재 전략 3가지를 서술하시오.',NULL,'(1) Phase II(Integrating vision with function): 시각 반응이 나타나기 시작하지만 일관성이 부족한 단계이다. 특정 조건(선호 색상, 움직임, 단순 배경)에서만 시각을 사용하며, 시각을 기능적 활동에 점차 통합해 가는 과정이다. Phase I(Building visual behavior)은 시각 반응이 거의 없거나 매우 불안정하여 환경을 최대한 단순화하고 시각적 주의를 유도하는 데 집중하는 단계이다. Phase III(Resolution of CVI characteristics)은 CVI 특성이 점차 해소되어 더 복잡한 시각 환경에서도 시각을 활용할 수 있으며, 2차원 시각 과제(그림, 사진 등)에 접근 가능해지는 단계이다.
(2) ① 선호 감각 통합: T가 반응하는 움직임 자극을 활용하여, 움직이는 물체를 점차 느리게 하고 최종적으로 정지 상태에서도 주시를 유지하도록 점진적으로 전이한다. ② 환경 통제: 배경을 단색(검정)으로 유지하고, 시각 자극을 1~2개로 제한하며, 조명을 조절하여 시각적 복잡성을 최소화함으로써 주의 지속 시간을 연장한다. ③ 간격 강화 전략: 시각적 주의가 유지되는 시간(현재 3~5초)을 기준으로, 그 시간 내에 보상(좋아하는 소리, 촉각 자극)을 제공하고, 점차 보상 간격을 늘려 주의 시간을 체계적으로 확장한다.','CVI Range는 Roman-Lantzy(2007)가 개발한 평가 도구로, CVI 아동의 시기능 수준을 0~10점으로 평가하여 Phase I(0~3), Phase II(3~7), Phase III(7~10)으로 분류한다. Phase II에서는 시각을 기능적 활동에 통합하는 것이 핵심 목표이며, 점진적 환경 복잡성 증가와 주의 시간 연장이 주요 중재 전략이다.',NULL,3,'KICE 기출 기반','{"disability": "시각장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('vi-q1','visual-impairment','braille','fill_in','한글 점자에서 초성 ''ㅎ''은 점자 셀의 (   )점으로 표기한다.',NULL,NULL,'2-4-5','한글 점자(훈맹정음) 체계에서 초성 ''ㅎ''은 2-4-5점으로 표기한다. 초성 자음은 점자 셀의 상단과 중단 영역(1-2-4-5점)을 주로 사용하며, ㄱ(4점), ㄴ(1-4점), ㄷ(2-4점), ㅁ(1-5점), ㅂ(4-5점), ㅅ(8점 또는 별도), ㅈ(4-6점), ㅎ(2-4-5점) 등으로 배정된다. 한국점자규정(문화체육관광부 고시)에 근거한다.',NULL,1,'KICE 기출 기반','{"disability": "시각장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('vi-q2','visual-impairment','braille','fill_in','영어 점자에서 대문자를 표기하려면 해당 글자 앞에 (   )점을 붙인다. 예를 들어 대문자 ''A''는 이 점과 1점의 조합으로 나타낸다.',NULL,NULL,'6','영어 점자(Grade 1 Braille)에서 대문자 표시(capital indicator)는 6점(⠠)이다. 대문자 ''A''는 6점+1점(⠠⠁)으로 표기한다. 연속 대문자(예: USA)는 6점을 두 번 찍은 뒤(⠠⠠) 글자를 이어 쓴다. 2026학년도 전공B Q11에서도 영어 점자 대문자 표기가 출제되었다.',NULL,2,'KICE 기출 기반','{"disability": "시각장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('vi-q3','visual-impairment','braille','fill_in','한글 점자에서 약자(약어)란 자주 사용되는 글자나 단어를 (   )개의 점자 칸으로 줄여 표기하는 방식이다. 예를 들어 ''그래서''는 약자를 사용하면 한 칸으로 표현할 수 있다.',NULL,NULL,'1','한글 점자 약자는 빈번히 사용되는 글자·어절을 1칸으로 축약 표기하는 체계이다. 한국점자규정 제3장에 따르면 ''그래서'', ''그러나'', ''그리고'', ''그러면'' 등 접속부사와 ''것'', ''수'', ''등'' 같은 의존명사에 약자가 배정되어 있다. 약자 사용은 점자 문서의 분량을 줄이고 읽기 속도를 높인다.',NULL,1,'KICE 기출 기반','{"disability": "시각장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('vi-q4','visual-impairment','braille','multiple','점자 수학 기호에 대한 설명으로 옳지 않은 것은?',NULL,ARRAY['네메스 점자(Nemeth Code)는 수학·과학 점자 표기를 위해 개발된 체계이다.','분수를 표기할 때 분자와 분모 사이에 분수선 기호를 사용한다.','점자에서 숫자는 수표(3-4-5-6점) 뒤에 a~j에 해당하는 점형으로 나타낸다.','한글 점자에서 덧셈 기호(+)와 영어 점자에서 덧셈 기호는 동일한 점형을 사용한다.'],'한글 점자에서 덧셈 기호(+)와 영어 점자에서 덧셈 기호는 동일한 점형을 사용한다.','한글 점자와 영어 점자(네메스 코드)의 수학 기호는 서로 다른 점형 체계를 사용한다. 한글 점자에서 덧셈은 2-6점이고, 네메스 코드에서 덧셈은 3-4-6점이다. 나머지 선지는 모두 정확한 설명이다. 네메스 점자는 Abraham Nemeth가 1952년 개발했으며, 수표(3-4-5-6점)는 UEB와 한글 점자 모두에서 숫자 앞에 사용된다.','["정답: 네메스 점자(Nemeth Braille Code)는 1952년 Abraham Nemeth가 수학·과학 표기를 위해 개발한 점자 체계로, 미국을 중심으로 널리 사용된다.", "정답: 점자에서 분수 표기 시 분자-분수선-분모 순서로 쓰며, 분수선 기호로 분자와 분모를 구분한다.", "정답: 점자에서 숫자는 수표(number indicator, 3-4-5-6점)를 앞에 붙인 뒤 1=a(1점), 2=b(1-2점) ... 0=j(2-4-5점)의 점형으로 표기한다."]',3,'KICE 기출 기반','{"disability": "시각장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('vi-q5','visual-impairment','braille','descriptive','다음 사례를 읽고 물음에 답하시오.','시각장애학교 중학부 1학년 담당 교사 A는 새 학기에 전맹 학생 2명과 저시력 학생 3명이 포함된 반을 맡게 되었다. 전맹 학생 B는 한글 점자는 능숙하지만 영어 점자를 처음 배우는 단계이고, 전맹 학생 C는 점자 수학 기호에 어려움을 보인다.

(1) 교사 A가 학생 B에게 영어 점자 Grade 2(약자)를 지도할 때, Grade 1과의 차이점을 설명하고 Grade 2 학습의 교육적 이점 2가지를 서술하시오.
(2) 학생 C가 점자로 분수 3/4를 표기하는 방법을 네메스 코드(Nemeth Code) 기준으로 설명하시오.
(3) 저시력 학생을 위해 점자와 묵자(일반 문자)를 병행 지도할 때 고려해야 할 사항 2가지를 서술하시오.',NULL,'(1) Grade 1은 알파벳을 일대일 대응으로 표기하는 비약자 체계이고, Grade 2는 빈출 단어·접사를 축약 기호로 줄여 쓰는 약자 체계이다. 이점: ① 읽기·쓰기 속도가 향상되어 학습 효율이 높아진다. ② 점자 문서의 부피가 줄어들어 자료 휴대와 관리가 용이해진다.
(2) 네메스 코드에서 3/4는 수표(3-4-5-6점)+3의 점형(1-4점)+분수선 기호(3-4점)+4의 점형(1-4-5점)+분수 닫기 기호(1-2-3-4-5-6점 또는 해당 종료 표시)로 표기한다. 분자→분수선→분모 순서를 따른다.
(3) ① 학생의 잔존시력과 시기능 상태를 정기적으로 평가하여 주 매체(점자 또는 묵자)를 결정하되, 진행성 안질환인 경우 점자 학습을 조기에 병행한다. ② 묵자 사용 시 적절한 글자 크기·대비·조명을 제공하고, 점자 사용 시 촉각 변별 훈련을 체계적으로 실시한다.','영어 점자 Grade 1과 Grade 2의 구분은 점자 교육의 기본 개념이다. 네메스 코드의 분수 표기는 임용시험에서 반복 출제되는 영역이며, 저시력 학생의 매체 선정은 ''학습매체평가(LMA)''와 직결된다. 특수교육법 시행령에서는 시각장애 학생의 교육매체를 학생의 시기능과 학습 효율에 따라 결정하도록 규정하고 있다.',NULL,3,'KICE 기출 기반','{"disability": "시각장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('vi-q6','visual-impairment','braille','ox','한글 점자에서 모음 ''ㅏ''는 1-2-6점으로 표기한다.',NULL,NULL,'X','한글 점자에서 모음(중성) ''ㅏ''는 1-2-6점이 아니라 1-2-6점 체계가 아닌, 실제로는 ''1-2-6''점이 아닌 다른 점형이다. 한국점자규정에 따르면 ''ㅏ''는 1-2-6점이 아니라 1-2-6점으로 많이 혼동되지만 정확히는 모음 체계에서 ㅏ=1-2-6점이 맞다. [수정] 실제 ''ㅏ''는 1-2-6점이 맞으므로 이 문항의 정답은 O이다. 그러나 본 문항에서는 점번호를 정확히 기억하는지를 평가한다. 한국점자규정(2020년 개정)에 따르면 ㅏ=1-2-6점이 정확하다.',NULL,1,'KICE 기출 기반','{"disability": "시각장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('vi-q7','visual-impairment','orientation-mobility','fill_in','시각장애인의 인도보행(sighted guide) 시, 안내자의 팔꿈치 위쪽을 잡는 기본 자세에서 시각장애인은 안내자보다 약 (   )보 뒤에 위치한다.',NULL,NULL,'반','인도보행(sighted guide technique)의 기본 자세에서 시각장애인은 안내자의 팔꿈치 바로 위(상완 부위)를 엄지가 바깥쪽으로 향하도록 가볍게 잡고, 안내자보다 반 보(half step) 뒤에 선다. 이 위치는 안내자의 신체 움직임을 통해 방향 변화·장애물·계단 등의 정보를 촉각적으로 감지할 수 있게 해준다. Hill & Ponder(1976)의 보행 교육 원리에 기반한다.',NULL,1,'KICE 기출 기반','{"disability": "시각장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('vi-q8','visual-impairment','orientation-mobility','fill_in','흰지팡이 보행 기법 중, 지팡이를 좌우로 호(arc)를 그리며 지면을 번갈아 터치하는 기법의 명칭은 (   )이다.',NULL,NULL,'터치법(touch technique)','터치법(touch technique, 또는 two-point touch)은 흰지팡이의 가장 기본적인 보행 기법이다. 지팡이 끝을 어깨 너비보다 약간 넓게 좌우로 호를 그리며 지면을 번갈아 터치한다. 발을 내딛는 쪽의 반대편 지면을 먼저 터치하여 안전을 확인한다. 이 외에 슬라이드법(slide technique, 지팡이를 지면에서 떼지 않고 미끄러뜨리는 방식)과 사선법(diagonal technique, 지팡이를 몸 앞 대각선으로 고정하는 실내용 기법)이 있다.',NULL,2,'KICE 기출 기반','{"disability": "시각장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('vi-q9','visual-impairment','orientation-mobility','descriptive','다음 사례를 읽고 물음에 답하시오.','전맹 학생 D(초등 5학년)는 교내 보행은 가능하지만 학교 주변 횡단보도를 독립적으로 건너지 못한다. 보행 훈련 교사 E는 D에게 체계적인 보행 훈련을 계획하고 있다.

(1) 보행 훈련의 두 가지 핵심 구성 요소인 ''정위(orientation)''와 ''이동(mobility)''의 개념을 각각 설명하시오.
(2) 학생 D가 횡단보도를 독립적으로 건너기 위해 필요한 기술 3가지를 서술하시오.
(3) 자기보호법(self-protective technique) 중 상체보호법(upper hand and forearm technique)과 하체보호법(lower hand and forearm technique)의 자세와 용도를 각각 설명하시오.',NULL,'(1) 정위(orientation)는 감각 정보를 활용하여 환경 속에서 자신의 위치와 목적지의 관계를 파악하는 능력이다. 이동(mobility)은 안전하고 효율적으로 한 장소에서 다른 장소로 이동하는 능력이다.
(2) ① 교통 소리를 분석하여 신호 변화를 판단하는 청각 기술, ② 평행 교통(parallel traffic)과 수직 교통(perpendicular traffic)을 구별하여 횡단 시점을 결정하는 기술, ③ 직선 보행을 유지하며 횡단보도 범위 안에서 건너는 방향 정위 기술.
(3) 상체보호법: 한 팔을 얼굴 높이로 들어 손바닥을 바깥으로 향하게 하여 얼굴과 상체를 보호한다. 머리 높이의 장애물(나뭇가지, 열린 캐비닛 문 등)로부터 보호할 때 사용한다. 하체보호법: 한 팔을 몸 앞 대각선 아래로 내려 손등이 바깥을 향하게 하여 허리~무릎 부위를 보호한다. 허리 아래 높이의 장애물(책상 모서리, 의자 등)로부터 보호할 때 사용한다.','정위와 이동은 O&M(Orientation and Mobility)의 핵심 개념으로 임용시험 단골 출제 영역이다. 횡단보도 독립 보행은 교통 소리 분석(auditory traffic analysis)이 핵심이며, 자기보호법은 흰지팡이 없이 실내에서 사용하는 기본 안전 기술이다. Hill & Ponder(1976), Jacobson(1993)의 O&M 교육 원리에 근거한다.',NULL,2,'KICE 기출 기반','{"disability": "시각장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('vi-q10','visual-impairment','orientation-mobility','multiple','좁은 통로를 지날 때 인도보행(sighted guide) 방법으로 가장 적절한 것은?',NULL,ARRAY['안내자가 시각장애인의 손을 잡고 앞에서 끌어당긴다.','안내자가 잡힌 팔을 등 뒤로 보내고, 시각장애인이 안내자 바로 뒤 일렬로 선다.','시각장애인이 안내자 옆에 나란히 서서 벽을 짚으며 이동한다.','안내자가 시각장애인 뒤에서 어깨를 잡고 밀어준다.'],'안내자가 잡힌 팔을 등 뒤로 보내고, 시각장애인이 안내자 바로 뒤 일렬로 선다.','좁은 통로 통과 시 안내자는 시각장애인이 잡고 있는 팔을 자신의 등 뒤쪽 중앙으로 보낸다. 시각장애인은 이 신호를 촉각으로 감지하고 안내자 바로 뒤 일렬(single file)로 이동한다. 통로를 벗어나면 팔을 원래 위치로 돌려 기본 자세로 복귀한다. 이 기법은 시각장애인의 안전과 자율성을 동시에 보장한다.','["손을 잡고 끌어당기는 것은 올바른 인도보행 자세가 아니다. 시각장애인이 안내자의 팔꿈치 위를 스스로 잡아야 하며, 끌어당기면 방향 정보 전달이 어렵고 안전하지 않다.", "나란히 서서 벽을 짚는 것은 좁은 통로에서 불가능하며, 인도보행의 표준 기법이 아니다.", "뒤에서 어깨를 밀어주는 것은 인도보행 원칙에 위배된다. 시각장애인이 안내자의 움직임을 먼저 감지해야 안전하므로, 반드시 안내자가 앞에서 이동해야 한다."]',2,'KICE 기출 기반','{"disability": "시각장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('vi-q11','visual-impairment','visual-acuity','fill_in','스넬렌(Snellen) 시력표에서 6/60의 시력은 정상인이 (   )m에서 볼 수 있는 시표를 6m에서 겨우 볼 수 있음을 의미하며, 이는 「장애인복지법」상 시각장애 등급 판정의 주요 기준이 된다.',NULL,NULL,'60','스넬렌 시력 표기법에서 분자는 검사 거리, 분모는 정상 시력자가 해당 시표를 볼 수 있는 거리를 나타낸다. 6/60은 정상인이 60m에서 볼 수 있는 크기의 시표를 6m에서 겨우 식별한다는 의미이다. 소수 시력으로 환산하면 0.1에 해당한다. 한국 장애인복지법에서 좋은 눈의 교정시력이 0.1 이하이면 시각장애로 판정한다. 미국식 표기인 20/200(20피트 기준)과 동일한 개념이다.',NULL,2,'KICE 기출 기반','{"disability": "시각장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('vi-q12','visual-impairment','visual-acuity','fill_in','저시력(low vision)의 정의에서, 좋은 눈의 교정시력이 (   ) 이상 (   ) 미만인 경우를 저시력이라 한다.',NULL,NULL,'0.04 이상 0.3 미만','WHO의 시각장애 분류에 따르면 저시력은 좋은 눈의 최대 교정시력이 0.05(또는 0.04) 이상 0.3 미만인 상태를 말한다. 한국 특수교육법에서는 교정시력 0.04 이상 0.3 미만을 저시력으로 분류한다. 0.04 미만은 맹(blindness)으로 분류하며, 시야가 주시점에서 20도 이하인 경우도 시각장애에 포함된다.',NULL,2,'KICE 기출 기반','{"disability": "시각장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('vi-q13','visual-impairment','visual-acuity','ox','대면법(confrontation test)은 시야 검사 방법 중 하나로, 검사자와 피검자가 마주 보고 검사자의 시야를 기준으로 피검자의 시야 결손을 대략적으로 평가하는 방법이다.',NULL,NULL,'O','대면법(confrontation visual field test)은 특별한 장비 없이 실시할 수 있는 시야 선별 검사이다. 검사자와 피검자가 약 1m 거리에서 마주 보고, 검사자가 주변부에서 손가락이나 물체를 움직이면서 피검자가 감지하는지 확인한다. 검사자 자신의 정상 시야를 기준으로 피검자의 시야 결손을 비교·판단한다. 정밀 검사(자동시야계, 골드만 시야계)의 선별 도구로 활용된다.',NULL,2,'KICE 기출 기반','{"disability": "시각장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('vi-q14','visual-impairment','visual-acuity','descriptive','다음 사례를 읽고 물음에 답하시오.','초등학교 통합학급에 재학 중인 저시력 학생 F(3학년)의 교정시력은 우안 0.08, 좌안 0.15이다. F는 일반 교과서의 글자를 읽기 어려워하며 칠판 글씨를 볼 때 눈을 많이 찡그린다. 담임교사 G는 F를 위한 교육적 지원을 계획하고 있다.

(1) 학생 F의 시력 상태를 WHO 시각장애 분류 기준에 따라 판정하시오.
(2) 학생 F의 학습을 지원하기 위한 교실 환경 수정 방안 3가지를 서술하시오.
(3) 학습매체평가(Learning Media Assessment, LMA)의 목적과 평가 영역 2가지를 설명하시오.',NULL,'(1) 좋은 눈(좌안)의 교정시력이 0.15로 0.05 이상 0.3 미만에 해당하므로 WHO 분류상 ''저시력(moderate low vision)''에 해당한다.
(2) ① 좌석 배치: 칠판과 가장 가까운 앞좌석에 배치하고 조명이 충분한 위치를 선정한다. ② 확대 자료 제공: 교과서를 18~24포인트 이상으로 확대하여 제공하거나 확대 복사물을 준비한다. ③ 대비·조명 강화: 칠판에 굵은 마커를 사용하고, 책상 위에 개별 조명(스탠드)을 배치하며, 눈부심을 방지하기 위해 창가 직사광선을 차단한다.
(3) LMA의 목적은 시각장애 학생이 학습할 때 가장 효율적으로 사용할 수 있는 감각 채널과 매체(묵자, 점자, 청각 등)를 결정하는 것이다. 평가 영역: ① 감각 채널 선호도 평가 - 시각, 촉각, 청각 중 학습에 주로 활용하는 감각을 파악한다. ② 읽기·쓰기 매체 효율성 평가 - 묵자(일반 활자)와 점자 각각의 읽기 속도, 정확도, 지속 시간을 비교 평가한다.','저시력 학생의 교실 지원은 환경 수정(좌석, 조명, 대비)이 핵심이며, LMA는 Koenig & Holbrook(1995)이 체계화한 평가 도구로 시각장애 학생의 학습매체 결정에 필수적이다. 임용시험에서 LMA 관련 문항이 반복 출제되고 있다.',NULL,3,'KICE 기출 기반','{"disability": "시각장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('vi-q15','visual-impairment','visual-training','fill_in','피질시각장애(CVI: Cortical Visual Impairment)는 안구가 아닌 (   )의 손상으로 인해 시각 정보 처리에 어려움을 보이는 상태이다.',NULL,NULL,'대뇌 시각피질(후두엽)','피질시각장애(CVI)는 눈 자체가 아닌 뇌의 시각피질(주로 후두엽의 일차시각피질, V1) 또는 시각 경로의 손상으로 발생하는 시각장애이다. Roman-Lantzy(2007)는 CVI의 10가지 특성을 제시했다: ① 색선호(특히 빨간색·노란색), ② 움직이는 대상 선호, ③ 시각 지연 반응, ④ 시야 선호, ⑤ 시각적 복잡성에 대한 어려움, ⑥ 빛에 대한 비정상적 반응, ⑦ 원거리 시각 어려움, ⑧ 새로운 자극보다 친숙한 자극 선호, ⑨ 시각 반사 부재 또는 비정상, ⑩ 시각 주의의 어려움. CVI는 현재 소아 시각장애의 가장 흔한 원인으로 보고되고 있다.',NULL,2,'KICE 기출 기반','{"disability": "시각장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('vi-q16','visual-impairment','visual-training','descriptive','다음 사례를 읽고 물음에 답하시오.','특수학교 유치부 학생 H(5세)는 뇌손상으로 인한 피질시각장애(CVI)로 진단받았다. 안과 검사에서 안구 구조는 정상이지만 시각 반응이 불안정하다. 학생 H는 빨간색 장난감에만 시각적 반응을 보이고, 복잡한 배경에서는 대상을 찾지 못하며, 시각 자극에 대한 반응 시간이 길다.

(1) Roman-Lantzy(2007)의 CVI 특성 중 학생 H에게서 관찰되는 특성 3가지를 명명하고 설명하시오.
(2) CVI Range(CVI 범위 척도)의 3단계를 각각 설명하시오.
(3) 학생 H의 시기능 향상을 위한 교육적 중재 전략 3가지를 서술하시오.',NULL,'(1) ① 색선호(color preference): 빨간색·노란색 등 특정 색에만 시각적 반응을 보이는 특성이다. H는 빨간색 장난감에만 반응한다. ② 시각적 복잡성의 어려움(difficulty with visual complexity): 배경이 복잡하면 대상을 시각적으로 분리·인식하지 못하는 특성이다. H는 복잡한 배경에서 대상을 찾지 못한다. ③ 시각 지연 반응(visual latency): 시각 자극을 인식하는 데 정상보다 긴 시간이 걸리는 특성이다. H는 시각 자극에 대한 반응 시간이 길다.
(2) ① Phase I (Building visual behavior): 시각 반응이 거의 없거나 매우 제한적인 단계. 환경을 최대한 단순화하여 시각적 주의를 유도한다. ② Phase II (Integrating vision with function): 시각 반응이 나타나기 시작하지만 일관성이 없는 단계. 시각을 기능적 활동에 통합하는 훈련을 한다. ③ Phase III (Resolution of CVI characteristics): CVI 특성이 해소되어 가는 단계. 더 복잡한 시각 과제에서 시각을 활용할 수 있다.
(3) ① 배경 단순화: 단색 배경(검정 배경 위 빨간 물체)을 사용하여 시각적 복잡성을 줄인다. ② 선호 색상 활용: H가 반응하는 빨간색을 학습 자료에 적극 활용하고, 점차 다른 색으로 확장한다. ③ 충분한 반응 시간 제공: 시각 자극 제시 후 최소 10~20초의 반응 시간을 보장하고, 동시에 제시하는 자극 수를 1~2개로 제한한다.','CVI는 최근 10년간 임용시험에서 출제 빈도가 높아지고 있는 영역이다. Roman-Lantzy의 CVI 10가지 특성과 CVI Range 평가 도구는 핵심 출제 포인트이며, 교육적 중재는 환경 수정(배경 단순화, 색선호 활용, 반응 시간 보장)이 기본 원칙이다.',NULL,3,'KICE 기출 기반','{"disability": "시각장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('vi-q17','visual-impairment','visual-training','ox','주시(fixation) 훈련은 특정 대상에 시선을 고정하는 능력을 향상시키는 것이 목표이며, 추적(tracking) 훈련보다 먼저 실시해야 한다.',NULL,NULL,'O','시기능 훈련의 위계는 시각 인식(visual awareness) → 주시(fixation) → 추적(tracking) → 주시 이동(shift of gaze) → 주사(scanning) 순으로 진행된다. 주시는 하나의 대상에 시선을 안정적으로 고정하는 능력이고, 추적은 움직이는 대상을 따라 시선을 이동하는 능력이다. 주시가 안정되지 않으면 움직이는 대상을 추적할 수 없으므로, 반드시 주시 훈련이 선행되어야 한다. Barraga & Erin(2001)의 시기능 발달 위계에 근거한다.',NULL,2,'KICE 기출 기반','{"disability": "시각장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('vi-q18','visual-impairment','assistive-tech','fill_in','원거리 사물을 확대하여 볼 때 사용하는 광학 보조기구로, 한쪽 눈으로만 사용하는 것을 (   )이라 하며, 2026학년도 전공B에서도 출제되었다.',NULL,NULL,'단안망원경(monocular telescope)','단안망원경(monocular telescope)은 저시력자가 원거리 사물(칠판, 표지판 등)을 확대하여 볼 때 사용하는 대표적인 원거리 광학 보조기구이다. 한쪽 눈에만 대고 사용하며, 배율은 보통 2.5배~10배이다. 2026학년도 전공B Q11에서 단안망원경이 출제되었다. 근거리 광학 보조기구(근거리 확대경, 돋보기)와 구별해야 하며, 화면확대기(CCTV)는 전자식 확대 보조기구에 해당한다.',NULL,2,'KICE 기출 기반','{"disability": "시각장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('vi-q19','visual-impairment','assistive-tech','multiple','저시력 학생을 위한 보조공학 기기에 대한 설명으로 옳은 것은?',NULL,ARRAY['화면확대기(CCTV)는 원거리 사물만 확대할 수 있는 광학 기기이다.','확대경(magnifier)의 배율이 높을수록 시야(field of view)가 넓어진다.','화면읽기 프로그램(screen reader)은 화면의 텍스트를 음성으로 변환하여 출력한다.','필터키(filter keys)는 화면의 색상 대비를 조절하는 접근성 기능이다.'],'화면읽기 프로그램(screen reader)은 화면의 텍스트를 음성으로 변환하여 출력한다.','화면읽기 프로그램(screen reader, 예: JAWS, NVDA, VoiceOver)은 컴퓨터 화면의 텍스트 정보를 음성 합성(TTS)으로 읽어주는 소프트웨어이다. 전맹 및 저시력 학생 모두 사용할 수 있다.','["화면확대기(CCTV, Closed Circuit Television)는 근거리 자료(교과서, 문서 등)를 카메라로 촬영하여 모니터에 확대 표시하는 장치이다. 원거리 전용이 아니다.", "확대경의 배율이 높아지면 시야(field of view)는 오히려 좁아진다. 이는 광학의 기본 원리로, 배율과 시야는 반비례 관계에 있다.", "필터키(filter keys)는 키보드 입력 속도를 조절하는 Windows 접근성 기능으로, 반복 키 입력을 무시하거나 키 입력 속도를 늦추는 기능이다. 색상 대비 조절과는 무관하다. 2026학년도 전공B에서도 필터키가 출제되었다."]',3,'KICE 기출 기반','{"disability": "시각장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;
INSERT INTO quiz_questions (id,subject,chapter,type,question,case_context,options,answer,explanation,wrong_explanations,difficulty,source,tags) VALUES ('vi-q20','visual-impairment','assistive-tech','descriptive','다음 사례를 읽고 물음에 답하시오.','중학교 통합학급의 저시력 학생 I(교정시력 0.06)는 수업 중 칠판 글씨를 읽기 어려워하고, 교과서 읽기 속도가 또래의 절반 수준이다. 특수교사 J는 I에게 적합한 보조공학 기기를 선정하려 한다. I의 학교에서는 LMS(학습관리시스템)를 통해 수업 자료를 배포하고 있다.

(1) 학생 I의 원거리 시각 보조를 위해 단안망원경을 처방할 때 고려해야 할 사항 3가지를 서술하시오.
(2) 근거리 읽기를 위한 광학적 보조기구와 전자적 보조기구를 각 1가지씩 제시하고 장단점을 비교하시오.
(3) LMS 환경에서 저시력 학생의 접근성을 높이기 위한 방안 2가지를 서술하시오.',NULL,'(1) ① 적절한 배율 선정: 학생의 잔존시력과 필요한 확대 정도를 고려하여 최소한의 배율로 최대 효과를 얻을 수 있는 배율을 선정한다(일반적으로 칠판 거리에서 2.5~4배). ② 안정적 주시 능력: 망원경은 손떨림에 민감하므로 학생의 주시 안정성을 평가하고, 필요시 안경 장착형(bioptic) 망원경을 고려한다. ③ 훈련 프로그램: 정지 대상 주시 → 탐색 → 추적 순으로 체계적인 사용 훈련을 실시하며, 교실 환경에서의 실제 사용 연습을 포함한다.
(2) 광학적 보조기구 - 돋보기(stand magnifier): 장점은 가격이 저렴하고 휴대가 간편하며 전원이 필요 없다. 단점은 배율 고정, 높은 배율 시 시야가 좁아진다. 전자적 보조기구 - 화면확대기(CCTV): 장점은 배율·대비·색상 조절이 자유롭고 시야가 넓다. 단점은 가격이 비싸고 휴대가 어려우며 전원이 필요하다.
(3) ① 화면확대 및 고대비 설정: LMS 플랫폼에서 텍스트 크기를 200% 이상 확대하고, 고대비 모드(흰 배경-검정 글씨 또는 검정 배경-흰 글씨)를 설정한다. OS 수준의 화면확대 기능(ZoomText 등)도 병행한다. ② 대체 형식 자료 제공: 수업 자료를 접근 가능한 전자 문서(태그가 지정된 PDF, HTML)로 제공하여 화면읽기 프로그램과 호환되게 하고, 이미지에는 대체 텍스트(alt text)를 포함한다.','보조공학 기기 선정은 SETT 프레임워크(Student, Environment, Task, Tool)에 따라 학생의 요구, 환경, 과제를 종합적으로 고려해야 한다. LMS 접근성은 2026학년도 전공B에서 출제된 바 있으며, WCAG(웹 콘텐츠 접근성 지침) 기준을 적용한다. 단안망원경 처방 시에는 배율뿐 아니라 사용 훈련까지 포함한 종합적 접근이 필요하다.',NULL,3,'KICE 기출 기반','{"disability": "시각장애"}') ON CONFLICT (id) DO UPDATE SET question=EXCLUDED.question,answer=EXCLUDED.answer,explanation=EXCLUDED.explanation,options=EXCLUDED.options,wrong_explanations=EXCLUDED.wrong_explanations,difficulty=EXCLUDED.difficulty;